insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1740, '15', '치매 대상자의 주보호자인 며느리가 다음과 같이 말할 때 요양보호사의 대처방법은? "시아버지를 돌보고 있는데 남편은 고맙다는 말 한마디도 안 하고, 딸은 자기를 하나도 챙기지 않는다며 투정해요. 내가 집에서 노는 줄 알아요."', '["\"남편분에게 얼마나 힘든지 해보라고 하세요.\"", "\"가족들이 몰라주는 것 같아 속상하시겠어요.\"", "\"딸이 엄마를 도와주지는 못할망정 너무하네요.\"", "\"며느리가 돌보는건 당연해요. 조금만 참으세요.\"", "\"제가 가족들에게 도와주라고 말해 볼게요.\""]'::jsonb, 2, '치매 환자를 돌보는 주보호자의 감정에 대해 공감하고, 적절한 대처 방법을 찾는 것.', 'Tìm hiểu cảm xúc của người chăm sóc chính bệnh nhân Alzheimer và tìm cách xử lý phù hợp.', '{"1": ""}'::jsonb, '[{"term_ko": "주보호자", "term_vi": "Người chăm sóc chính", "def_ko": "환자를 곁에서 가장 많이 도와주는 사람", "def_vi": "Người giúp đỡ bệnh nhân nhiều nhất ở bên cạnh"}, {"term_ko": "시아버지", "term_vi": "Bố chồng", "def_ko": "남편의 아버지", "def_vi": "Bố của chồng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1739, '15', '치매 대상자가 주변에 아무도 없는데 저리 가!라고 소리치며 저기 검은 옷 입은 사람이 자꾸 나를 쳐다봐.라고 말할 때 올바른 대처방법은?', '["아무도 없다고 대상자에게 말한다.", "저리 가라고 대상자와 같이 소리친다.", "잘못한 일을 혼내려고 왔나보다고 말한다.", "간식을 제공하거나 좋아하는 활동을 하게 한다.", "기운이 없어서 헛것이 보이는 것이라고 말한다."]'::jsonb, 4, '치매 대상자의 이상 행동에 대한 올바른 대처 방법을 이해하고 있는지를 평가하기 위한 문제입니다.', 'Đây là câu hỏi để đánh giá xem bạn có hiểu cách xử lý hành vi bất thường của người bị bệnh Alzheimer hay không.', '{"1": "대상자에게 아무도 없다고 말하는 것은 대상자의 불안을 더욱 심화시킬 수 있습니다.\nNói với bệnh nhân rằng không có ai sẽ làm trầm trọng thêm sự lo lắng của họ.", "2": "함께 소리치는 것은 상황을 더욱 악화시킬 수 있으므로 적절하지 않습니다.\nHét cùng với bệnh nhân có thể làm tình huống tồi tệ hơn và không thích hợp.", "3": "잘못한 일을 혼내려고 왔다고 말하는 것은 불필요한 혼란을 일으킬 수 있습니다.\nNói rằng bạn đến để la mắng họ có thể gây ra sự nhầm lẫn không cần thiết.\n\n[정답]", "4": "Cung cấp thức ăn nhẹ hoặc cho họ tham gia hoạt động yêu thích là cách xử lý phù hợp.", "5": "기운이 없어서 헛것이 보인다고 말하는 것은 대상자를 불안하게 만들 수 있습니다.\nNói rằng họ mệt mỏi và thấy ảo giác có thể làm tăng lo lắng cho bệnh nhân."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력과 사고에 영향을 미치는 질병", "def_vi": "Bệnh ảnh hưởng đến trí nhớ và suy nghĩ."}, {"term_ko": "대상자", "term_vi": "Người nhận chăm sóc", "def_ko": "보호를 받는 사람", "def_vi": "Người được chăm sóc"}, {"term_ko": "불안", "term_vi": "Lo lắng", "def_ko": "걱정스러운 감정", "def_vi": "Cảm xúc lo lắng"}, {"term_ko": "대처 방법", "term_vi": "Cách xử lý", "def_ko": "문제를 해결하는 방식", "def_vi": "Cách giải quyết vấn đề"}, {"term_ko": "활동", "term_vi": "Hoạt động", "def_ko": "어떤 행동이나 작업", "def_vi": "Hành động hoặc công việc nào đó"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1738, '15', '치매 대상자가 다음과 같은정신행동증상을 보일 때 대처방법은? "목걸이가 없어졌어. 며느리가 가져간게 분명해. 내 방에 몰래 들어가는 걸 봤거든."', '["\"지난번에도 그러시더니, 또 의심하시네요.\"", "\"그래요? 반지나 팔찌는 없어지지 않았어요?\"", "\"앞으로는 저한테 맡기세요. 잘 보관해 드릴게요.\"", "\"목걸이 여기 있잖아요. 왜 그렇게 의심이 많으세요?\"", "\"목걸이가 없어져서 많이 속상하시겠어요.\"라며 함께 찾아본다."]'::jsonb, 5, '대체적으로 치매 대상자의 정신행동증상에 적합한 대처방법을 묻고 있습니다.', 'Hỏi về phương pháp ứng phó phù hợp với triệu chứng hành vi tâm thần của người bị sa sút trí tuệ.', '{"1": "대상자의 감정을 무시하고 비난하는 것이므로 부적절합니다.\nCách này không đúng vì phớt lờ cảm xúc của người bệnh và chỉ trích họ.", "2": "의심을 덜게 하기 위한 방식이지만, 상황을 인정하지 않아서 적절하지 않습니다.\nCách này không phù hợp vì không thừa nhận tình huống, mặc dù nó có thể làm giảm sự nghi ngờ.\n\n[정답]", "5": "Phương pháp này là tiếp cận phù hợp nhất vì hiểu cảm xúc của người bệnh và muốn cùng giải quyết vấn đề.", "3": "책임을 떠넘기는 것이므로 신뢰를 구축하기 어렵습니다.\nCách này sẽ khó xây dựng niềm tin vì chuyển trách nhiệm cho người khác.", "4": "비난의 요소가 있으며 대상자의 감정을 더욱 나쁘게 할 수 있습니다.\nCách này có yếu tố chỉ trích và có thể làm cho cảm xúc của bệnh nhân tồi tệ hơn."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "인지능력이 감소하는 병증", "def_vi": "Bệnh giảm khả năng nhận thức"}, {"term_ko": "대상자", "term_vi": "Người được chữa trị", "def_ko": "치료를 받는 사람", "def_vi": "Người nhận được trị liệu"}, {"term_ko": "정신행동증상", "term_vi": "Triệu chứng hành vi tâm thần", "def_ko": "정신적 또는 행동적 문제를 나타내는 증상", "def_vi": "Triệu chứng biểu hiện vấn đề về tâm lý hoặc hành vi"}, {"term_ko": "대처방법", "term_vi": "Phương pháp ứng phó", "def_ko": "특정 상황에 대한 대응 방법", "def_vi": "Phương pháp đáp ứng với một tình huống cụ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1737, '15', '치매 대상자가 자신의 옷에 배설한 것을 인지하지 못하고 의자에 앉아있을 때 대처방법은?', '["\"어휴 냄새...어르신은 냄새도 안 나세요?\"", "\"왜, 자꾸 실수하시는 거예요? 화장실은 저쪽에 있잖아요.\"", "\"화장실에 가서 옷 갈아입어요.\" 조용하고 부드럽게 말한다.", "\"대변을 봤으면 말씀을 하셔야지, 가만히 계시면 어떻게 해요?\"", "\"너무 많이 드셨나 봐요. 식사량과 음료수 섭취량을 줄여야겠네요.\""]'::jsonb, 3, '치매 환자에 대한 적절한 대처 방법을 묻는 문제입니다.', 'Câu hỏi này hỏi về cách đối phó phù hợp với bệnh nhân mất trí nhớ.', '{"1": "치매 환자에게는 냄새에 대한 말이 불안감이나 수치심을 유발할 수 있습니다.\nNói về mùi hôi có thể gây ra lo lắng hoặc xấu hổ cho bệnh nhân mất trí nhớ.", "2": "치매 환자에게 책임을 묻는 발언은 부정적인 반응을 일으킬 수 있습니다.\nViệc hỏi trách nhiệm có thể gây ra phản ứng tiêu cực từ bệnh nhân mất trí nhớ.\n\n[정답]", "3": "Nói nhẹ nhàng và êm ái sẽ giúp ích cho bệnh nhân mất trí nhớ.", "4": "책임을 묻는 질문은 치매 환자의 자존감에 해롭고, 부정적인 감정을 초래할 수 있습니다.\nCâu hỏi đặt trách nhiệm có thể gây hại cho lòng tự trọng và mang lại cảm giác tiêu cực cho bệnh nhân mất trí nhớ.", "5": "이러한 발언은 치료보다는 문제를 가중시킬 수 있습니다.\nCâu nói này có thể làm nặng thêm vấn đề hơn là chữa trị."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "기억과 사고에 영향을 미치는 질병", "def_vi": "Bệnh ảnh hưởng đến trí nhớ và tư duy"}, {"term_ko": "대처", "term_vi": "Xử lý", "def_ko": "문제나 상황에 맞게 행동함", "def_vi": "Hành động phù hợp với tình huống hoặc vấn đề"}, {"term_ko": "부드럽다", "term_vi": "Mềm mại", "def_ko": "외부에 심한 영향이 없다", "def_vi": "Không có ảnh hưởng mạnh mẽ đến bên ngoài"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1736, '15', '시도 때도 없이 먹으려 하는 치매 대상자가 다음과 말할 때 대처 방법은? "저녁 준비하고 있어? 나 밥 안 먹었는데, 밥 안 줬잖아?"', '["\"제가 방금 드렸잖아요.\" 라고 말한다.", "\"지금은 바빠서준비할 수 없습니다.\" 라고 말한다.", "\"조금만 기다려 주세요.\" 라고 말하며 화초를 닦아 달라고 말한다.", "\"하루 종일 너무 많이 드셔서 드릴 수 없습니다.\"라고 말한다.", "\"밥을 더 드리면 따님에게 혼나요. 이해해 주세요.\"라고 말한다."]'::jsonb, 3, '치매 환자에게 적절한 대처 방법을 이해하고 적용하는 능력을 평가하기 위해 제시한 질문입니다.', 'Câu hỏi được đưa ra nhằm đánh giá khả năng hiểu và áp dụng phương pháp đối phó phù hợp với bệnh nhân Alzheimer.', '{"1": "''제가 방금 드렸잖아요.'' 라고 말한다는 것은 환자의 불안감을 오히려 악화시킬 수 있습니다.\nCâu trả lời này có thể làm tăng thêm sự lo lắng cho bệnh nhân.\n\n[정답]", "3": "Nói ''Chỉ cần chờ một chút.'' và đề nghị bệnh nhân lau cây cũng có thể có hiệu quả tích cực bằng cách chuyển sự chú ý của họ sang điều khác.", "2": "''지금은 바빠서 준비할 수 없습니다.''라고 말하는 것은 환자를 실망시키고 상황을 악화시킬 수 있습니다.\nNói ''Bây giờ tôi bận nên không thể chuẩn bị'' có thể khiến bệnh nhân thất vọng và làm tình hình trở nên xấu đi.", "4": "''하루 종일 너무 많이 드셔서 드릴 수 없습니다.''라고 말하는 것은 환자의 기분이 상할 수 있습니다.\nNói ''Bạn đã ăn quá nhiều suốt cả ngày nên không thể đưa cho bạn được'' có thể làm tổn thương tâm trạng của bệnh nhân.", "5": "''밥을 더 드리면 따님에게 혼나요. 이해해 주세요.''라고 말하는 것은 환자에게 혼란을 줄 수 있습니다.\nNói ''Nếu bạn ăn thêm cơm, bạn sẽ bị con gái mắng. Xin hãy hiểu.'' có thể gây nhầm lẫn cho bệnh nhân."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력과 인지 기능이 점차적으로 저하되는 질환", "def_vi": "Bệnh lí suy giảm trí nhớ và chức năng nhận thức dần dần"}, {"term_ko": "대처", "term_vi": "Đối phó", "def_ko": "문제에 대응하는 방법", "def_vi": "Cách ứng phó với vấn đề"}, {"term_ko": "불안감", "term_vi": "Dùng từ", "def_ko": "마음이 편안하지 않은 상태", "def_vi": "Trạng thái không thoải mái trong tâm trí"}, {"term_ko": "주변", "term_vi": "Xung quanh", "def_ko": "인근 지역, 주변 환경", "def_vi": "Khu vực xung quanh, môi trường xung quanh"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1735, '15', '치매 대상자가 같은 곳을 왔다 갔다 하고, 침을 뱉는 행동을 반복할 때 대처 방법은?', '["그만하라고 야단을 친다.", "반복하는행동을 못하게 한다.", "반복 행동을 지적하여 바로 잡는다.", "뒤에서 다가가 큰소리로 대상자를 부른다.", "수건 접기를 하여 관심을 다른 곳으로 유도한다."]'::jsonb, 5, '치매 환자에 대한 대처 방법을 이해하고 있는지를 평가한다.', 'Đánh giá khả năng hiểu biết về phương pháp xử lý đối với bệnh nhân bị bệnh mất trí nhớ.', '{"1": "그만하라고 야단을 친다.\n이 방법은 오히려 치매 환자에게 혼란과 불안을 초래할 수 있다.\nPhương pháp này có thể tạo ra sự nhầm lẫn và lo lắng cho bệnh nhân bị mất trí nhớ.", "2": "반복하는 행동을 못하게 한다.\n역시 이 방법은 치매 환자의 행동을 억제하기보다는 이해하고 대처하는 것이 필요하다.\nCách này cũng không nên vì cần phải hiểu và xử lý hành vi của bệnh nhân thay vì kiềm chế.", "3": "반복 행동을 지적하여 바로 잡는다.\n치매 환자는 인지능력이 떨어져 잘 이해하지 못할 수 있다.\nBệnh nhân mất trí nhớ có thể không nhận thức được do khả năng nhận thức giảm.", "4": "뒤에서 다가가 큰소리로 대상자를 부른다.\n이 방법은 치매 환자에게 놀라움을 줄 수 있어서 피해야 한다.\nCách này có thể gây bất ngờ cho bệnh nhân và nên tránh.\n\n[정답]", "5": "수건 접기를 하여 관심을 다른 곳으로 유도한다.\n이 방법은 부정적인 행동을 줄이고 긍정적인 대처 방법으로 환자의 관심을 전환시킨다.\nCách này giúp giảm bớt hành vi tiêu cực và chuyển sự chú ý của bệnh nhân sang một hoạt động tích cực khác.", "6": "(없음)"}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력을 잃는 질환", "def_vi": "Bệnh làm mất khả năng nhớ"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "돌보는 사람", "def_vi": "Người được chăm sóc"}, {"term_ko": "반복 행동", "term_vi": "Hành vi lặp lại", "def_ko": "같은 행동을 여러 번 하는 것", "def_vi": "Làm hành động nhiều lần"}, {"term_ko": "수건", "term_vi": "Khăn", "def_ko": "물건의 일종, 일반적으로 사용", "def_vi": "Một loại đồ vật, sử dụng chung"}, {"term_ko": "관심", "term_vi": "Sự quan tâm", "def_ko": "주목하는 것", "def_vi": "Điều được chú ý"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1734, '15', '공격성이 나타나는 치매 대상자의 옷을 갈아입히는 방법으로 옳은 것은?', '["강제로 옷을 갈아입힌다.", "대상자가 화를 내면 같이 화를 낸다.", "옷에 물을 쏟아 젖게 하여 갈아입힌다.", "요양보호사의 기분이 좋을 때 갈아입힌다.", "가족에게 도움을 요청하여 함께 갈아입힌다."]'::jsonb, 3, '치매 환자에게 옷을 갈아입힐 때 필요한 접근 방식을 이해하고 있는지를 평가한다.', 'Đánh giá khả năng hiểu cách tiếp cận cần thiết khi thay quần áo cho bệnh nhân mắc chứng mất trí nhớ.', '{"1": "Ép buộc mặc quần áo không chỉ gây căng thẳng cho bệnh nhân mà còn không an toàn.\n\n[정답]", "3": "Khi bệnh nhân mất trí nhớ có biểu hiện hung hăng, cần phải có cách tiếp cận nhẹ nhàng, và việc làm ướt quần áo để thay có thể làm giảm cảm giác lo lắng cho bệnh nhân.", "4": "Tâm trạng của người chăm sóc không quan trọng, mà tình trạng của bệnh nhân cần được ưu tiên.", "5": "Việc yêu cầu sự giúp đỡ từ gia đình có thể là một phương pháp tốt, nhưng cần có cách tiếp cận mà có thể tự làm một mình."}'::jsonb, '[{"term_ko": "공격성", "term_vi": "Aggression", "def_ko": "환자가 보이는 스트레스나 감정의 폭발", "def_vi": "Những sự bùng nổ cảm xúc hoặc căng thẳng của bệnh nhân"}, {"term_ko": "갈아입히다", "term_vi": "Thay đồ", "def_ko": "옷을 입히기 위해 변화를 주다", "def_vi": "Thay đổi để mặc một bộ quần áo khác"}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자의 돌봄을 담당하는 전문가", "def_vi": "Chuyên gia chịu trách nhiệm chăm sóc bệnh nhân"}, {"term_ko": "가족", "term_vi": "Gia đình", "def_ko": "친척이나 가까운 사람", "def_vi": "Người thân hoặc những người gần gũi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1733, '15', '치매 대상자가 인사를 하거나 말을 걸어도 반응이 없고, 의자에 가만히 앉아있을 때 요양보호사의 대처방법은?', '["대답하지 않으면 말 걸지 말고 그냥 둔다.", "대상자의 흥미를 유발할 수 있는 활동을 시도한다.", "대상자의 사소한 말이나 행동에는 관심을 두지 않는다.", "혼자 있는 시간을 갖도록 배려한다.", "걱정거리가 있는지 물어본다."]'::jsonb, 2, '치매 대상자에 대한 올바른 대처 방법을 물어보는 문제입니다.', 'Câu hỏi này hỏi về cách ứng phó đúng với người bị chứng mất trí nhớ.', '{"1": "대답하지 않으면 말 걸지 말고 그냥 둔다.\n대상자와의 소통이 부족해질 수 있습니다.\nNếu không trả lời, có thể dẫn đến sự thiếu giao tiếp với người bệnh.\n\n[정답]", "2": "대상자의 흥미를 유발할 수 있는 활동을 시도한다.\n대상자가 반응하도록 유도할 수 있는 효과적인 방법입니다.\nThử các hoạt động có thể kích thích sự hứng thú của người bệnh là cách hiệu quả để khuyến khích phản ứng.", "3": "대상자의 사소한 말이나 행동에는 관심을 두지 않는다.\n관심을 두지 않으면 소통이 더 어려워질 수 있습니다.\nNếu không quan tâm đến những lời nói hay hành động nhỏ của người bệnh, việc giao tiếp sẽ càng khó khăn hơn.", "4": "혼자 있는 시간을 갖도록 배려한다.\n상황에 따라 적절한 보살핌이 필요합니다.\nCần phải cân nhắc việc chăm sóc phù hợp tùy thuộc vào tình huống.", "5": "걱정거리가 있는지 물어본다.\n반응이 없는 상태에서 질문은 부담을 줄 수 있습니다.\nHỏi về những lo lắng có thể gây áp lực cho người bệnh trong trạng thái không phản ứng."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "기억력, 사고력의 저하로 인한 증상", "def_vi": "Triệu chứng giảm trí nhớ và khả năng tư duy"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "요양보호 서비스의 수혜자", "def_vi": "Người nhận dịch vụ chăm sóc"}, {"term_ko": "반응", "term_vi": "Phản ứng", "def_ko": "자극에 대한 응답", "def_vi": "Đáp ứng với kích thích"}, {"term_ko": "소통", "term_vi": "Giao tiếp", "def_ko": "의사소통하는 것", "def_vi": "Việc giao tiếp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1732, '15', '치매 대상자의 목욕을 도와주려고 샤워기로 물을 뿌리자 대상자가 놀라서 소리를 지르며 밖으로 나가려고 할 때, 돕는 방법은?', '["욕실 문을 잠그고 빨리 씻긴다.", "목욕 도중에 소리를 질러도 무시한다.", "샤워기 물을 잠그고 대상자 혼자 욕실에 두고 나온다.", "목욕 후 대상자가 좋아하는 일을 하자며 목욕을 유도한다.", "대상자보다 큰소리로 야단치며 행동을 제압한다."]'::jsonb, 4, '치매 대상자에게 적절한 안전한 목욕 도와주기 방법을 찾기 위한 문제입니다.', 'Câu hỏi nhằm tìm ra phương pháp hỗ trợ tắm an toàn và hợp lý cho người bệnh đã bị mất trí nhớ.', '{"1": "Khóa cửa nhà tắm và tắm nhanh. Điều này không an toàn cho đối tượng và có thể làm họ hoảng sợ.", "2": "Bỏ qua tiếng hét giữa khi tắm. Điều này có thể làm tăng thêm lo lắng cho đối tượng.\n\n[정답]", "4": "Khuyến khích người bệnh tắm bằng cách hứa hẹn điều họ thích sau khi tắm. Đây là phương pháp giúp an tâm và hiệu quả.", "3": "Tắt vòi sen và để người bệnh ở một mình trong phòng tắm. Đây là hành động bỏ mặc họ, rất nguy hiểm.", "5": "La lớn hơn và kiểm soát hành động của bệnh nhân. Điều này sẽ làm tăng sự lo lắng cho họ và ảnh hưởng đến sự tin tưởng."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 사고 기능이 손상된 상태", "def_vi": "Tình trạng tổn thương trí nhớ và khả năng suy nghĩ"}, {"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "간호나 돌봄을 받는 사람", "def_vi": "Người nhận sự chăm sóc hoặc điều trị"}, {"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "몸을 물로 씻는 것", "def_vi": "Hành động rửa sạch cơ thể bằng nước"}, {"term_ko": "욕실", "term_vi": "Phòng tắm", "def_ko": "목욕을 하는 방", "def_vi": "Phòng dành cho việc tắm"}, {"term_ko": "안심", "term_vi": "Yên tâm", "def_ko": "불안하지 않게 하는 것", "def_vi": "Làm cho người khác không lo lắng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1731, '15', '중풍으로 오른쪽 팔과 다리가 불편한 대상자가 치매 증상이 십해지면서 옷을 갈아 입지 않으려고 할 때 돕는 방법은?', '["냄새나도 모른척하며 다른 일을 한다.", "갈아입을 옷을 주고 혼자서 갈아입게 한다.", "대상자가 거부해도 강제로 옷을 갈아입힌다.", "갈아입지 않으려는 이유를 설명해 달라고 한다.", "가족과 상의하여 동일한 유형의 옷을 구입하여 입게 한다."]'::jsonb, 5, '대상자의 치매 증상과 의사소통의 어려움을 고려하여 적절한 방법을 찾는 것.', 'Câu hỏi yêu cầu tìm phương pháp hợp lý trong bối cảnh bệnh nhân bị chứng mất trí nhớ và khó khăn trong giao tiếp.', '{"1": "환자의 정서와 위생을 고려하지 않는 방법이다.\nPhương pháp này không xem xét cảm xúc và vệ sinh của bệnh nhân.", "2": "환자가 혼자서 옷을 갈아입는 것은 위험할 수 있다.\nViệc để bệnh nhân tự thay quần áo có thể gây nguy hiểm.\n\n[정답]", "5": "Phương pháp này xem xét sự thoải mái và sở thích của bệnh nhân.", "3": "강제로 옷을 입히는 것은 대상자의 신뢰를 잃게 만든다.\nViệc ép buộc thay đồ có thể làm mất lòng tin của bệnh nhân.", "4": "이유를 물어보는 것은 치매 환자에게 적합하지 않다.\nHỏi lý do là không phù hợp với bệnh nhân mắc chứng mất trí nhớ."}'::jsonb, '[{"term_ko": "중풍", "term_vi": "Đột quỵ", "def_ko": "뇌졸중", "def_vi": "tổn thương do máu không lưu thông đến não"}, {"term_ko": "옷", "term_vi": "Quần áo", "def_ko": "착용하는 물건", "def_vi": "vật dụng mặc trên người"}, {"term_ko": "치매", "term_vi": "Mất trí nhớ", "def_ko": "기억 상실증", "def_vi": "chứng bệnh liên quan đến trí tuệ"}, {"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "치료 또는 간호를 받는 사람", "def_vi": "người nhận điều trị hoặc chăm sóc"}, {"term_ko": "갈아입다", "term_vi": "Thay quần áo", "def_ko": "착용하던 것을 벗고 새로운 것을 착용하다", "def_vi": "bỏ cái cũ và mặc cái mới"}, {"term_ko": "강제로", "term_vi": "Bằng cách cưỡng chế", "def_ko": "힘을 사용하여", "def_vi": "sử dụng sức mạnh để thực hiện hành động"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1730, '14', '세면하기를 거부하는 치매 대상자에게 적합한 요양보호사의돌봄 방법은? 치매로 진단받은 73세 남성은 씻지 않은 지 일주일이 되어간다. 가족들이 설득하여 억지로 씻기려고 했지만, 그때마다 소리를 지르고 화를 내서 너무 힘들었다고 한다.', '["진정제를 먹인 후 씻긴다.", "가족과 함께 강제로 씻긴다.", "더러워서 씻어야 한다고 대상자를 설득한다.", "요양보호사가 물로 씻는 시늉을 보이며 스스로 씻게 한다.", "거부가 심하면 서비스 제공이 어렵다고 가족에게 말한다."]'::jsonb, 4, '치매 대상자에 대한 효과적인 돌봄 방법을 평가하는 것이다.', 'Đánh giá phương pháp chăm sóc hiệu quả cho bệnh nhân mắc bệnh Alzheimer.', '{"1": "진정제를 사용하여 강제로 씻기면 대상자의 불안을 증대시킬 수 있다.\nViệc sử dụng thuốc an thần để cưỡng chế tắm có thể làm tăng lo lắng của bệnh nhân.", "2": "가족과 강제로 씻기면 대상자는 더욱 반항할 수 있다.\nCưỡng chế tắm cùng gia đình có thể làm cho bệnh nhân phản ứng mạnh hơn.", "3": "단순 설득은 효과가 없으며, 대상자의 의사와 감정을 존중해야 한다.\nViệc chỉ thuyết phục đơn giản không hiệu quả, cần tôn trọng ý chí và cảm xúc của bệnh nhân.\n\n[정답]", "4": "Phương pháp để nhân viên chăm sóc chỉ cho bệnh nhân bằng cách bắt chước sẽ tôn trọng tính tự chủ và giảm lo âu của bệnh nhân.", "5": "서비스 제공이 어렵다는 위협은 대화를 단절시킬 수 있다.\nGây ra sự đổ vỡ trong giao tiếp bằng cách đe dọa rằng sẽ khó khăn khi cung cấp dịch vụ."}'::jsonb, '[{"term_ko": "세면", "term_vi": "Rửa mặt", "def_ko": "씻는 것", "def_vi": "Rửa cơ thể"}, {"term_ko": "치매", "term_vi": "Bệnh sa sút trí tuệ", "def_ko": "기억력 및 사고력 손상", "def_vi": "Giảm sút khả năng ghi nhớ và tư duy"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "돌봄 받을 사람이자 환자", "def_vi": "Người nhận chăm sóc và bệnh nhân"}, {"term_ko": "강제", "term_vi": "Cưỡng chế", "def_ko": "억지로, 할 수 없이", "def_vi": "Ép buộc, không thể khác"}, {"term_ko": "자율성", "term_vi": "Tính tự chủ", "def_ko": "스스로 결정할 수 있는 능력", "def_vi": "Khả năng tự quyết định"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1729, '14', '다음 사례에서 치매 대상자의 올바른 돌봄 방법으로 옳은 것은? 치매 대상자인 85세 남성은 식사할 때 수저를 사용하지 않고 손으로 음식을 집어 먹으려고 한다. 요양보호사가 수저로 먹으라고 하면 몇 번 서툴게 먹다가 다시 손으로 음식을 집는다.', '["포크나 젓가락을 사용하게 한다.", "\"손으로먹으면 더럽잖아요.\" 말하면 먹여준다.", "\"수저로 드셔야지요.\" 하고 몸짓과 함께 부드럽게 말한다.", "\"어르신은 말도 안 듣고 고집이 참 세네요.\" 하며 그냥 둔다.", "\"수저 사용은 안 하려면 식사하지 마세요.\" 말하며 식사를 치운다."]'::jsonb, 3, '치매 대상자를 올바르게 돌보는 방법을 이해하고 적용하는지 확인하기 위함입니다.', 'Kiểm tra hiểu biết và áp dụng cách chăm sóc đúng cho người mắc chứng mất trí.', '{"1": "포크나 젓가락은 치매 대상자에게 적합한 도구가 아닐 수 있습니다.\nDùng nĩa hoặc đũa có thể không phải là dụng cụ thích hợp cho người mắc chứng mất trí.\n\n[정답]", "3": "Cần sử dụng lời nói nhẹ nhàng và cử chỉ để hướng dẫn cách đúng.", "4": "고집을 부리는 태도는 부정적인 행동으로, 돌봄에 적절하지 않습니다.\nThái độ cứng đầu là hành động tiêu cực và không phù hợp trong việc chăm sóc.", "5": "식사를 치우는 것은 대상자의 필요를 충족하지 않으므로 부적절합니다.\nDọn dẹp thức ăn không đáp ứng nhu cầu của bệnh nhân là không phù hợp."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "알츠하이머 병 등으로 인한 기억력 상실 및 인지 능력 장애", "def_vi": "Mất trí nhớ và rối loạn nhận thức do các bệnh như Alzheimer."}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1728, '14', '다음 사례에서 치매 대상자의 적합한 돌봄 방법으로 옳은 것은? 치매 대상자인 80세 여성은 물컵을 손으로 잡고 물을 마시지만 대부분 흘린다. 요양보호사의 도움으로 물을 다 마시고 나면 컵을 테이블에 놓지 못하고 바닥에 떨어뜨린다.', '["물 대신 국을 많이 먹게 한다.", "컵에 빨대를 꽂아 물을 마시게 한다.", "깨질 수 있으니 컵 사용을 못하게 한다.", "요실금을 예방하기 위해 물 섭취를 제한한다.", "언제 물을 마셨는지를 기억했다가 물을 마시게 한다."]'::jsonb, 5, '치매 대상자에게 적합한 돌봄 방법을 찾는 것이며, 적절한 수분 섭취를 중요시합니다.', 'Tìm ra phương pháp chăm sóc phù hợp cho bệnh nhân mắc chứng sa sút trí tuệ, quan trọng việc cung cấp đủ nước cho họ.', '{"1": "물 대신 국을 많이 먹게 한다.\n국이 수분을 제공하더라도, 치매 환자가 이를 인지하기 어려운 경우가 많습니다.\nMặc dù nước súp có thể cung cấp độ ẩm, nhưng bệnh nhân sa sút trí tuệ thường gặp khó khăn trong việc nhận thức điều này.\n\n[정답]", "5": "언제 물을 마셨는지를 기억했다가 물을 마시게 한다.\n이 방법은 환자가 수분을 섭취하도록 도와줄 수 있습니다.\nPhương pháp này có thể giúp bệnh nhân nhớ để uống nước.", "3": "깨질 수 있으니 컵 사용을 못하게 한다.\n컵 사용을 금지하면 환자는 수분 섭취에 어려움을 겪을 수 있습니다.\nCấm sử dụng cốc có thể khiến bệnh nhân gặp khó khăn trong việc uống nước.", "4": "요실금을 예방하기 위해 물 섭취를 제한한다.\n수분 섭취를 제한하면 탈수 위험이 있으므로 바람직하지 않습니다.\nGiới hạn lượng nước sẽ làm tăng nguy cơ mất nước, vì vậy không nên."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력이나 사고 능력이 점차적으로 저하되는 질병", "def_vi": "Bệnh suy giảm trí nhớ hoặc khả năng suy nghĩ dần dần"}, {"term_ko": "적합한", "term_vi": "Phù hợp", "def_ko": "적절한, 알맞은", "def_vi": "Thích hợp, đúng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1727, '14', '심폐소생술을 할 때 자동심장충격기를 사용하는 방법으로 옳은 것은?', '["30회의 가슴압박을 마친 후에 전원을 켠다.", "패드는 옷 위에 붙여서 감전을 방지한다.", "분석 중이라는 음성지시가 나오면 심폐소생술을 시작한다.", "정상 호흡은있으나 반응이 없는 대상자에게 사용한다.", "심장충격 실시 후 즉시 가슴압박을 실시한다."]'::jsonb, 5, '심폐소생술과 자동심장충격기 사용에 대한 이해를 평가하고자 함.', 'Đánh giá sự hiểu biết về hồi sức tim phổi và cách sử dụng máy khử rung tim tự động.', '{"1": "가슴압박 후 전원을 켜는 것은 잘못된 순서임.\nViệc bật nguồn sau khi ấn ngực là thứ tự sai.\n\n[정답]", "5": "Hành động đúng là thực hiện nén ngực ngay sau khi sốc tim.", "2": "패드는 직접 피부에 붙여야 하며, 옷 위에 붙이면 감전 위험이 있음.\nMiếng dán phải được dán trực tiếp lên da, dán trên quần áo sẽ gây nguy hiểm điện giật.", "3": "분석 중일 때는 심폐소생술을 중지해야 함.\nTrong khi phân tích, hồi sức tim phổi phải ngừng lại.", "4": "정상 호흡이 있는 경우 전혀 사용하지 않음.\nTrong trường hợp có sự thở bình thường thì không sử dụng."}'::jsonb, '[{"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "심장과 호흡이 정지된 상태에서 생명을 구하기 위한 응급 처치법", "def_vi": "Phương pháp cấp cứu nhằm cứu sống khi tim và hô hấp ngừng lại"}, {"term_ko": "자동심장충격기", "term_vi": "Máy khử rung tim tự động", "def_ko": "심장을 전기적으로 자극하여 정상 리듬으로 회복시키는 장치", "def_vi": "Thiết bị kích thích tim điện để phục hồi nhịp sinh lý"}, {"term_ko": "가슴압박", "term_vi": "Nén ngực", "def_ko": "심장을 압박하여 혈액 순환을 돕는 행위", "def_vi": "Hành động ấn tim để hỗ trợ tuần hoàn máu"}, {"term_ko": "패드", "term_vi": "Miếng dán", "def_ko": "전기 신호를 전달하는 장비의 일부분", "def_vi": "Một phần của thiết bị truyền tín hiệu điện"}, {"term_ko": "정상 호흡", "term_vi": "Hơi thở bình thường", "def_ko": "정상적인 호흡 상태", "def_vi": "Trạng thái hô hấp bình thường"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1726, '14', '자동심장충격기 사용 시 심장충격 후 즉시 해야하는 것은?', '["인공호흡을 한다.", "가슴압박을 한다.", "대상자에게서 손을 뗀다.", "턱을 위로 당겨 기도를 열어준다.", "패드를 떼었다가 다시 붙인다."]'::jsonb, 2, '(한국어 의도) 자동심장충격기 사용 후 적절한 후속 조치를 확인하는 것', '(베트남어 의도) Xác định các bước thích hợp sau khi sử dụng máy khử rung tim tự động', '{"1": "Thực hiện hô hấp nhân tạo. (Không khuyến nghị thực hiện hô hấp nhân tạo ngay lập tức sau khi sốc điện)\n\n[정답]", "2": "Thực hiện ép ngực. (Cần bắt đầu ép ngực ngay lập tức sau khi sốc điện)", "3": "Rời tay khỏi người bệnh. (Chỉ nên rời tay sau khi kiểm tra an toàn)", "4": "Kéo cằm lên để mở đường thở. (Chỉ cần làm nếu có triệu chứng hoặc nhận thấy cần thiết)", "5": "Lột rồi dán lại điện cực. (Các điện cực nên được giữ cố định trong khi thực hiện ép ngực)"}'::jsonb, '[{"term_ko": "자동심장충격기", "term_vi": "Máy khử rung tim tự động", "def_ko": "심장 문제가 생겼을 때 전기 충격을 주어 심장을 정상으로 되돌리기 위한 기계", "def_vi": "Máy dùng để cung cấp sốc điện để khôi phục nhịp tim bình thường khi có vấn đề về tim"}, {"term_ko": "가슴압박", "term_vi": "Ép ngực", "def_ko": "심장 기능이 멈췄을 때 혈액 순환을 유지하기 위해 가슴을 눌러주는 것", "def_vi": "Hành động đè lên ngực để duy trì lưu thông máu khi chức năng tim ngừng"}, {"term_ko": "인공호흡", "term_vi": "Hô hấp nhân tạo", "def_ko": "호흡이 정지된 사람에게 공기를 불어넣는 조치", "def_vi": "Biện pháp thổi không khí vào người đã ngừng thở"}, {"term_ko": "기도", "term_vi": "Đường thở", "def_ko": "공기가 통과하는 경로", "def_vi": "Lộ trình không khí đi qua"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1725, '14', '자동심장충격기의 쇼크 버튼을 눌러야 하는 시점으로 옳은 것은?', '["전원을 켜자마자", "인공호흡을 한 후", "패드를 부착한 직후", "심장리듬을 분석하기 직전", "에너지 충전이 완료된 후"]'::jsonb, 5, '이 문제는 자동심장충격기의 적절한 사용 시점을 평가하는 것을 목표로 합니다.', 'Câu hỏi này nhằm đánh giá thời điểm sử dụng đúng cách máy khử rung tim tự động.', '{"1": "Khi vừa bật nguồn của máy khử rung tim tự động, nhưng không phải là thời điểm cần nhấn nút sốc.", "2": "Sau khi hô hấp nhân tạo, cần phải phân tích nhịp tim, vì vậy không nên nhấn nút sốc.", "3": "Ngay sau khi gắn các pad, đó là thời điểm cần phân tích nhịp tim, vì vậy không nên nhấn nút sốc.", "4": "Ngay trước khi phân tích nhịp tim, vì vậy không nên nhấn nút này tại thời điểm này.\n\n[정답]", "5": "Phải nhấn nút sốc sau khi đã hoàn tất việc nạp năng lượng."}'::jsonb, '[{"term_ko": "자동심장충격기", "term_vi": "Máy khử rung tim tự động", "def_ko": "심장 리듬 이상 시 전기 충격을 주는 장치", "def_vi": "Thiết bị cung cấp điện cho nhịp tim bất thường"}, {"term_ko": "전원", "term_vi": "Nguồn", "def_ko": "기계의 작동을 시작하기 위한 전기", "def_vi": "Điện cần thiết để khởi động thiết bị"}, {"term_ko": "패드", "term_vi": "Pad", "def_ko": "몸에 부착하여 전기를 전달하는 전극", "def_vi": "Điện cực được gắn lên cơ thể để truyền điện"}, {"term_ko": "심장리듬", "term_vi": "Nhịp tim", "def_ko": "심장의 전기적 활동을 나타내는 주기", "def_vi": "Hoạt động điện của tim"}, {"term_ko": "에너지 충전", "term_vi": "Nạp năng lượng", "def_ko": "기계가 작동을 위해 필요 전기를 저장하는 과정", "def_vi": "Quá trình lưu trữ điện năng cần thiết cho thiết bị hoạt động"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1724, '14', '자동심장충격기 사용 시 가슴 압박을 반드시 중단해야 하는 경우는?', '["자동심장충격기의 전원을 켤 때", "자동심장충격기의 패드를 부착할 때", "자동심장충격기에서 심장리듬을 분석할 때", "자동심장충격기가 에너지를 충전하는 동안", "자동심장충격기의 쇼크 버튼을 누른 후 2분 동안"]'::jsonb, 3, '자동심장충격기 사용 시 가슴 압박을 중단해야 하는 상황에 대한 이해를 테스트하는 것입니다.', 'Bài kiểm tra nhằm kiểm tra sự hiểu biết về tình huống khi cần ngừng ép ngực khi sử dụng máy khử rung tim tự động.', '{"1": "Khi bật nguồn của máy khử rung tim tự động, không cần ngừng ép ngực.\n\n[정답]", "3": "Khi máy khử rung tim tự động phân tích nhịp tim, phải ngừng ép ngực.", "2": "Khi gắn các miếng đệm của máy khử rung tim tự động, không cần ngừng ép ngực.", "4": "Phải ngừng ép ngực trong khi máy khử rung tim tự động đang sạc năng lượng.", "5": "Sau khi nhấn nút sốc của máy khử rung tim tự động, phải tiếp tục ép ngực trong 2 phút."}'::jsonb, '[{"term_ko": "자동심장충격기", "term_vi": "Máy khử rung tim tự động", "def_ko": "심장 기능이 정지된 환자에게 전기 쇼크를 주어 심장을 다시 뛰게 하는 기기", "def_vi": "Thiết bị dùng để cung cấp sốc điện cho bệnh nhân bị ngừng tim"}, {"term_ko": "압박", "term_vi": "Ép", "def_ko": "힘을 가하여 누르다", "def_vi": "Đẩy lực để nhấn"}, {"term_ko": "패드", "term_vi": "Miếng đệm", "def_ko": "전극이 부착된 판", "def_vi": "Tấm có điện cực gắn vào"}, {"term_ko": "심장리듬", "term_vi": "Nhịp tim", "def_ko": "심장이 뛰는 규칙적인 패턴", "def_vi": "Mô hình nhịp đập của tim"}, {"term_ko": "에너지", "term_vi": "Năng lượng", "def_ko": "일을 하는 능력", "def_vi": "Khả năng thực hiện công việc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1723, '14', '자동심장충격기를 사용하고 관리하는 방법으로 옳은 것은?', '["충전 중에는 가슴압박을 멈추고 기다린다.", "심장충격 버튼을 누르기 전 대상자에게서 손을 뗀다.", "전극패드 부착 후 즉시 심장충격을 시행한다.", "전기 충격이 전달된 즉시 대상자에게서 손을 뗀다.", "자동심장충격기는 매년 1회정기 점검한다."]'::jsonb, 2, '자동심장충격기 사용법에 대해 이해하고 있는지를 평가하기 위함입니다.', 'Để đánh giá khả năng hiểu biết về cách sử dụng máy khử rung tim tự động.', '{"1": "충전 중에는 가슴압박을 멈추고 기다려야 하며, 이는 잘못된 방법입니다.\nKhi sạc, bạn cần dừng ép ngực và chờ, đây là cách sai.\n\n[정답]", "2": "심장충격 버튼을 누르기 전 대상자에게서 손을 떼어야 하며, 이는 올바른 방법입니다.\nTrước khi nhấn nút sốc tim, bạn cần rút tay khỏi người bệnh, đây là cách đúng.", "3": "전극패드 부착 후 즉시 심장충격을 시행하는 것은 위험할 수 있으며, 올바르지 않습니다.\nViệc thực hiện sốc tim ngay lập tức sau khi gắn miếng điện cực có thể gây nguy hiểm và không đúng.", "4": "전기 충격이 전달된 즉시 대상자에게서 손을 뗀다는 것은 전극패드 부착과 관련하여 염두에 두어야 할 사항으로, 순서가 맞지 않습니다.\nViệc rút tay ngay lập tức sau khi điện được truyền cần lưu ý liên quan đến việc gắn miếng điện cực và không đúng thứ tự.", "5": "자동심장충격기는 매년 1회 정기 점검을 원칙으로 하지만, 실제로는 사용 빈도에 따라 다를 수 있습니다.\nMáy khử rung tim tự động nên được kiểm tra định kỳ hàng năm nhưng thực tế có thể khác tùy thuộc vào tần suất sử dụng."}'::jsonb, '[{"term_ko": "자동심장충격기", "term_vi": "Máy khử rung tim tự động", "def_ko": "자동으로 심장충격을 주는 장비", "def_vi": "Thiết bị tự động cung cấp sốc điện cho tim"}, {"term_ko": "가슴압박", "term_vi": "Ép ngực", "def_ko": "심폐소생술의 일환으로 심장을 압박하는 행동", "def_vi": "Hành động ép tim trong hồi sức tim phổi"}, {"term_ko": "전극패드", "term_vi": "Miếng điện cực", "def_ko": "심장에 부착하는 전극판", "def_vi": "Miếng dán vào tim"}, {"term_ko": "심장충격", "term_vi": "Sốc tim", "def_ko": "심장에 전기 충격을 주는 행위", "def_vi": "Hành động cung cấp sốc điện cho tim"}, {"term_ko": "정기 점검", "term_vi": "Kiểm tra định kỳ", "def_ko": "정해진 주기로 점검하는 것", "def_vi": "Kiểm tra theo chu kỳ đã định"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1722, '14', '심폐소생술을 할 때 자동심장충격기를 사용하는 방법으로 옳은 것은?', '["패드를 붙인 후 전원을 켠다.", "심장리듬 분석 주에는 인공 호흡을 한다.", "심장 충격을 위한 충전 중에는 가슴 압박을 한다.", "가슴압박과 동시에 쇼크 버튼을 누른다.", "충격이 전달된 즉시 대상자의 반응과 호흡을 재확인한다."]'::jsonb, 3, '(한국어 의도: 심폐소생술과 관련된 자동심장충격기 사용 방법에 대한 이해 여부 확인)', '(베트남어 의도: Kiểm tra sự hiểu biết về cách sử dụng máy khử rung tim tự động liên quan đến hồi sức tim phổi)', '{"1": "Đáp án này sai vì máy khử rung tim tự động cần được bật sau khi dán miếng dán.\n\n[정답]", "3": "Điều này có nghĩa là tiếp tục ấn ngực trong quá trình nạp điện để sốc tim.", "2": "Đáp án này sai vì trong quá trình phân tích nhịp tim không nên thực hiện hô hấp nhân tạo.", "4": "Đáp án này sai vì không nên ấn nút sốc cùng lúc với việc ấn ngực.", "5": "Đáp án này sai vì xác nhận phản ứng và hơi thở nên được thực hiện sau khi sốc đã được thực hiện."}'::jsonb, '[{"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "심정지환자를 위한 응급처치법", "def_vi": "Phương pháp cấp cứu cho bệnh nhân ngừng tim"}, {"term_ko": "자동심장충격기", "term_vi": "Máy khử rung tim tự động", "def_ko": "심장을 자동으로 충격하여 회복시키는 장치", "def_vi": "Thiết bị tự động sốc tim để phục hồi"}, {"term_ko": "패드", "term_vi": "Miếng dán", "def_ko": "전극이 부착된 부위", "def_vi": "Vị trí dán điện cực"}, {"term_ko": "가슴 압박", "term_vi": "Ấn ngực", "def_ko": "심폐소생술의 한 방법", "def_vi": "Một phương pháp trong hồi sức tim phổi"}, {"term_ko": "충전", "term_vi": "Nạp", "def_ko": "충격을 위한 에너지를 저장하는 과정", "def_vi": "Quá trình lưu trữ năng lượng cho sốc"}, {"term_ko": "호흡", "term_vi": "Hô hấp", "def_ko": "공기를 들이마시는 행동", "def_vi": "Hành động hít vào không khí"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1721, '14', '심폐소생술을 할 때 자동심장충격기를 사용하는 방법으로 옳은 것은?', '["심장리듬을 분석한후 패드를 부착한다.", "심장리듬 분석 중에는 가슴압박을 지속한다.", "심장충격 버튼을 누르기 전에 대상자를 꽉 잡는다.", "심폐소생술 중 자동심장충격기가 도착하면 지체없이 전원을 켠다.", "심장충격 버튼을누르고 1분 후에 가슴압박을 시작한다."]'::jsonb, 4, '자동심장충격기를 사용할 때 올바른 사용 방법을 이해하고 있는지를 평가하는 문제입니다.', 'Câu hỏi nhằm đánh giá khả năng hiểu đúng cách sử dụng máy khử rung tim tự động.', '{"1": "심장리듬을 분석한 후 패드를 부착한다.\n이 순서는 잘못되었습니다. 패드는 심장 리듬을 분석하기 전에 부착해야 합니다.\nCách này là sai. Miếng dán nên được gắn trước khi phân tích nhịp tim.", "2": "심장리듬 분석 중에는 가슴압박을 지속한다.\n이것은 잘못된 방법입니다. 심장 리듬 분석 중에는 압박을 중단해야 합니다.\nCách này sai. Trong khi phân tích nhịp tim, cần ngừng ép ngực.", "3": "심장충격 버튼을 누르기 전에 대상자를 꽉 잡는다.\n대상자를 잡는 것은 필요하지 않으며 올바른 방법이 아닙니다.\nViệc giữ chặt bệnh nhân là không cần thiết và không phải là cách đúng.\n\n[정답]", "4": "Trong khi sơ cứu, khi máy khử rung tim tự động đến, cần bật ngay lập tức.", "5": "심장충격 버튼을 누르고 1분 후에 가슴압박을 시작한다.\n이 방법은 잘못되었습니다. 가슴압박은 심장충격 버튼을 누르자마자 시작해야 합니다.\nCách này sai. Cần bắt đầu ép ngực ngay sau khi nhấn nút khử rung tim."}'::jsonb, '[{"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "심정지 환자를 위한 응급처치", "def_vi": "Sơ cứu cho bệnh nhân ngừng tim"}, {"term_ko": "자동심장충격기", "term_vi": "Máy khử rung tim tự động", "def_ko": "심장리듬에 따라 심장을 다시 뛰게 하는 기기", "def_vi": "Thiết bị giúp tim hồi phục theo nhịp tim"}, {"term_ko": "가슴압박", "term_vi": "Ép ngực", "def_ko": "심장소생에서 가슴을 눌러주는 행동", "def_vi": "Hành động đè lên ngực trong hồi sức tim"}, {"term_ko": "심장리듬", "term_vi": "Nhịp tim", "def_ko": "심장의 전기적 활동 상태", "def_vi": "Trạng thái hoạt động điện của tim"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1720, '14', '자동심장 충격기를 사용하는 방법으로 옳은 것은?', '["두 개의 패드를 부착 후 전원 버튼을 누른다.", "심장 리듬 분석을 5분마다 한다.", "심장리듬 분석 중에는 가슴압박을 중단한다.", "심장충격 버튼을 누르기 전 인공호흡을 집중적으로 한다.", "전극 패드를 왼쪽 빗장뼈 (쇄골)와 오른쪽 젖꼭지 아래에 붙인다."]'::jsonb, 3, '자동심장 충격기를 사용하는 올바른 방법을 이해하고 선택하는 것이 중요하다.', 'Việc hiểu và chọn cách sử dụng máy sốc điện tim tự động là rất quan trọng.', '{"1": "자동심장 충격기를 사용할 때 두 개의 패드를 부착하는 것은 필수적이지만, 전원을 누르는 시점은 고정적이지 않다.\nViệc gắn hai tấm điện cực là cần thiết khi sử dụng máy sốc điện nhưng thời điểm bấm nút nguồn không cố định.", "2": "심장 리듬 분석은 5분마다 하는 것이 아니라, 자동심장 충격기가 필요할 때마다 이루어진다.\nPhân tích nhịp tim không thực hiện mỗi 5 phút mà được thực hiện khi máy sốc điện tự động cần thiết.\n\n[정답]", "3": "Phải ngừng ép ngực trong quá trình phân tích nhịp tim để tăng độ chính xác của phân tích nhịp tim.", "4": "심장충격 버튼을 누르기 전에 인공호흡을 집중적으로 하는 것은 필요하지 않으며, 심장 충격 후에 가슴 압박을 계속해야 한다.\nKhông cần tập trung vào việc hô hấp nhân tạo trước khi nhấn nút sốc tim, mà cần tiếp tục ép ngực sau khi sốc tim.", "5": "전극 패드는 정확한 위치에 부착해야 하지만, 왼쪽 빗장뼈와 오른쪽 젖꼭지 아래에 붙이는 것은 잘못된 정보이다.\nCác tấm điện cực cần phải được gắn đúng vị trí, nhưng thông tin này về việc gắn vào xương đòn bên trái và dưới núm vú bên phải là sai."}'::jsonb, '[{"term_ko": "자동심장 충격기", "term_vi": "Máy sốc điện tim tự động", "def_ko": "사람이 심장마비 시 전기 충격을 주어 심장을 다시 정상적으로 뛰게 하는 장치", "def_vi": "Thiết bị gây sốc điện cho tim để làm cho tim đập lại bình thường trong trường hợp ngừng tim"}, {"term_ko": "심장 리듬", "term_vi": "Nhịp tim", "def_ko": "심장의 전기적 활동 상태", "def_vi": "Trạng thái hoạt động điện của tim"}, {"term_ko": "가슴압박", "term_vi": "Ép ngực", "def_ko": "심장을 압박하여 혈액을 순환시키는 행위", "def_vi": "Hành động ép tim để tuần hoàn máu"}, {"term_ko": "전극 패드", "term_vi": "Tấm điện cực", "def_ko": "자동심장 충격기를 사용하여 전기충격을 주기 위해 필요한 장비", "def_vi": "Thiết bị cần thiết để gây sốc điện bằng máy sốc điện tim tự động"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1719, '14', '다음 중 자동심장충격기를 사용해야 하는 대상자는?', '["호흡이 미세한 대상자", "심 정지 대상자", "의식이 없는 대상자", "출혈이 심한 대상자", "경련중인 대상자"]'::jsonb, 2, '자동심장충격기의 사용이 필요한 상황을 이해하고 있는지를 평가하기 위한 질문입니다.', 'Câu hỏi này nhằm đánh giá liệu người học có hiểu tình huống nào cần sử dụng máy shock tim tự động hay không.', '{"1": "호흡이 미세한 대상자는 심정지 상태가 아니므로 자동심장충격기를 사용하지 않습니다.\nNgười có hơi thở yếu không phải là trường hợp ngừng tim, vì vậy không sử dụng máy shock tim tự động.\n\n[정답]", "2": "Người ngừng tim là tình huống cần sử dụng máy shock tim tự động.", "3": "의식이 없는 대상자는 심정지인지 확인이 필요하므로 자동심장충격기를 사용할 필요가 없습니다.\nNgười không có ý thức cần phải kiểm tra xem có thực sự ngừng tim hay không, do đó không cần sử dụng máy shock tim tự động.", "4": "출혈이 심한 대상자는 심정지 상태가 아님으로 사용하지 않습니다.\nNgười bị chảy máu nhiều không phải là trường hợp ngừng tim, do đó không sử dụng.", "5": "경련중인 대상자는 심정지 상태가 아니므로 자동심장충격기를 사용하지 않습니다.\nNgười đang co giật không phải là trường hợp ngừng tim, vì vậy không sử dụng máy shock tim tự động."}'::jsonb, '[{"term_ko": "자동심장충격기", "term_vi": "Máy shock tim tự động", "def_ko": "심장 정지를 감지하여 전기 충격을 주는 기기", "def_vi": "Thiết bị phát hiện ngừng tim và cung cấp cú sốc điện"}, {"term_ko": "심 정지", "term_vi": "Ngừng tim", "def_ko": "심장이 멈춘 상태", "def_vi": "Tình trạng tim ngừng đập"}, {"term_ko": "의식", "term_vi": "Ý thức", "def_ko": "자신의 상태를 인식하는 능력", "def_vi": "Khả năng nhận thức về tình trạng của bản thân"}, {"term_ko": "출혈", "term_vi": "Chảy máu", "def_ko": "혈액이 외부로 나오거나 내부에서 새는 것", "def_vi": "Máu ra ngoài hoặc chảy bên trong"}, {"term_ko": "경련", "term_vi": "Co giật", "def_ko": "불수의적인 근육 수축", "def_vi": "Cơn co thắt cơ không tự nguyện"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1718, '14', '자동심장충격기 사용 순서로 옳은 것은? 가. 전원켜기 나. 심장리듬 분석 다. 심장충격 시행 라.패드 부착 마. 즉시 심폐소생술 시행', '["가 - 다 - 나 - 라 - 마", "가 - 다 - 라 - 나 - 마", "가 - 라 - 나 - 다 - 마", "가 - 나 - 다 - 라 - 마", "가 - 나 - 라 - 다 - 마"]'::jsonb, 3, NULL, NULL, '{"1": "전원 켜고 심장 충격 시행 순서가 잘못되어 있습니다.", "2": "전원 켜고 심장 충격 시행 후 심장 리듬 분석을 하는 순서가 잘못되어 있습니다.\n[정답]", "3": "전원 켜고 패드를 부착 후 심장 리듬 분석 후 충격을 시행하는 순서입니다.", "4": "전원 켜고 리듬 분석이 먼저 나와야 하므로 잘못된 순서입니다.", "5": "전원 켜고 패드 부착 후 심장 리듬 분석이 뒤에 있으므로 잘못된 순서입니다."}'::jsonb, '[{"term_ko": "자동심장충격기", "term_vi": "Máy khử rung tim tự động", "def_ko": "심장에서 부정맥이나 급성 심장마비를 상황에서 전기 충격을 주는 기기", "def_vi": "Thiết bị cung cấp sốc điện trong trường hợp rối loạn nhịp tim hoặc ngừng tim"}, {"term_ko": "심장리듬", "term_vi": "Nhịp tim", "def_ko": "심장이 활동하는 양상", "def_vi": "Hình thức hoạt động của tim"}, {"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "심장과 호흡이 멈춘 사람을 살리기 위한 응급 처치", "def_vi": "Thao tác cấp cứu cho người ngừng tim và ngừng thở"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1717, '14', '요양보호사가 심폐소생술을 종료해야 할 시점은?', '["맥박이 없을 때", "호흡이 없을 때", "자동심장충격기 사용 후", "가족이 멈추길 원할 때", "119 구급 대원에게 인계할 때"]'::jsonb, 5, NULL, NULL, '{"1": "심폐소생술은 맥박이 없을 때에도 계속 진행해야 합니다.", "2": "호흡이 없을 경우에도 심폐소생술을 계속해야 합니다.\n[정답]", "3": "자동심장충격기를 사용할 후에도 심폐소생술은 지속해야 합니다.", "4": "가족이 멈추기를 희망하더라도, 전문가의 판단에 따라 심폐소생술이 지속되어야 할 수 있습니다.", "5": "119 구급 대원에게 인계할 때 심폐소생술을 종료해야 합니다."}'::jsonb, '[{"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "심장과 호흡이 멈춘 환자에게 다시 호흡과 순환을 회복시키기 위한 응급조치", "def_vi": "Biện pháp cấp cứu nhằm phục hồi hô hấp và tuần hoàn cho bệnh nhân khi tim và hô hấp ngừng lại"}, {"term_ko": "자동심장충격기", "term_vi": "Máy shock tim tự động", "def_ko": "심장 박동을 재개시키기 위해 전기적 충격을 주는 기기", "def_vi": "Thiết bị cung cấp sốc điện để khôi phục nhịp tim"}, {"term_ko": "구급 대원", "term_vi": "Nhân viên cấp cứu", "def_ko": "응급 상황에서 환자를 돕는 전문가", "def_vi": "Chuyên gia giúp đỡ bệnh nhân trong tình huống khẩn cấp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1716, '14', '심폐소생술 시 가슴압박을 실시하는 방법으로 옳은 것은?', '["가슴이 3cm 눌릴 정도로 압박한다.", "가슴뼈 아래쪽 명치 부위를 강하게 압박한다.", "대상자의 몸과수직이 되도록 하여 가슴을 압박한다.", "압박된 가슴이 이완되지 않도록 빠르게 압박한다.", "체중을 실어 깍지를 낀 두 손의 손바닥으로 압박한다."]'::jsonb, 3, NULL, NULL, '{"1": "가슴압박 깊이는 일반적으로 5-6cm로 권장되며 3cm는 부족하다.\n[정답]", "3": "가슴을 압박할 때는 대상자의 몸과 수직이 되어야 올바른 압박이 이루어진다.", "2": "명치 부위를 압박하면 정확한 가슴압박이 이루어지지 않는다.", "4": "압박 후 가슴이 이완되지 않으면 효과적인 순환이 이루어지지 않는다.", "5": "두 손의 손바닥을 사용하되, 체중을 실어서 압박하는 것이 효과적이다."}'::jsonb, '[{"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "환자의 호흡과 맥박이 멈췄을 때 실시하는 응급처치", "def_vi": "Sơ cứu khi bệnh nhân ngừng thở và ngừng mạch"}, {"term_ko": "가슴압박", "term_vi": "Ép ngực", "def_ko": "심장을 압박하여 혈액 순환을 도와주는 행위", "def_vi": "Hành động ấn vào ngực để hỗ trợ tuần hoàn máu"}, {"term_ko": "명치", "term_vi": "Xương ức", "def_ko": "가슴 중앙 아래쪽에 위치하는 부위", "def_vi": "Vùng ở giữa dưới ngực"}, {"term_ko": "체중", "term_vi": "Khối lượng", "def_ko": "몸의 무게", "def_vi": "Trọng lượng cơ thể"}, {"term_ko": "압박", "term_vi": "Áp lực", "def_ko": "힘을 가하거나 눌러서 누르는 행위", "def_vi": "Hành động gây sức ép"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1715, '14', '심폐소생술을 할 때 가슴을 압박하는 방법으로 옳은 것은?', '["복장뼈의 하단 칼돌기를 직접 압박한다.", "분당 100~120회 속도로 압박한다.", "대상자의 골반에 걸터앉아서 압박한다.", "등 밑에 낮은 베개를 고인후 압박한다.", "압박 위칠를 바꾸어 가면서 실시한다."]'::jsonb, 2, NULL, NULL, '{"1": "복장뼈의 하단 칼돌기를 직접 압박하는 것은 잘못된 방법입니다.  \n[정답]", "2": "분당 100~120회 속도로 압박하는 것이 올바른 가슴 압박 속도입니다.", "3": "대상자의 골반에 걸터앉아서 압박하는 것은 올바른 방법이 아닙니다.", "4": "등 밑에 낮은 베개를 고인후 압박하는 것은 올바른 시행 방법이 아닙니다.", "5": "압박 위치를 바꾸어 가면서 실시하는 것은 권장되지 않는 방법입니다."}'::jsonb, '[{"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "생명을 구하기 위한 응급처치", "def_vi": "Cứu sinh khẩn cấp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1714, '14', '심폐소생술 시 가슴압박을 실시하는 방법으로 옳은 것은?', '["압박된 가슴이 눌린 상태로 유지되게 압박한다.", "분당 60회의 속도로 가슴을 압박한다.", "손가락을 가슴에 대고 압박한다.", "양쪽 팔을 45도 정도 굽혀 압박한다.", "가슴이 5cm 눌릴 정도로 압박한다."]'::jsonb, 5, NULL, NULL, '{"1": "압박된 가슴이 눌린 상태로 유지되게 압박한다: 가슴 압박 시 눌린 상태가 유지되어야 하지 않습니다.\n[정답]", "5": "가슴이 5cm 눌릴 정도로 압박한다: 심폐소생술의 올바른 가슴압박 깊이입니다.", "3": "손가락을 가슴에 대고 압박한다: 손가락으로 압박하는 것은 부적절합니다.", "4": "양쪽 팔을 45도 정도 굽혀 압박한다: 팔의 각도는 똑바로 펴는 것이 더 적절합니다.", "2": "분당 60회의 속도로 가슴을 압박한다: 가슴압박 속도는 분당 100-120회가 적절합니다."}'::jsonb, '[{"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "심장과 호흡이 멈춘 환자를 살리기 위한 응급처치", "def_vi": "Cấp cứu cho bệnh nhân khi tim và hô hấp ngừng lại"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1713, '14', '심폐소생술 시 가슴 압박을 위한 손 위치는?', '["오른쪽 가슴", "왼쪽 가슴", "흉골 아래쪽 절반부위", "명치 아래", "상복부"]'::jsonb, 3, NULL, NULL, '{"1": "오른쪽 가슴 부위에서는 효과적인 압박이 불가능합니다.", "2": "왼쪽 가슴도 마찬가지로 효과적이지 않습니다.\n[정답]", "3": "흉골 아래쪽 절반부위가 심폐소생술 시 가슴 압박을 위한 올바른 위치입니다.", "4": "명치 아래는 적절한 위치가 아닙니다.", "5": "상복부도 심폐소생술 시 적용되지 않습니다."}'::jsonb, '[{"term_ko": "심폐소생술", "term_vi": "Hồi phục tim phổi", "def_ko": "생명을 구하기 위한 응급 처치법", "def_vi": "Phương pháp cấp cứu nhằm cứu sống"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1712, '14', '심폐소생술을 시행하는 순서로 옳은 것은?', '["도움요청 - 반응확인 - 호흡확인 - 가슴압박 - 회복자세", "도움요청 - 호흡확인 - 반응확인 - 가슴압박 - 회복자세", "반응확인 - 호흡확인 - 가슴압박 - 인공호흡 - 도움요청", "반응확인 - 도움요청 - 호흡확인 - 가슴압박 - 회복자세", "호흡확인 - 가슴압박 - 반응확인 - 도움요청 - 회복자세"]'::jsonb, 4, NULL, NULL, '{"1": "도움요청을 먼저 해야 하지만, 반응확인을 먼저 한 후에 도움을 요청해야 한다.\n[정답]", "4": "반응확인을 먼저 한 후 도움요청, 호흡확인, 가슴압박, 회복자세를 취해야 한다.", "3": "반응확인 후 호흡확인을 해야 하지만, 도움요청이 늦어진다.", "2": "호흡확인을 먼저 하는 것은 잘못된 순서다.", "5": "호흡확인을 먼저 하는 것은 잘못된 순서다."}'::jsonb, '[{"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "심장을 다시 뛰게 하려는 응급처치 방법", "def_vi": "Phương pháp cấp cứu để làm tim hoạt động trở lại"}, {"term_ko": "가슴압박", "term_vi": "Ép ngực", "def_ko": "심장 압박을 통해 혈액 순환을 돕는 방법", "def_vi": "Phương pháp hỗ trợ tuần hoàn máu thông qua việc thúc đẩy tim"}, {"term_ko": "회복자세", "term_vi": "Tư thế hồi phục", "def_ko": "의식을 회복한 사람의 올바른 자세", "def_vi": "Tư thế đúng cho người đã hồi phục ý thức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1711, '14', '쓰러져 있는 대상자를 발견했을 때 가장 먼저 해야 하는 것은?', '["도움 요청", "반응 확인", "호흡 확인", "가슴 압박", "회복 자세"]'::jsonb, 2, NULL, NULL, '{"1": "도움 요청: 도움이 필요하지만, 우선 반응을 확인해야 한다.\n[정답]", "2": "반응 확인: 대상자의 상태를 파악하기 위해 가장 먼저 확인해야 하는 점이다.", "3": "호흡 확인: 반응을 확인한 후 수행하는 과정이다.", "4": "가슴 압박: 호흡이나 반응이 없을 때 지침에 따라 진행해야 한다.", "5": "회복 자세: 대상자의 상태에 따라 필요할 수 있지만, 먼저 반응 확인이 필요하다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "사람(환자)", "def_vi": "bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1710, '14', '호흡이 없는 대상자에게 심폐소생술을 할 때 가슴압박을 하는 이유는?', '["의식 회복", "통증 감소", "합병증 예방", "폐에 산소공급", "심장과 뇌로 충분한 혈액공급"]'::jsonb, 5, NULL, NULL, '{"1": "의식 회복은 심폐소생술의 목적 중 하나일 수 있지만, 가슴 압박의 직접적인 이유는 아닙니다.\n[정답]", "5": "심장과 뇌로 충분한 혈액 공급이 가장 중요한 이유입니다. 가슴 압박을 통해 심장의 펌프 기능을 대체하여 혈류를 유지합니다.", "3": "합병증 예방은 심폐소생술 후 고려해야 할 사항이지 가슴 압박의 직접적인 이유는 아닙니다.", "4": "폐에 산소 공급은 인공호흡을 통해 이루어지지만 가슴 압박의 목적은 아닙니다.", "2": "통증 감소는 심폐소생술의 주목적이 아닙니다."}'::jsonb, '[{"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "생명을 구하기 위한 응급처치", "def_vi": "Cách cấp cứu để cứu sống"}, {"term_ko": "호흡", "term_vi": "Hô hấp", "def_ko": "숨쉬는 것", "def_vi": "Việc thở"}, {"term_ko": "가슴압박", "term_vi": "Ép ngực", "def_ko": "가슴을 누르는 기술", "def_vi": "Kỹ thuật nén ngực"}, {"term_ko": "혈액", "term_vi": "Máu", "def_ko": "몸안의 액체", "def_vi": "Chất lỏng trong cơ thể"}, {"term_ko": "산소", "term_vi": "Oxy", "def_ko": "생명 유지에 필요한 기체", "def_vi": "Khí cần thiết cho sự sống"}, {"term_ko": "합병증", "term_vi": "Biến chứng", "def_ko": "원인이 복잡한 질환", "def_vi": "Bệnh lý phức tạp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1709, '14', '심정지 대상자에게 심폐소생술을 하는 일차적인 목적은?', '["폐 기능 회복", "뇌 손상 최소화", "면역 기능 강화", "신장 기능 향상", "근골격 손상 회복"]'::jsonb, 2, NULL, NULL, '{"1": "폐 기능 회복: 심폐소생술은 폐 기능을 직접적으로 회복하는 것이 아닙니다.\n[정답]", "2": "뇌 손상 최소화: 심정지 후 뇌는 산소 공급이 중단되어 손상이 발생할 수 있는데, 심폐소생술은 이를 방지하기 위한 조치입니다.", "3": "면역 기능 강화: 면역 기능과는 직접적인 관련이 없습니다.", "4": "신장 기능 향상: 신장 기능을 향상시키는 것은 심폐소생술의 목표가 아닙니다.", "5": "근골격 손상 회복: 근골격 손상은 심폐소생술과 관련이 없습니다."}'::jsonb, '[{"term_ko": "심정지", "term_vi": "Ngừng tim", "def_ko": "심장이 멈춘 상태", "def_vi": "Trạng thái tim ngừng hoạt động"}, {"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "심장을 재시작하기 위한 응급처치 방법", "def_vi": "Phương pháp cấp cứu để khôi phục hoạt động của tim"}, {"term_ko": "뇌", "term_vi": "Não", "def_ko": "인간의 두뇌", "def_vi": "Bộ não của con người"}, {"term_ko": "손상", "term_vi": "Tổn thương", "def_ko": "신체나 정신의 해를 입음", "def_vi": "Gây hại cho cơ thể hoặc tâm trí"}, {"term_ko": "최소화", "term_vi": "Giảm thiểu", "def_ko": "가장 적은 정도로 줄이다", "def_vi": "Giảm đến mức tối thiểu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1708, '14', '산책하던 대상자가 넘어져 손목 골절이 의심될 때 대처방법은?', '["손목 부위를 지압해 준다.", "튀어나온 뼈를 압박한다.", "반지와 시계를 제거해 준다.", "손을 심장 위치보다 낮게 내리게 한다.", "손목을 반복적으로 털어 보게 한다."]'::jsonb, 3, NULL, NULL, '{"1": "손목 부위를 지압해 주는 것은 부상이 악화될 수 있으므로 부적절합니다.\n[정답]", "3": "손목의 부종 예방 및 혈액 순환을 위해 반지와 시계를 제거해 주는 것이 필요합니다.", "2": "튀어나온 뼈를 압박하는 것은 더욱 큰 피해를 줄 수 있으므로 절대 하면 안 됩니다.", "4": "손을 심장 위치보다 낮게 내리면 혈액 순환에 문제가 생길 수 있으므로 좋지 않습니다.", "5": "손목을 반복적으로 털어 보게 하는 것은 통증을 유발할 수 있어 적절하지 않습니다."}'::jsonb, '[{"term_ko": "손목", "term_vi": "Cổ tay", "def_ko": "손과 팔을 연결해 주는 관절", "def_vi": "Khớp nối giữa tay và cánh tay"}, {"term_ko": "골절", "term_vi": "Gãy xương", "def_ko": "뼈가 부러진 상태", "def_vi": "Tình trạng xương bị gãy"}, {"term_ko": "부종", "term_vi": "Sưng", "def_ko": "부풀어 오르는 것", "def_vi": "Sự phồng lên"}, {"term_ko": "혈액", "term_vi": "Máu", "def_ko": "몸 속에서 흐르는 액체", "def_vi": "Chất lỏng chảy trong cơ thể"}, {"term_ko": "압박", "term_vi": "Ép", "def_ko": "눌러서 압력을 가하는 것", "def_vi": "Nhấn để tạo áp lực"}, {"term_ko": "대처", "term_vi": "Xử lý", "def_ko": "상황에 맞게 행동하는 것", "def_vi": "Hành động phù hợp với tình huống"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1707, '14', '발가락 골절이 의심되는 대상자를 돕는 방법으로 옳은 것은?', '["발가락 부위를 붕대로 압박한다.", "부종 예방을 위해 파스를 뿌려 준다.", "혈액 순환이 잘 되도록 온찜질을 한다.", "손상 부위에 외형상 변형이 있는지 관찰한다.", "크기가 넉넉한 신발을 신기고 걸어 보게 한다."]'::jsonb, 4, NULL, NULL, '{"1": "발가락 부위를 압박하면 추가적인 손상을 유발할 수 있습니다.\n[정답]", "4": "손상 부위의 외형상 변형 여부를 관찰하는 것은 골절을 의심할 때 중요한 사항입니다.", "2": "부종 예방을 위해 파스를 뿌리는 것은 일반적인 조치가 아닙니다.", "3": "온찜질은 초기 손상 시에는 적절하지 않습니다.", "5": "크기가 넉넉한 신발을 신게 하여 걸어보게 하는 것은 오히려 추가적인 통증을 유발할 수 있습니다."}'::jsonb, '[{"term_ko": "발가락", "term_vi": "Ngón chân", "def_ko": "발의 끝 부분", "def_vi": "Phần đầu của bàn chân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1706, '14', '다음 중 가장 먼저 응급처치를 해야 하는 대상자는?', '["설사와 복통을 호소하는 대상자", "운동 직후 혈압이 상승한 대상자", "손가락을 베어 출혈이 있는 대상자", "발목 염좌로 통증을 호소하는 대상자", "얼굴에 화상을 입어 호흡이 곤란한 대상자"]'::jsonb, 5, NULL, NULL, '{"1": "설사와 복통은 통증이 있지만 급성 위험 요소는 낮습니다.", "2": "운동 직후의 혈압 상승은 주의가 필요하지만 즉각적인 응급처치는 아닙니다.", "3": "손가락 출혈은 관리가 필요하지만 호흡과 관련이 없어 우선순위는 낮습니다.\n[정답]", "4": "얼굴에 화상을 입어 호흡이 곤란한 경우 즉각적인 조치가 요구됩니다.", "5": "발목 염좌는 통증이 있더라도 생명이 위태로운 상황은 아닙니다."}'::jsonb, '[{"term_ko": "응급처치", "term_vi": "Xử lý khẩn cấp", "def_ko": "긴급 상황에서 수행하는 치료", "def_vi": "Điều trị trong tình huống khẩn cấp"}, {"term_ko": "대상자", "term_vi": "Người nhận chăm sóc", "def_ko": "치료를 받는 환자", "def_vi": "Bệnh nhân nhận điều trị"}, {"term_ko": "호흡", "term_vi": "Hô hấp", "def_ko": "공기를 흡입하고 내보내는 과정", "def_vi": "Quá trình hít vào và thải ra không khí"}, {"term_ko": "출혈", "term_vi": "Chảy máu", "def_ko": "혈액이 신체 밖으로 나오는 것", "def_vi": "Máu ra ngoài cơ thể"}, {"term_ko": "염좌", "term_vi": "Bong gân", "def_ko": "인대가 손상되는 증상", "def_vi": "Triệu chứng tổn thương dây chằng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1705, '14', '정수기를 사용하던 대상자가 뜨거운 물에 손을 데었을 때 대처방법은?', '["손이 붓기 전에 반지를 빼 준다.", "화상 부위에 핸드크림을 발라준다.", "얼음 조각을 대주어 열기를 식혀준다.", "물집이 생기지 않도록 압박붕대를 감아 준다.", "손으로 화상 부위를 만져서 감각이 있는지 확인한다."]'::jsonb, 1, NULL, NULL, '{"1": "손이 붓기 전에 반지를 빼 준다. - 화상으로 인한 부종을 고려할 때, 지속적인 압박을 줄 수 있는 반지는 제거해야 한다.\n[정답]", "2": "화상 부위에 핸드크림을 발라준다. - 핸드크림을 사용하면 화상을 악화시킬 수 있으므로 적절하지 않다.", "3": "얼음 조각을 대주어 열기를 식혀준다. - 얼음은 직접 대면 화상을 심하게 할 수 있으므로 사용하지 않는 것이 좋다.", "4": "물집이 생기지 않도록 압박붕대를 감아 준다. - 압박은 오히려 물집을 악화시킬 수 있으므로 권장되지 않는다.", "5": "손으로 화상 부위를 만져서 감각이 있는지 확인한다. - 감각을 확인하는 것은 불필요하며, 감각을 확인하기 위해 만지는 것은 추천하지 않는다."}'::jsonb, '[{"term_ko": "정수기", "term_vi": "Máy lọc nước", "def_ko": "정수기(한국어)", "def_vi": "Máy lọc nước"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1704, '14', '대상자가 팔에 뜨거운 물을 쏟아 화상을 입었을 때 응급처치 방법은?', '["물집이 생기면 터뜨려 준다.", "경미한 화상은 기름을 발라준다.", "수돗물을 화상 부위에 세게 틀어 준다.", "통증이 없어질 때까지 15분 이상 찬물에 담근다.", "화상의 심한 정도를 잘 모르면 상태를 지켜본다."]'::jsonb, 4, NULL, NULL, '{"1": "화상 부위의 물집은 감염의 위험이 있으므로 터뜨리지 않아야 합니다.", "2": "기름을 바르는 것은 화상 치료에 적절하지 않습니다.", "3": "세게 틀면 더욱 상처가 심해질 수 있으니 주의해야 합니다.\n[정답]", "4": "찬물에 담그는 방법이 올바르며, 추천되는 시간입니다.", "5": "화상 정도에 따라 즉각적인 응급조치가 필요합니다."}'::jsonb, '[{"term_ko": "응급처치", "term_vi": "Sơ cứu", "def_ko": "응급 상황에서의 치료 방법", "def_vi": "Phương pháp điều trị trong tình huống khẩn cấp"}, {"term_ko": "화상", "term_vi": "Bỏng", "def_ko": "피부가 뜨거운 물체에 닿아 손상된 상태", "def_vi": "Tình trạng tổn thương da do tiếp xúc với vật nóng"}, {"term_ko": "물집", "term_vi": "Bọng nước", "def_ko": "피부 위에 생긴 액체가 고여 있는 부분", "def_vi": "Vùng chứa chất lỏng nổi trên da"}, {"term_ko": "통증", "term_vi": "Đau", "def_ko": "아픔을 느끼는 상태", "def_vi": "Tình trạng cảm thấy đau"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1703, '14', '대상자가 한꺼번에 많은 약을 먹은 후 의식을 잃고 쓰러져 있을 때 대처방법은?', '["하임리히법을 적용한다.", "따뜻한 보리차를 먹게 한다.", "엎드려 고개를 옆으로 돌린 자세로 눕힌다.", "남은 약과 용기를 119 대원에게 전달한다.", "구토물을 즉시 치워 주위를 깨끗하게 한다."]'::jsonb, 4, NULL, NULL, '{"1": "하임리히법은 기도가 막혔을 때 사용하는 방법으로, 약을 과다 복용한 상황에서는 적절하지 않습니다.\n[정답]", "2": "따뜻한 보리차를 먹게 하는 것은 도움되지 않으며, 의식을 잃은 상태에서는 음식을 섭취할 수 없습니다.", "3": "엎드려 고개를 옆으로 돌린 자세로 눕히는 것은 기도를 확보하는 방법이지만, 상황에 따라 다를 수 있습니다.", "4": "남은 약과 용기를 119 대원에게 전달하는 것은 응급 상황에서 중요한 정보 제공이며 올바른 대처 방법입니다.", "5": "구토물을 즉시 치워 주위를 깨끗하게 하는 것은 중요하지만, 먼저 의식을 잃은 대상자를 적절히 응급처치 하는 것이 우선입니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자(한국어)", "def_vi": "Bệnh nhân"}, {"term_ko": "의식", "term_vi": "Ý thức", "def_ko": "정신(한국어)", "def_vi": "Tinh thần"}, {"term_ko": "약", "term_vi": "Thuốc", "def_ko": "약품(한국어)", "def_vi": "Dược phẩm"}, {"term_ko": "고개", "term_vi": "Cái đầu", "def_ko": "머리(한국어)", "def_vi": "Đầu"}, {"term_ko": "구토", "term_vi": "Nôn", "def_ko": "토하다(한국어)", "def_vi": "Nôn"}, {"term_ko": "대원", "term_vi": "Nhân viên", "def_ko": "구성원(한국어)", "def_vi": "Nhân viên"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1702, '14', '대상자가 한꺼번에 많은 약물을 복용하여 약물중독이 되었을 때 대처방법은?', '["구토를 억제하는 약물을 제공한다.", "입 안에 손가락을 넣어 약을 구토하게 한다.", "옷을 느슨하게 하고 따뜻한 우유를 먹인다.", "주변에 있는 먹고 남은 약과 용기를 치운다.", "의식이 없으면 천장을 바라보는 자세로 눕힌다."]'::jsonb, 5, NULL, NULL, '{"1": "구토를 억제하는 약물을 제공하는 것은 위험한 상황에서 적절하지 않습니다.\n[정답]", "5": "의식이 없으면 환자를 천장을 바라보는 자세로 눕히는 것이 안전합니다.", "2": "손가락을 넣는 것은 위험할 수 있으며 추천되지 않습니다.", "3": "옷을 느슨하게 하고 따뜻한 우유를 주는 것은 효과적이지 않습니다.", "4": "남은 약과 용기를 치우는 것은 중요하지만, 즉각적인 대처 방법은 아닙니다."}'::jsonb, '[{"term_ko": "약물", "term_vi": "Thuốc", "def_ko": "약(한국어)", "def_vi": "Thuốc"}, {"term_ko": "중독", "term_vi": "Ngộ độc", "def_ko": "독에 빠진 상태(한국어)", "def_vi": "Tình trạng bị độc"}, {"term_ko": "구토", "term_vi": "Nôn mửa", "def_ko": "토하는 것(한국어)", "def_vi": "Nôn"}, {"term_ko": "의식", "term_vi": "Ý thức", "def_ko": "인지능력(한국어)", "def_vi": "Khả năng nhận thức"}, {"term_ko": "자세", "term_vi": "Tư thế", "def_ko": "신체의 위치(한국어)", "def_vi": "Vị trí cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1701, '14', '장구 연주를 하던 대상자가 몸이 뻣뻣해지고 침을 흘리며 쓰러질 때 대처방법은?', '["제자리에 앉혀 머리를 뒤로 젖히게 한다.", "얼굴을 옆으로 돌려 눕히고 장구를 치운다.", "대상자를 부축하여 안전한 곳으로 옮긴다.", "장구채를 손수건으로 싸서 입에 물려 준다.", "똑바로 눕히고 목 아래에 베개를 받쳐 준다."]'::jsonb, 2, NULL, NULL, '{"1": "제자리에 앉혀 머리를 뒤로 젖히게 하는 것은 기도를 막을 수 있으므로 위험합니다.\n[정답]", "2": "얼굴을 옆으로 돌려 눕히고 장구를 치운다. 이는 대상자의 안전을 보장하고 기도 보호를 위한 올바른 방법입니다.", "3": "대상자를 부축하여 안전한 곳으로 옮기는 것은 적절한 대처가 아니며, 상황이 심각할 수 있습니다.", "4": "장구채를 손수건으로 싸서 입에 물려 주는 것은 안전하지 않으며, 다칠 위험이 있습니다.", "5": "똑바로 눕히고 목 아래에 베개를 받쳐주는 것은 기도를 막을 수 있으므로 부적절한 방법입니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1700, '14', '산책을 하던 대상자가 쓰러져 경련을 할 때 응급처치 방법은?', '["찬물을 마시게 한다.", "119가 올 때까지 가슴 압박을 한다.", "머리를 뒤로 젖혀 기도를 유지한다.", "상체를 높여 편하게 호흡하게 한다.", "상의 단추를 풀고 옆에서 조용히 관찰한다."]'::jsonb, 5, NULL, NULL, '{"1": "찬물을 마시게 하는 것은 일반적으로 도움이 되지 않습니다.\n[정답]", "5": "상의 단추를 풀고 옆에서 조용히 관찰하는 것이 가장 적절한 대처입니다.", "2": "119가 올 때까지 가슴 압박을 하는 것은 부적절한 대처입니다.", "3": "머리를 뒤로 젖혀 기도를 유지하는 것도 해당 상황에서 불필요합니다.", "4": "상체를 높이기보다 안정된 자세를 유지하는 것이 중요합니다."}'::jsonb, '[{"term_ko": "응급처치", "term_vi": "Xử lý khẩn cấp", "def_ko": "긴급한 상황에서 치료해주는 방법", "def_vi": "Phương pháp điều trị trong tình huống khẩn cấp"}, {"term_ko": "경련", "term_vi": "Co giật", "def_ko": "갑자기 벌떡 일어나는 흔들림", "def_vi": "Sự co giật đột ngột"}, {"term_ko": "기도", "term_vi": "Đường thở", "def_ko": "호흡할 수 있는 경로", "def_vi": "Lối để thở"}, {"term_ko": "관찰", "term_vi": "Quan sát", "def_ko": "상황을 주의 깊게 지켜보는 것", "def_vi": "Theo dõi tình huống một cách cẩn thận"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1699, '14', '대상자가 경련을 일으킬 때 대처방법으로 옳은 것은?', '["인공호흡을 한다.", "팔 다리를 꽉 잡고 발작을 멈추게 한다.", "똑바로 눕혀 머리가 바닥에 직접 닿게 한다.", "침으로 숨쉬기 힘든 경우 손수건을 입에 넣어준다.", "119에 신고하고 경련이 발생한 시각을 기록한다."]'::jsonb, 5, NULL, NULL, '{"1": "인공호흡은 경련 시 필요하지 않으며 상황에 따라 부적절할 수 있습니다.\n[정답]", "5": "119에 신고하고 경련이 발생한 시각을 기록하는 것이 가장 올바른 대처입니다.", "2": "팔과 다리를 꽉 잡는 것은 부상의 위험이 있으며, 발작을 멈추게 할 수 없습니다.", "3": "똑바로 눕히는 것은 위험할 수 있으며, 머리가 바닥에 직접 닿는 것은 바람직하지 않습니다.", "4": "손수건을 입에 넣는 것은 기도 막힘의 위험이 있어 매우 위험합니다."}'::jsonb, '[{"term_ko": "경련", "term_vi": "Co giật", "def_ko": "발작(한국어)", "def_vi": "Cơn co giật(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1698, '14', '대상자가 넘어져 팔에 찰과상을 입고 출혈이 심할 때 응급처치 방법은?', '["지혈제를 뿌려준다.", "깨끗한 수건으로 상처를 압박한다.", "출혈부위를 흐르는 물로 씻는다.", "손으로 직접 출혈부위를 압박한다.", "상처를 압박한 첫 번째 패드를 반복 교체한다."]'::jsonb, 2, NULL, NULL, '{"1": "지혈제를 뿌리는 것은 일반적인 응급처치 방법이 아닙니다.\n[정답]", "2": "깨끗한 수건으로 상처를 압박하면 출혈을 멈추게 할 수 있습니다.", "3": "출혈부위를 흐르는 물로 씻는 것은 상처를 청소하기 위한 방법이지만, 출혈이 심할 경우에는 적합하지 않습니다.", "4": "손으로 직접 출혈부위를 압박하는 것은 가능하지만, 깨끗한 수건이나 천으로 압박하는 것이 더 효과적입니다.", "5": "상처를 압박한 첫 번째 패드를 반복 교체하기보다는 처음에 단단히 압박하는 것이 중요합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자(한국어)", "def_vi": "Bệnh nhân"}, {"term_ko": "몸", "term_vi": "Cơ thể", "def_ko": "신체(한국어)", "def_vi": "Cơ thể"}, {"term_ko": "출혈", "term_vi": "Chảy máu", "def_ko": "피가 나는 것(한국어)", "def_vi": "Chảy máu"}, {"term_ko": "응급처치", "term_vi": "Sơ cứu", "def_ko": "긴급한 상황에서의 의료적인 도움(한국어)", "def_vi": "Sơ cứu"}, {"term_ko": "압박하다", "term_vi": "Ép", "def_ko": "누르다(한국어)", "def_vi": "Ép"}, {"term_ko": "수건", "term_vi": "Khăn", "def_ko": "물건을 닦는 천(한국어)", "def_vi": "Khăn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1697, '14', '대상자가 날카로운 물건에 손을 베어 피가 날 때 응급처치 방법은?', '["따뜻한 물에 손을 담가준다.", "출혈이 있는 손을 알코올로 씻어 준다.", "장갑을 착용하고 멸균거즈로 압박한다.", "압박붕대를 감은 뒤, 멸균거즈로 지혈한다.", "출혈이 지속되면 상처를 압박한 패드를 교체한다."]'::jsonb, 3, NULL, NULL, '{"1": "따뜻한 물에 담그는 것은 출혈을 막는 방법이 아닙니다.", "2": "알코올로 씻는 것은 상처에 자극을 줄 수 있으므로 적절하지 않습니다.\n[정답]", "3": "장갑을 착용하고 멸균거즈로 압박하는 것이 올바른 응급처치 방법입니다.", "4": "압박붕대를 감은 뒤 멸균거즈로 지혈하는 것도 필요하지만, 기본적으로는 압박이 선행되어야 합니다.", "5": "압박한 패드를 교체하는 것은 추가적인 처치이므로 초기 대응으로는 적절하지 않습니다."}'::jsonb, '[{"term_ko": "응급처치", "term_vi": "Sơ cứu", "def_ko": "즉각적인 치료 또는 대응", "def_vi": "Sự điều trị hoặc phản ứng ngay lập tức"}, {"term_ko": "출혈", "term_vi": "Chảy máu", "def_ko": "피가 흐르는 상태", "def_vi": "Tình trạng máu chảy"}, {"term_ko": "장갑", "term_vi": "Găng tay", "def_ko": "손을 보호하는 의복", "def_vi": "Trang phục bảo vệ tay"}, {"term_ko": "멸균거즈", "term_vi": "Gạc vô trùng", "def_ko": "세균이 없는 거즈", "def_vi": "Băng gạc không có vi khuẩn"}, {"term_ko": "압박붕대", "term_vi": "Băng ép", "def_ko": "압박을 위한 붕대", "def_vi": "Băng cho áp lực"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1696, '14', '급성 저혈압 (쇼크)에 대한 설명과 대처방법으로 옳은 것은?', '["혈액순환에 필요한 혈액량이 과도해서 발생한다.", "팔과 다리로 혈액량을 증가시키기 위한 조치를 한다.", "심부전 환자는 눕기보다 앉아서 호흡하게 한다.", "상황이 종료될 때까지 반복적으로 숨을 몰아쉬게 한다.", "선 자세에서 천천히 제자리걸음을 걷게 한다."]'::jsonb, 3, NULL, NULL, '{"1": "혈액순환에 필요한 혈액량이 부족해서 발생하는 것이지 과도해서 발생하지 않습니다.\n[정답]", "2": "팔과 다리로 혈액량을 증가시키기 위한 조치는 일반적으로 사용하는 방법은 아닙니다.", "3": "심부전 환자는 눕기보다 앉아서 호흡을 하는 것이 더 좋은 방법입니다.", "4": "상황이 종료될 때까지 반복적으로 숨을 몰아쉬게 하는 것은 바람직하지 않습니다.", "5": "선 자세에서 제자리걸음을 걷는 것은 저혈압 환자에게 좋지 않은 방법입니다."}'::jsonb, '[{"term_ko": "급성 저혈압", "term_vi": "Hạ huyết áp cấp tính", "def_ko": "갑작스럽고 심각한 혈압 저하(한국어)", "def_vi": "Giảm huyết áp đột ngột và nghiêm trọng"}, {"term_ko": "쇼크", "term_vi": "Sốc", "def_ko": "생명 위협적 상태(한국어)", "def_vi": "Tình trạng đe dọa đến tính mạng"}, {"term_ko": "심부전", "term_vi": "Suy tim", "def_ko": "심장이 혈액을 충분히 펌프하지 못하는 상태(한국어)", "def_vi": "Tình trạng tim không bơm đủ máu"}, {"term_ko": "혈액량", "term_vi": "Lượng máu", "def_ko": "혈관에 존재하는 혈액의 총량(한국어)", "def_vi": "Tổng lượng máu trong mạch"}, {"term_ko": "호흡", "term_vi": "Hô hấp", "def_ko": "산소를 흡입하고 이산화탄소를 내보내는 과정(한국어)", "def_vi": "Quá trình hít oxy và thải carbon dioxide"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1695, '14', '심장 질환이 있는 대상자에게 급성 저혈압인 쇼크가 발생했을 때 응급처치 방법은?', '["원활한 호흡을 위해 측위로 눕힌다.", "다리가 30cm정도 올라가도록 해준다.", "상황이 종료될 때까지 물을 제공한다.", "혈압과 맥박이 안정되기를 기다렸다가 119에 신고한다.", "입에서 토사물이 나오면 기도유지를 위해 고개를 뒤로 젖힌다."]'::jsonb, 2, NULL, NULL, '{"1": "원활한 호흡을 위해 측위로 눕히는 것은 필요하지만, 저혈압 상태에서는 다리를 올리는 것이 중요합니다.\n[정답]", "2": "다리가 30cm 정도 올라가게 해주는 것은 저혈압을 개선하는 응급처치 방법입니다.", "3": "상황 종료 전까지 물을 제공하는 것은 위험할 수 있습니다.", "4": "혈압과 맥박이 안정될 때까지 기다리면서 신고하는 것은 응급처치 순서에서 우선적으로 행동해야 할 사항이 아닙니다.", "5": "입에서 토사물이 나오는 경우 기도유지를 위해 고개를 젖히는 것은 바른 방법이 아닙니다."}'::jsonb, '[{"term_ko": "심장", "term_vi": "Tim", "def_ko": "심장(한국어)", "def_vi": "Tim(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1694, '14', '급성 저혈압 증상으로 옳은 것은?', '["호흡수가 감소한다.", "손발에 열감이 있다.", "피부색이 붉게 변한다.", "혈압이 80/50 이하로 낮아진다.", "맥박 수가 100회 이상으로 빨라진다."]'::jsonb, 5, NULL, NULL, '{"1": "호흡수가 감소하는 것은 일반적으로 저혈압의 증상과 일치하지 않습니다.\n[정답]", "5": "맥박 수가 100회 이상으로 빨라지는 것은 저혈압의 일반적인 반응입니다.", "2": "손발에 열감이 있는 것은 저혈압 증상과 관련이 없습니다.", "3": "피부색이 붉게 변하는 것은 저혈압이 아닌 고혈압에서 나타나는 증상입니다.", "4": "혈압이 80/50 이하로 낮아지는 것은 저혈압의 주된 특징이나, 증상 접근에서는 맥박 수의 변화를 더 강조합니다."}'::jsonb, '[{"term_ko": "급성", "term_vi": "저혈압", "def_ko": "급성(한국어) / cấp tính(베트남어)", "def_vi": "저혈압(한국어) / huyết áp thấp(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1693, '14', '식사를 하던 대상자가 갑자기 의식을 잃고 쓰러졌을 때 대처방법은?', '["가슴압박과 인공호흡을 한다.", "손가락을 입에 넣어 구토시킨다.", "편평한 바닥에 눕히고 머리를 뒤로 젖힌다.", "옷의 단추를 풀어 주고 심호흡을 하게 한다.", "119에 신고하고 심폐소생술을 실시한다."]'::jsonb, 5, NULL, NULL, '{"1": "가슴압박과 인공호흡은 심정지 시에 시행하는 방법으로, 의식을 잃고 쓰러진 경우에는 필요한 조치가 아닙니다.\n[정답]", "5": "119에 신고하고 심폐소생술을 실시하는 것이 가장 올바른 대처 방법입니다.", "2": "손가락을 입에 넣어 구토시키는 것은 위급할 때 권장되지 않으며, 오히려 위험할 수 있습니다.", "3": "편평한 바닥에 눕히고 머리를 뒤로 젖히는 것은 기도의 확보에는 도움이 되지만, 신속한 대처가 필요합니다.", "4": "옷의 단추를 풀어주고 심호흡을 하게 하는 것은 응급처치로 적절하지 않습니다."}'::jsonb, '[{"term_ko": "응급상황", "term_vi": "Tình huống khẩn cấp", "def_ko": "즉각적인 도움이 필요한 상황", "def_vi": "Tình huống cần sự giúp đỡ ngay lập tức"}, {"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "심장이 멈춘 경우에 시행하는 처치", "def_vi": "Biện pháp thực hiện khi tim ngừng đập"}, {"term_ko": "구토", "term_vi": "Nôn", "def_ko": "음식물을 토해내는 것", "def_vi": "Nôn thức ăn ra ngoài"}, {"term_ko": "기대", "term_vi": "Mong đợi", "def_ko": "의식을 잃지 않고 계신 상태", "def_vi": "Trạng thái không mất ý thức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1692, '14', '하임리히법을 적용하는 경우로 옳은 것은?', '["이물질로 인한 질식", "식중독에 의한 복통", "심정지 상태", "경련", "골절"]'::jsonb, 1, NULL, NULL, '{"1": "하임리히법은 이물질로 인해 기도가 막힌 경우에 적용해야 합니다.\n[정답]", "2": "식중독은 주로 식사를 통해 감염되는 문제이며 하임리히법과는 관련이 없습니다.", "3": "심정지는 응급상황이지만 하임리히법과는 직접적으로 무관합니다.", "4": "경련은 다른 응급처치가 필요하며 하임리히법과는 관련이 없습니다.", "5": "골절은 뼈에 관련된 문제로 하임리히법과는 관계가 없습니다."}'::jsonb, '[{"term_ko": "하임리히법", "term_vi": "Phương pháp Heimlich", "def_ko": "기도가 막힌 환자를 구하기 위한 응급처치 방법", "def_vi": "Phương pháp sơ cứu cho bệnh nhân bị nghẹt thở"}, {"term_ko": "이물질", "term_vi": "Dị vật", "def_ko": "신체에 들어가서 문제를 일으키는 물질", "def_vi": "Chất gây vấn đề khi vào cơ thể"}, {"term_ko": "심정지", "term_vi": "Ngừng tim", "def_ko": "심장이 멈춘 상태", "def_vi": "Tình trạng tim ngừng đập"}, {"term_ko": "경련", "term_vi": "Co giật", "def_ko": "불수의적인 수축과 이완", "def_vi": "Co cơ không tự nguyện"}, {"term_ko": "골절", "term_vi": "Gãy xương", "def_ko": "뼈가 부러진 상태", "def_vi": "Tình trạng xương bị gãy"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1691, '14', '대상자가 보호자와 함께 떡을 먹다가 기도가 막혀 괴로운 표정을 지을 때 응급처치 방법은?', '["바닥에 주저 앉힌 후 팔다리를 주물러 준다.", "5cm 깊이로 눌리도록 가슴을 압박한다.", "손가락을 입에 넣어 궅를 유발하여 빼낸다.", "뒤에서 주먹을 쥔 손을 감싸 배꼽과 명치 중간을 후상방으로 밀어올린다.", "등 두드리기와 복부 밀어내기를 교대로 실시한다."]'::jsonb, 4, NULL, NULL, '{"1": "바닥에 주저 앉히는 것은 응급처치로 적절하지 않다.\n[정답]", "4": "뒤에서 주먹을 쥔 손을 감싸 배꼽과 명치 중간을 후상방으로 밀어올리는 방법은 기도를 확보하는 데 효과적이다.", "3": "손가락을 넣어 궈를 유발하는 방법은 위험할 수 있기 때문에 사용하지 않는다.", "2": "가슴을 압박하는 방법은 부적절하다.", "5": "등 두드리기와 복부 밀어내기를 교환하는 방법은 좋지만, 주먹을 감싸고 압력을 가하는 것이 더 효과적이다."}'::jsonb, '[{"term_ko": "응급처치", "term_vi": "Sơ cứu", "def_ko": "긴급 상황에서 즉각적으로 필요한 치료", "def_vi": "Điều trị cần thiết ngay lập tức trong tình huống khẩn cấp"}, {"term_ko": "기도", "term_vi": "Đường thở", "def_ko": "공기가 인체 내로 들어가고 나가는 통로", "def_vi": "Lối không khí vào và ra trong cơ thể"}, {"term_ko": "표정", "term_vi": "Biểu cảm", "def_ko": "얼굴의 감정을 나타내는 방법", "def_vi": "Cách thể hiện cảm xúc trên khuôn mặt"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1690, '14', '목 안에 이물질이 걸려 육안으로 보일 때 올바른 응급처치는?', '["큰 기침을 하게 하여 뱉어내게 한다.", "입 안에 손가락을 넣어 빼낸다.", "천천히 심호흡을 하도록 유인한다.", "즉시 인공호흡을 실시한다.", "물과 함께 삼키도록 한다."]'::jsonb, 1, NULL, NULL, '{"1": "큰 기침을 하게 하여 뱉어내게 한다. - 기침으로 이물질을 제거하는 것이 가장 효과적이다.\n[정답]", "2": "입 안에 손가락을 넣어 빼낸다. - 이 방법은 손가락이 이물질을 더 밀어넣을 위험이 있다.", "3": "천천히 심호흡을 하도록 유인한다. - 이 방법은 이물질을 제거하는 데 도움이 되지 않는다.", "4": "즉시 인공호흡을 실시한다. - 인공호흡은 기도가 막혀 있는 상태에서 실시해선 안 된다.", "5": "물과 함께 삼키도록 한다. - 물로 이물질을 넘기는 것은 위험할 수 있다."}'::jsonb, '[{"term_ko": "이물질", "term_vi": "Dị vật", "def_ko": "뜻(한국어)", "def_vi": "nghĩa(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1689, '14', '대상자가 기침을 하며 기침을 하며 호흡 곤란, 목을 조르는 듯한 자세를 할 때 의심해야 할 것은?', '["경련", "저산소증", "열사병", "심부전", "질식"]'::jsonb, 5, NULL, NULL, '{"1": "경련은 근육의 수축으로 인한 증상으로, 기침과 직접적인 연관성이 없습니다.\n[정답]", "5": "질식은 호흡이 방해받는 상태를 설명하며, 기침과 호흡 곤란 증상은 질식과 관련이 있습니다.", "3": "열사병은 고온 환경에서 발생하는 증상이며, 기침과는 관련이 없습니다.", "4": "심부전은 심장의 기능 저하로 발생하며, 기침보다는 다른 증상들이 주로 나타납니다.", "2": "저산소증은 산소 부족을 의미하지만, 기침 및 특정 자세는 질식을 의심하게 합니다."}'::jsonb, '[{"term_ko": "기침", "term_vi": "호흡 곤란", "def_ko": "기침(ho)", "def_vi": "숨쉬기 어려움(khó thở)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1688, '14', '감염성 질환 관리 중 코로나19에 대한 설명으로 옳은 것은?', '["잠복기 없이 인체에 감염된다.", "격리가 필요 없는 가벼운 감기 증상이다.", "감염된 사람의 물건을 함께 사용해도 된다.", "만성폐쇄성 폐질환이 있는 후기고령자에서 사망 위험이 높다.", "실내에서 전파속도를 늦추기 위해 외부 공기를 차단한다."]'::jsonb, 4, NULL, NULL, '{"1": "코로나19는 일반적으로 잠복기가 존재한다. 따라서 이 설명은 옳지 않다.\n[정답]", "4": "만성폐쇄성 폐질환이 있는 후기고령자에서 사망 위험이 높다는 연구 결과가 있다.", "2": "코로나19는 심각한 질병으로 간주되며 격리가 필요하다.", "3": "감염된 사람의 물건을 함께 사용하면 감염 위험이 증가하므로 이 설명은 틀리다.", "5": "외부 공기를 차단하는 것은 오히려 전파를 증가시킬 수 있다."}'::jsonb, '[{"term_ko": "감염성 질환", "term_vi": "Bệnh truyền nhiễm", "def_ko": "감염이 원인인 질병", "def_vi": "Bệnh do nhiễm trùng gây ra"}, {"term_ko": "격리", "term_vi": "Cách ly", "def_ko": "감염된 사람을 다른 사람과 분리하는 조치", "def_vi": "Biện pháp tách người nhiễm bệnh ra khỏi người khác"}, {"term_ko": "사망 위험", "term_vi": "Nguy cơ tử vong", "def_ko": "사망할 가능성", "def_vi": "Khả năng tử vong"}, {"term_ko": "만성폐쇄성 폐질환", "term_vi": "Bệnh phổi tắc nghẽn mãn tính", "def_ko": "호흡기 질환의 일종", "def_vi": "Một loại bệnh hô hấp"}, {"term_ko": "잠복기", "term_vi": "Thời gian ủ bệnh", "def_ko": "병이 발생하기 전 감염된 상태", "def_vi": "Trạng thái nhiễm trùng trước khi phát bệnh"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1687, '14', '감염성 질환에 대한 설명과 감염관리 방법으로 옳은 것은?', '["옴 - 감염 대상자의 수건, 혈압계, 체온계를 함께 사용한다.", "독감 - 회복 중 발열과 누런 가래가 생기는 것은 정상이다.", "결핵 - 퇴원 후자택에서 결핵관리 전담간호사의 관리를 받는다.", "이 - 사면발이와 머릿니는 두피에 가려움증을 유발시킨다.", "노로바이러스 장염 - 요양보호사의증상이 경미하면 마스크를 착용하고 업무를 본다."]'::jsonb, 3, NULL, NULL, '{"1": "옴은 감염성 질환이지만, 감염 대상자의 위생 용품을 함께 사용하지 않아야 합니다.\n[정답]", "3": "결핵은 퇴원 후 자택에서 전문 간호사의 관리가 필요합니다.", "2": "독감 회복 중의 발열과 증상은 비정상이므로 주의가 필요합니다.", "4": "사면발이와 머릿니는 가려움증을 유발하지만, 이는 일반적인 증상이며 관리가 중요합니다.", "5": "노로바이러스 장염에 걸린 경우, 경미한 증상일지라도 요양보호사는 감염 예방을 위해 마스크 착용이 필수입니다."}'::jsonb, '[{"term_ko": "감염성 질환", "term_vi": "감염관리", "def_ko": "전염병 (Bệnh truyền nhiễm)", "def_vi": "quản lý nhiễm trùng (Quản lý nhiễm trùng)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1686, '14', '시설을 감염 예방을 위해 반드시 따로 처리해야 하는 것은?', '["천식 대상자가 사용한 식기", "대상포진 대상자의 세면도구", "요실금 대상자의 얼룩진 침구", "결핵 대상자의 가래가 묻은 휴지", "접촉성피부염 대상자의 오염된 의복"]'::jsonb, 4, NULL, NULL, '{"1": "천식은 호흡기 질환으로 감염과 직접적인 연관이 없습니다. \n[정답]", "2": "결핵은 공기를 통해 전파되는 감염병으로, 이에 따라 세면도구는 반드시 따로 처리해야 합니다.", "3": "요실금은 일반적으로 감염 위험이 낮으나, 상황에 따라 적절한 처리가 필요합니다.", "4": "결핵 대상자의 가래가 묻은 휴지는 감염 위험이 크므로 반드시 따로 처리해야 합니다.", "5": "접촉성 피부염은 일반적으로 전파되지 않으나, 오염된 의복은 적절히 처리해야 합니다."}'::jsonb, '[{"term_ko": "감염", "term_vi": "인감", "def_ko": "감염(感染)", "def_vi": "nhiễm trùng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1685, '14', '오염된 물질이 묻었을 때 처리하는 방법으로 옳은 것은?', '["심각하게 오염된 침구류는 분리하여 버린다.", "체액이 묻은 유리 조각은 일반 쓰레기로 버린다.", "침구에 쏟아진 체액은 표백제를 사용하여 닦아낸다.", "분비물에 오염된 장갑은 신속하게 세척 후 사용한다.", "바닥에 쏟아진 혈액은 표백제와 물을 1:9로 혼합하여 닦아낸다."]'::jsonb, 5, NULL, NULL, '{"1": "심각하게 오염된 침구류는 분리하여 안전하게 처분하는 것이 맞지만, 처리 방법이 아닌 단순 폐기에 대한 설명이므로 오답입니다.\n[정답]", "5": "바닥에 쏟아진 혈액은 표백제와 물을 1:9로 혼합하여 안전하게 처리하는 방법이므로 정답입니다.", "3": "침구에 쏟아진 체액은 표백제를 사용하여 닦아내기 전에 먼저 적절한 방법으로 처리해야 하므로 오답입니다.", "4": "분비물에 오염된 장갑은 세척 후 재사용할 수 없으며, 폐기해야 하므로 오답입니다.", "2": "체액이 묻은 유리 조각은 반드시 위험 폐기물로 처리해야 하며, 일반 쓰레기로 버릴 수 없으므로 오답입니다."}'::jsonb, '[{"term_ko": "오염", "term_vi": "Ô nhiễm", "def_ko": "더럽혀지다(한국어)", "def_vi": "Bị bẩn(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1684, '14', '호흡기 감염병이 유행하는 시기에 요양보호사의 안전을 위한 가장 경제적이며 효과적인 감염 예방은?', '["보습제를 바른다.", "예방접종을 한다.", "6단계 손 씻기를 한다.", "채소를 반드시 익혀 먹는다.", "고용량 비타민제를 복용한다."]'::jsonb, 3, NULL, NULL, '{"1": "보습제를 바르는 것은 호흡기 감염 예방과 직접적인 연관이 없습니다.\n[정답]", "2": "예방접종은 감염병 예방에 중요하지만, 경제적으로 가장 효과적인 방법은 아닙니다.", "3": "6단계 손 씻기는 감염 예방에 가장 효과적이고 경제적인 방법입니다.", "4": "채소를 익혀 먹는 것은 식중독 예방에는 도움이 되지만, 호흡기 감염 예방에는 관계가 없습니다.", "5": "고용량 비타민제를 복용하는 것은 면역력 증진에 도움이 될 수 있지만, 경제적인 방법으로는 적합하지 않습니다."}'::jsonb, '[{"term_ko": "호흡기", "term_vi": "Hô hấp", "def_ko": "숨 쉬는 기관", "def_vi": "cơ quan hô hấp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1683, '14', '근무 중 감염 예방을 위한 손 위생 방법으로 옳은 것은?', '["세면대에 깨끗한 물을받아 충분히 씻는다.", "반지나 팔찌는 손을 씻은 후 착용한다.", "엄지손가락은 반대편 엄지손가락으로 문질러 씻는다.", "손가락 끝을 반대편 손바닥에 문질러 손톱 밑까지 씻는다.", "세균 번식을 막기 위해 젖은 수건은 말려서 다시 사용한다."]'::jsonb, 4, NULL, NULL, '{"1": "세면대에 깨끗한 물을 받아 씻는 것은 기본적인 단계지만, 단순히 물로 씻는 것만으로는 충분하지 않습니다.\n[정답] (④) 손가락 끝을 반대편 손바닥에 문질러 손톱 밑까지 씻는 것이 올바른 손 위생 방법입니다.", "2": "반지나 팔찌는 손을 씻은 후 착용하는 것이 아니라, 착용하기 전 반드시 제거해야 합니다.", "3": "엄지손가락은 반대편 엄지손가락으로 문질러 씻는 것이 아니며, 손 전체를 잘 씻어야 합니다.", "5": "젖은 수건을 재사용하는 것은 세균 번식을 유발할 수 있으므로 잘못된 방법입니다."}'::jsonb, '[{"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "감염(한국어)", "def_vi": "Nhiễm trùng(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1682, '14', '감염 예방을 위해 손을 씻는 방법으로 옳은 것은?', '["손을 씻은 후 물기는 털어서 말린다.", "손이 건조하면 손 씻기 횟수를 줄인다.", "배설물을 처리한 손은 마른 휴지로 닦는다.", "멸균제품을 개봉하기 전 반드시 손을 씻는다.", "기침 후에는 흐르는 물과 비누로 10초 동안 씻는다."]'::jsonb, 4, NULL, NULL, '{"1": "손을 씻은 후 물기를 털어서 말리는 것은 올바르지 않습니다. 물기를 닦기 위해서는 깨끗한 수건이나 기구를 사용하는 것이 좋습니다.\n[정답]", "4": "멸균제품을 개봉하기 전 반드시 손을 씻는 것은 올바른 방법입니다. 감염 예방을 위해서는 항상 청결한 상태를 유지해야 합니다.", "3": "배설물을 처리한 손은 마른 휴지로 닦는 것은 적절하지 않으며, 반드시 손을 씻어야 합니다.", "2": "손이 건조하더라도 손 씻기 횟수를 줄여서는 안 됩니다. 감염 예방을 위해서는 손 씻기가 중요합니다.", "5": "기침 후에는 흐르는 물과 비누로 10초 이상 씻는 것이 권장됩니다. 10초는 불충분합니다."}'::jsonb, '[{"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "감염(한국어)", "def_vi": "sự nhiễm trùng"}, {"term_ko": "예방", "term_vi": "Ngăn ngừa", "def_ko": "예방(한국어)", "def_vi": "sự phòng ngừa"}, {"term_ko": "손", "term_vi": "Tay", "def_ko": "손(한국어)", "def_vi": "tay"}, {"term_ko": "비누", "term_vi": "Xà phòng", "def_ko": "비누(한국어)", "def_vi": "xà phòng"}, {"term_ko": "멸균", "term_vi": "Tiệt trùng", "def_ko": "멸균(한국어)", "def_vi": "sự tiệt trùng"}, {"term_ko": "청결", "term_vi": "Sạch sẽ", "def_ko": "청결(한국어)", "def_vi": "sạch sẽ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1681, '14', '감염 예방을 위한 개인 보호구 사용 방법으로 옳은 것은?', '["옷을 갈아입힐 때 일회용 장갑을 작용한다.", "대상자와 산책할 때 안면보호구를 착용한다.", "목욕할 때는 보안경을 착용하고 몸을 씻긴다.", "기저귀를 갈 때 일회용 방수성가운을 착용한다.", "결핵 대상자를 돌볼 때 일회용 마스크와 장갑을 착용한다."]'::jsonb, 5, NULL, NULL, '{"1": "옷을 갈아입힐 때 일회용 장갑을 사용하는 것은 맞지만 특정 상황에 따라 달라질 수 있다. 그러나 일반적으로 권장되지 않는다.", "2": "대상자와 산책할 때 안면보호구를 착용하는 것은 반드시 필요한 상황이 아니므로 옳지 않다.", "3": "목욕할 때 보안경을 착용하는 것은 일반적이지 않으며, 필요하지 않다.", "4": "기저귀를 갈 때 일회용 방수성 가운을 착용하는 것은 적절하지 않을 수 있다.\n[정답]", "5": "결핵 대상자를 돌볼 때는 감염 예방을 위해 일회용 마스크와 장갑을 착용해야 한다."}'::jsonb, '[{"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "감염", "def_vi": "Nhiễm trùng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1680, '14', '돌봄제공자인 요양보호사가 감염예방 원칙을 준수한 경우는?', '["휴지로 손을 닦고 장갑을 착용하였다.", "대상자의 배설물을 맨손으로 만졌다.", "사용한 장갑을 착용하고 깨끗한 물건을 만지지 않았다.", "대상자의 혈액이 몸에 닿아서 업무를 모두 마치고 닦았다.", "대상자의 분비물이 몸에 묻을 우려가 있어도 장갑만 착용했다."]'::jsonb, 3, NULL, NULL, '{"1": "휴지로 손을 닦고 장갑을 착용하였다. - 손을 닦는 것이 아니라 세척해야 합니다.\n[정답]", "3": "사용한 장갑을 착용하고 깨끗한 물건을 만지지 않았다. - 감염 예방 원칙을 잘 준수한 경우입니다.", "2": "대상자의 배설물을 맨손으로 만졌다. - 감염 예방 원칙을 위반한 것입니다.", "4": "대상자의 혈액이 몸에 닿아서 업무를 모두 마치고 닦았다. - 즉시 적절한 처치를 해야 합니다.", "5": "대상자의 분비물이 몸에 묻을 우려가 있어도 장갑만 착용했다. - 장갑 외에 추가적인 예방 조치가 필요합니다."}'::jsonb, '[{"term_ko": "감염 예방", "term_vi": "Phòng ngừa lây nhiễm", "def_ko": "감염을 막는 방법", "def_vi": "Các phương pháp ngăn chặn sự lây lan của vi trùng"}, {"term_ko": "장갑", "term_vi": "Găng tay", "def_ko": "손을 보호하는 착용물", "def_vi": "Đồ bảo vệ tay"}, {"term_ko": "세척", "term_vi": "Rửa", "def_ko": "깨끗하게 씻다", "def_vi": "Làm sạch bằng nước"}, {"term_ko": "배설물", "term_vi": "Phân", "def_ko": "신체에서 나오는 노폐물", "def_vi": "Chất thải từ cơ thể"}, {"term_ko": "혈액", "term_vi": "Máu", "def_ko": "몸속의 액체", "def_vi": "Chất lỏng trong cơ thể"}, {"term_ko": "분비물", "term_vi": "Chất tiết", "def_ko": "몸에서 나오는 액체", "def_vi": "Dịch tiết từ cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1679, '14', '감염성 질환에 이환된 대상자를 돌보는 방법으로 옳은 것은?', '["젖은 수건은 건조한후 반복 사용한다.", "오염된 장갑은 깨끗이 씻어 재사용한다.", "마스크만 착용하고 대상자의 배설물을 만진다.", "일을 마친 후 착용했던 장갑 상태로 업무를 본다.", "질병의 전파를 막기 일회용 방수가운을 착용한다."]'::jsonb, 5, NULL, NULL, '{"1": "젖은 수건은 건조한 후 반복 사용하지 않아야 한다. 오염을 방지하기 위함이다.\n[정답]", "5": "질병의 전파를 막기 위해 일회용 방수가운을 착용하는 것이 올바른 방법이다.", "2": "오염된 장갑은 깨끗이 씻어 재사용해서는 안 된다. 오염물질이 남을 수 있다.", "3": "마스크만 착용하고 대상자의 배설물을 만지는 것은 위험하다. 장갑 등 추가적인 보호장구가 필요하다.", "4": "일을 마친 후 착용했던 장갑 상태로 업무를 보면 안 된다. 반드시 교체해야 한다."}'::jsonb, '[{"term_ko": "감염성 질환", "term_vi": "Bệnh truyền nhiễm", "def_ko": "감염 bệnh", "def_vi": "Bệnh do vi khuẩn hoặc virus gây ra"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1678, '14', '감염의 6가지 연결고리에 대한 설명으로 옳은 것은?', '["미생물은 인체 밖에서 바로 소멸한다.", "요양보호사는 감염의 민감한 대상자에 속한다.", "6가지 중 한 가지만 통제해서는 전파를 막을 수 없다.", "미생물은 손과 손을 접촉하는 직접 접촉경로만 전파된다.", "면역기능이 떨어진 대상자는 질병 전파를 막기 위해서 격리한다."]'::jsonb, 2, NULL, NULL, '{"1": "미생물은 인체 밖에서 바로 소멸하지 않습니다. 적절한 환경에서는 생존할 수 있습니다.\n[정답]", "2": "요양보호사는 감염에 취약한 대상자에게 직접적으로 접촉하기 때문에 민감한 대상자에 속합니다.", "3": "감염의 6가지 연결고리 중 하나의 통제로는 전파를 완전히 막을 수 없습니다. 모든 고리를 통제해야 효과적인 예방이 가능합니다.", "4": "미생물은 직접 접촉경로 외에도 공기, 물 등을 통해 전파될 수 있습니다.", "5": "면역기능이 떨어진 대상자는 감염을 예방하기 위해 격리할 수 있지만, 이는 일반적인 경우는 아닙니다."}'::jsonb, '[{"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "감염(한국어)", "def_vi": "Nhiễm trùng(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1677, '14', '전기 사고를 예방하고 안전하게 사용하는 방법으로 옳은 것은?', '["전선에서 불꽃이 일어나면 물을 뿌린다.", "정전으로 해동된 식품은 다시 냉동한다.", "벗겨진 전기코드는 청테이프로 감아 사용한다.", "정전 시 누전차단기의 이상 유무를 확인한다.", "콘센트에서 플러그를 뺄 때에는 지그재그로 움직여 뺀다."]'::jsonb, 4, NULL, NULL, '{"1": "전선에서 불꽃이 나는 경우 물을 사용하면 더 큰 사고를 유발할 수 있습니다.\n[정답]", "4": "정전 시 누전차단기의 이상 유무를 확인하는 것은 안전을 유지하는 데 중요합니다.", "2": "해동된 식품은 다시 냉동할 경우 세균 증식의 위험이 있습니다.", "3": "벗겨진 전기코드를 청테이프로 감아 사용하는 것은 잘못된 방법입니다.", "5": "콘센트에서 플러그를 빼는 방법은 수직으로 당겨 빼야 합니다."}'::jsonb, '[{"term_ko": "전기 사고", "term_vi": "Tai nạn điện", "def_ko": "전기 gây 발생하는 사고(한국어)", "def_vi": "Tai nạn xảy ra do điện(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1676, '14', '가정용 산소호흡기를 사용하는 재가대상자의 가정에 정전이 발생했을 때 대처방법은?', '["누전차단기를 즉시 교체한다.", "대상자와 함께 밖으로 대피한다.", "119에 신고하여 긴급후송을 준비한다.", "전선을 잡고 플러그를 빼서 다시 꽂는다.", "젖은 수건으로 콘센트의 쌓인 먼지를 닦는다."]'::jsonb, 3, NULL, NULL, '{"1": "누전차단기를 즉시 교체하는 것은 적절하지 않다. 정전 시에는 전기 배선을 건드리는 것이 위험할 수 있다.\n[정답]", "2": "대상자와 함께 밖으로 대피하는 것은 안전한 선택일 수 있지만, 재가대상자의 상태에 따라 다를 수 있다.", "3": "119에 신고하여 긴급후송을 준비하는 것이 가장 안전한 대처이다. 산소 공급이 중단될 경우 위험하기 때문에 신속하게 조치를 취해야 한다.", "4": "전선을 잡고 플러그를 빼서 다시 꽂는 것은 위험한 행동이다. 전기가 흐르고 있는 상황에서는 매우 위험하다.", "5": "젖은 수건으로 콘센트의 쌓인 먼지를 닦는 것은 전기 사고를 유발할 수 있으므로 절대 해서는 안 된다."}'::jsonb, '[{"term_ko": "가정용", "term_vi": "Thiết bị gia đình", "def_ko": "가정에서 사용하는 것", "def_vi": "Sử dụng trong gia đình"}, {"term_ko": "산소호흡기", "term_vi": "Máy thở oxy", "def_ko": "산소를 공급하는 기계", "def_vi": "Thiết bị cung cấp oxy"}, {"term_ko": "정전", "term_vi": "Mất điện", "def_ko": "전기가 공급되지 않는 상태", "def_vi": "Trạng thái không có điện"}, {"term_ko": "대처방법", "term_vi": "Phương pháp xử lý", "def_ko": "문제를 해결하기 위한 조치", "def_vi": "Biện pháp giải quyết vấn đề"}, {"term_ko": "응급후송", "term_vi": "Chuyển viện khẩn cấp", "def_ko": "응급환자를 병원으로 이송하는 것", "def_vi": "Vận chuyển bệnh nhân khẩn cấp ra bệnh viện"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1675, '14', '지진이 발생하여 집이 흔들릴 때 대처 방법은?', '["창문을 열고 환기한다.", "가스밸브를 점검한 후에 열어둔다.", "흔들름이 멈추면 바로 전기를 사용한다.", "탁자가 없으면 머리를 팔로 감싸고 우으린다.", "밖으로 나가 건물의 계단 밑으로 대피한다."]'::jsonb, 4, NULL, NULL, '{"1": "창문을 열고 환기하는 것은 지진 발생 시 안전에 도움이 되지 않습니다.\n[정답]", "2": "가스밸브를 점검한 후 열어두는 것은 안전하지 않은 행동입니다.", "3": "흔들림이 멈춘 후 전기를 사용하는 것은 위험할 수 있습니다.", "4": "탁자가 없으면 머리를 팔로 감싸고 우는 것이 위험으로부터 스스로를 보호하는 올바른 행동입니다.", "5": "밖으로 나가 건물의 계단 밑으로 대피하는 것은 지진 발생 시 위험할 수 있습니다."}'::jsonb, '[{"term_ko": "지진", "term_vi": "Động đất", "def_ko": "지구의 내부에서 발생하는 진동", "def_vi": "Sự rung chuyển xảy ra trong lòng đất"}, {"term_ko": "대처", "term_vi": "Ứng phó", "def_ko": "어떤 상황에 대해 행동하는 것", "def_vi": "Hành động đối với một tình huống"}, {"term_ko": "탁자", "term_vi": "Bàn", "def_ko": "사각형의 가구", "def_vi": "Một đồ vật có bốn chân dùng để đặt đồ"}, {"term_ko": "계단", "term_vi": "Cầu thang", "def_ko": "건물 내부의 걸어 올라가거나 내려가는 구조물", "def_vi": "Cấu trúc để đi lên hoặc đi xuống trong tòa nhà"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1674, '14', '가정에서 지진이 발생했을 때 대처방법은?', '["흔들리는 동안에는 탁자 위에 엎드린다.", "흔들림은 잠시 멈추면 출입문을 잠근다.", "깨지기 쉬운 물건은 높은 곳에 올려 둔다.", "엘리베이터를 타고 신속하게 밖으로 나간다.", "식탁 밑으로 들어가 식탁 다리를 잡고 웅크린다."]'::jsonb, 5, NULL, NULL, '{"1": "흔들리는 동안에는 탁자 위에 엎드리는 것은 매우 위험합니다. 지진 중에는 탁자 위가 아닌 튼튼한 물체 아래로 들어가야 합니다.\n[정답]", "5": "식탁 밑으로 들어가 식탁 다리를 잡고 웅크리는 것이 가장 안전한 방법입니다.", "3": "깨지기 쉬운 물건은 높은 곳에 두면 안 되고, 저지대에 두어야 합니다.", "4": "엘리베이터를 타는 것은 끔찍한 위험을 초래할 수 있습니다. 지진 중에는 엘리베이터 사용을 피해야 합니다.", "2": "흔들림이 멈추면 출입문을 잠그는 것은 적절한 행동이 아닙니다."}'::jsonb, '[{"term_ko": "지진", "term_vi": "Động đất", "def_ko": "지구의 내부에서 발생하는 강한 진동", "def_vi": "Sự rung lắc mạnh xảy ra trong lòng đất"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1673, '14', '홍수로 인해 수해가 발생했을 때 대처방법은?', '["가스밸브를 열어 개통상태를 점검한다.", "물이 집 안으로 밀려오는 경우 모래주머니로 막는다.", "밀려온 물이 집 안에서 빠진 직후 전기 차단기를 올린다.", "홍수로 밀려온 물에 몸이 젖은 경우 수건으로 닦는다.", "집 안의 물이 빠지고 나면 라이터를 사용하여 불을 켠다."]'::jsonb, 2, NULL, NULL, '{"1": "가스 누출 위험이 있으므로 가스밸브를 점검하는 것이 적절한 상황이 아닙니다.\n[정답]", "2": "물이 집 안으로 밀려오는 경우 모래주머니로 막는 것이 가장 안전한 대처 방법입니다.", "3": "전기 차단기는 물이 빠진 후에 올려야 안전합니다.", "4": "몸이 젖은 경우 수건으로 닦는 것은 대처 방법이 아닙니다.", "5": "불을 켜는 것은 매우 위험하며, 물이 빠지고 난 후에도 위험합니다."}'::jsonb, '[{"term_ko": "홍수", "term_vi": "Lũ lụt", "def_ko": "물이 넘쳐흐르는 현상", "def_vi": "Hiện tượng nước tràn"}, {"term_ko": "수해", "term_vi": "Thiệt hại do nước", "def_ko": "물로 인한 피해", "def_vi": "Thiệt hại do nước gây ra"}, {"term_ko": "모래주머니", "term_vi": "Bao cát", "def_ko": "물리적 장치로 물을 차단", "def_vi": "Thiết bị vật lý dùng để chặn nước"}, {"term_ko": "전기 차단기", "term_vi": "Công tắc điện", "def_ko": "전기를 끊는 장치", "def_vi": "Thiết bị ngắt điện"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1672, '14', '태풍 예보를 듣고 대비하는 방법으로 옳은 것은?', '["현관문과 창문을 열어둔다.", "차량을 낮은 지대로 옮긴다.", "욕조에 물을 미리 받아둔다.", "주유되어 있는 자동차의 연료를 비운다.", "전기 차단기를 내리고 통신 기기는 끈다."]'::jsonb, 3, NULL, NULL, '{"1": "현관문과 창문을 열어두면 바람의 영향으로 피해를 입을 수 있으므로 위험합니다.\n[정답]", "3": "욕조에 물을 미리 받아두는 것은 비상시 필요한 물을 확보하는 좋은 방법입니다.", "2": "차량을 낮은 지대로 옮기는 것은 홍수 등의 위험에 노출될 수 있기에 바람직하지 않습니다.", "4": "주유된 자동차의 연료를 비우는 것은 비상 상황에서 필요할 수 있는 연료를 아끼는 것과는 반대로 위험을 초래할 수 있습니다.", "5": "전기 차단기를 내리고 통신 기기를 끄는 것은 필요한 정보를 받아들이는 데 방해가 될 수 있습니다."}'::jsonb, '[{"term_ko": "태풍", "term_vi": "Bão", "def_ko": "강한 바람과 비를 동반한 자연현상", "def_vi": "Hiện tượng thiên nhiên có gió mạnh và mưa"}, {"term_ko": "예보", "term_vi": "Dự báo", "def_ko": "미리 예측하는 것", "def_vi": "Dự đoán trước"}, {"term_ko": "대비", "term_vi": "Chuẩn bị", "def_ko": "준비하는 것", "def_vi": "Hành động chuẩn bị"}, {"term_ko": "욕조", "term_vi": "Bồn tắm", "def_ko": "욕실에 있는 큰 물탱크", "def_vi": "Bể chứa nước lớn trong phòng tắm"}, {"term_ko": "차량", "term_vi": "Xe", "def_ko": "자동차", "def_vi": "Ô tô"}, {"term_ko": "연료", "term_vi": "Nhiên liệu", "def_ko": "자동차가 운행하는 데 필요한 물질", "def_vi": "Chất cần thiết cho việc vận hành ô tô"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1671, '14', '유해가스가 방출되는 화재 발생 시 대처방법과 안전 수칙으로 옳은 것은?', '["마른 수건으로 입을 감싼다.", "숨을 깊이 들이마시며 대피한다.", "두 손으로 벽을 짚으며 밖으로 나간다.", "''불이야''라고 소리치고 비상벨을 누른다.", "화재를 대비하여 옥상 출입문을 항상 잠가둔다."]'::jsonb, 4, NULL, NULL, '{"1": "마른 수건으로 입을 감싸는 것은 가스의 흡입을 줄이는 방법이지만 대처 방법으로는 효과적이지 않습니다.\n[정답]", "4": "''불이야''라고 소리치고 비상벨을 누르는 것이 가장 적절한 대처 방법입니다.", "3": "두 손으로 벽을 짚으며 밖으로 나가는 것은 방향을 잃지 않기 위한 방법이지만 불필요하게 시간을 소모할 수 있습니다.", "2": "숨을 깊이 들이마시며 대피하는 것은 유해가스를 더 많이 흡입하게 되는 위험한 행동입니다.", "5": "화재를 대비하여 옥상 출입문을 잠가두는 것은 종종 잘못된 대비책으로, 불시의 대피가 어려워질 수 있습니다."}'::jsonb, '[{"term_ko": "유해가스", "term_vi": "Khí độc", "def_ko": "해로운 기체", "def_vi": "Khí gây hại"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1670, '14', '시설에서 화재가 발생했을 때 대처방법으로 옳은 것은?', '["엘리베이터를 타고 이동한다.", "연기로 앞이 보이지 않으면 그대로 서 있는다.", "코와 입을 감싸고 최대한 자세를 높여 이동한다.", "불길이 천장까지 닿으면 소화기로 신속하게 진화한다.", "방향을 알기 힘들 때에는 계속 한쪽 손으로 벽을 짚으면서 나간다."]'::jsonb, 5, NULL, NULL, '{"1": "엘리베이터는 화재 시에 사용하면 안 되는 이동 수단입니다.\n[정답]", "2": "연기로 앞이 보이지 않는 상황에서는 서 있지 말고 안전한 방향으로 이동해야 합니다.", "3": "코와 입을 감싸고 자세를 낮추는 것이 중요하나, 자세를 높여 이동하는 것은 안전하지 않습니다.", "4": "불길이 천장까지 닿으면 소화기로 진화 시도가 위험하므로 즉각 대피해야 합니다.", "5": "방향을 알기 힘들 때에는 벽을 짚으며 이동하는 것이 안전한 방법입니다."}'::jsonb, '[{"term_ko": "화재", "term_vi": "이동", "def_ko": "불 화재(화재)", "def_vi": "이동(di chuyển)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1669, '14', '화재 예방을 위해 지켜야 하는 안전 수칙으로 옳은 것은?', '["요리가 끝날 때까지 주방에 있는다.", "세탁물은 난로 바로옆에 널어말린다.", "실내 소화기 위치를 자주 바꾸어 놓는다.", "소화기사용 시 벽을 등지고 소화기 분말을 쏜다.", "콘센트 하나에 여러 개의 전열기구 플러그를 꽂는다."]'::jsonb, 1, NULL, NULL, '{"1": "주방에서 요리를 하고 있을 때는 화재를 예방하기 위해 주방에 있는 것이 중요합니다.\n[정답]", "2": "난로 바로 옆에 세탁물을 널면 화재의 위험이 증가합니다.", "3": "실내 소화기의 위치를 자주 바꾸는 것은 위기 시 혼란을 초래할 수 있습니다.", "4": "소화기 사용 시 벽을 등지는 것이 바람직하지 않습니다.", "5": "콘센트 하나에 여러 개의 전열 기구를 꽂는 것은 과열의 위험이 있습니다."}'::jsonb, '[{"term_ko": "화재", "term_vi": "Hỏa hoạn", "def_ko": "불이 나는 것", "def_vi": "Lửa cháy"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1668, '14', '가스레인지 불에 음식을 올려놓고 자꾸 잊어버리는 대상자를 돕는 방법은?', '["배달 음식으로 식단표를 작성하게 한다.", "휴대용 가스레인지를 사용하게 한다.", "가족과 상의하여 가스레인지를 없앤다.", "조리할 때는 주방을 떠나지 않도록 교육한다.", "일주일 분량의 음식을 한꺼번에 준비해둔다."]'::jsonb, 4, NULL, NULL, '{"1": "배달 음식으로 식단표를 작성하는 것은 대처 방법이 아닙니다.\n[정답]", "2": "휴대용 가스레인지를 사용하게 하는 것은 상황을 오히려 악화시킬 수 있습니다.", "3": "가족과 상의하여 가스레인지를 없애는 것은 비현실적인 접근입니다.", "4": "조리할 때는 주방을 떠나지 않도록 교육하는 것은 매우 효과적인 방법입니다.", "5": "일주일 분량의 음식을 한꺼번에 준비해두는 것은 장기적인 해결책이지만, 즉각적인 대처에는 적합하지 않습니다."}'::jsonb, '[{"term_ko": "가스레인지", "term_vi": "Bếp gas", "def_ko": "가스를 연료로 사용하는 조리 기구", "def_vi": "Thiết bị nấu ăn sử dụng khí đốt"}, {"term_ko": "음식", "term_vi": "Thức ăn", "def_ko": "조리한 식사", "def_vi": "Món ăn đã nấu"}, {"term_ko": "대상자", "term_vi": "Người cần giúp đỡ", "def_ko": "도움을 필요한 사람", "def_vi": "Người cần trợ giúp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1667, '14', '방문요양 시 대상자에게 응급상황이발생했을 때 요양보호사는 언제까지 응급처치를 해야 하는가?', '["근무시간이 끝날 때까지", "시설장이 도착할 떄까지", "보호자가 도착할 때까지", "119 구급대원이 도착할 때까지", "동료 요양보호사가 도착할 때까지"]'::jsonb, 4, NULL, NULL, '{"1": "요양보호사가 근무시간이 끝날 때까지 응급처치를 해야 한다는 것은 적절하지 않습니다.\n[정답]", "4": "요양보호사는 응급 상황 발생 시 119 구급대원이 도착할 때까지 응급처치를 계속해야 합니다.", "3": "보호자가 도착할 때까지는 응급처치를 기다릴 수 없으며,", "2": "시설장이 도착할 때까지도 반응이 필요합니다.", "5": "동료 요양보호사가 도착할 때까지 응급처치를 중단하는 것은 위험합니다."}'::jsonb, '[{"term_ko": "응급상황", "term_vi": "Tình huống khẩn cấp", "def_ko": "응급 상황(한국어)", "def_vi": "Tình huống gấp rút(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1666, '14', '위기 상황에 대한 대처 방법으로 옳은 것은?', '["응급처치를 먼저 한 후에 119에 신고한다.", "갖고과 연락이 되지 않으면 응급처치를 미룬다.", "대상자가 명료하게 대답을 했어도 119에 신고한다.", "119에 신고 시 보호자의 연락처, 가족 정보를 알려준다.", "심한 통증을 호소하면 전문적인 치료가 필요하다고 판단한다."]'::jsonb, 5, NULL, NULL, '{"1": "응급처치는 상황에 따라 다르게 적용되며, 즉시 신고가 우선될 수 있습니다.\n[정답]", "2": "응급처치는 반드시 진행해야 하며 연락이 되지 않더라도 미룰 수 없습니다.", "3": "대상자가 명료하게 대답했다고 하더라도, 그 응급 상황의 심각성을 고려해 119에 신고해야 합니다.", "4": "119에 신고할 때는 보호자의 연락처와 가족 정보가 중요하므로 꼭 알려줘야 합니다.", "5": "심한 통증이 있을 경우 전문적인 치료를 요구할 수 있으니 이를 반드시 인지해야 합니다."}'::jsonb, '[{"term_ko": "위기", "term_vi": "Tình huống khẩn cấp", "def_ko": "위기 상황(상급의 문제나 심각한 상황)", "def_vi": "Tình huống nghiêm trọng hoặc vấn đề cấp bách"}, {"term_ko": "응급처치", "term_vi": "Sơ cứu", "def_ko": "즉각적으로 처리하는 치료", "def_vi": "Điều trị ngay lập tức"}, {"term_ko": "신고하다", "term_vi": "Báo cáo", "def_ko": "공식적으로 알리는 것", "def_vi": "Thông báo chính thức"}, {"term_ko": "통증", "term_vi": "Đau", "def_ko": "신체의 고통", "def_vi": "Đau đớn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1665, '14', '의학적 위기상황에 대한 대처 방법으로 옳은 것은?', '["가장 먼저 가족 또는 기관장에게 보고한다.", "119에 신고를 했다면 전화를 끊고 응급처치를 한다.", "신고를 해야 할지 고민이 되는 상황이라면 신고한다.", "호흡이나 맥박이 정상적이어도 119에 신고한다.", "상황이 종료되었다면 기록은 작성하지 않아도 된다."]'::jsonb, 3, NULL, NULL, '{"1": "일반적으로는 지금 당장 대처하는 것이 먼저지만, 위기상황에서도 가족 또는 기관장에게 즉시 보고하는 것은 종종 중요합니다.\n[정답]", "2": "응급처치를 즉시 시행해야 하며, 신고 후 응급처치가 이어져야 합니다.", "3": "신고가 필요한 상황이라면 반드시 신고해야 하며, 고민할 시간이 없습니다.", "4": "정상적인 호흡이나 맥박이 확인되더라도, 안전을 위해 신고하는 것이 중요합니다.", "5": "상황이 종료된 후에는 반드시 기록을 남겨야 하며, 기록에 대한 의무가 있습니다."}'::jsonb, '[{"term_ko": "의학적", "term_vi": "Y học", "def_ko": "의학에 관한", "def_vi": "Liên quan đến y học"}, {"term_ko": "위기상황", "term_vi": "Tình huống khẩn cấp", "def_ko": "심각한 상황", "def_vi": "Tình huống nghiêm trọng"}, {"term_ko": "대처", "term_vi": "Xử lý", "def_ko": "문제를 해결하기 위한 행위", "def_vi": "Hành động để giải quyết vấn đề"}, {"term_ko": "응급처치", "term_vi": "Sơ cứu", "def_ko": "응급 상황에서 시행하는 치료", "def_vi": "Điều trị trong tình huống khẩn cấp"}, {"term_ko": "보고", "term_vi": "Báo cáo", "def_ko": "상황을 알리는 행위", "def_vi": "Hành động thông báo"}, {"term_ko": "기록", "term_vi": "Ghi chép", "def_ko": "사건이나 상황을 남기는 것", "def_vi": "Việc ghi lại sự kiện hoặc tình huống"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1664, '14', '다음 중 의학적 위기 상황으로 응급처치를 실시해야 하는 상황은?', '["호흡이 안정적일 때", "기침이 자주나올 때", "맥박이 강하게 뛸 때", "의식의 변화가 있을 때", "전신에 피로를 느낄 때"]'::jsonb, 4, NULL, NULL, '{"1": "호흡이 안정적이라는 것은 위기 상황이 아님을 나타냅니다.", "2": "기침이 자주 나온다고 해서 즉각적인 응급처치가 필요한 상황은 아닙니다. \n[정답]", "3": "맥박이 강하게 뛰는 것은 상황에 따라 다르지만, 반드시 응급처치가 필요한 것은 아닙니다.", "4": "의식의 변화가 있으면 즉각적인 응급처치가 필요합니다.", "5": "전신에 피로를 느낀다고 해서 응급처치가 필요한 상황은 아닙니다."}'::jsonb, '[{"term_ko": "의학적", "term_vi": "Y học", "def_ko": "의학과 관련된", "def_vi": "Liên quan đến y học"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1663, '13', '호스피스, 완화의료 서비스에 대한 설명으로 옳은 것은?', '["말기질환을 가진 환자에게만 제공되는 의료서비스이다.", "만성폐쇄성 호흡기 질호나자는 입원형 이용이 가능하다.", "자문형은 자택으로전문인력이 방문하여 서비스를 제공한다.", "만성 간경화 환자는 자문형 서비스를 이용할 수 있다.", "입원형은 가정에서 돌보기 어려운 노인을 대상으로 한다."]'::jsonb, 4, NULL, NULL, '{"1": "호스피스는 말기환자에게 뿐만 아니라 다양한 상태의 환자에게 제공될 수 있는 서비스입니다.\n[정답]", "2": "만성폐쇄성호흡기질환(COPD) 환자는 입원형 서비스를 이용할 수 있습니다.", "3": "자문형 서비스는 자택에서 제공되는 것이 맞지만, 전문 인력이 방문하는 형태는 맞지만 자문형으로만 한정될 수 없습니다.", "4": "만성 간경화 환자는 자문형 서비스를 이용할 수 있습니다.", "5": "입원형 서비스는 가정에서 돌보기 어려운 환자를 위한 서비스입니다."}'::jsonb, '[{"term_ko": "호스피스", "term_vi": "Chăm sóc giảm nhẹ", "def_ko": "말기환자에게 제공되는 의료 및 정서적 지원 서비스", "def_vi": "Dịch vụ hỗ trợ y tế và tinh thần dành cho bệnh nhân giai đoạn cuối"}, {"term_ko": "완화의료", "term_vi": "Y tế giảm nhẹ", "def_ko": "환자의 고통을 줄이고 삶의 질을 향상시키기 위한 의료", "def_vi": "Y tế nhằm giảm nhẹ nỗi đau và cải thiện chất lượng cuộc sống của bệnh nhân"}, {"term_ko": "입원형", "term_vi": "Hình thức nhập viện", "def_ko": "병원에서 제공되는 형태", "def_vi": "Hình thức cung cấp dịch vụ tại bệnh viện"}, {"term_ko": "자문형", "term_vi": "Hình thức tư vấn", "def_ko": "전문가가 환자의 집으로 방문하여 제공하는 서비스", "def_vi": "Dịch vụ được cung cấp qua việc chuyên gia đến thăm nhà bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1662, '13', '호스피스, 완화의료 이용에 대한 설명으로 옳은 것은?', '["국내에서는 입원형 서비스만 제공한다.", "치료 가능한 말기질환을 가진 환자와 가족을 대상으로 한다.", "후천성면역결핍증 환자는 입원형 서비스를 이용할 수 있다.", "가정형은 외래진료를 보듯이 환자가 방문하는 형태이다.", "통증, 신체적, 심리적, 영적 고통을 완화하여 삶의 질을 향상시키는 의료서비스이다."]'::jsonb, 5, NULL, NULL, '{"1": "국내에서는 입원형 서비스만 제공한다. (잘못된 설명으로, 국내에서는 가정형 호스피스 서비스도 제공된다.)\n[정답]", "5": "통증, 신체적, 심리적, 영적 고통을 완화하여 삶의 질을 향상시키는 의료서비스이다. (옳은 설명으로, 호스피스의 주요 목적이기도 하다.)", "3": "후천성면역결핍증 환자는 입원형 서비스를 이용할 수 있다. (옳지 않은 설명으로, 호스피스는 일단 치료가 불가능한 상태에서 제공된다.)", "4": "가정형은 외래진료를 보듯이 환자가 방문하는 형태이다. (잘못된 설명으로, 가정형 호스피스는 환자가 집에서 받는 서비스이다.)", "2": "치료 가능한 말기질환을 가진 환자와 가족을 대상으로 한다. (잘못된 설명으로, 호스피스는 치료가 불가능한 말기환자를 대상으로 한다.)"}'::jsonb, '[{"term_ko": "호스피스", "term_vi": "Chăm sóc giảm nhẹ", "def_ko": "환자의 마지막 단계를 지원하는 의료 서비스", "def_vi": "Dịch vụ y tế hỗ trợ bệnh nhân ở giai đoạn cuối"}, {"term_ko": "완화의료", "term_vi": "Chăm sóc giảm nhẹ", "def_ko": "치료가 불가능한 환자의 고통을 줄이는 의료", "def_vi": "Y tế nhằm giảm bớt khổ sở"}, {"term_ko": "입원형", "term_vi": "Nhập viện", "def_ko": "병원에 누워 치료를 받는 형태", "def_vi": "Hình thức điều trị tại bệnh viện"}, {"term_ko": "가정형", "term_vi": "Hỗ trợ tại nhà", "def_ko": "집에서 치료를 받는 형태", "def_vi": "Dịch vụ y tế tại nhà"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1661, '13', '사전연명의료의향서에 대한 설명으로 옳은 것은?', '["말기환자나 임종과정에 있는 사람만 작성할 수 있다.", "사전연명의료의향서 등록기관에 등록해야만 효력이 생긴다.", "등록 후에는 내용을 변경, 철회할 수 없다.", "등록기관에 등록하면 모든 의료기관에 자동 연동된다.", "통증완화를 위한 의료행위와 영양분 및 물 공급을 중단한다."]'::jsonb, 2, NULL, NULL, NULL, NULL) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1660, '13', '다음 중에서 사전연명의료의향서의 효력이 발생하는 경우는?', '["17세 청소년이 자발적 의사로 직접 작성한 경우", "30세 위암 환자의 부탁으로 가족이 작성한 경우", "65세 대장암 환자가 자발적으로 요청한 경우", "70세 노인의 요청에 따라 담당 의사가 작성한 경우", "80세 뇌졸중 환자의 요양보호사가 대리로 작성한 경우"]'::jsonb, 3, NULL, NULL, '{"1": "17세 청소년은 법적으로 자율적인 의사결정 능력이 부족하여 효력이 인정되지 않습니다.\n[정답]", "3": "65세 대장암 환자가 자발적으로 요청한 경우, 법적으로 유효한 사전연명의료의향서로 인정됩니다.", "2": "30세 위암 환자의 부탁으로 가족이 작성한 경우, 본인의 자발적 의사에 따른 것이 아니므로 효력이 없습니다.", "4": "70세 노인의 요청에 따라 담당 의사가 작성한 경우, 법적 효력을 갖기 위해서는 환자가 자발적으로 작성해야 합니다.", "5": "80세 뇌졸중 환자의 요양보호사가 대리로 작성한 경우, 대리 작성은 법적으로 인정되지 않으므로 효력이 없습니다."}'::jsonb, '[{"term_ko": "사전연명의료의향서", "term_vi": "Văn bản nguyện vọng chăm sóc y tế trước", "def_ko": "사전의료의향서(한국어)", "def_vi": "Văn bản ý muốn chăm sóc y tế được lập trước (베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1659, '13', '시설 대상자가 요양보호사에게 사전연명의료의향서를 대신 작성해 달라고 할 때 반응으로 옳은 것은?', '["\"시설에 오기 전에 작성했어야 합니다.\"", "\"시설장과 상의해서 작성해야만 합니다.\"", "\"잔여ㅢ동의가 있어야 작성할 수 있습니다.\"", "\"어르신이 직접 작성하는 것이 원칙입니다.\"", "\"작성과 동시에 효력이 발생하여 신중하셔야 합니다.\""]'::jsonb, 4, NULL, NULL, '{"1": "시설에 오기 전에 혼자서 결정하고 작성해야 한다는 의미의 발언으로 공감과 이해를 도와주지 못한다.", "2": "시설장과의 논의는 필요하나, 직접 작성해야 한다는 원칙은 변하지 않는다.", "3": "잔여 동의가 필요하다는 것은 잘못된 정보로, 어르신의 의사에 따라 작성할 수 있다.\n[정답]", "4": "어르신이 직접 작성하는 것이 원칙으로, 요양보호사는 이에 대해 지원할 수 있으며, 직접 작성하는 것을 권장한다.", "5": "작성과 동시에 효력이 발생하는 것이 아니라, 어르신의 의사를 반영하는 것이 우선시 되어야 한다."}'::jsonb, '[{"term_ko": "사전연명의료의향서", "term_vi": "Tài liệu ý kiến y tế trước", "def_ko": "의사가 환자의 의사를 존중하여 생명유지 치료에 대한 권리를 정하는 문서", "def_vi": "Tài liệu xác định quyền của bệnh nhân về việc điều trị duy trì sự sống"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1658, '13', '사전연명의료의향서에 관한 설명으로 옳은 것은?서', '["65세가 되어야 작성할 수 있다.", "본인이 직접 작성하지 않은 경우 효력이 없다.", "작성한 후 병, 의원 어디서나 등록할 수 있다.", "연명의료중단 시 물과 영양분 공급이 중단된다.", "작성자가 글씨를 쓸 수 없는 경우에는 사전연명의료의향서를 작성할 수 없다."]'::jsonb, 2, NULL, NULL, '{"1": "65세가 아닌, 성인이면 누구나 작성할 수 있다. \n[정답]", "2": "본인이 직접 작성해야 효력이 있다.", "3": "등록은 보건소에 해야 하며, 병의원에서는 등록할 수 없다.", "4": "연명의료중단 시 물과 영양분 공급은 계속 유지된다.", "5": "작성자가 글씨를 쓸 수 없더라도 대리인이 작성할 수 있다."}'::jsonb, '[{"term_ko": "사전연명의료의향서", "term_vi": "Giấy chỉ đạo y tế trước khi chết", "def_ko": "사전으로 고안된 의료 지침서", "def_vi": "Tài liệu chỉ đạo y tế đã được lập trước"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1657, '13', '말기 암환자가 사전연명의료의향서를 작성하면 치료가 어떻게 되는지 물을 때 요양 보호사의 반응으로 옳은 것은?', '["\"모든 치료가중단됩니다.\"", "\"혈액투석은 계속 진행됩니다.\"", "\"항암제 치료는 의사가 판단하여 결정합니다.\"", "\"통증완화를 위한 진통제와 물은 계속 공급됩니다.\"", "\"인공호흡기 치료는 비용을 부담하면 계속할 수 있습니다.\""]'::jsonb, 4, NULL, NULL, '{"1": "치료 중단에 대한 설명은 과장된 부분이 있어 옳지 않습니다.\n[정답]", "4": "통증 완화를 위한 진통제와 기본적인 수분 공급은 계속 진행됩니다. 이는 환자의 편안함을 위해 중요합니다.", "2": "혈액 투석은 일반적으로 연명의료의향서와 관련이 없으므로 정확한 설명이 아닙니다.", "3": "항암제 치료는 환자의 상태와 의사의 판단에 따라 다르지만, 연명의료의향서에 따라 선택되지 않을 가능성이 높습니다.", "5": "인공호흡기 치료는 연명의료 포함에 따라 관리되므로 누락된 부분이 있습니다."}'::jsonb, '[{"term_ko": "말기", "term_vi": "Giai đoạn cuối", "def_ko": "말기의, 사람이 더 이상 회복되지 않는 단계", "def_vi": "Giai đoạn không thể phục hồi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1656, '13', '사전연명의료의향서''를 등록한 대상자가 임종과정에 있을 때 제공 받을 수 있는 것은?', '["혈액 투석", "산소 공급", "심폐소생술", "항암제 투여", "혈압상승제 투여"]'::jsonb, 2, NULL, NULL, '{"1": "혈액 투석은 임종과정에서 생명을 연장하기 위한 방법으로 간주되며, 사전연명의료의향서의 적용을 받지 않습니다.\n[정답]", "2": "산소 공급은 호흡을 지원하기 위한 방법으로, 임종과정에 있을 때 필수적인 지원으로 제공될 수 있습니다.", "3": "심폐소생술은 생명 연장을 위한 조치를 포함하며, 일반적으로 사전연명의료의향서에서 배제됩니다.", "4": "항암제 투여는 체내의 암세포를 치료하기 위한 비즈니스적 접근으로, 임종과정에서 시행되지 않습니다.", "5": "혈압상승제 투여는 환자의 생명을 연장하기 위한 치료의 일환으로 간주되어 제공되지 않습니다."}'::jsonb, '[{"term_ko": "사전연명의료의향서", "term_vi": "Hồ sơ ý chí chăm sóc y tế trước", "def_ko": "환자가 자신의 연명치료에 대한 의사를 사전에 밝히는 문서", "def_vi": "Tài liệu mà bệnh nhân công bố ý chí của mình về điều trị sự sống trước"}, {"term_ko": "임종과정", "term_vi": "Quá trình cuối đời", "def_ko": "생명이 끝나는 과정", "def_vi": "Quá trình mà cuộc sống kết thúc"}, {"term_ko": "산소 공급", "term_vi": "Cung cấp oxy", "def_ko": "호흡을 지원하는 행위", "def_vi": "Hành động hỗ trợ hô hấp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1655, '13', '임종과정에 있는 환자에게 심폐소생술, 혈액 투석, 항암제 투여, 인공 호흡기 착용 등 치료효과 없이 임종과정의 기간만을 연장하는 의학적 시술에 대한 의사결정을 하는 것은?', '["임종", "심폐소생술", "사전연명의료의향서", "호스피스", "완화의료"]'::jsonb, 3, NULL, NULL, '{"1": "임종: 생명이 다하는 과정으로 더 이상 치료가 필요하지 않는 상태입니다.", "2": "심폐소생술: 심장이 멈추거나 호흡이 멈춘 환자에게 실시하는 응급 처치입니다.\n[정답]", "3": "사전연명의료의향서: 환자의 의사를 미리 문서화하여 치료를 받지 않겠다는 의사를 표현하는 서류입니다.", "4": "호스피스: 말기 환자를 위한 전문적인 의료 서비스로 편안한 죽음을 도와주는 프로그램입니다.", "5": "완화의료: 생명을 위협하는 질병의 고통을 경감시키기 위한 치료를 의미합니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Im dong", "def_ko": "생명이 다하는 과정", "def_vi": "Quá trình khi sự sống kết thúc"}, {"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "심장이 멈추거나 호흡이 멈춘 환자에게 실시하는 응급 처치", "def_vi": "Can thiệp khẩn cấp cho bệnh nhân khi tim hoặc hơi thở ngừng lại"}, {"term_ko": "사전연명의료의향서", "term_vi": "Giấy quyết định y tế trước", "def_ko": "환자의 의사를 미리 문서화하는 서류", "def_vi": "Tài liệu ghi lại ý kiến của bệnh nhân"}, {"term_ko": "호스피스", "term_vi": "Chăm sóc giảm nhẹ", "def_ko": "말기 환자를 위한 전문적인 의료 서비스", "def_vi": "Dịch vụ y tế chuyên nghiệp dành cho bệnh nhân giai đoạn cuối"}, {"term_ko": "완화의료", "term_vi": "Y tế giảm nhẹ", "def_ko": "생명을 위협하는 질병의 고통을 경감시키기 위한 치료", "def_vi": "Điều trị nhằm giảm bớt cơn đau"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1654, '13', '임종 대상자의 품위 유지를 위한 권리 중 잘못 된 것은?', '["치료를 거부할 권리", "고통으로부터 자유로울 권리", "사생활을 침해받지 않을 권리", "원하지 않은 사람을 만날 권리", "평화와 존엄 속에서 죽을 권리"]'::jsonb, 4, NULL, NULL, '{"1": "치료를 거부할 권리는 임종 대상자의 자율성을 존중하는 것임.\n[정답]", "4": "원하지 않은 사람을 만날 권리는 일반적으로 인정되지 않음.", "2": "고통으로부터 자유로울 권리는 환자의 기본적인 권리로 보장됨.", "3": "사생활을 침해받지 않을 권리는 환자의 프라이버시를 보호하는 권리임.", "5": "평화와 존엄 속에서 죽을 권리는 인간으로서의 기본적인 권리로 여겨짐."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối đời", "def_ko": "죽음을 앞둔 상태", "def_vi": "Trạng thái chuẩn bị cho cái chết"}, {"term_ko": "품위", "term_vi": "Dignity", "def_ko": "존엄성", "def_vi": "Nhân phẩm"}, {"term_ko": "권리", "term_vi": "Quyền", "def_ko": "권리", "def_vi": "Quyền"}, {"term_ko": "고통", "term_vi": "Đau đớn", "def_ko": "아픔", "def_vi": "Đau đớn"}, {"term_ko": "사생활", "term_vi": "Đời tư", "def_ko": "개인의 프라이버시", "def_vi": "Đời tư"}, {"term_ko": "침해", "term_vi": "Xâm phạm", "def_ko": "위반", "def_vi": "Xâm phạm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1653, '13', '임종 대상자의 가족을 돕는 방법으로 옳은 것은?', '["스스로를 잘 돌볼 수 있도록 격려한다.", "슬픈 감정을 억제하도록 돕는다.", "조용히 혼자있게 해준다.", "장례식에 참석하여 가족을 돕는다.", "가족을 대신하여 대상자의 유품을 정리한다."]'::jsonb, 1, NULL, NULL, '{"1": "스스로를 잘 돌볼 수 있도록 격려하는 것은 가족이 감정을 표현하고 스스로 회복할 수 있게 돕는 긍정적인 방법입니다.\n[정답]", "2": "슬픈 감정을 억제하도록 돕는 것은 오히려 가족의 감정 표현을 저해할 수 있어바람직하지 않습니다.", "3": "조용히 혼자 있게 해주는 것은 가족이 고립감을 느낄 수 있으므로 지원 방식으로 적절하지 않습니다.", "4": "장례식에 참석하여 가족을 돕는 것은 사회적 지지의 일환이지만, 주된 질문의 요지는 임종 대상자와의 관계에서의 도움을 강조하기 때문에 직접적 지원 방법으로 보기는 어렵습니다.", "5": "가족을 대신하여 대상자의 유품을 정리하는 것은 존중 부족으로 해석될 수 있습니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối", "def_ko": "생의 마지막 단계", "def_vi": "Giai đoạn cuối của cuộc sống"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1652, '13', '사별 전 가족 요양보호 방법으로 옳은 것은?', '["가족 외 다른 사람의 만남을 제한한다.", "대상자가하는 모든 말을 가족에게 전달하지 않는다.", "임종이 임박하면 가족에게 연락하여 응급실로 옮긴다.", "마음의 아픔을 들어주며 가족의 부족한 점은짚어준다.", "가족 중 생일이 있으면 케이크를 준비하여 함께 하게한다."]'::jsonb, 5, NULL, NULL, '{"1": "사별 전에는 가족의 심리적 안정을 위해 외부의 만남을 제한하는 것이 좋지 않다.\n[정답]", "2": "대상자가 하는 모든 말을 가족에게 전달하는 것이 가족의 의사소통을 늘리고 감정적인 지지를 제공한다.", "3": "임종이 임박했을 때는 응급실로 옮기기보다는 가족이 곁에 있도록 도와주는 것이 중요하다.", "4": "마음의 아픔을 들어주고 가족의 부족한 점을 짚어주는 것은 중요한 과정이지만, 감정을 상하게 하지 않도록 주의해야 한다.", "5": "가족 중 생일이 있는 경우 케이크를 준비하여 함께 하는 것은 가족 간의 정서적 유대를 강화할 수 있는 좋은 방법이므로 옳다."}'::jsonb, '[{"term_ko": "사별", "term_vi": "Ly hôn", "def_ko": "죽음으로 인한 가족과의 이별", "def_vi": "Chia tay do chết"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1651, '13', '임종이 임박한 대상자의 요양보호 방법으로 옳은 것은?', '["대상자의 의사결정을 배제한다.", "끝까지 회복할 수 있다는 희망을 준다.", "만나고 싶어하는 사람을 만나게 해준다.", "장례식에 관련해서는 가족과 상의 후 알려준다.", "요양보호사가 믿는 종교의 임종의식을 연결해준다."]'::jsonb, 3, NULL, NULL, '{"1": "대상자의 의사결정을 배제하는 것은 비윤리적이며, 대상자의 자율성을 존중해야 합니다.\n[정답]", "3": "임종이 임박한 대상자가 만나고 싶어하는 사람을 만나게 해주는 것은 정서적 지원을 제공하는 좋은 방법입니다.", "2": "끝까지 회복할 수 있다는 희망을 주는 것은 현실적이지 않을 수 있으며, 대상자의 상태에 따라 달라져야 합니다.", "4": "장례식에 관한 사항은 가족과 상의 후에 알려줘야 하며, 대상자에게 혼란을 줄 수 있습니다.", "5": "요양보호사가 믿는 종교의 임종의식을 연결하는 것은 개인의 신념에 따라 다르므로, 대상자의 의사를 확인해야 합니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Sự chết", "def_ko": "죽음에 가까운 상태", "def_vi": "Trạng thái gần cái chết"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1650, '13', '임종이 가까워지는 대상자가 주위 사람들에 대해 혼돈을 느낄 때 돕기 방법은?', '["대상자 혼자 있게 한다.", "가족 사진을 머리맡에 둔다.", "담요를 두껍게 덮어준다.", "움직이지 못하게 억제한다.", "따뜻한 물로 목욕을 시킨다."]'::jsonb, 2, NULL, NULL, '{"1": "대상자가 혼자 있게 하는 것은 혼란을 가중시킬 수 있어 바람직하지 않습니다.\n[정답]", "2": "가족 사진을 머리맡에 두면 대상자가 안심하고 안정감을 느낄 수 있습니다.", "3": "담요를 두껍게 덮어주는 것은 편안함을 줄 수 있으나 혼돈을 해소하는 데 직접적인 도움이 되지는 않습니다.", "4": "움직이지 못하게 억제하는 것은 대상자의 불안감을 더욱 증가시킬 수 있습니다.", "5": "따뜻한 물로 목욕시키는 것은 신체적 편안함을 줄 수 있지만 혼란 상태에 대한 도움은 부족합니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối đời", "def_ko": "세상을 떠나는 단계", "def_vi": "Giai đoạn sắp chết"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1649, '13', '임종을 앞둔 대상자의 호흡수와 호흡의 깊이가 불규칙할 때 대처방법은?', '["보온을 해준다.", "물을 먹인다.", "몸을 흔들어 준다.", "가습기를 약하게 켜둔다.", "머리를 낮게 내려준다."]'::jsonb, 4, NULL, NULL, '{"1": "보온을 해주는 것은 중요하지만 호흡수와 깊이가 불규칙할 때는 다른 대처가 필요합니다.\n[정답]", "4": "가습기를 약하게 켜두면 호흡을 도와주는 역할을 합니다.", "3": "몸을 흔들어 주는 것은 적절한 방법이 아닙니다.", "2": "물을 먹이는 것은 적절하지 않으며, 위험할 수 있습니다.", "5": "머리를 낮게 내려주는 것은 호흡에 도움이 되지 않습니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Sắp tử vong", "def_ko": "죽음을 앞둔 상태", "def_vi": "Trạng thái sắp chết"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1648, '13', '임종 단계에 있는 대상자의 신체, 정신적 변화에 대한 대처 방법은?', '["체온유지를 위해 전기담요를 덮어준다.", "무의식 상태이면 구강관리를 따로 하지 않는다.", "음식이나 수분 섭취를 강요하지 않는다.", "혼돈 시에는 ''내가 누구냐''고 물어본다.", "대상자가 반응하지 않으면 말하지 않는다"]'::jsonb, 3, NULL, NULL, '{"1": "체온유지를 위해 전기담요를 덮어주는 것은 과열의 위험이 있어 적절하지 않습니다.\n[정답]", "3": "음식이나 수분 섭취를 강요하지 않는 것은 임종 환자의 편안함을 유지하는 데 중요합니다.", "2": "무의식 상태일 때 구강관리를 따로 하지 않는 것은 일반적으로 맞지만, 구강 위생을 고려할 필요가 있습니다.", "4": "혼돈 상태에서는 환자를 더 혼란스럽게 할 수 있으므로, 적절한 질문을 피하는 것이 좋습니다.", "5": "대상자가 반응하지 않는 경우 대화를 하지 않는 것은 바람직하지 않지만, 환자의 상태에 따라 다를 수 있습니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối đời", "def_ko": "죽음을 앞둔 상태", "def_vi": "Trạng thái sắp qua đời"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1647, '13', '임종이 임박한 대상자에게 나타나는 신체적 변화로 옳은 것은?', '["수면시간 감소", "체온의 상승", "소변량 증가", "변실금 증가", "근긴장도 증가"]'::jsonb, 4, NULL, NULL, '{"1": "수면시간 감소는 일반적으로 임종기 환자에게 나타나는 변화입니다.\n[정답]", "4": "변실금 증가는 임종이 가까운 환자에서 흔하게 나타나는 변화입니다.", "2": "체온의 상승은 일반적으로 임종기 환자에게 나타나지 않고 오히려 저하되는 경향이 있습니다.", "3": "소변량 증가는 수분 섭취량과 관련이 있으며, 임종기 환자에서는 보통 소변량이 감소합니다.", "5": "근긴장도는 임종이 임박할수록 감소하는 경향이 있습니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối", "def_ko": "죽음의 직전 단계", "def_vi": "Giai đoạn gần cái chết"}, {"term_ko": "변실금", "term_vi": "Tiểu tiện không kiểm soát", "def_ko": "대변을 조절하지 못하는 상태", "def_vi": "Tình trạng không kiểm soát được việc đại tiểu tiện"}, {"term_ko": "수면시간", "term_vi": "Thời gian ngủ", "def_ko": "잠자는 동안의 시간", "def_vi": "Thời gian trong khi ngủ"}, {"term_ko": "체온", "term_vi": "Nhiệt độ cơ thể", "def_ko": "몸의 온도", "def_vi": "Nhiệt độ của cơ thể"}, {"term_ko": "소변량", "term_vi": "Lượng nước tiểu", "def_ko": "배출되는 소변의 양", "def_vi": "Lượng nước tiểu được thải ra"}, {"term_ko": "근긴장도", "term_vi": "Độ căng cơ", "def_ko": "근육의 긴장 상태", "def_vi": "Trạng thái căng cơ của cơ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1646, '13', '임종과정 동안에 나타나는 신체변화에 대한 요양보호로 옳은 것은?', '["실금하면 침상변기를 대준다.", "몸이 차가워지면 담요를 덮어준다.", "수면상태가 길어지면 흔들어 깨운다.", "가래가 축적되면 침상머리를 낮춘다.", "착용하고 있는 기저귀를 제거한다."]'::jsonb, 2, NULL, NULL, '{"1": "실금은 자연스러운 과정으로, 침상변기를 제공해주는 것이 좋지만 항상 적절한 방법은 아닙니다.\n[정답]", "2": "몸이 차가워지는 경우에는 담요를 덮어주는 것이 적합합니다.", "3": "수면 상태가 길어질 경우에는 흔들어 깨우기보다는 편안하게 두는 것이 바람직합니다.", "4": "가래가 축적되면 침상머리를 높여야 기도를 유지하는 데 도움이 됩니다.", "5": "기저귀는 필요한 경우 착용해야 하므로 무조건 제거하는 것은 적절하지 않습니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối đời", "def_ko": "생의 마지막 단계", "def_vi": "Giai đoạn cuối của cuộc sống"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1645, '13', '임종과정 동안 나타나는 대상자의 증상으로 옳은 것은?', '["혈액순환이 빨라진다.", "호흡이 규칙적이다.", "수분섭취와 소변량이 많아진다.", "무호흡과 깊고 빠른 호흡이 교대로 나타난다.", "식은땀을 흐리며 맥박이 강해진다."]'::jsonb, 4, NULL, NULL, '{"1": "혈액순환이 빨라진다. - 일반적으로 임종 과정에서는 혈액순환이 둔화되는 경향이 있어 이 선택지는 옳지 않습니다.", "2": "호흡이 규칙적이다. - 임종 직전에는 호흡이 불규칙해지는 경우가 많아 이 선택지도 옳지 않습니다.", "3": "수분섭취와 소변량이 많아진다. - 임종에는 수분섭취가 줄어들고 소변량도 감소하는 경향이 있어 이 선택지도 옳지 않습니다.\n[정답]", "4": "무호흡과 깊고 빠른 호흡이 교대로 나타난다. - 임종 과정에서는 무호흡과 불규칙한 호흡이 빈번하게 나타납니다.", "5": "식은땀을 흐리며 맥박이 강해진다. - 임종에는 보통 맥박이 약해지고 불규칙해지는 경우가 많아 이 선택지도 옳지 않습니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn sắp chết", "def_ko": "죽음에 가까워지는 상태", "def_vi": "Trạng thái gần chết"}, {"term_ko": "호흡", "term_vi": "Hơi thở", "def_ko": "공기를 들이마시고 내보내는 행위", "def_vi": "Hành động hít và thở"}, {"term_ko": "무호흡", "term_vi": "Ngừng thở", "def_ko": "숨을 쉬지 못하는 상태", "def_vi": "Trạng thái không thở"}, {"term_ko": "소변량", "term_vi": "Lượng nước tiểu", "def_ko": "배출되는 소변의 양", "def_vi": "Lượng nước tiểu được thải ra"}, {"term_ko": "식은땀", "term_vi": "Mồ hôi lạnh", "def_ko": "차가운 땀", "def_vi": "Mồ hôi lạnh"}, {"term_ko": "맥박", "term_vi": "Mạch", "def_ko": "혈액이 심장에서 나오는 박동", "def_vi": "Nhịp tim"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1644, '13', '임종 대상자를 도울 때 마지막까지 남아 있는 감각을 고려하여 돕는 방법은?', '["손을 잡아 준다.", "조명을 밝게 켜 둔다.", "가족사진을 보여 준다.", "즐겨 듣던 음악을 들려준다.", "좋아하는 아로마 향을 맡게 한다."]'::jsonb, 4, NULL, NULL, '{"1": "손을 잡아 주는 것은 정서적 지지를 줄 수 있지만, 감각적으로 가장 효과적이지 않습니다.\n[정답]", "4": "즐겨 듣던 음악을 들려주는 것은 청각을 자극하여 임종 대상자에게 안정과 평화를 줄 수 있습니다.", "2": "조명을 밝게 켜 두는 것은 오히려 불편함을 줄 수 있습니다.", "3": "가족사진을 보여 주는 것은 시각적 자극을 줄 수 있으나, 청각보다 중요한 감각이 아닙니다.", "5": "좋아하는 아로마 향을 맡게 하는 것은 후각을 자극하지만, 음악과 비교할 때 임종 대상자에게 더 큰 안정감을 주지 못할 수 있습니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối đời", "def_ko": "죽음을 준비하는 마지막 단계", "def_vi": "Giai đoạn chuẩn bị cho cái chết"}, {"term_ko": "감각", "term_vi": "Cảm giác", "def_ko": "외부 세계를 인식하는 능력", "def_vi": "Khả năng nhận biết thế giới bên ngoài"}, {"term_ko": "음악", "term_vi": "Âm nhạc", "def_ko": "소리로 이루어진 예술", "def_vi": "Nghệ thuật bằng âm thanh"}, {"term_ko": "아로마", "term_vi": "Hương liệu", "def_ko": "향기로운 물질", "def_vi": "Chất có mùi thơm"}, {"term_ko": "가족사진", "term_vi": "Ảnh gia đình", "def_ko": "가족의 사진", "def_vi": "Hình ảnh của gia đình"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1643, '13', '임종 시 마지막까지 남아 있는 감각기관은?', '["후각", "청각", "시각", "촉각", "미각"]'::jsonb, 2, NULL, NULL, '{"1": "후각: 후각은 임종 시에도 일부 기능이 남아 있을 수 있으나, 일반적으로 청각보다 오래 남아있지 않습니다.\n[정답]", "2": "청각: 임종 시 청각은 가장 마지막까지 남아 있는 감각기관으로 알려져 있습니다.", "3": "시각: 시각은 종종 임종과 함께 소실됩니다.", "4": "촉각: 촉각도 임종 시 느껴질 수 있지만, 청각보다는 먼저 소실되는 경향이 있습니다.", "5": "미각: 미각은 임종 시 매우 약화됩니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối", "def_ko": "죽음의 직전 단계", "def_vi": "Giai đoạn trước khi chết"}, {"term_ko": "감각기관", "term_vi": "Cơ quan cảm giác", "def_ko": "오감의 기능을 담당하는 기관", "def_vi": "Cơ quan đảm nhận chức năng của năm giác quan"}, {"term_ko": "청각", "term_vi": "Thính giác", "def_ko": "소리를 인식하는 능력", "def_vi": "Khả năng nhận biết âm thanh"}, {"term_ko": "후각", "term_vi": "Khứu giác", "def_ko": "냄새를 인식하는 능력", "def_vi": "Khả năng nhận biết mùi"}, {"term_ko": "시각", "term_vi": "Thị giác", "def_ko": "빛과 색을 인식하는 능력", "def_vi": "Khả năng nhận biết ánh sáng và màu sắc"}, {"term_ko": "촉각", "term_vi": "Xúc giác", "def_ko": "접촉을 감지하는 능력", "def_vi": "Khả năng cảm nhận tiếp xúc"}, {"term_ko": "미각", "term_vi": "Vị giác", "def_ko": "맛을 인식하는 능력", "def_vi": "Khả năng nhận biết hương vị"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1642, '13', '임종 대상자가 시간과 장소를 혼동하고 주위에 있는 사람을 알아보지 못할 때 돕는 방법은?', '["동작을 못하게 억제한다.", "큰 소리로 반복 질문을 한다.", "손을 잡아 흔들어 깨운다.", "대상자를 의식하지 않고 가족과 대화한다.", "서비스를 제공하기 전에 요양보호사임을 알린다."]'::jsonb, 5, NULL, NULL, '{"1": "동작을 못하게 억제하는 것은 오히려 대상자의 불안감을 증가시킬 수 있습니다.\n[정답]", "2": "큰 소리로 반복 질문하기 보다는 부드러운 토론이 필요합니다.", "3": "손을 잡아 흔들어 깨우는 행동은 대상자에게 스트레스를 줄 수 있습니다.", "4": "대상자를 의식하지 않고 가족과 대화하는 것은 대상자의 고립감을 초래할 수 있습니다.", "5": "서비스를 제공하기 전에 요양보호사임을 알리는 것은 신뢰를 형성하는 데 도움이 됩니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối", "def_ko": "죽음에 가까운 상태", "def_vi": "Tình trạng gần chết"}, {"term_ko": "혼동", "term_vi": "Nhầm lẫn", "def_ko": "헷갈림", "def_vi": "Sự nhầm lẫn"}, {"term_ko": "주위", "term_vi": "Xung quanh", "def_ko": "주변", "def_vi": "Môi trường xung quanh"}, {"term_ko": "알아보다", "term_vi": "Nhận ra", "def_ko": "인식하다", "def_vi": "Nhận thức"}, {"term_ko": "신뢰", "term_vi": "Tin tưởng", "def_ko": "믿음", "def_vi": "Niềm tin"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1641, '13', '임종이 임박한 대상자의 증상으로 옳은 것은?', '["눈의 초점이 뚜렷하다.", "피부색이 점차 붉게 변한다.", "동공의 크기가 작아진다.", "항문이 열리고 실변을 한다.", "자극에 민감하게 반응한다."]'::jsonb, 4, NULL, NULL, '{"1": "눈의 초점이 뚜렷하다: 일반적으로 임종 시 초점이 흐려진다.", "2": "피부색이 점차 붉게 변한다: 보통 피부색은 창백해지거나 청색증이 나타난다.\n[정답]", "3": "동공의 크기가 작아진다: 임종 시에는 동공이 확장되거나 반응이 둔해진다.", "4": "항문이 열리고 실변을 한다: 임종 시의 일반적인 증상으로 심리적 압박에 따라 나타날 수 있다.", "5": "자극에 민감하게 반응한다: 임종 시 자극에 대한 반응이 둔화된다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối", "def_ko": "죽음에 가까운 상태", "def_vi": "Trạng thái gần chết"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1640, '13', '임종이 임박하였을 때 나타나는 증상으로 옳은 것은?', '["식은땀이 멈춘다.", "대소변을 의식한다.", "맥박이 강해진다.", "촉각이 상승한다.", "동공이 확대된다."]'::jsonb, 5, NULL, NULL, '{"1": "식은땀은 일반적으로 임종의 증상이 아니다.\n[정답]", "5": "임종이 임박하면 동공이 확대되는 경우가 있다.", "2": "대소변을 의식하는 것은 일반적으로 임종이 임박한 환자에게서 나타나지 않는다.", "3": "맥박이 강해지는 것은 임종 시 일반적으로 관찰되지 않는다.", "4": "촉각이 상승하는 것은 보통 나타나지 않는 증상이다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối", "def_ko": "죽음을 앞두고 있는 상태", "def_vi": "Trạng thái trước khi chết"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "몸에서 나타나는 변화", "def_vi": "Sự thay đổi trong cơ thể"}, {"term_ko": "동공", "term_vi": "Đồng tử", "def_ko": "눈의 검은 부분", "def_vi": "Phần màu đen của mắt"}, {"term_ko": "맥박", "term_vi": "Nhịp tim", "def_ko": "심장 박동", "def_vi": "Đập của tim"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1639, '13', '임종이 임박하였을 때 나타나는 증상은?', '["손발이 따뜻해진다.", "혈압이 올라간다.", "의식이 뚜렷해진다.", "근육의 긴장도가 상승한다.", "호흡이 가쁘고 깊어진다."]'::jsonb, 5, NULL, NULL, '{"1": "손발이 차가워지는 현상이 일반적입니다.\n[정답]", "5": "호흡이 가쁘고 깊어지는 것은 임종이 임박했을 때의 전형적인 증상입니다.", "2": "혈압은 흔히 하락하는 경향이 있습니다.", "3": "의식은 점차 흐려지며 뚜렷해지지 않습니다.", "4": "근육의 긴장도는 보통 감소합니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Sự sống", "def_ko": "생명의 마지막 단계", "def_vi": "Giai đoạn cuối cùng của cuộc sống"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1638, '13', '임종 대상자와 가족에게 임종기 상담기술을 지원하는 방법은?', '["자신의 감정을 솔직하게 표현하도록 격려한다.", "가족의 결정에 의견을 제시하여 도움을 준다.", "죽음에 대한 애도의 감정을 참을 수 있게 도와준다.", "경험상 감정 정리는 빨리하는 것이 좋다고 알려준다.", "요양보호사가 신뢰하는 종교 지도자와 면담을 주선한다."]'::jsonb, 1, NULL, NULL, '{"1": "자신의 감정을 솔직하게 표현하도록 격려한다. 감정의 솔직한 표현은 치유의 첫걸음입니다.\n[정답]", "2": "가족의 결정에 의견을 제시하여 도움을 준다. 의견 제시는 지원이 아니라 간섭으로 비칠 수 있습니다.", "3": "죽음에 대한 애도의 감정을 참을 수 있게 도와준다. 애도의 감정은 자연스러운 것이므로 참을 필요는 없습니다.", "4": "경험상 감정 정리는 빨리하는 것이 좋다고 알려준다. 감정 정리는 개인의 필요에 따라 다르게 이루어져야 합니다.", "5": "요양보호사가 신뢰하는 종교 지도자와 면담을 주선한다. 신뢰하는 종교 지도자와의 면담이 해결책일 수 있지만, 요양보호사의 선택이 될 수는 없습니다."}'::jsonb, '[{"term_ko": "임종기", "term_vi": "Thời kỳ cuối đời", "def_ko": "죽음을 앞둔 시기", "def_vi": "Thời gian trước khi chết"}, {"term_ko": "상담기술", "term_vi": "Kỹ năng tư vấn", "def_ko": "문제를 해결하기 위한 대화 기법", "def_vi": "Kỹ thuật trò chuyện để giải quyết vấn đề"}, {"term_ko": "감정을 표현하다", "term_vi": "Thể hiện cảm xúc", "def_ko": "자신의 감정을 드러내다", "def_vi": "Biểu thị cảm xúc của bản thân"}, {"term_ko": "애도", "term_vi": "Tang tóc", "def_ko": "죽은 사람을 잃은 슬픔", "def_vi": "Nỗi buồn vì mất người đã chết"}, {"term_ko": "결정", "term_vi": "Quyết định", "def_ko": "선택 또는 선택지", "def_vi": "Lựa chọn hoặc lựa chọn"}, {"term_ko": "신뢰", "term_vi": "Tin tưởng", "def_ko": "믿다, 의지하다", "def_vi": "Tin vào, dựa vào"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1637, '13', '임종적응 단계 중 우울에 해당하는 것은?', '["아니야, 나는 믿을 수 없어", "왜 하필이면 나야. 왜 지금이야", "우리 아이가 시집갈 때 까지만 살게 해주세요.", "내가 살 수 없다니 너무 슬퍼", "나는 지쳤어"]'::jsonb, 4, NULL, NULL, '{"1": "이 선택지는 부정의 단계를 나타냅니다.", "2": "이 선택지는 분노의 단계를 나타냅니다.", "3": "이 선택지는 협상의 단계를 나타냅니다.\n[정답]", "4": "슬픔이 우울의 감정을 잘 나타내며, 임종적응 단계에서 중요한 부분입니다.", "5": "이 선택지는 탈진이나 무기력을 나타내므로 우울과 관련이 있습니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối", "def_ko": "죽음에 이르는 단계", "def_vi": "Giai đoạn dẫn đến cái chết"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1636, '13', '다음과 같이 말하는 췌장암 말기 대상자의 임종적응 단계는?"지쳤어. 지금껏 살면서 내가 할 일은 다했어. 자식들도 다 잘 살고 있고... 이만큼 살았으면 됐지 뭐"', '["부정", "분노", "타협", "우울", "수용"]'::jsonb, 5, NULL, NULL, '{"1": "부정: 자신이 죽음을 받아들이지 못하고, 현실을 부정하는 단계입니다.", "2": "분노: 죽음을 받아들이기 어려워 화를 내는 단계입니다.", "3": "타협: 자신의 상태에 대해 다른 사람과 거래하려는 단계입니다.", "4": "우울: 씁쓸함이나 무기력한 감정을 느끼는 단계입니다.\n[정답]", "5": "수용: 자신의 삶을 돌아보며 죽음을 수용하는 단계로, 대체로 평온한 마음 상태를 나타냅니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối đời", "def_ko": "죽음에 이르는 단계", "def_vi": "Giai đoạn dẫn đến cái chết"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1635, '13', '다음 설명에 해당하는 임종적응 단계는?"손주가 장가갈 때 까지만 살게 해주세요."라고 말한다. "삶이 얼마 간이라도 연장되기를 바란다.', '["부정", "타협", "수용", "분노", "우울"]'::jsonb, 2, NULL, NULL, NULL, NULL) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1634, '13', '다음 설명에 해당하는 임종적응 단계는?"나는 아니야, 왜 하필이면 나야!"라고 말하며 어디에서나 누구에게나 불만스러운 면만을 찾으려고 한다.', '["부정", "우울", "타협", "분노", "수용"]'::jsonb, 4, NULL, NULL, '{"1": "부정: 환자가 죽음을 받아들이지 못하고 부정을 표현하는 단계입니다.\n[정답]", "4": "분노: ''나는 아니야, 왜 하필이면 나야!''라는 태도가 분노를 나타내고 있습니다.", "2": "우울: 우울 단계는 슬픔이 가장 두드러지는 시기입니다.", "3": "타협: 환자가 상황을 받아들이기 위해 방법을 찾는 단계입니다.", "5": "수용: 죽음을 수용하고 준비하는 단계입니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối đời", "def_ko": "죽음에 다가가는 과정", "def_vi": "Quá trình đến cái chết"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1633, '12', '임종적응 단계에서 자신의 병을 인식하면서도 사실로 받아들이려 하지 않는 심리적 반응은?', '["부정", "분노", "타협", "우울", "수용"]'::jsonb, 1, NULL, NULL, '{"1": "부정: 자신의 병을 인식하면서도 사실로 받아들이려 하지 않는 심리적 반응이다.\n[정답]", "2": "분노: 자신의 상황에 대한 불만이나 분노를 표현하는 단계이다.", "3": "타협: 자신의 상태를 인정하지만, 어떤 조건을 통해 회복하려고 하는 단계이다.", "4": "우울: 상실감과 슬픔을 느끼는 단계이다.", "5": "수용: 자신의 병을 받아들이고, 상황을 수용하는 최종 단계이다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối đời", "def_ko": "죽음에 가까운 상태", "def_vi": "Trạng thái gần cái chết"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1632, '12', '중증 인지기능 장애 대상자의 기분을 전환하고 스트레스를 해소할 수 있는 인지자극훈련 활동은?', '["얼굴 삼행시", "탬버린 연주하기", "손가락 낭독회", "날짜 계산기", "뇌 건강 일기쓰기"]'::jsonb, 2, NULL, NULL, '{"1": "얼굴 삼행시는 창의력과 언어 능력을 자극하나, 인지기능 장애 대상자에게는 다소 어려울 수 있습니다.\n[정답]", "2": "탬버린 연주하기는 리듬 감각과 운동성을 자극하여 기분 전환 및 스트레스 해소에 효과적입니다.", "3": "손가락 낭독회는 청각적 자극이 필요하지만 모임의 형태로 인지자극 훈련을 하기에는 적합하지 않을 수 있습니다.", "4": "날짜 계산기는 인지기능에 도전할 수 있으나, 스트레스 해소 활동으로는 적합하지 않습니다.", "5": "뇌 건강 일기쓰기는 자기 반성을 통해 인지기능을 사용하나, 효과적인 기분 전환으로는 제한적입니다."}'::jsonb, '[{"term_ko": "중증", "term_vi": "인지기능", "def_ko": "심한 정도 / nặng nề", "def_vi": "인지 능력 / chức năng nhận thức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1631, '12', '치매 대상자를 위한 인지자극 훈련 방법으로 옳은 것은?', '["대상자에게 익숙한 물건을 버리고 새롭게 교체한다.", "기분이 좋고 집중을 잘하는시간에 활동을 배치한다.", "약속을 보호자가 모두 기억하여 그때마다 알려준다.", "아침잠이 많은 대상자를 이른 아침에 깨워 운동하게 한다.", "주방일을 해본 적 없는 대상자에게 요리관련 활동을 제안한다."]'::jsonb, 2, NULL, NULL, '{"1": "대상자에게 익숙한 물건을 버리는 것은 혼란을 초래할 수 있습니다.\n[정답]", "2": "기분이 좋고 집중이 잘 되는 시간에 활동을 배치하는 것은 인지자극 훈련에 효과적입니다.", "3": "약속을 보호자가 모두 기억하여 알려주는 것은 대상자의 자주성을 줄일 수 있어 좋지 않습니다.", "4": "아침잠이 많은 대상자를 이른 아침에 깨우는 것은 스트레스를 유발할 수 있습니다.", "5": "요리를 해본 적이 없는 대상자에게 요리관련 활동을 제안하는 것은 당사자의 실패 경험을 초래할 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억과 인지 기능의 저하", "def_vi": "Giảm khả năng ghi nhớ và nhận thức"}, {"term_ko": "인지자극", "term_vi": "Kích thích nhận thức", "def_ko": "인지 기능을 자극하고 개선하기 위한 활동", "def_vi": "Các hoạt động nhằm kích thích và cải thiện chức năng nhận thức"}, {"term_ko": "훈련 방법", "term_vi": "Phương pháp huấn luyện", "def_ko": "특정 기술이나 능력을 훈련하는 방법", "def_vi": "Cách để huấn luyện các kỹ năng hoặc khả năng nhất định"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1630, '12', '중증 인지기능 장애 대상자를 위한 바람직한 인지자극 훈련 방법은?', '["대상자의 컨디션에 맞게 활동을 제공한다.", "세탁 등 간단한 일상생활도 모두 도움을 준다.", "과거의 직업과 관련 없는 다양한 활동을 제안한다.", "문제행동이 관찰되면 적극적으로 지적하고 제지한다.", "인지장애가 심해 회복이 어려우면 프로그램에서 제외한다."]'::jsonb, 1, NULL, NULL, '{"1": "대상자의 컨디션에 맞게 활동을 제공하는 것은 인지자극 훈련에서 중요한 요소입니다.\n[정답]", "2": "세탁 등 간단한 일상생활에도 도움을 주는 것은 필요하지만, 인지 자극과는 거리가 있습니다.", "3": "과거의 직업과 관련 없는 다양한 활동은 효과적인 자극이 아니므로 바람직하지 않습니다.", "4": "문제행동이 관찰되면 적극적으로 지적하고 제지하는 것은 부정적인 경험을 초래할 수 있습니다.", "5": "인지장애가 심해 회복이 어려운 대상자를 프로그램에서 제외하는 것은 그들의 자존감에 악영향을 줄 수 있습니다."}'::jsonb, '[{"term_ko": "중증", "term_vi": "Nặng", "def_ko": "심각한 정도(한국어)", "def_vi": "Mức độ nghiêm trọng(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1629, '12', '경증 치매대상자가 다음과 같은 활동에 참여할 때 향상될 수 있는 인지기능은?과일가게에서 살 수 있는 것을 말해보기 도로 위를 달릴 수 있는 운송 기구 말하기', '["계산력", "통제력", "친화력", "순응력", "언어능력"]'::jsonb, 5, NULL, NULL, '{"1": "계산력: 수치나 양을 다루는 능력을 의미하지만, 이번 문제와는 관련이 적습니다.\n[정답]", "5": "언어능력: 과일가게에서 살 수 있는 것을 말해보기와 같은 활동을 통해 언어적 표현과 소통 능력이 향상될 수 있습니다.", "2": "통제력: 자신의 행동이나 감정을 조절하는 능력을 의미하지만, 질문에 적합하지 않습니다.", "3": "친화력: 타인과의 관계를 맺고 유지하는 능력이지만, 주어진 활동과의 연결성이 약합니다.", "4": "순응력: 사회적 규범에 따르는 능력을 의미하지만, 이 질문에서 요구하는 인지기능과는 무관합니다."}'::jsonb, '[{"term_ko": "경증", "term_vi": "Nhẹ", "def_ko": "가벼운 정도(한국어)", "def_vi": "Mức độ nhẹ(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1628, '12', '경증 인지기능 장애 대상자가 다음과 같은 활동으로 도움이 될 수 있는 것은?학용품 이름, 생선 가게에서 살 수 있는 것들 말하기 ''ㄱ''으로 시작하는 단어 말하기', '["창의적 사고력", "언어의 유창성", "감성적 표현능력", "다양한 억양 조절능력", "주의력 및 기억력 향상"]'::jsonb, 2, NULL, NULL, '{"1": "창의적 사고력은 문제 해결이나 새로운 아이디어 생성과 관련이 있습니다.\n[정답]", "2": "언어의 유창성은 단어를 유창하게 발화하는 능력으로, 본 문제에서 요구되는 활동에 적합합니다.", "3": "감성적 표현능력은 감정을 표현하는 데 도움이 되는 능력입니다.", "4": "다양한 억양 조절능력은 말의 억양을 조절하는 능력입니다.", "5": "주의력 및 기억력 향상은 주의 집중과 기억력 개선에 관한 내용입니다."}'::jsonb, '[{"term_ko": "경증", "term_vi": "Nhẹ", "def_ko": "가벼운 정도", "def_vi": "Mức độ nhẹ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1627, '12', '치매 대상에게 다음과 같은 인지훈련을 할 때 향상될 수 있는 주요인지기능은?책을 읽다가 숫자와 음이 같은 글자가 나오면 해당 숫자만큼 손가락으로 표시한다. -시장에 사(4)람들이 많이(2) 모여있다.', '["계산력", "표현력", "지남력", "기억력", "주의집중력"]'::jsonb, 5, NULL, NULL, '{"1": "계산력: 숫자를 사용하여 계산하는 능력으로, 책 읽기와는 관련성이 낮음.\n[정답]", "5": "주의집중력: 숫자와 음이 같은 글자를 찾고 손가락으로 표시하는 과정은 주의집중력을 요구하는 훈련임.", "3": "지남력: 장소나 시간의 인식을 포함하는 능력으로, 문제와는 무관함.", "4": "기억력: 과거의 정보 기억과 관련이 있으나, 문제의 훈련 내용과 연결되지 않음.", "2": "표현력: 언어나 감정을 표현하는 능력으로, 이훈련과는 관련이 없음."}'::jsonb, '[{"term_ko": "인지훈련", "term_vi": "Đào tạo nhận thức", "def_ko": "인지 기능을 향상시키기 위한 훈련", "def_vi": "Sự tập luyện nhằm cải thiện khả năng nhận thức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1626, '12', '치매 대상자에게 다음과 같은 인지자극 훈련을 할 때 향상될 수 있는 것은?신문, 드라마, 새로 만난 주변인을 선택하여 이름을 기입하고 얼굴의 특징과 연관지어 삼행시를 지어 적는다.', '["순응력", "계산력", "공감능력", "관리능력", "언어능력"]'::jsonb, 5, NULL, NULL, '{"1": "순응력은 타인의 요청이나 요구에 맞추는 능력으로, 직접적인 관련이 없다.\n[정답]", "5": "언어능력은 신문, 드라마, 주변인의 이름과 특징을 연관지어 삼행시를 작성하는 과정에서 개선될 수 있다.", "3": "공감능력은 주변인의 특징을 이해하고 연결짓는 데 필요하지만, 주된 향상 대상은 아니다.", "4": "관리능력은 인지자극 훈련과는 관련이 적고, 주로 일상적인 생활 기술과 관련된다.", "2": "계산력은 수치적 문제 해결과 관련이 있으며, 이 문제와 직접적인 연관이 없다."}'::jsonb, '[{"term_ko": "인지자극", "term_vi": "Kích thích nhận thức", "def_ko": "인지적 기능을 자극하여 개선하는 훈련", "def_vi": "Huấn luyện cải thiện chức năng nhận thức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1624, '12', '치매대상자의 지남력을 향상하기 위한 프로그램으로 옳은 것은?', '["달력 만들기", "악기 연주하기", "똑같이 그리기", "점선으로 옮겨 그리기", "여러 가지 단어 말하기"]'::jsonb, 1, NULL, NULL, '{"1": "달력을 제작함으로써 날짜 및 시간 개념을 인지하고 기억하는 데 도움을 준다.\n[정답]", "2": "악기를 연주하는 것은 창의성을 자극할 수 있으나 지남력에는 직접적인 도움이 되지 않는다.", "3": "똑같이 그리기는 시각적 인지 능력에는 도움이 될 수 있으나 지남력 향상과는 연관이 적다.", "4": "점선으로 옮겨 그리기는 운동기능을 발달시킬 수 있지만 지남력 향상에는 효과적이지 않다.", "5": "여러 가지 단어를 말하는 것은 언어 능력 향상에 도움이 되지만 지남력과는 직접적인 연관이 없다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억, 사고, 행동의 기능이 점진적으로 감소하는 질병", "def_vi": "Bệnh suy giảm chức năng ghi nhớ, tư duy và hành vi dần dần"}, {"term_ko": "지남력", "term_vi": "Khả năng định vị thời gian", "def_ko": "시간이나 장소 등을 인지하는 능력", "def_vi": "Khả năng nhận thức về thời gian hoặc địa điểm"}, {"term_ko": "달력", "term_vi": "Lịch", "def_ko": "날짜를 표시한 표", "def_vi": "Bảng hiển thị ngày tháng"}, {"term_ko": "악기", "term_vi": "Nhạc cụ", "def_ko": "음악을 연주하는 도구", "def_vi": "Công cụ để chơi nhạc"}, {"term_ko": "언어", "term_vi": "Ngôn ngữ", "def_ko": "의사소통을 위한 기호 체계", "def_vi": "Hệ thống ký hiệu để giao tiếp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1623, '12', '치매는 없으나 혼자서 움직이기 힘든 대상자의 인지기능 훈련프로그램 내용이다. 다음과같은 질문으로 향상될 수 있는 것은?누구 다녀가신 분은 계셨나요? / 점심엔 무엇을 드셨나요?', '["단기 기억력", "계산력", "공감능력", "창의력", "순응력"]'::jsonb, 1, NULL, NULL, '{"1": "단기 기억력을 향상시키기 위한 질문입니다. [정답]", "2": "계산력은 숫자와 관련된 질문으로 다루어지지 않습니다.", "3": "공감능력은 감정의 이해와 관련된 질문이 필요합니다.", "4": "창의력은 새로운 생각이나 아이디어를 생성하는 능력으로 질문과 관련이 없습니다.", "5": "순응력은 다른 사람의 요구에 따르는 능력으로 현재 질문과는 거리가 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Chứng mất trí nhớ", "def_ko": "치매", "def_vi": "chứng mất trí nhớ"}, {"term_ko": "인지기능", "term_vi": "Chức năng nhận thức", "def_ko": "인지 기능", "def_vi": "chức năng nhận thức"}, {"term_ko": "훈련프로그램", "term_vi": "Chương trình tập huấn", "def_ko": "훈련 프로그램", "def_vi": "chương trình tập huấn"}, {"term_ko": "기억력", "term_vi": "Trí nhớ", "def_ko": "기억력", "def_vi": "trí nhớ"}, {"term_ko": "계산력", "term_vi": "Năng lực tính toán", "def_ko": "계산 능력", "def_vi": "năng lực tính toán"}, {"term_ko": "공감능력", "term_vi": "Năng lực đồng cảm", "def_ko": "공감 능력", "def_vi": "năng lực đồng cảm"}, {"term_ko": "창의력", "term_vi": "Năng lực sáng tạo", "def_ko": "창의력", "def_vi": "năng lực sáng tạo"}, {"term_ko": "순응력", "term_vi": "Năng lực tuân thủ", "def_ko": "순응 능력", "def_vi": "năng lực tuân thủ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1622, '12', '치매 대상자의 인지 자극을 위한 ''일기쓰기'' 프로그램에 관한 설명으로 옳은 것은?', '["중증 치매 대상자에게 진행한다.", "작성한 일기내용에 대해 대화한다.", "형식 없는 빈 종이에 쓰게 해야 한다.", "대상자의 계산력을 높이는 데에 중점을 둔다.", "요양보호사의 흥미와 관심이 있는 주제로 쓰게 한다."]'::jsonb, 2, NULL, NULL, '{"1": "중증 치매 대상자에게는 인지 자극의 효과가 제한적일 수 있어 적합하지 않다.\n[정답]", "2": "작성한 일기내용에 대해 대화하는 것이 인지 자극에 도움이 된다.", "3": "형식이 없는 빈 종이에 쓰기보다는 어느 정도의 가이드라인이 필요하다.", "4": "일기쓰기 프로그램의 주 목적은 계산력 강화가 아니라 인지 자극이다.", "5": "흥미와 관심을 유도하는 것은 중요하지만, 이는 기본 요건이 아니므로 보편적으로 적용되기 어렵다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력이나 사고력의 저하가 나타나는 질환", "def_vi": "Bệnh giảm trí nhớ hoặc suy giảm tư duy"}, {"term_ko": "인지", "term_vi": "Nhận thức", "def_ko": "인식하고 이해하는 능력", "def_vi": "Khả năng nhận biết và hiểu"}, {"term_ko": "자극", "term_vi": "Kích thích", "def_ko": "반응을 유도하는 것", "def_vi": "Điều dẫn đến phản ứng"}, {"term_ko": "일기", "term_vi": "Nhật ký", "def_ko": "개인의 일상이나 생각을 기록한 글", "def_vi": "Tác phẩm viết về cuộc sống hoặc suy nghĩ cá nhân"}, {"term_ko": "대화", "term_vi": "Đối thoại", "def_ko": "서로 이야기를 나누는 것", "def_vi": "Trao đổi ý kiến với nhau"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1621, '12', '인지기능에 문제가 없는 대상자에게 적합한 인지자극 훈련은?', '["선 따라 그리기", "탬버린 흔들기", "인사말 연결하기", "뇌 건강 일기 쓰기", "물건보며 과거 회상하기"]'::jsonb, 4, NULL, NULL, '{"1": "선 따라 그리기는 운동 기능을 포함하므로 인지자극 훈련과는 다소 거리가 있습니다.\n[정답]", "4": "뇌 건강 일기 쓰기는 인지기능을 활용하여 자신의 생각과 감정을 정리하는 훈련으로 적합합니다.", "2": "탬버린 흔들기는 리듬 감각을 개발하지만 인지적 자극으로서는 부족합니다.", "3": "인사말 연결하기는 의사소통 능력에 중점을 두고 있지만 구체적인 인지훈련이 아닙니다.", "5": "물건보며 과거 회상하기는 감정적 자극은 있지만 인지적 자극을 활성화하는 데 한계가 있습니다."}'::jsonb, '[{"term_ko": "인지기능", "term_vi": "Chức năng nhận thức", "def_ko": "인지적 능력(한국어)", "def_vi": "Năng lực nhận thức (베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1620, '12', '치매 대상자를 위한 인지자극 훈련에 관한 설명으로 옳은 것은?', '["가족의수발 부담을 증가시킨다.", "치매의 진행을 늦추는 약물요법에 해당된다.", "''맨손체조 하기''는 지남력을 향상시키는 활동이다.", "인지자극훈련 대상자는혼자서 움직일 수 있어야 한다.", "인지기능에 대한 인식이 있는 숙련된 요양보호사가 담당한다."]'::jsonb, 5, NULL, NULL, '{"1": "가족의 수발 부담을 증가시키는 것은 부정적인 요소이며, 인지자극 훈련의 목적이 아닙니다.", "2": "약물요법은 인지자극 훈련이 아니라, 치매 진행을 늦추는 방법의 일환입니다.\n[정답]", "3": "''맨손체조 하기''는 지남력을 향상시키는 활동은 아니며, 지남력 훈련과는 다소 차이가 있습니다.", "4": "인지자극훈련 대상자는 혼자서 움직일 수 있어야 한다는 조건은 없습니다.", "5": "인지기능에 대한 인식이 있는 숙련된 요양보호사가 담당하는 것이 올바른 설명입니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력 및 인지 기능의 저하가 특징인 질병", "def_vi": "Bệnh đặc trưng bởi sự suy giảm trí nhớ và chức năng nhận thức"}, {"term_ko": "인지자극 훈련", "term_vi": "Đào tạo kích thích nhận thức", "def_ko": "인지 기능을 활성화하는 훈련 방법", "def_vi": "Phương pháp đào tạo để kích hoạt chức năng nhận thức"}, {"term_ko": "지남력", "term_vi": "Khả năng định hướng", "def_ko": "시간과 장소를 인지하는 능력", "def_vi": "Khả năng nhận biết thời gian và địa điểm"}, {"term_ko": "숙련된", "term_vi": "Có kinh nghiệm", "def_ko": "경험이 많은, 능숙한", "def_vi": "Kinh nghiệm phong phú, thành thạo"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1619, '12', '빗소리나 개구리 울음소리'' 를 들으면서 어린 시절 이야기를 할 때 향상될 수 있는 인지능력은?', '["순발력", "계산력", "통제력", "지남력", "지구력"]'::jsonb, 4, NULL, NULL, '{"1": "순발력은 상황에 즉각 반응하는 능력으로, 직접적인 관계가 없다.\n[정답]", "4": "지남력은 공간에서 자신의 위치를 파악하고 방향을 찾는 능력으로, 어린 시절 이야기를 회상하는 과정에서 향상될 수 있다.", "2": "계산력은 수치적인 능력으로 관련이 적다.", "3": "통제력은 감정이나 행위를 제어하는 능력으로, 문제와는 거리가 있다.", "5": "지구력은 체력과 관련이 있는 개념으로 무관하다."}'::jsonb, '[{"term_ko": "인지능력", "term_vi": "Nhận thức", "def_ko": "능력(한국어)", "def_vi": "khả năng(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1618, '12', '치매 말기 대상자와 의사소통하는 방법으로 옳은 것은?', '["빠르고 명확하게 말한다.", "대화 시 신체접촉을 피한다.", "대상자가 대답하지 않아도 계속해서 이야기한다.", "구체적인 대답을 요구하는 질문을 한다.", "전문적인 용어를 사용하여 대화한다."]'::jsonb, 3, NULL, NULL, '{"1": "빠르고 명확하게 말하는 것은 오히려 대상자를 혼란스럽게 할 수 있습니다.\n[정답]", "3": "대화 시 대상자가 대답하지 않더라도 계속해서 이야기하는 것은 대상자에게 안정감을 줄 수 있습니다.", "2": "신체접촉은 어떤 경우에는 필요한 경우도 있으므로 피하는 것이 항상 옳다고 볼 수 없습니다.", "4": "구체적인 대답을 요구하면 치매 환자에게 불필요한 스트레스를 줄 수 있습니다.", "5": "전문적인 용어를 사용하면 치매 환자가 이해하기 어려운 경우가 많습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력이나 사고력이 떨어지는 질병", "def_vi": "Bệnh làm giảm khả năng nhớ và suy nghĩ"}, {"term_ko": "말하다", "term_vi": "Nói", "def_ko": "말을 하다", "def_vi": "Làm cho âm thanh để giao tiếp"}, {"term_ko": "신체접촉", "term_vi": "Tiếp xúc cơ thể", "def_ko": "몸에 닿는 것", "def_vi": "Sự tiếp xúc vật lý giữa hai hoặc nhiều người"}, {"term_ko": "전문적인", "term_vi": "Chuyên môn", "def_ko": "특정 분야에 관련된", "def_vi": "Liên quan đến lĩnh vực cụ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1617, '12', '치매 말기 대상자와 의사소통 방법으로 옳은 것은?', '["신체적 접촉은 피한다.", "큰 소리로 말한다.", "이름을 부르면서 이야기를 시작한다.", "대상자가 보지 않더라도 계속 말한다.", "대화가 끝나면 조용히 나간다."]'::jsonb, 3, NULL, NULL, '{"1": "신체적 접촉은 피하는 것이 아니라, 오히려 긍정적인 신체적 접촉이 도움이 될 수 있습니다.", "2": "큰 소리로 말하는 것은 오해를 초래할 수 있으며, 환자에게 스트레스를 줄 수 있습니다.\n[정답]", "3": "이름을 부르면서 이야기를 시작하는 것은 친밀감을 주고 환자의 주의를 끌 수 있어 효과적인 방법입니다.", "4": "대상자가 보지 않더라도 계속 말하는 것은 환자의 이해를 방해할 수 있습니다.", "5": "대화가 끝난 후 조용히 나가는 것은 환자에게 불안감을 줄 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "뜻(한국어)", "def_vi": "nghĩa(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1616, '12', '치매 말기 대상자의 의사소통문제로 ( ) 안에 들어갈 말로 옳은 것은?요양보호사: 식사는 하셨어요? 치매대상자: ( )', '["벌써 식사시간이야?", "배고파 죽겠어. 빨리 밥 줘.", "내가밥을 먹었던가?", "모르겠어. 언제 먹었는지...", "식사는 하셨어요?"]'::jsonb, 5, NULL, NULL, '{"1": "벌써 식사시간이야? - 적절한 의사소통이 아닙니다.", "2": "배고파 죽겠어. 빨리 밥 줘. - 공격적인 발언으로, 의사소통 문제를 보여줍니다.  \n[정답]", "3": "내가 밥을 먹었던가? - 기억의 혼란을 나타내지만, 질문에 대한 직접적인 응답이 아닙니다.", "4": "모르겠어. 언제 먹었는지... - 기억의 혼란을 나타내지만, 의사소통이 원활하지 않습니다.", "5": "식사는 하셨어요? - 질문의 반복으로, 의사소통 능력에 변화를 보이지 않고 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 사고능력이 저하되는 질환", "def_vi": "Bệnh suy giảm trí nhớ và khả năng tư duy"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1615, '12', '치매 말기 단계에서 자주 발생하는 의사소통 문제는?', '["앵무새처럼 상대방의 말을 그대로 따라한다.", "과거, 현재, 미래 시제의 올바른 사용이 어렵다.", "사용하는 어휘의 수가 점차적으로 제한된다.", "올바른 이름을 지칭하지 못한다.", "대화 중 말이 끊기는 횟수가 증가한다."]'::jsonb, 1, NULL, NULL, '{"1": "앵무새처럼 상대방의 말을 그대로 따라하는 것은 치매 환자에서 흔하게 나타날 수 있는 의사소통 방법입니다.\n[정답]", "2": "과거, 현재, 미래 시제의 올바른 사용이 어렵다는 증상도 있을 수 있지만, 이 문제는 치매 말기 단계에서 특정하기에는 부족합니다.", "3": "사용하는 어휘의 수가 점차적으로 제한된다는 것은 사실이지만, 이는 모든 치매 환자에게서 발생하지 않습니다.", "4": "올바른 이름을 지칭하지 못하는 경우는 치매 환자가 겪는 일반적인 어려움이긴 하지만, 앵무새와 같은 증상보다는 덜 구체적입니다.", "5": "대화 중 말이 끊기는 횟수가 증가하는 것은 증상 중 하나일 수 있으나, 문제에서 묻는 의사소통 문제의 범위와는 거리가 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "치매", "def_vi": "bệnh Alzheimer"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1614, '12', '치매 중기 단계에서 자주 나타나는 의사소통 문제는?', '["대화 중에 말이 끊기는 횟수가 증가한다.", "자주 확인하고 설명을 요구한다.", "물건이나 사람의이름을 부르는 것이 어렵다.", "대화 시 시선을 맞추는 것을 어려워한다.", "말이 없어진다."]'::jsonb, 1, NULL, NULL, '{"1": "대화 중에 말이 끊기는 횟수가 증가하는 것은 치매 중기 단계에서 자주 나타나는 증상입니다.\n[정답]", "2": "자주 확인하고 설명을 요구하는 경우도 있지만, 이는 중기의 주요 의사소통 문제와는 거리가 있습니다.", "3": "물건이나 사람의 이름을 부르는 것이 어려운 경우도 있지만, 상대적으로 덜 자주 나타나는 문제입니다.", "4": "대화 시 시선을 맞추는 것을 어려워하는 것은 보편적으로 나타나는 경향은 아니며, 개인차가 큽니다.", "5": "말이 없어진다는 것은 더 진행된 단계에서 나타나는 주된 증상으로, 중기 단계의 주요 문제와는 다소 차이가 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억, 사고, 외부 자극에 대해 반응을 제대로 하지 못하는 상태", "def_vi": "Trạng thái không thể phản ứng đúng với trí nhớ, suy nghĩ và kích thích từ bên ngoài"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1613, '12', '치매 초기 단계에서 자주 나타나는 의사소통 문제는?', '["애매모호한 내용을 이야기한다.", "명칭 실어증을 보인다.", "대화의 주제가 자주 바뀐다.", "시선을 맞추는데 어려움이 있다.", "무언증이 나타난다."]'::jsonb, 3, NULL, NULL, '{"1": "애매모호한 내용을 이야기한다는 초기 단계에서 나타날 수 있으나, 명확한 특징은 아닙니다.\n[정답]", "2": "명칭 실어증은 치매의 진행 단계에서 나타나는 증상입니다.", "3": "대화의 주제가 자주 바뀌는 것은 치매 초기 단계에서 자주 보이는 의사소통 문제입니다.", "4": "시선을 맞추는데 어려움이 있는 것은 보통 후기에 주로 나타나는 증상입니다.", "5": "무언증이 나타나는 것은 치매가 진행된 상태에서 주로 관찰됩니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "알츠하이머병(다른 형태의 인지장애 포함)", "def_vi": "Bệnh khó khăn về trí nhớ và nhận thức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1612, '12', '치매 대상자와 의사소통 방법으로 옳은 것은?', '["항상 현재 상황을 알려준다.", "대상자 옆에서 이야기한다.", "목소리 톤을 높여서 말한다.", "유행어를 사용한다.", "대상자의 행동을 복잡하게 해석한다."]'::jsonb, 1, NULL, NULL, '{"1": "항상 현재 상황을 알려준다. - 치매 대상자는 기억이 저하되어 있으므로, 현재 상황을 주기적으로 알려주는 것이 필요합니다.\n[정답]", "2": "대상자 옆에서 이야기한다. - 옆에서 이야기하는 것이 아니라, 시선을 맞춰주며 대화하는 것이 더 효과적입니다.", "3": "목소리 톤을 높여서 말한다. - 목소리를 높이는 것은 불필요한 긴장을 유발할 수 있습니다.", "4": "유행어를 사용한다. - 유행어는 치매 대상자가 이해하기 어려운 경우가 많습니다.", "5": "대상자의 행동을 복잡하게 해석한다. - 복잡한 해석은 대상자의 혼란을 초래할 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "기억력 손상으로 인한 인지기능 저하", "def_vi": "Suy giảm chức năng nhận thức do mất trí nhớ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1611, '12', '다른 내용은 언어적 의사소통의 기본원칙에 어긋난 행동이다. 해당되는 것은?요양보호사가 74세 치매 할아버지에게 "10시가 되면 병원에 가야하니까 양말을 벗지 말고 거실에 앉아 계세요." 라고 말한다.', '["일상적인어휘 사용하기", "적절한 존칭어 사용하기", "한 번에 한 가지씩 시행 유도하기", "현재 상황 제시하기", "얼굴 마주보고 대화하기"]'::jsonb, 3, NULL, NULL, '{"1": "일상적인 어휘를 사용하는 것은 의사소통의 기본 원칙에 부합합니다.\n[정답]", "3": "한 번에 한 가지씩 시행 유도하지 않는 것은 의사소통의 원칙에 어긋나므로 정답입니다.", "2": "적절한 존칭어 사용은 의사소통의 기본 원칙에 잘 맞습니다.", "4": "현재 상황을 제시하는 것은 의사소통의 원칙에 부합합니다.", "5": "얼굴을 마주보고 대화하는 것은 효과적인 의사소통 방식입니다."}'::jsonb, '[{"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "대화하거나 정보를 주고받는 것", "def_vi": "Hành động nói chuyện hoặc trao đổi thông tin"}, {"term_ko": "기본원칙", "term_vi": "Nguyên tắc cơ bản", "def_ko": "기본적으로 따라야 하는 원칙", "def_vi": "Nguyên tắc cần tuân theo"}, {"term_ko": "적절한", "term_vi": "Thích hợp", "def_ko": "알맞고 적합한", "def_vi": "Đúng và phù hợp"}, {"term_ko": "존칭어", "term_vi": "Kính ngữ", "def_ko": "상대방을 존중하는 언어", "def_vi": "Ngôn ngữ tôn trọng đối phương"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1610, '12', '치매 대상자와 대화 시 올바른 방법은?', '["뒤에서 어깨를 감싸며 부드럽게 다가간다.", "가까운곳에서 얼굴을 마주보고 말한다.", "몸동작을 크게 과장해서 표현한다.", "길고 자세하게 설명한다.", "대상자가이해하지 못하면 대화를 멈춘다."]'::jsonb, 2, NULL, NULL, '{"1": "뒤에서 어깨를 감싸며 다가가는 것은 대상자가 위축될 수 있어 좋지 않은 접근이다.\n[정답]", "2": "가까운 곳에서 얼굴을 마주보고 말하는 것은 대상자가 대화를 이해하는 데 도움을 준다.", "3": "몸동작을 크게 과장하는 것은 대상자가 혼란스러울 수 있다.", "4": "길고 자세하게 설명하는 것은 치매 대상자에게 부담을 줄 수 있다.", "5": "대상자가 이해하지 못하면 대화를 멈추는 것은 오히려 더 소외감을 줄 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억 상실이나 인지 기능 저하를 보이는 질환", "def_vi": "Bệnh mà người bệnh bị suy giảm trí nhớ hoặc chức năng nhận thức"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "정보를 주고받는 과정", "def_vi": "Quá trình trao đổi thông tin"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "케어를 받는 사람", "def_vi": "Người được chăm sóc"}, {"term_ko": "이해", "term_vi": "Hiểu", "def_ko": "내용을 파악하는 과정", "def_vi": "Quá trình nắm bắt nội dung"}, {"term_ko": "소외감", "term_vi": "Cảm giác bị cô lập", "def_ko": "사회에서 소외된 느낌", "def_vi": "Cảm giác tách biệt khỏi xã hội"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1609, '12', '인지능력 저하로 자기 마음대로 생각하는 치매 대상자와 의사소통 방법은?', '["대화주제를 자주 바꾼다.", "새로운 물건을 활용하여 대화를 시도한다.", "''네'', ''아니오''로 답할 수 있는 질문을 한다.", "대상자가 반응하지 않으면 대화를 바꾼다.", "대상자의 행동을 자의적으로 해석하여 의미를 파악한다."]'::jsonb, 3, NULL, NULL, '{"1": "대화주제를 자주 바꾸는 것은 혼란을 야기할 수 있으므로 좋지 않습니다.", "2": "새로운 물건을 활용하여 대화를 시도하는 것은 도움이 될 수 있으나, 응답을 유도하기 위해서는 제한된 선택지가 필요합니다.\n[정답]", "3": "''네'', ''아니오''로 답할 수 있는 질문은 간단하고 명확하여 치매 대상자가 쉽게 반응할 수 있도록 돕습니다.", "4": "대상자가 반응하지 않는 경우 대화를 바꾸는 것은 효과적이지 않을 수 있으며, 반응을 기다리는 것이 더 중요합니다.", "5": "대상자의 행동을 자의적으로 해석하여 의미를 파악하는 것은 잘못된 해석을 초래할 수 있어 바람직하지 않습니다."}'::jsonb, '[{"term_ko": "인지능력", "term_vi": "자기", "def_ko": "능력或 khả năng nhận thức", "def_vi": "자신 hoặc bản thân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1608, '12', '종이접기'' 프로그램에 참여한 치매 대상자가 따라 하지 못하고 머뭇거릴 때 돕는 방법은?', '["어린아이 대하듯 한다.", "이해하지 못하면 반복적으로 설명을 한다.", "말 이외에다른 신호는 사용하지 않는다.", "문제행동 시 ''왜'' 그랬냐고 묻는다.", "한 번에 여러 가지 일을 알려준다."]'::jsonb, 2, NULL, NULL, '{"1": "어린아이 대하듯 한다는 것은 대상자의 자존감을 상해할 수 있어 부적절한 방법입니다.\n[정답]", "2": "이해하지 못하면 반복적으로 설명을 하는 것은 치매 환자에게 필요한 지원 방법입니다.", "3": "말 이외의 다른 신호를 사용하지 않는 것은 다양하고 효과적인 소통 방법을 제한합니다.", "4": "문제행동 시 ''왜'' 그랬냐고 묻는 것은 오히려 환자에게 스트레스를 줄 수 있습니다.", "5": "한 번에 여러 가지 일을 알려주는 것은 치매 환자가 혼란스러워질 수 있으므로 적절하지 않습니다."}'::jsonb, '[{"term_ko": "종이접기", "term_vi": "Gấp giấy", "def_ko": "종이를 접어서 만드는 예술 또는 활동", "def_vi": "Nghệ thuật hoặc hoạt động tạo ra từ việc gấp giấy"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1607, '12', '치매 대상자와의 의사소통 원칙으로 옳은 것은?', '["주로 \"왜\"라고 묻고 답하게 한다.", "대상자의 속도에맞춘다.", "자세하고 길게 설명한다.", "신체적 접촉을 삼간다.", "과거를 회상하지 않도록 한다."]'::jsonb, 2, NULL, NULL, '{"1": "''왜''라는 질문은 치매 환자에게 혼란을 줄 수 있습니다.\n[정답]", "2": "대상자의 속도에 맞추는 것은 의사소통에서 매우 중요합니다.", "3": "자세하고 길게 설명하면 오히려 이해를 어렵게 만들 수 있습니다.", "4": "신체적 접촉은 오히려 신뢰를 쌓는데 도움이 될 수 있습니다.", "5": "과거를 회상하는 것은 치매 환자와의 의사소통에서 긍정적인 효과를 줄 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Chứng mất trí nhớ", "def_ko": "기억과 인지 기능의 감소를 초래하는 상태", "def_vi": "Tình trạng giảm chức năng ghi nhớ và nhận thức"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "정보와 감정을 교환하는 과정", "def_vi": "Quá trình trao đổi thông tin và cảm xúc"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "도움이나 지원이 필요한 사람", "def_vi": "Người cần sự giúp đỡ hoặc hỗ trợ"}, {"term_ko": "속도", "term_vi": "Tốc độ", "def_ko": "어떤 일이 진행되는 빠르기", "def_vi": "Độ nhanh của một công việc"}, {"term_ko": "신체적 접촉", "term_vi": "Tiếp xúc cơ thể", "def_ko": "신체를 통해 하는 접촉", "def_vi": "Sự tiếp xúc qua cơ thể"}, {"term_ko": "회상", "term_vi": "Hồi tưởng", "def_ko": "과거의 일을 기억하거나 떠올리는 것", "def_vi": "Nhớ lại hoặc gợi lại những sự việc trong quá khứ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1606, '12', '치매 대상자의 대화 중 의사소통 방법이 옳은 것은?요양보호사: 오늘 목욕하기로 한 날이에요. 목욕 시작하실까요? 대상자: (목욕하지 않은 상태) 나 목욕 다 했어. 빨래도 다 했다고.', '["목욕 안 하셨잖아요. 다 알아요.", "그러지 말고 목욕한 후에 같이 외출해요.", "언제 목욕하셨어요?", "잘 하셨어요. 그럼 이제 샤워하실래요?", "거짓말하시면 앞으로 목욕 안 할 거예요."]'::jsonb, 4, NULL, NULL, '{"1": "목욕을 하지 않은 사실을 지적하므로 부적절합니다.\n[정답]", "4": "긍정적인 반응을 통해 환자가 샤워를 하도록 유도하는 방법입니다.", "2": "거부감을 줄 수 있는 제안으로 부적절합니다.", "3": "과거의 행동을 물어보는 것은 치매 환자에게 혼란을 줄 수 있습니다.", "5": "부정적인 어조로 말하여 환자의 불안감을 증가시킬 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억과 사고 기능에 문제가 생기는 질환", "def_vi": "Bệnh lý xảy ra với chức năng trí nhớ và tư duy"}, {"term_ko": "대화", "term_vi": "Giao tiếp", "def_ko": "사람들 간의 말이나 글로 이루어지는 의사소통", "def_vi": "Sự trao đổi thông tin bằng lời nói hoặc chữ viết"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "정보를 주고받는 과정", "def_vi": "Quá trình truyền đạt và nhận thông tin"}, {"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "몸을 깨끗이 하기 위한 행동", "def_vi": "Hành động làm sạch cơ thể"}, {"term_ko": "대상자", "term_vi": "Người nhận chăm sóc", "def_ko": "서비스 받는 사람, 보호 대상", "def_vi": "Người nhận dịch vụ, người đang được chăm sóc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1605, '12', '치매 대상자와의 의사소통으로 옳은 것은?', '["허리가 많이 아프세요?", "8시가 되면 약 드세요.", "할머니 오늘은 기분이 괜찮아?", "우유는 드셔도 되지만 콜라는 안 돼요.", "식사를 왜 조금만 하세요?"]'::jsonb, 1, NULL, NULL, '{"1": "허리가 많이 아프세요? (치매 대상자의 신체적 불편함을 확인하는 질문으로 적절하다.)\n[정답]", "2": "8시가 되면 약 드세요. (치매 환자에게 시간 엄수를 강조하는 표현은 적절하지 않다.)", "3": "할머니 오늘은 기분이 괜찮아? (부드러운 질문이지만 직접적인 질문은 치매 환자에게 혼란을 줄 수 있다.)", "4": "우유는 드셔도 되지만 콜라는 안 돼요. (식이 제한을 알리는 것이 적절치 않다.)", "5": "식사를 왜 조금만 하세요? (치매 환자에게 질문하는 것보다는 지지적인 표현이 필요하다.)"}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh sa sút trí tuệ", "def_ko": "기억력 및 인지 기능의 저하로 인한 질병", "def_vi": "Bệnh mất trí nhớ và giảm chức năng nhận thức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1604, '12', '치매 대상자에게 질문을 할 때 올바른 방법은?', '["어떤 음식을 좋아하세요?", "사과드실래요?", "식사하고 양치질한 후에 외출해요.", "거기에 가만히 앉아서 기다리세요.", "거실은 되지만 방에는 들어가지 마세요."]'::jsonb, 2, NULL, NULL, '{"1": "어떤 음식을 좋아하세요? : 치매 환자에게는 구체적인 질문보다는 단순하고 명확한 질문이 필요합니다.\n[정답]", "2": "사과드실래요? : 간단하고 이해하기 쉬운 질문으로, 대답하기 용이합니다.", "3": "식사하고 양치질한 후에 외출해요. : 지시형 질문으로, 치매 환자에게 혼란을 줄 수 있습니다.", "4": "거기에 가만히 앉아서 기다리세요. : 명령형으로, 찬반을 묻거나 의견을 물어볼 수 있는 질문이 아닙니다.", "5": "거실은 되지만 방에는 들어가지 마세요. : 제한적인 지시로서 이해하기 낫습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억이나 사고 기능이 상실되는 질병", "def_vi": "Bệnh không còn khả năng ghi nhớ hoặc suy nghĩ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1603, '12', '치매 대상자와 의사소통하는 방법으로 옳은 것은?', '["어제는 무엇을 드셨어요?", "몸이 어떻게 아프세요?", "우유 드실래요? 주스 드실래요?", "어디로 여행가고 싶으세요?", "식사 후 양치하고 산책하실래요?"]'::jsonb, 3, NULL, NULL, '{"1": "''어제는 무엇을 드셨어요?''와 같은 질문은 치매 환자가 기억하기 어려울 수 있습니다.", "2": "''몸이 어떻게 아프세요?''는 구체적인 증상을 확인할 수 있지만, 복잡한 질문일 수 있습니다.\n[정답]", "3": "''우유 드실래요? 주스 드실래요?''는 간단하고 선택지를 제공하여 의사소통을 용이하게 합니다.", "4": "''어디로 여행가고 싶으세요?''는 추상적인 질문으로 치매 대상자가 이해하기 어려울 수 있습니다.", "5": "''식사 후 양치하고 산책하실래요?''는 여러 가지 활동을 한 번에 제안하여 혼란을 줄 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력 및 사고 능력이 감소하는 질환", "def_vi": "Bệnh giảm khả năng ghi nhớ và tư duy"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "정보를 주고받는 행위", "def_vi": "Hành động trao đổi thông tin"}, {"term_ko": "대상자", "term_vi": "Người nhận", "def_ko": "서비스나 도움을 받는 사람", "def_vi": "Người nhận dịch vụ hoặc hỗ trợ"}, {"term_ko": "선택지", "term_vi": "Lựa chọn", "def_ko": "여러 가지 중에서 선택할 수 있는 것", "def_vi": "Những điều có thể chọn từ nhiều cái"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1602, '12', '다음 중 치매대상자와 의사소통 방법으로 옳은 것은? 대상자: 손주가 나랑 여행가자고 하는데 어떻게 할까? 요양보호사: ( )', '["어르신 생각은 어떠세요?", "어르신 하고 싶은 데로 하세요.", "어디로 여행가고 싶으세요?", "가고 싶세요? 가고 싶지 않으세요?", "건강검진 받고 사진도 찍고 여권도 만들어야지요."]'::jsonb, 4, NULL, NULL, '{"1": "어르신의 생각을 물어보는 질문으로, 치매환자가 이해하기 어려울 수 있다.\n[정답]", "4": "가고 싶습니다라고 대답할 수 있는 명확한 선택지를 제공한다.", "3": "여행지를 물어보는 질문으로, 치매환자가 기억하지 못할 위험이 있다.", "5": "장기적인 건강 관리에 대한 내용으로, 치매대상자의 현재 의사소통에는 적합하지 않다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력이나 사고력의 저하로 인한 질환", "def_vi": "Bệnh do suy giảm trí nhớ hoặc khả năng tư duy"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "서로 의견을 주고받는 행위", "def_vi": "Hành động trao đổi ý kiến với nhau"}, {"term_ko": "대상자", "term_vi": "Người nhận", "def_ko": "서비스나 도움을 받는 사람", "def_vi": "Người nhận dịch vụ hoặc sự giúp đỡ"}, {"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "노인이나 환자 등을 돌보는 직업", "def_vi": "Nghề chăm sóc người cao tuổi hoặc bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1601, '12', '다음 대화 중 효과적인 의사소통으로 옳은 것은?대상자: 아이고 아파. 배가 아파 죽겠어. 요양보호사: ( )', '["또 왜 그러세요?", "오늘 점심 못 드시겠네요?", "그럼 누워계세요.", "어제 무엇을 얼마나 드셨어요?", "(배를 맍지며) 여기가 아프세요?"]'::jsonb, 5, NULL, NULL, '{"1": "또 왜 그러세요? - 단순히 질문을 반복하는 것으로, 상황을 파악하는 데 비효율적입니다.\n[정답]", "2": "(배를 맍지며) 여기가 아프세요? - 직접적인 질문으로, 대상자의 증상을 더 잘 이해할 수 있게 도와줍니다.", "3": "그럼 누워계세요. - 상황을 무시하고 단순한 지시만 합니다.", "4": "어제 무엇을 얼마나 드셨어요? - 질문이 적절하지만, 현재의 아픔과는 연결되지 않습니다.", "5": "오늘 점심 못 드시겠네요? - 아픔에 대한 적절한 반응이 아닙니다."}'::jsonb, '[{"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "의사전달(한국어)", "def_vi": "Truyền đạt ý kiến"}, {"term_ko": "대화", "term_vi": "Cuộc trò chuyện", "def_ko": "서로 이야기함(한국어)", "def_vi": "Nói chuyện với nhau"}, {"term_ko": "효과적", "term_vi": "Hiệu quả", "def_ko": "성과가 있는(한국어)", "def_vi": "Có kết quả"}, {"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "돌봄받는 사람(한국어)", "def_vi": "Người nhận sự chăm sóc"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "병이 나타나는 상태(한국어)", "def_vi": "Trạng thái xuất hiện bệnh"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1600, '12', '혼자서 요리를 할 수 없는 치매 대상자가 된장국을 끓이겠다고 고집을 부릴 때 대처방법으로 옳은 것은?', '["제가 도와드릴게요. 같이 끓일까요?", "요리가 하고 싶어도 하면 안돼요. 위험해요.", "제가 해 드릴테니 조금만 기다리세요.", "그럼 끓여보세요. 맛이 어떨지 궁금하네요.", "어떻게 끓일지 먼저 설명해 보세요."]'::jsonb, 1, NULL, NULL, '{"1": "제가 도와드릴게요. 같이 끓일까요? - 동행을 통해 안전하게 요리할 수 있도록 돕는 좋은 방법입니다.\n[정답]", "2": "요리가 하고 싶어도 하면 안돼요. 위험해요. - 치매 대상자의 자율성을 위축시키는 부정적인 방법입니다.", "3": "제가 해 드릴테니 조금만 기다리세요. - 자기 주도성을 줄이고 대화를 단절할 수 있습니다.", "4": "그럼 끓여보세요. 맛이 어떨지 궁금하네요. - 위험한 상황을 초래할 수 있습니다.", "5": "어떻게 끓일지 먼저 설명해 보세요. - 대상자의 기억력과 이해를 고려하지 않은 방법입니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "기억력과 인지 기능의 저하로 일상생활에 어려움을 겪는 상태", "def_vi": "Tình trạng suy giảm trí nhớ và khả năng nhận thức gây khó khăn trong sinh hoạt hàng ngày"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1599, '12', '다음 대화에서 요양보호사의 적절한 대처방법은?딸:"엄마! 맛이 없으니까 이제 음식하지 마세요." 대상자: (화가 나서방으로 들어가며) 그럼, 네가 알아서해 먹어. 난 안 먹어 요양보호사: (대상자에게 다가가) ( )', '["\"엄마가 힘드실까봐 일부러 한 말일 거예요.\"", "\"밥을 안 드시면 본인만 손해예요. 참으세요.\"", "\"음식 솜씨가 예전 같지 않다고하니 속상하시지요.\"", "\"이제부터는 따님한테 하라고 하세요.\"", "\"앞으로 제가 음식을 만들어드릴게요.\""]'::jsonb, 3, NULL, NULL, '{"1": "요양보호사가 사정없이 대화를 이어가는 것은 바람직하지 않습니다.\n[정답]", "3": "대상자의 기분을 이해하고 공감하는 대화가 적절합니다.", "2": "대화의 진행이 아니라 대상자를 자극할 수 있는 발언입니다.", "4": "요양보호사의 역할에 어긋나는 발언입니다.", "5": "자신이 해야 하는 일로 상황을 더 악화시킬 수 있습니다."}'::jsonb, '[{"term_ko": "적절한", "term_vi": "phù hợp", "def_ko": "적합한(한국어)", "def_vi": "thích hợp(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1598, '12', '시설에서 생활하는 치매대상자가 거실에 나와 바지를 벗으며 성기를 노출할 경우 대처방법은?', '["스스로 옷을 입을 때까지 기다린다.", "경범죄로 처벌받을 수 있다고 경고한다.", "거실에 있는 사람들은 다른 곳으로 이동시킨다.", "여러사람 앞에서 망신을 주어 행동을 멈추게 한다.", "좋아하는 물건이나 활동을 통해 관심 전환을 유도한다."]'::jsonb, 5, NULL, NULL, '{"1": "스스로 옷을 입을 때까지 기다리는 것은 적절하지 않은 대처 방법입니다.\n[정답]", "5": "좋아하는 물건이나 활동을 통해 관심 전환을 유도하는 것은 효과적인 대처 방법입니다.", "2": "경범죄로 처벌받을 수 있다고 경고하는 것은 적절하지 않으며, 오히려 불안감을 조성할 수 있습니다.", "3": "거실에 있는 사람들을 다른 곳으로 이동시키는 것은 상황을 악화시킬 수 있습니다.", "4": "여러 사람 앞에서 망신을 주는 것은 치매대상자의 심리적 상처를 초래할 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "기억이나 사고 기능의 점진적인 손실", "def_vi": "Sự mất mát dần dần về khả năng nhớ hoặc suy nghĩ"}, {"term_ko": "대처 방법", "term_vi": "Cách xử lý", "def_ko": "문제 상황에 대처하기 위한 방법", "def_vi": "Phương pháp ứng phó với tình huống"}, {"term_ko": "관심 전환", "term_vi": "Chuyển hướng sự chú ý", "def_ko": "주의를 다른 곳으로 돌리는 것", "def_vi": "Đổi hướng sự chú ý sang nơi khác"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1597, '12', '시설 치매대상자가 담당 요양보호사를 애인이라고 하면서 다음과 같은 행동을 할 때 대처방법은?', '["가족에게 알려 계약을 종료하겠다고 말한다.", "성희롱으로 노인보호전문기관에 신고한다고 말한다.", "치매 대상자에게 나타나는증상이라고 이해하고 넘어간다.", "애인이 아니라 어르신을 돌보는 전문가라고 권위적으로 말한다.", "멈추지 않으면 담당 요양보호사 변경을 요청하겠다고 경고한다."]'::jsonb, 5, NULL, NULL, '{"1": "가족에게 알려 계약을 종료하겠다고 말하는 것은 적절한 대처가 아닙니다.\n[정답]", "5": "멈추지 않으면 담당 요양보호사 변경을 요청하겠다고 경고하는 것은 상황을 개선하기 위한 적절한 방법입니다.", "3": "치매 대상자에게 나타나는 증상이라고 이해하고 넘어가는 것은 문제 해결이 되지 않습니다.", "4": "애인이 아니라 어르신을 돌보는 전문가라고 권위적으로 말하는 것은 부적절한 접근입니다.", "2": "성희롱으로 신고한다고 하는 것은 상황을 악화시킬 수 있습니다."}'::jsonb, '[{"term_ko": "담당", "term_vi": "Người phụ trách", "def_ko": "책임을 맡은", "def_vi": "người chịu trách nhiệm"}, {"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "노인을 돌보는 전문가", "def_vi": "Chuyên gia chăm sóc người cao tuổi"}, {"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력과 사고력이 저하되는 질병", "def_vi": "Bệnh giảm trí nhớ và khả năng suy nghĩ"}, {"term_ko": "행동", "term_vi": "Hành động", "def_ko": "몸의 움직임이나 태도", "def_vi": "Di chuyển hoặc thái độ của cơ thể"}, {"term_ko": "성과", "term_vi": "Hiệu quả", "def_ko": "효과", "def_vi": "Kết quả"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1596, '12', '프로그램 참여 중에 남자 치매대상자가 옆에 앉은 여자 대상자의 가슴을 만질 때 대처방법은?', '["무슨 짓이냐고 손을 때려서 제지한다.", "여자 대상자에게 사과하라고 한다.", "내일부터 참여시키지 않겠다고 한다.", "여자 대상자를 다른 장소로 이동시킨다.", "큰 소리로 당장 방으로 들어가라고 한다."]'::jsonb, 4, NULL, NULL, '{"1": "무슨 짓이냐고 손을 때려서 제지하는 것은 폭력을 유발할 수 있다. \n[정답]", "4": "여자 대상자를 다른 장소로 이동시키는 것은 상황을 잠재우는 적절한 방법이다.", "2": "여자 대상자에게 사과하라고 하는 것은 적절한 대화 방식이 아니다.", "3": "내일부터 참여시키지 않겠다고 하는 것은 문제 해결이 아니다.", "5": "큰 소리로 당장 방으로 들어가라고 하는 것은 불필요한 위협을 줄 수 있다."}'::jsonb, '[{"term_ko": "프로그램", "term_vi": "Chương trình", "def_ko": "프로그램(한국어)", "def_vi": "chương trình(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1595, '12', '치매 대상자가 반복적으로 바지 지퍼를 내리면서 요양보호사에게 올려 달라고 할 때 대처방법은?', '["지퍼가 없는 바지로 갈아입힌다.", "창피를 주어 행동을 멈추게 한다.", "계속하면 서비스를 중단하겠다고 한다.", "가족에게 상황을 설명하고 퇴소를 권한다.", "도와줄 수 없으니 스스로 지퍼를 올리라고 한다."]'::jsonb, 1, NULL, NULL, '{"1": "지퍼가 없는 바지로 갈아입힘으로써 대상자의 불편함을 해소할 수 있다. \n[정답]", "2": "창피를 주는 것은 오히려 대처 방법으로 부적절하다.", "3": "서비스를 중단하겠다고 위협하는 것은 대상자에게 부정적인 영향을 미칠 수 있다.", "4": "가족에게 퇴소를 권하는 것은 문제 해결보다는 회피에 가까운 방법이다.", "5": "스스로 지퍼를 올리라고 요구하는 것은 치매 환자의 상황을 고려하지 않은 대처 방법이다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Mất trí", "def_ko": "기억력을 잃는 질환", "def_vi": "Bệnh mất trí nhớ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1594, '12', '다음 사례에서 치매 대상자를 돕는 방법으로 옳은 것은?시설에서 낮 동안 잘 지내던 대상자가해질녘이 되면 "오늘도 수고하셨어요. 저는 퇴근합니다."라고 하면서 밖으로 나가려고 한다.', '["아직 일이 끝나지 않아 못 간다고 말한다.", "요양시설이라 나갈 수 없다고 설득한다.", "조명을 어둡게 하여 밤이라는 것을 알린다.", "빠른 박자의 음악을 크게 틀어준다.", "대상자가 좋아하는 텔레비전 프로그램을 켜준다."]'::jsonb, 5, NULL, NULL, '{"1": "아직 일이 끝나지 않아 못 간다고 말한다. 치매 환자는 현실을 정확히 이해하지 못할 수 있으므로 이 방법은 도움이 되지 않습니다.\n[정답]", "5": "대상자가 좋아하는 텔레비전 프로그램을 켜준다. 이는 대상자의 관심을 끌고 안정을 취하게 하여 퇴근하려는 행동을 완화시킬 수 있습니다.", "3": "조명을 어둡게 하여 밤이라는 것을 알린다. 치매 환자에게 혼란을 줄 수 있는 방법입니다.", "4": "빠른 박자의 음악을 크게 틀어준다. 이는 오히려 불안을 유발할 수 있습니다.", "2": "요양시설이라 나갈 수 없다고 설득한다. 설득이 통하지 않을 가능성이 높습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력과 인지 기능의 저하로 인한 질환", "def_vi": "Bệnh suy giảm trí nhớ và nhận thức"}, {"term_ko": "요양시설", "term_vi": "Cơ sở dưỡng lão", "def_ko": "노인이나 장애인을 위한 시설", "def_vi": "Nơi chăm sóc người già hoặc người khuyết tật"}, {"term_ko": "퇴근", "term_vi": "Về nhà", "def_ko": "일을 마치고 집으로 돌아가는 것", "def_vi": "Trở về nhà sau khi làm việc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1593, '12', '시설 치매 대상자가 해 질 무렵이 되면 가방을 들고 아들 집으로 가겠다고 할 때 대처방법은?', '["들고 있는 가방을 보이지 않는 곳으로 치운다.", "침실 조명을 어둡게 하여 잠을 청하게 한다.", "좋아하는 따뜻한 음료를 마시러 가자고 한다.", "아들이 여행을 가서 집에 아무도 없다고 말한다.", "지금은 늦었으니 내일 아들을 만나러 가자고 한다."]'::jsonb, 3, NULL, NULL, '{"1": "가방을 치우는 것은 환자의 불안을 증가시킬 수 있습니다.\n[정답]", "3": "환자의 좋아하는 음료를 제안하여 긍정적인 방향으로 유도하는 것이 좋습니다.", "2": "침실 조명을 어둡게 하면 불안감을 느낄 수 있습니다.", "4": "아들이 여행 중이라고 말하는 것은 신뢰를 해치게 될 수 있습니다.", "5": "내일 만나자고 하는 것은 환자가 느끼는 즉각적인 욕구를 무시하는 것입니다."}'::jsonb, '[{"term_ko": "시설", "term_vi": "시설", "def_ko": "장소(한국어)", "def_vi": "địa điểm(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1592, '12', '치매 대상자가 해질녘만 되면 다른 대상자를 따라다니며 여보 무서워. 같이 있자.라고 할 때 대처방법은?', '["\"겁이 많아지셨네요. 뭐가 무서운지 말씀해 보세요.\"", "\"거짓말하면서 자꾸 괴롭히면 여기서 나가셔야 돼요.\"", "\"할아버지는 작년에 돌아가셨어요. 이젠 받아들이세요.\"", "\"저분이 할아버지로 보이세요? 사진하고 많이 다르잖아요.\"", "\"할아버지를 많이 의지하셨나봐요. 할아버지 이야기 좀 해주세요.\""]'::jsonb, 5, NULL, NULL, '{"1": "단순히 겁을 인정하는 대화보다는 감정을 나누는 것이 더 중요하다.\n[정답]", "5": "할아버지에 대한 긍정적인 기억을 회상하도록 유도하여 안정감을 줄 수 있다.", "3": "과거의 사실을 진술하는 것은 대처로 적절하지 않다.", "4": "환자가 느끼는 감정을 이해하지 않고 비판하는 것은 좋지 않다.", "2": "부정적인 언행은 환자의 불안을 더욱 악화시킬 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Hội chứng suy giảm trí nhớ", "def_ko": "기억력과 사고 능력 저하", "def_vi": "Suy giảm khả năng ghi nhớ và tư duy"}, {"term_ko": "대처방법", "term_vi": "Phương pháp ứng phó", "def_ko": "상황에 적절히 대응하는 방법", "def_vi": "Cách đối phó phù hợp với tình huống"}, {"term_ko": "정서적 지지", "term_vi": "Hỗ trợ tinh thần", "def_ko": "정서적으로 지원하는 것", "def_vi": "Hỗ trợ về mặt cảm xúc"}, {"term_ko": "안정감", "term_vi": "Cảm giác ổn định", "def_ko": "심리적으로 편안한 상태", "def_vi": "Trạng thái tâm lý thoải mái"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1591, '12', '치매 대상자가 해질녘만 되면 다른 대상자의 사물함에서 옷을 꺼낼 때 대처방법은?', '["\"어르신 옷을 같이 찾아봐요.\"라며 이끈다.", "\"왜 남의 옷에 손을 대세요!\"라며 소리친다.", "다른 대상자에게 귓속말로 이해하라고 말한다.", "\"옷은 내일 찾고 주무세요.\"라고 하며 조명을 끈다.", "\"남의 옷을 마음대로 가져가면 안돼요.\"라며 옷을 정리한다."]'::jsonb, 1, NULL, NULL, '{"1": "''어르신 옷을 같이 찾아봐요.''라며 이끈다. - 긍정적이고 지지적인 대처로, 대상을 안정시키는 방법입니다.\n[정답]", "2": "''왜 남의 옷에 손을 대세요!''라며 소리친다. - 부정적인 반응으로, 대상자를 혼란스럽게 할 수 있습니다.", "3": "다른 대상자에게 귓속말로 이해하라고 말한다. - 비공식적인 방법으로 문제 해결에 도움이 되지 않을 수 있습니다.", "4": "''옷은 내일 찾고 주무세요.''라고 하며 조명을 끈다. - 해결책 제시보다는 회피하는 태도로, 적절하지 않습니다.", "5": "''남의 옷을 마음대로 가져가면 안돼요.''라며 옷을 정리한다. - 따지는 방식으로, 대상자에게 불쾌감을 줄 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh sa sút trí tuệ", "def_ko": "기억력 및 사고 능력의 저하(한국어)", "def_vi": "Sự suy giảm trí nhớ và khả năng suy nghĩ"}, {"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "도움이 필요한 사람(한국어)", "def_vi": "Người cần sự trợ giúp"}, {"term_ko": "대처방법", "term_vi": "Cách đối phó", "def_ko": "문제를 해결하기 위한 방법(한국어)", "def_vi": "Phương pháp giải quyết vấn đề"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1590, '12', '다음 상황에서 요양보호사의 대처방법은?시설 치매대상자가 해질녘이 되면 "죽어야 하는데...죽지도않는다."라며 운다.', '["죽음에 대해서 말하지 말라고 한다.", "눈물을 닦아주며 옆에 있어준다.", "나이 들면 누구나 드는 생각이라고 말한다.", "그렇게 말하는 사람이 더 오래 산다고 말한다.", "다른 대상자에게 피해가 되니 조용히 하라고 한다."]'::jsonb, 2, NULL, NULL, '{"1": "죽음에 대해서 말하지 말라고 한다. - 대상자의 감정을 무시하는 대처법입니다.\n[정답]", "2": "눈물을 닦아주며 옆에 있어준다. - 대상자의 감정을 공감하고 지지해주는 올바른 대처입니다.", "3": "나이 들면 누구나 드는 생각이라고 말한다. - 대상자의 감정을 간과하고 일반화하는 대처법입니다.", "4": "그렇게 말하는 사람이 더 오래 산다고 말한다. - 대화의 흐름을 이해하지 않는 비유적 표현입니다.", "5": "다른 대상자에게 피해가 되니 조용히 하라고 한다. - 대상자의 감정을 억압하는 대처법입니다."}'::jsonb, '[{"term_ko": "대처방법", "term_vi": "Phương pháp đối phó", "def_ko": "대처하는 방법(한국어)", "def_vi": "Cách phản ứng trong tình huống"}, {"term_ko": "눈물", "term_vi": "Nước mắt", "def_ko": "울때 나오는 액체(한국어)", "def_vi": "Chất lỏng chảy ra khi khóc"}, {"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 사고력이 저하되는 질환(한국어)", "def_vi": "Bệnh suy giảm trí nhớ và khả năng suy nghĩ"}, {"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "도움을 받는 사람(한국어)", "def_vi": "Người nhận được sự chăm sóc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1589, '12', '치매 대상자에게 발생하는 석양증후군의 문제 행동 유형으로 옳은 것은?', '["낮에는 유순하지만 저녁이 되면 방을 왔다갔다하며 불안해한다.", "짐을 싸다가 다시풀어놓는 행동을 반복한다.", "손에 만져지는 것은 무엇이든 먹으려고 한다.", "아무런 목적지도 없이 돌아다닌다.", "다른 사람이 자신의 물건을 훔쳐갔다고 의심하며 화를 낸다."]'::jsonb, 1, NULL, NULL, '{"1": "낮에는 유순하지만 저녁이 되면 방을 왔다갔다하며 불안해한다. [정답] 이는 석양증후군에서 흔히 나타나는 행동으로, 저녁 시간에 불안이 증가하는 것을 의미합니다.", "2": "짐을 싸다가 다시풀어놓는 행동을 반복한다. 이 행동은 석양증후군과 관련이 적습니다.", "3": "손에 만져지는 것은 무엇이든 먹으려고 한다. 이는 다른 행동 유형으로, 석양증후군과는 직접적인 연관이 없습니다.", "4": "아무런 목적지도 없이 돌아다닌다. 이 행동은 석양증후군의 일부로 볼 수 있으나, 더 일반적인 행동입니다.", "5": "다른 사람이 자신의 물건을 훔쳐갔다고 의심하며 화를 낸다. 이는 편집증적 행동으로 석양증후군의 특성과는 다릅니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Nâng cao chức năng tâm thần", "def_ko": "기억 및 사고 능력의 지속적인 감소", "def_vi": "Giảm khả năng ghi nhớ và tư duy một cách liên tục"}, {"term_ko": "석양증후군", "term_vi": "Hội chứng chiều tà", "def_ko": "저녁에 행동 문제를 증가시키는 상태", "def_vi": "Tình trạng tăng cường vấn đề hành vi vào buổi tối"}, {"term_ko": "불안", "term_vi": "Lo lắng", "def_ko": "열린 마음 상태", "def_vi": "Trạng thái tâm trí lo âu"}, {"term_ko": "편집증", "term_vi": "Hoang tưởng", "def_ko": "타인에 대한 강한 의심 및 불신", "def_vi": "Sự nghi ngờ và bất tín nhiệm mạnh mẽ đối với người khác"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1588, '12', '치매 대상자가 석양증후군으로 밤에 잠을 못 잘 때 돕는 방법은?', '["수면제를 제공한다.", "낮에 움직이거나 활동하게 한다.", "혼자 쉴 수 있는 시간을 준다.", "텔레비전을 끄고 조명을 은은하게 해준다.", "낮 시간에 프로그램 참여를 제한한다."]'::jsonb, 2, NULL, NULL, '{"1": "수면제를 제공하는 것은 의존성을 초래할 수 있습니다.\n[정답]", "2": "낮에 움직이거나 활동하게 하는 것은 밤에 수면을 개선하는 데 도움을 줍니다.", "3": "혼자 쉴 수 있는 시간을 주면 좋지만, 활동적인 낮이 더 효과적입니다.", "4": "조명을 은은하게 해주는 것 또한 중요하나 낮 동안의 활동이 우선입니다.", "5": "낮 시간에 프로그램 참여를 제한하는 것은 오히려 부정적 영향을 미칠 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력의 저하와 인지기능의 감소가 있는 질병", "def_vi": "Một bệnh lý mà khả năng ghi nhớ và chức năng nhận thức suy giảm"}, {"term_ko": "석양증후군", "term_vi": "Hội chứng hoàng hôn", "def_ko": "저녁에 증상이 악화되는 현상", "def_vi": "Hiện tượng triệu chứng xấu đi vào buổi tối"}, {"term_ko": "수면제", "term_vi": "Thuốc an thần", "def_ko": "수면을 유도하는 약물", "def_vi": "Thuốc giúp tạo giấc ngủ"}, {"term_ko": "혼자", "term_vi": "Một mình", "def_ko": "다른 사람 없이", "def_vi": "Không có người khác"}, {"term_ko": "조명", "term_vi": "Ánh sáng", "def_ko": "빛을 비추는 장치", "def_vi": "Thiết bị chiếu sáng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1587, '12', '시설 치매대상자가 내가 대장이다! 나를 따르라!라고 소리를 지르며 따라오지 않는 다른 대상자에게 화를 낼 때 대처방법은?', '["진짜 대장같이 멋있다고 칭찬해 준다.", "행동이 잦아들 때까지 자리를 피한다.", "모든 대상자들을 대장놀이에 참여시킨다.", "오늘만 대장하고 내일은 다른 사람 시키자고 한다.", "좋아하는 드라마를 보자며 텔레비전을 틀어준다."]'::jsonb, 5, NULL, NULL, '{"1": "진짜 대장 같다고 칭찬하는 것은 오히려 환자의 행동을 부추길 수 있습니다.\n[정답]", "2": "행동이 잦아들 때까지 자리를 피하는 것은 환자의 감정을 무시할 수 있습니다.", "3": "모든 대상자를 대장놀이에 참여시키는 것은 상황을 더 복잡하게 만들 수 있습니다.", "4": "오늘만 대장으로 하고 내일은 다른 사람 시키자고 하는 것은 일관성이 없으므로 환자를 혼란스럽게 만들 수 있습니다.", "5": "좋아하는 드라마를 보자며 텔레비전을 틀어주는 것은 환자의 집중을 다른 곳으로 돌리는 효과적인 방법입니다."}'::jsonb, '[{"term_ko": "시설", "term_vi": "Đơn vị", "def_ko": "기관, 시설", "def_vi": "cơ sở, tổ chức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1586, '12', '치매 대상자가 큰 소리로 욕을 하며 의자를 던지려고 할 때 대처방법은?', '["신속하게 자리를 피한다.", "힘으로 제압하며 진정시킨다.", "방 안에 혼자 있게 하여 행동을 수정한다.", "화가 난 것을 이해 한다고 부드럽게 말한다.", "폭력적인 행동을 계속하면 퇴소시킨다고 경고한다."]'::jsonb, 4, NULL, NULL, '{"1": "신속하게 자리를 피하는 것은 상황을 악화시킬 수 있다.\n[정답]", "4": "화가 난 것을 이해한다고 부드럽게 말하는 것은 치매 대상자의 감정을 인정하고 안정시킬 수 있다.", "2": "힘으로 제압하는 것은 폭력을 유발할 수 있으므로 바람직하지 않다.", "3": "혼자 있게 하는 것은 외롭고 두려움을 느끼게 할 수 있다.", "5": "퇴소 경고는 상황을 더욱 악화시킬 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 사고력의 약화로 인한 질병", "def_vi": "Bệnh do suy yếu trí nhớ và khả năng suy luận"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1585, '12', '치매 대상자가 흥분하여 탁자를 치며 난폭한 행동을 보일 때 대처방법은?', '["탁자를 다른 곳으로 치운다.", "힘으로 제압하여 행동을 제지한다.", "흥분이 가라앉을 때까지 지켜본다.", "정원으로 데리고 나가 안정시킨다.", "권위적이고 강압적인 태도로 경고한다."]'::jsonb, 4, NULL, NULL, '{"1": "탁자를 다른 곳으로 치우는 것은 상황을 악화시킬 수 있습니다.\n[정답]", "4": "정원으로 데리고 나가 안정시키는 것이 가장 효과적인 방법입니다.", "2": "힘으로 제압하는 것은 더 큰 문제를 일으킬 수 있습니다.", "3": "흥분이 가라앉을 때까지 지켜보는 것은 위험할 수 있습니다.", "5": "권위적이고 강압적인 태도의 경고는 오히려 대상자의 불안을 증가시킬 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력과 인지 기능의 저하", "def_vi": "Sự suy giảm trí nhớ và khả năng nhận thức"}, {"term_ko": "흥분", "term_vi": "Hưng phấn", "def_ko": "감정이 격해지거나 뜨거워지는 상태", "def_vi": "Trạng thái cảm xúc tăng cao hoặc nóng nảy"}, {"term_ko": "난폭한", "term_vi": "Bạo lực", "def_ko": "폭력적이거나 통제되지 않는 상태", "def_vi": "Tình trạng bạo lực hoặc không thể kiểm soát"}, {"term_ko": "대처방법", "term_vi": "Phương pháp xử lý", "def_ko": "문제를 해결하기 위한 행동이나 방법", "def_vi": "Hành động hoặc phương pháp để giải quyết vấn đề"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1584, '12', '프로그램에 참여 중이던 치매 대상자가 흥분하여 갑자기 고함을 지르며 공격적인 행동을 할 때 대처방법은?', '["참여 중인 활동을 중지하고 다른 자극을 주지 않는다.", "스스로 화가 풀릴 때까지 그대로 둔다.", "모든 프로그램에서 제외시킨다고 경고한다.", "다른 프로그램을 진행하여 관심변화를 유도한다.", "진정된 후 대상자의 이상 행동을 상기시킨다."]'::jsonb, 1, NULL, NULL, '{"1": "참여 중인 활동을 중지하고 다른 자극을 주지 않는다. (이 방법은 대상자가 흥분할 때 즉각적인 대처로 효과적입니다.)\n[정답]", "2": "스스로 화가 풀릴 때까지 그대로 둔다. (이 방법은 대상자를 방치하는 것이므로 바람직하지 않습니다.)", "3": "모든 프로그램에서 제외시킨다고 경고한다. (이 방법은 대상자의 불안감을 증가시킬 수 있습니다.)", "4": "다른 프로그램을 진행하여 관심변화를 유도한다. (대상자가 흥분했을 때 즉각적으로 다른 자극은 부적절할 수 있습니다.)", "5": "진정된 후 대상자의 이상 행동을 상기시킨다. (이 방법은 흥분 상태에서는 효과적이지 않으며, 이후에 조치하는 것이 좋습니다.)"}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người tham gia", "def_ko": "환자 또는 구성원", "def_vi": "Bệnh nhân hoặc thành viên"}, {"term_ko": "흥분", "term_vi": "Hưng phấn", "def_ko": "감정적으로 긴장한 상태", "def_vi": "Trạng thái cảm xúc căng thẳng"}, {"term_ko": "공격적인 행동", "term_vi": "Hành vi tấn công", "def_ko": "남을 해치거나 위협하는 행동", "def_vi": "Hành động gây hại hoặc đe dọa đến người khác"}, {"term_ko": "참여", "term_vi": "Tham gia", "def_ko": "어떤 활동에 참여함", "def_vi": "Tham gia vào một hoạt động"}, {"term_ko": "진정", "term_vi": "Trấn tĩnh", "def_ko": "마음이나 감정을 편안하게 만드는 것", "def_vi": "Làm dịu tâm trí hoặc cảm xúc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1583, '12', '치매 대상자가 시설에서 같은 방을 쓰는 동료 노인과 마주칠 때마다, 욕하고 화를 내며 매일 말싸움을 할 때 돕는 방법은?', '["단호한 어조로 제지한다.", "싸울 때마다 사과하게 한다.", "왜 그러는지 이유를 물어본다.", "퇴소할 수 있다고 경고한다.", "방을 바꾸어서 서로 마주치지 않게 한다."]'::jsonb, 5, NULL, NULL, '{"1": "단호한 어조로 제지한다: 이 방법은 상황을 악화시킬 수 있으며, 대상자의 감정을 헤아리지 못하는 방식이다.\n[정답]", "5": "방을 바꾸어서 서로 마주치지 않게 한다: 이는 근본적인 문제 해결로, 서로 간의 갈등을 예방하는 방법이다.", "3": "왜 그러는지 이유를 물어본다: 대상자가 감정적으로 어려움을 겪고 있는 상황에서 이해를 요청하는 것은 불필요할 수 있다.", "4": "퇴소할 수 있다고 경고한다: 이는 대상자에게 위협을 주어 심리적 부담만 가중할 수 있다.", "2": "싸울 때마다 사과하게 한다: 이는 문제를 해결하기보다는 대처를 그르치는 결과를 초래할 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "질병(한국어)", "def_vi": "Bệnh thiếu trí nhớ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1582, '12', '치매 대상자에게 나타나는 파괴적 행동의 특징은?', '["매일 반복적으로 나타난다.", "질병 초기에 나타난다.", "에너지가 소모되어도 계속된다.", "수개월 이상 지속된다.", "치매 대상자 모두에게 나타나는 증상이다."]'::jsonb, 2, NULL, NULL, '{"1": "매일 반복적으로 나타나는 것은 아닙니다. 치매에 따라 다르기 때문입니다.\n[정답]", "2": "질병 초기에 나타나는 특징으로 빈번하게 감지가 됩니다.", "3": "에너지가 소모되더라도 일시적일 수 있습니다.", "4": "수개월 이상 지속될 수도 있지만 개인차가 큽니다.", "5": "모든 치매 대상자에게 나타나는 증상은 아닙니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 인지 기능이 저하되는 상태", "def_vi": "Tình trạng suy giảm trí nhớ và chức năng nhận thức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1581, '12', '다음과 같은 치매 대상자의 문제행동 유형은?• 난폭한 행동이 자주 일어나지 않는다. • 난폭한 행동이 오래 지속되지 않는다. • 초기 분노 에너지가 소모되면 행동을 중지한다.', '["파괴적 행동", "망상", "배회", "석양증후군", "섬망"]'::jsonb, 1, NULL, NULL, '{"1": "파괴적 행동: 난폭한 행동이 주된 특성이며, 이 문제의 설명에 부합함.\n[정답]", "2": "망상: 비현실적인 믿음이나 생각을 나타내는 행동이지만, 난폭한 행동과는 관련이 적음.", "3": "배회: 정처 없이 돌아다니는 행동으로, 문제에서 제시된 특성과 일치하지 않음.", "4": "석양증후군: 저녁에 더 심해지는 행동 양상으로, 여기서 설명하는 상황과 맞지 않음.", "5": "섬망: 혼란 상태를 의미하며, 난폭한 행동과는 구별되는 개념임."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억 상실과 인지 기능 저하를 특징으로 하는 질병", "def_vi": "Bệnh có đặc trưng là mất trí nhớ và suy giảm chức năng nhận thức"}, {"term_ko": "난폭한", "term_vi": "Hung hăng", "def_ko": "주위나 사람에게 해를 끼치는 행동", "def_vi": "Hành vi gây hại cho người khác hoặc môi trường xung quanh"}, {"term_ko": "파괴적", "term_vi": "Phá hoại", "def_ko": "무언가를 부수거나 해치려는 성향", "def_vi": "Xu hướng muốn đập vỡ hoặc làm hại cái gì đó"}, {"term_ko": "망상", "term_vi": "Ảo giác", "def_ko": "비현실적인 믿음", "def_vi": "Niềm tin không thực tế"}, {"term_ko": "배회", "term_vi": "Lang thang", "def_ko": "방향 없이 돌아다니는 것", "def_vi": "Đi lang thang không có mục đích"}, {"term_ko": "석양증후군", "term_vi": "Hội chứng hoàng hôn", "def_ko": "저녁 시간에 나타나는 행동 양상", "def_vi": "Hành vi xảy ra vào buổi tối"}, {"term_ko": "섬망", "term_vi": "Rối loạn ý thức", "def_ko": "혼란 상태", "def_vi": "Tình trạng nhầm lẫn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1580, '12', '시설에서 생활하고 있는 치매 대상자가 다음과 같은 행동을 할 때 대처방법으로 옳은 것은?• 거실에 있는 의자가 자신의 것이라면서 다른 사람이 앉지 못하게 한다. • 다른 사람이 앉지 못하게 긴 의자를 혼자 차지하고 눕는다.', '["거실에 있는 의자를 없앤다.", "시설의 규칙을 단호하게 말한다.", "대상자를 거실에 나오지 못하게 한다.", "날짜를 지정하여 앉는 순서를 정한다.", "차분하게 대하고 다른 곳으로 관심을 유도한다."]'::jsonb, 5, NULL, NULL, '{"1": "거실에 있는 의자를 없애는 것은 대상자의 기본 권리를 침해할 수 있습니다.\n[정답]", "5": "차분하게 대하고 다른 곳으로 관심을 유도하는 방법은 대상자의 감정을 조절하고 긍정적인 방향으로 풀어나가는 데 도움이 됩니다.", "2": "시설의 규칙을 단호하게 말하는 것은 오히려 대립을 초래할 수 있습니다.", "3": "대상자를 거실에 나오지 못하게 하는 것은 사회적 고립을 초래할 수 있습니다.", "4": "날짜를 지정하여 앉는 순서를 정하는 것은 특정한 규칙성을 가져오지만, 대상자의 상태에 따라 불리할 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억, 사고, 행동의 변화로 인해 발생하는 증상", "def_vi": "Triệu chứng thay đổi về trí nhớ, suy nghĩ và hành vi"}, {"term_ko": "대상자", "term_vi": "Người đối tượng", "def_ko": "도움이 필요한 사람", "def_vi": "Người cần giúp đỡ"}, {"term_ko": "의자", "term_vi": "Ghế", "def_ko": "앉는 가구", "def_vi": "Đồ dùng ngồi"}, {"term_ko": "거실", "term_vi": "Phòng khách", "def_ko": "집의 한 부분", "def_vi": "Một phần của nhà"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1579, '12', '치매 대상자가 자신의 양말을 다른 사람이 훔쳐갔다고 의심하며 화를 낼 때 대처방법은?', '["누가 가져갔다고 생각되는지 물어본다.", "나중에 찾아주겠다고 단호하게 말한다.", "같은 양말을 준비했다가 쉽게 찾을 수 있게 한다.", "아무도 가져간 사람이 없다고 차분하게 설명한다.", "물건을 찾아주고 훈계한다."]'::jsonb, 3, NULL, NULL, '{"1": "누가 가져갔다고 생각되는지 물어보는 것은 환자의 불안감을 증폭시킬 수 있습니다.\n[정답]", "3": "같은 양말을 준비했다가 쉽게 찾을 수 있게 하는 것은 환자의 불안감을 해소하는 효과적인 방법입니다.", "2": "나중에 찾아주겠다고 단호하게 말하는 것은 환자의 감정을 이해하지 못하는 것으로 비춰질 수 있습니다.", "4": "아무도 가져간 사람이 없다고 차분하게 설명하는 것은 환자의 현실 인식과 다를 수 있어, 효과적이지 않을 수 있습니다.", "5": "물건을 찾아주고 훈계하는 것은 환자에게 부정적인 감정을 유발할 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh sa sút trí tuệ", "def_ko": "기억과 사고능력이 저하된 상태", "def_vi": "Tình trạng suy giảm trí nhớ và khả năng tư duy"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1578, '12', '치매 대상자가 도둑망상으로 자신의 방을 지키려고 고집을 부리는 경우 올바른 대처방법은?', '["도둑이 없다고 설득한다.", "귀중품은 맡겨 놓으라고 한다.", "위험하지 않으면 방에 있게 한다.", "화를 내며 방 밖으로 데리고 나간다.", "방 문을 잠그고 들어가지 못하게 한다."]'::jsonb, 3, NULL, NULL, '{"1": "도둑이 없다고 설득하는 것은 오히려 환자의 불안감을 증가시킬 수 있습니다.\n[정답]", "3": "위험하지 않으면 방에 있게 하는 것이 환자의 자율성을 존중하고 불필요한 스트레스를 줄이는 방법입니다.", "2": "귀중품을 맡기라고 하는 것은 환자의 어려움을 이해하지 못한 대처 방식입니다.", "4": "화를 내며 방 밖으로 데리고 나가는 것은 환자에게 불안과 스트레스를 초래할 수 있습니다.", "5": "방 문을 잠그고 들어가지 못하게 하는 것은 환자의 안전을 위협하는 방법이 될 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "기억력과 인지 기능의 감퇴가 나타나는 상태", "def_vi": "Tình trạng suy giảm trí nhớ và chức năng nhận thức"}, {"term_ko": "도둑망상", "term_vi": "Ảo tưởng trộm cắp", "def_ko": "누군가가 자신을 훔치려 한다는 잘못된 믿음", "def_vi": "Niềm tin sai lầm rằng có người muốn ăn cắp của mình"}, {"term_ko": "고집", "term_vi": "Cố chấp", "def_ko": "고집스럽게 주장하거나 반대하지 않고 계속 유지하는 것", "def_vi": "Đòi hỏi một cách cứng rắn hoặc kiên trì không thay đổi"}, {"term_ko": "대처방법", "term_vi": "Cách ứng phó", "def_ko": "문제를 해결하기 위한 방법", "def_vi": "Phương pháp để giải quyết vấn đề"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1577, '12', '시설에서 치매 대상자가 같은 방을 쓰는 다른 대상자를 가리키며 다음과 같이 말할 때, 요양보호사의 대처방법은?대상자: 저 여편네는 참 뻔뻔스러워. 남의 집에 들어와 살면서 몇 달 째 월세를 안 내고 있어 요양보호사: ( )', '["못 들은 척 하면서 반응하지 않는다.", "누구한테 그런 말을 들었는지 확인한다.", "월세 납입증명서를 임의로 만들어 보여준다.", "시설에 있는 사실을 지속저긍로 인식시킨다.", "다른 대상자에게 귓속말로 ''신경 쓰지 마세요''라고 이야기 해준다."]'::jsonb, 4, NULL, NULL, '{"1": "특정 상황에서 반응하지 않는 것은 부적절한 대응이다.\n[정답]", "4": "시설에 있는 사실을 지속적으로 인식시켜주는 것이 치매 환자에게 적절한 대처 방법이다.", "2": "누가 그런 말을 했는지 확인하는 것은 상황 해결에 도움이 되지 않는다.", "3": "임의로 증명서를 보여주는 것은 신뢰를 떨어뜨릴 수 있다.", "5": "다른 대상자에게 조용히 이야기하는 것은 문제가 해결되지 않는다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력과 사고 능력의 저하 질환", "def_vi": "Bệnh suy giảm trí nhớ và khả năng tư duy"}, {"term_ko": "대처방법", "term_vi": "Phương pháp đối phó", "def_ko": "문제에 대한 응답 또는 해결책", "def_vi": "Câu trả lời hoặc giải pháp cho một vấn đề"}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 전문인", "def_vi": "Người chăm sóc bệnh nhân"}, {"term_ko": "혼란", "term_vi": "Sự nhầm lẫn", "def_ko": "불확실한 상태", "def_vi": "Tình trạng không chắc chắn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1576, '12', '치매 대상자에게 식사를 제공할 때, 다음과 같은 경우 대처방법으로 옳은 것은?대상자: 누가 나를 죽이려고, 내 밥에 농약을 넣었어. 안 먹어 요양보호사: ( )', '["왜 농약을 넣었다고 생각하세요?", "경찰서에 신고할까요?", "그래요? 누가 넣었는지 보셨어요?", "안 넣었으니까 안심하고 드세요.", "제가 먼저 먹어볼게요. 같이 드세요."]'::jsonb, 5, NULL, NULL, '{"1": "왜 농약을 넣었다고 생각하세요? (대상자의 불안을 부추길 수 있는 질문입니다.)", "2": "경찰서에 신고할까요? (이 또한 대상자의 불안을 증가시킬 수 있습니다.)", "3": "그래요? 누가 넣었는지 보셨어요? (의심을 더욱 키우는 질문으로 잘못된 대처입니다.)\n[정답]", "4": "안 넣었으니까 안심하고 드세요. (대상자의 감정을 무시하고, 단순한 대답으로 심리적 안정을 주지 못합니다.)", "5": "제가 먼저 먹어볼게요. 같이 드세요. (이 행동은 대상자의 불안을 줄이고, 식사에 대한 신뢰를 주는 대처입니다.)"}'::jsonb, '[{"term_ko": "치매", "term_vi": "Người mất trí nhớ", "def_ko": "기억 상실과 인지 기능 저하", "def_vi": "Người có sự suy giảm trí nhớ và chức năng nhận thức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1575, '12', '치매 대상자가 갈비 굽는 냄새가 난다며 없는 갈비를 달라고 할 때 요양보호사의 대처방법은?', '["\"무슨 말씀이세요. 갈비는 없어요.\"", "\"조금 전에 같이 갈비 먹었잖아요.\"", "\"갈비가 드시고 싶군요. 함께 사러 나가요.\"", "\"있지도 않은 갈비 냄새가 어디서 난다고 그러세요?\"", "\"어제도 그러시더니 오늘 또 그러시네요.\""]'::jsonb, 3, NULL, NULL, '{"1": "치매 환자의 필요를 무시하는 태도를 보임. 이는 오히려 상처를 줄 수 있음.", "2": "환자의 기억을 부정하여 혼란을 줄 수 있어 부적절함.\n[정답]", "3": "환자의 감정을 인정하고 함께 행동함으로써 긍정적인 대처가 됨.", "4": "치매 환자의 감정을 무시하는 태도를 보이며 부적절한 대처임.", "5": "같은 행동을 반복적으로 언급하여 환자를 혼란스럽게 할 수 있음."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억과 사고 능력에 장애가 있는 질병", "def_vi": "Bệnh gây cản trở khả năng nhớ và suy nghĩ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1574, '12', '치매 대상자가 자신의 지갑을 잃어버렸다며 의심할 때 대처방법은?', '["함께 경찰서에 가서 신고하자고 말한다.", "원래부터 지갑은 없었다고 인식시킨다.", "지갑에 돈을 얼마나 넣어두었는지 물어본다.", "평소에 지갑을 두는 장소로 같이 가서 찾아본다.", "지갑은 시설에서 보관하고 있다고 설명한다."]'::jsonb, 4, NULL, NULL, '{"1": "경찰서에 신고하는 것은 치매 환자에게 추가적인 스트레스를 줄 수 있다.\n[정답]", "4": "지갑을 두는 장소로 같이 가서 찾아보는 것은 치매 대상자의 기억을 자극하고 안정을 줄 수 있는 방법이다.", "2": "지갑이 없었다고 인식시키는 것은 환자의 현실 감각을 혼란스럽게 한다.", "3": "돈의 양을 묻는 것은 환자의 불안감을 증대시킬 수 있다.", "5": "시설에서 보관하고 있다고 설명하는 것은 환자의 불안감을 해소하지 못할 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억이나 인지 기능의 장애", "def_vi": "Rối loạn trí nhớ hoặc khả năng nhận thức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1573, '12', '치매 대상자가 자신의 반지를 누가 훔쳐 갔다며 의심할 때 대처방법은?', '["반지를 함께 찾아본다.", "남을 의심하시면 안 된다고 말한다.", "똑같은 반지를 사 주겠다고 다독인다.", "평소에 귀중품 두는 곳을 알려 달라고 한다.", "눈가 반지를 가져갔다고 생각하는지 물어본다."]'::jsonb, 1, NULL, NULL, '{"1": "치매 환자에게 반지를 함께 찾아본다고 하면 그들의 불안을 해소하는 데 도움을 줄 수 있다.\n[정답]", "2": "남을 의심하면 안 된다고 말하는 것은 오히려 환자의 감정을 상처받게 할 수 있다.", "3": "똑같은 반지를 사 주겠다고 다독이는 것은 일시적인 진정이 될 수 있지만 근본적인 문제 해결이 아니다.", "4": "평소 귀중품 두는 곳을 알려 달라고 하는 것은 환자가 불안함을 더 느낄 수 있는 방법이다.", "5": "눈가 반지를 가져갔다고 생각하는지 물어보는 것은 환자의 의심을 더 부추길 수 있는 접근이다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력이나 사고력을 잃는 병", "def_vi": "Bệnh mất khả năng ghi nhớ hoặc tư duy"}, {"term_ko": "대처", "term_vi": "Xử lý", "def_ko": "어떤 상황에 대한 반응이나 처리", "def_vi": "Phản ứng hoặc xử lý với một tình huống"}, {"term_ko": "의심", "term_vi": "Nghi ngờ", "def_ko": "의심하는 마음", "def_vi": "Tâm trạng nghi ngờ"}, {"term_ko": "반지", "term_vi": "Nhẫn", "def_ko": "손가락에 끼는 장신구", "def_vi": "Trang sức được đeo trên ngón tay"}, {"term_ko": "귀중품", "term_vi": "Đồ quý giá", "def_ko": "소중한 물건", "def_vi": "Những vật phẩm quý giá"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1572, '12', '망상증이 있는 치매 대상자가 아들이 내 퇴직금 통장을 가져갔어.라며 화를 낼 때 대처방법은?', '["아들에게 연락하여 확인한다.", "통장을 직접 찾아서 건네준다.", "아들은 그럴 사람이 아니라고 말한다.", "통장을 가져가는 것을 보았는지 물어본다.", "이야기를 들어 주며 속상하겠다고 다독인다."]'::jsonb, 5, NULL, NULL, '{"1": "아들에게 연락하여 확인한다.\n상대방의 망상에 대해 직접적인 확인을 시도하는 것은 환자의 감정을 더 상하게 할 수 있습니다.\n\n[정답]", "5": "이야기를 들어 주며 속상하겠다고 다독인다.\n환자의 감정을 공감하고 듣는 것이 중요합니다.", "3": "아들은 그럴 사람이 아니라고 말한다.\n환자의 생각을 부정하는 것은 신뢰를 잃게 할 수 있습니다.", "4": "통장을 가져가는 것을 보았는지 물어본다.\n망상에 대한 추가 질문은 환자의 불안을 증대시킬 수 있습니다.", "2": "통장을 직접 찾아서 건네준다.\n환자의 요구를 즉시 충족시키는 것은 적절한 대처가 아닙니다."}'::jsonb, NULL) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1571, '12', '치매 대상자가 아무도 없는 창밖을 보면서 우리 아들 왔네! 엄마가 금방 나갈게. 라고 할 때 대처방법은?', '["\"밖에는 아무도 없어요.\" 라며 커튼을 친다.", "\"아들이 보고 싶군요.\" 라며 손을 잡아둔다.", "\"밖에 사람이 잇는지 눈을 크게 뜨고 보세요.\"라고 말한다.", "\"기력이 없으셔서 헛것이 보이는 거예요.\"라며 간식을 준다.", "\"아들을 지금 회사에서 일하고 있어요.\"라며 하던 일을 계속한다."]'::jsonb, 2, NULL, NULL, '{"1": ""}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "중증의 기억력 및 인지 기능 장애", "def_vi": "Rối loạn nghiêm trọng về trí nhớ và chức năng nhận thức"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "도움을 받는 사람", "def_vi": "Người nhận trợ giúp"}, {"term_ko": "대처방법", "term_vi": "Phương pháp ứng phó", "def_ko": "문제에 대처하는 방법", "def_vi": "Cách đối phó với vấn đề"}, {"term_ko": "간식", "term_vi": "Bánh nhẹ", "def_ko": "간단한 음식이나 간편한 음식을 가리킴", "def_vi": "Thức ăn nhẹ hoặc thực phẩm đơn giản"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1570, '12', '시설 치매대상자가 사무실로 뛰어 들어와 누군가 나를 잡으러 왔어.라며 책상 밑으로 숨을 때 대처방법은?', '["무슨 사건인지 이야기하게 한다.", "잡으러 온 사람이 누구인지 물어본다.", "책상 밑은 위험하다고 차분히 설명한다.", "시설에는 아무도 못들어온다고 말한다.", "이제 가고 없다며 안심시키고 같이 있어 준다."]'::jsonb, 5, NULL, NULL, '{"1": "무슨 사건인지 이야기하게 하여 상황을 진정시키고 이해시킬 수 있다.\n[정답]", "5": "이제 가고 없다며 안심시키고 같이 있어 주는 것이 최선의 방법이다.", "2": "잡으러 온 사람이 누구인지 물어보면 상황이 더욱 불안해질 수 있다.", "3": "책상 밑이 위험하다고 차분히 설명하는 것은 대상자가 듣지 못할 수 있다.", "4": "시설에는 아무도 못들어온다고 말하는 것은 신뢰를 떨어뜨릴 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Mất trí nhớ", "def_ko": "기억과 인지 기능이 저하되는 상태", "def_vi": "Tình trạng suy giảm trí nhớ và chức năng nhận thức"}, {"term_ko": "사무실", "term_vi": "Văn phòng", "def_ko": "업무를 수행하는 공간", "def_vi": "Không gian làm việc"}, {"term_ko": "대처방법", "term_vi": "Cách ứng phó", "def_ko": "문제 상황에 대응하는 방법", "def_vi": "Phương pháp đối phó với tình huống"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1569, '12', '치매 할아버지가 키가 작고 파마머리를 한 요양보호사만 보면 여보라고 부르며 따라 다닌다. 대처방법으로 옳은 것은?', '["(따뜻하게 손을 잡으며) \"할머니는 돌아가셨어요.\"", "(정색하며) \"할아버지 저는 할머니가 아니여요.\"", "(마주보며) \"할머니가 보고싶으신가 봐요.\"", "(웃으며) \"여보 불렀어요?\"", "(가까이 가서) \"제가 할머니로 보이세요?\""]'::jsonb, 3, NULL, NULL, '{"1": "(할아버지가 혼란스러워할 수 있으므로 부드럽게 설명하는 것이 좋지만, 감정적 지지를 제공하기보다는 직접적인 거부감이 생길 수 있다.)\n[정답]", "3": "(할아버지의 감정을 인정하며 대화를 시도하는 것이 가장 적절하다.)", "2": "(정색은 할아버지를 더 혼란스럽게 할 수 있으므로 바람직하지 않다.)", "4": "(웃음을 통해 상황을 넘길 수는 있지만, 할아버지의 감정을 소중히 여기는 것이 좋다.)", "5": "(제자리에 서 있으면서 할아버지를 더 혼란스럽게 만들 수 있다.)"}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh sa sút trí tuệ", "def_ko": "기억력과 사고의 능력이 줄어드는 질병", "def_vi": "Căn bệnh giảm khả năng ghi nhớ và tư duy"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1568, '12', '시설 치매대상자가 자신의 집으로 가겠다며 소란을 피울 때 요양보호사의 반응으로 적절한 것은?', '["\"혼자서는 집에 못 가시잖아요.\"", "\"저기 앉아서 텔레비전 보세요.\"", "\"집에 가도 이제 아무도 없어요.\"", "\"어르신이 나가시면 제가 원장님께 혼나요.\"", "\"아들이 모시러 올 때까지 우리 퍼즐 맞춰요.\""]'::jsonb, 5, NULL, NULL, '{"1": "혼자서 집에 가기 어려운 상황을 설명하며 대화를 유도하려는 의도나 다소 부정적인 반응입니다.", "2": "치매 대상자의 관심을 다른 곳으로 돌리려는 시도지만, 효과적이지 않을 수 있습니다.", "3": "집에 아무도 없다는 이야기는 대상자의 감정을 상하게 할 수 있습니다.", "4": "원장님께 혼날 수 있다는 표현도 대상자에게 부정적인 감정을 유발할 수 있습니다.\n[정답]", "5": "아들이 올 때까지 함께 퍼즐을 맞추자는 제안은 대상자의 감정을 존중하고, 긴장을 완화시킬 수 있는 긍정적인 반응입니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억 또는 사고 능력 감소로 인해 일상생활에 어려움이 있는 상태", "def_vi": "Tình trạng giảm khả năng nhớ hoặc tư duy gây khó khăn trong sinh hoạt hàng ngày"}, {"term_ko": "소란", "term_vi": "Sự ồn ào", "def_ko": "시끄럽고 분주한 상태", "def_vi": "Trạng thái ồn ào và bận rộn"}, {"term_ko": "반응", "term_vi": "Phản ứng", "def_ko": "상황에 대한 반응", "def_vi": "Phản ứng đối với một tình huống"}, {"term_ko": "퍼즐", "term_vi": "Đồ chơi ghép hình", "def_ko": "서로 맞춰야 하는 조각들로 이루어진 게임", "def_vi": "Trò chơi bao gồm các mảnh ghép cần phải khớp với nhau"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1567, '12', '야간에 거실에서 배회하는 치매 대상자를 돕는 방법으로 옳은 것은?', '["새로운 방으로 바꾸어 준다.", "실내조명을 어둡게 하여 동선을 줄인다.", "실외에 배회 코스를 만들어 다녀오게 한다.", "현관문을 열어 신선한 공기를 마시게 한다.", "학창시절에 대한 이야기를 하며 추억을 나눈다."]'::jsonb, 5, NULL, NULL, '{"1": "새로운 방으로 바꾸어 준다: 치매 환자에게 새로운 환경은 혼란을 줄 수 있다. \n[정답]", "5": "학창시절에 대한 이야기를 하며 추억을 나눈다: 치매 환자와의 감정적 유대감을 높이는 데 도움이 된다.", "3": "실외에 배회 코스를 만들어 다녀오게 한다: 외부 환경이 위험할 수 있어 적절하지 않다.", "4": "현관문을 열어 신선한 공기를 마시게 한다: 안전상 문제가 될 수 있다.", "2": "실내조명을 어둡게 하여 동선을 줄인다: 어두운 환경은 불안감을 증가시킬 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억이나 사고 능력이 감퇴되는 상태", "def_vi": "Tình trạng suy giảm khả năng nhớ hoặc suy nghĩ"}, {"term_ko": "배회", "term_vi": "Đi lang thang", "def_ko": "정해진 장소를 벗어나 돌아다님", "def_vi": "Đi ra ngoài khu vực đã xác định"}, {"term_ko": "충분한", "term_vi": "Đầy đủ", "def_ko": "양이 많이 있음", "def_vi": "Có nhiều lượng"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "위험이 없는 상태", "def_vi": "Tình trạng không có nguy hiểm"}, {"term_ko": "추억", "term_vi": "Kỉ niệm", "def_ko": "과거의 기억", "def_vi": "Kỷ niệm từ quá khứ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1566, '12', '치매 대상자가 남편 밥을 해줘야 한다며 집에 가야 돼.라고 말할 때 대처방법은?', '["\"저랑 같이 가실까요?\"라며 산책을 한다.", "\"남편은 식사했어요.\"라고 안심시킨다.", "\"아들이 와야 나가실 수 있어요.\"라고 말한다.", "\"이제는 어르신만 신경 쓰세요!\"라고 말한다.", "\"밖이 어두워져서 갈 수 없어요.\"라며 단념시킨다."]'::jsonb, 1, NULL, NULL, '{"1": "환자를 안심시키며 산책하는 것은 긍정적인 대처 방법이다.\n[정답]", "2": "''남편은 식사했어요.''라는 말은 사실을 기반으로 하지만, 안심시키는 방법으로 더 좋은 접근이 필요하다.", "3": "아들의 방문을 기다려야 한다고 말하는 것은 환자의 불안을 증가시킬 수 있다.", "4": "어르신만 신경 쓰라는 것은 환자의 감정을 무시한 표현으로 적절하지 않다.", "5": "밖이 어두워져서 간섭하는 것은 환자를 더 불안하게 할 수 있는 방법이다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억을 잃고 정신적인 기능이 저하된 상태", "def_vi": "Tình trạng mất khả năng ghi nhớ và suy giảm chức năng tinh thần"}, {"term_ko": "대처방법", "term_vi": "Phương pháp đối phó", "def_ko": "상황에 따라 적절한 처치를 하는 방식", "def_vi": "Cách xử lý phù hợp trong từng tình huống"}, {"term_ko": "안심시키다", "term_vi": "Yên tâm", "def_ko": "걱정을 덜어 주고 안전감을 주다", "def_vi": "Giảm bớt lo lắng và mang lại cảm giác an toàn"}, {"term_ko": "신경 쓰다", "term_vi": "Chú ý", "def_ko": "주의하거나 염려하다", "def_vi": "Quan tâm hoặc lo lắng về điều gì đó"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1565, '12', '치매 대상자가 목적 없이 집 안의 이곳저곳을 배회할 때 대처방법은?', '["배회하지 못하게 주의를 준다.", "색칠하기 활동을 하게 한다.", "취침 직전에 운동량을 늘려 준다.", "증상이 사라질 때까지 기다려준다.", "밖으로 나가 집 주변을 걷게 한다."]'::jsonb, 2, NULL, NULL, '{"1": "배회하지 못하게 주의를 준다.\n배회가 자연스러운 상태일 경우, 피해갈 수 없는 반응이기 때문에 주의를 주는 것은 효과적이지 않다.\n[정답]", "2": "색칠하기 활동을 하게 한다.\n색칠하기 활동은 집중력을 향상시키고 배회하는 행동을 줄이는 데 도움을 줄 수 있다.", "3": "취침 직전에 운동량을 늘려 준다.\n운동량을 늘리는 것은 수면에 도움이 될 수 있지만, 배회 행동을 직접적으로 감소시키지는 않는다.", "4": "증상이 사라질 때까지 기다려준다.\n단순히 기다리는 것은 반응적이지 않으며, 예방적 접근이 필요하다.", "5": "밖으로 나가 집 주변을 걷게 한다.\n밖으로 나가는 활동은 오히려 불안감을 증가시킬 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억 상실증, 인지 장애를 초래하는 질병", "def_vi": "Bệnh gây ra sự suy giảm trí nhớ và chức năng nhận thức"}, {"term_ko": "배회", "term_vi": "Đi lang thang", "def_ko": "목적 없이 돌아다니는 것", "def_vi": "Đi lại không có mục đích"}, {"term_ko": "주지", "term_vi": "Nhắc nhở", "def_ko": "주의하여 알려줌", "def_vi": "Nhắc nhở một cách chú ý"}, {"term_ko": "운동량", "term_vi": "Mức độ vận động", "def_ko": "신체 활동의 정도", "def_vi": "Mức độ hoạt động thể chất"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "병의 징후", "def_vi": "Dấu hiệu của bệnh"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1564, '12', '치매 대상자가 야간에 실내에서 계속 배회할 때 대처방법은?', '["따뜻한 녹차를 제공한다.", "이불과 베개를 새것으로 바꿔준다.", "실내조명을 끄고 침대에 눕게 한다.", "출입이 가능한 모든 곳의 문을 잠근다.", "빨래를 개면서 에너지를 소모하게 한다."]'::jsonb, 4, NULL, NULL, '{"1": "따뜻한 녹차를 제공하는 것은 이완 효과를 줄 수 있지만, 해결책이 아닙니다.\n[정답]", "4": "출입이 가능한 모든 곳의 문을 잠그는 것이 안전하게 보호할 수 있는 방법입니다.", "2": "이불과 베개를 새것으로 바꿔주는 것만으로는 문제를 해결할 수 없습니다.", "3": "실내조명을 끄고 침대에 눕게 하는 것은 오히려 불안감을 증대시킬 수 있습니다.", "5": "빨래를 개는 것은 에너지를 소모하게 할 수 있지만, 배회 행동을 예방하는 방법이 아닙니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "기억이나 인지 기능에 장애가 있는 상태", "def_vi": "Trạng thái rối loạn trí nhớ hoặc chức năng nhận thức"}, {"term_ko": "대상자", "term_vi": "Người nhận dịch vụ", "def_ko": "특정한 서비스를 받는 사람", "def_vi": "Người nhận dịch vụ cụ thể"}, {"term_ko": "야간", "term_vi": "Ban đêm", "def_ko": "밤 시간", "def_vi": "Thời gian vào ban đêm"}, {"term_ko": "배회", "term_vi": "Đi lang thang", "def_ko": "같은 곳을 이리 저리 돌아다니는 행동", "def_vi": "Hành vi di chuyển qua lại ở cùng một nơi"}, {"term_ko": "실내", "term_vi": "Trong nhà", "def_ko": "내부 공간", "def_vi": "Không gian nội bộ"}, {"term_ko": "출입", "term_vi": "Ra vào", "def_ko": "들어오고 나가는 것", "def_vi": "Vào và ra"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1563, '12', '야간에 배회하는 치매 대상자를 돕는 방법은?', '["침대 옆에 옷가지를 걸어 둔다.", "복잡한 일을 주어 집중하게 한다.", "집 안의 보행로를 따라 걷게 한다.", "실내조명을 어둡게 하여 동선을 줄인다.", "창문을 열어 신선한 공기를 마시게 한다."]'::jsonb, 3, NULL, NULL, '{"1": "침대 옆에 옷가지를 걸어 두는 것은 효과적일 수 있지만, 환자가 혼란스러워질 수 있습니다.\n[정답]", "3": "집 안의 보행로를 따라 걷게 하는 것은 안정감을 제공하고 배회하는 것을 줄이는 데 도움을 줄 수 있습니다.", "2": "복잡한 일을 주어 집중하게 하는 것은 오히려 혼란을 유발할 수 있습니다.", "4": "실내조명을 어둡게 하여 동선을 줄이는 것은 안전에 좋지 않을 수 있습니다.", "5": "창문을 열어 신선한 공기를 마시게 하는 것은 도움이 되지만, 배회하는 행동을 직접적으로 해결하지는 않습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력과 사고 능력이 저하되는 질환", "def_vi": "Bệnh giảm trí nhớ và khả năng tư duy"}, {"term_ko": "배회", "term_vi": "Đi lang thang", "def_ko": "정해진 경로 없이 돌아다니는 것", "def_vi": "Đi lại mà không có lộ trình xác định"}, {"term_ko": "조명", "term_vi": "Ánh sáng", "def_ko": "빛을 제공하는 장치", "def_vi": "Thiết bị cung cấp ánh sáng"}, {"term_ko": "안정감", "term_vi": "Cảm giác an toàn", "def_ko": "편안함과 안전함을 느끼는 것", "def_vi": "Cảm giác thoải mái và an toàn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1562, '12', '프로그램에 참여하던 치매 대상자가 갑자기 일어나서 안절부절 못하며 배회할 때 대처방법은?', '["신체적 욕구가 있는지 확인한다.", "커튼을 쳐서 실내를 어둡게 한다.", "그대로 놔둔 채 프로그램을 진행한다.", "조용한 방으로 데려가 혼자 있게 한다.", "프로그램에 집중하라고 권유한다."]'::jsonb, 1, NULL, NULL, '{"1": "신체적 욕구가 있는지 확인한다. - 치매 대상자가 불안해하는 이유를 파악하기 위해서는 이 방법이 중요하다.\n[정답]", "2": "커튼을 쳐서 실내를 어둡게 한다. - 밝은 환경에서 불안감이 증대할 수 있으므로 위험하다.", "3": "그대로 놔둔 채 프로그램을 진행한다. - 대처를 하지 않는 것은 바람직하지 않다.", "4": "조용한 방으로 데려가 혼자 있게 한다. - 혼자 두는 것은 더 불안감을 조성할 수 있다.", "5": "프로그램에 집중하라고 권유한다. - 치매 대상자의 불안은 강요로 해결될 수 없다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력과 사고 능력을 잃는 상태", "def_vi": "Tình trạng mất trí nhớ và khả năng suy nghĩ"}, {"term_ko": "불안", "term_vi": "Lo âu", "def_ko": "걱정이나 두려움을 느끼는 상태", "def_vi": "Trạng thái cảm thấy lo lắng hoặc sợ hãi"}, {"term_ko": "상황", "term_vi": "Tình huống", "def_ko": "특정한 여건이나 환경", "def_vi": "Điều kiện hoặc môi trường cụ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1561, '12', '프로그램에 참여하던 치매 대상자가 갑자기 일어나서 안절부절 못하며 배회할 때 대처방법은?', '["신체적 욕구가 있는지 확인한다.", "커튼을 쳐서 실내를 어둡게 한다.", "그대로 놔둔 채 프로그램을 진행한다.", "조용한 방으로 데려가 혼자 있게 한다.", "프로그램에 집중하라고 권유한다."]'::jsonb, 1, NULL, NULL, '{"1": "신체적 욕구가 있는지 확인한다. [정답] 치매 대상자가 불안해하는 경우 신체적 욕구가 있을 수 있으므로, 이를 확인하는 것이 중요합니다.", "2": "커튼을 쳐서 실내를 어둡게 한다. 실내를 어둡게 하는 것은 대상자가 불안감을 느끼게 할 수 있으며, 적절한 대처가 아닙니다.", "3": "그대로 놔둔 채 프로그램을 진행한다. 대상자의 행동을 무시하고 프로그램을 진행하는 것은 문제를 악화시킬 수 있습니다.", "4": "조용한 방으로 데려가 혼자 있게 한다. 혼자 있게 하는 것은 대상자가 더 외롭고 불안하게 느낄 수 있으므로 지양해야 합니다.", "5": "프로그램에 집중하라고 권유한다. 주의가 산만한 상태에서 집중하도록 요구하는 것은 부적절합니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "노인성 치매(일반적으로 기억력이나 판단력이 저하되는 상태)", "def_vi": "Đặc điểm tình trạng giảm trí nhớ hoặc phán đoán của người già"}, {"term_ko": "프로그램", "term_vi": "Chương trình", "def_ko": "특정 목표를 위해 구성된 일련의 행위나 활동", "def_vi": "Chuỗi hành động hoặc hoạt động được tổ chức nhằm đạt được mục tiêu nhất định"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "서비스나 지원을 받는 사람", "def_vi": "Người nhận dịch vụ hoặc hỗ trợ"}, {"term_ko": "배회", "term_vi": "Giao thông", "def_ko": "정해진 장소나 경로 없이 이리저리 돌아다님", "def_vi": "Đi vòng quanh mà không theo địa điểm hay lộ trình nhất định"}, {"term_ko": "안절부절", "term_vi": "Lo lắng", "def_ko": "불안한 마음으로 자리를 편안히 하지 못함", "def_vi": "Tâm trí không thoải mái, không thể ngồi yên"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1560, '12', '고향에 간다며 자주 주변을 돌아다니는 치매 대상자를 돕는 방법으로 옳은 것은?', '["시설의 주소와 전화번호를 외우게 한다.", "텔레비전을 크게 틀어 주어 집중하게 한다.", "대상자의 신분증은 보호자가 소지하게 한다.", "외출할 때 입을 겉옷을 문 입구에 걸어둔다.", "기관의 협조를 받아 사전에 지문을 등록해둔다."]'::jsonb, 5, NULL, NULL, '{"1": "시설의 주소와 전화번호를 외우게 하는 것은 치매 대상자에게 어려울 수 있다.\n[정답]", "5": "기관의 협조를 받아 사전에 지문을 등록해두면, 대상자의 안전을 더욱 보장할 수 있다.", "2": "텔레비전을 크게 틀어 주는 것은 오히려 혼란을 줄 수 있다.", "3": "신분증을 보호자가 소지하게 하는 것은 필요할 수 있지만, 외출 시의 안전과는 관련이 없다.", "4": "입을 겉옷을 문 입구에 걸어두는 것은 정리가 필요하지만, 안전과는 연결되지 않는다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "알츠하이머병과 같은 인지기능 저하 질환", "def_vi": "Bệnh suy giảm chức năng nhận thức như bệnh Alzheimer"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1559, '12', '밤에 잠을 이루지 못하고 거실을 서성거리는 치매 대상자를 돕는 방법은?', '["산책을 원하면 다녀오게 한다.", "부족한 잠은 낮잠으로 보충하게 한다.", "낮 시간에 간단한 야외활동ㅇ르 하게 한다.", "저녁 식사 후 고강도 근력운동을 하게 한다.", "잠이 들기 전까지 좋아하는 드라마를 보게 한다."]'::jsonb, 3, NULL, NULL, '{"1": "산책을 원하면 다녀오게 한다: 치매 대상자가 원하는 활동을 허용하는 것은 좋지만, 밤에 야외활동은 위험할 수 있다.\n[정답]", "2": "부족한 잠은 낮잠으로 보충하게 한다: 낮잠을 통해 부족한 잠을 보충할 수 있으나, 낮잠이 너무 길면 밤에 더 잠을 이루기 어려울 수 있다.", "3": "낮 시간에 간단한 야외활동을 하게 한다: 낮 시간의 활동은 밤의 수면에 긍정적 영향을 미칠 수 있다.", "4": "저녁 식사 후 고강도 근력운동을 하게 한다: 고강도 운동은 오히려 수면을 방해할 수 있다.", "5": "잠이 들기 전까지 좋아하는 드라마를 보게 한다: 이는 수면을 방해할 수 있는 요소가 될 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력과 사고력이 감소하는 질병", "def_vi": "Bệnh giảm trí nhớ và khả năng suy nghĩ"}, {"term_ko": "야외활동", "term_vi": "Hoạt động ngoài trời", "def_ko": "밖에서 하는 신체활동", "def_vi": "Hoạt động thể chất diễn ra bên ngoài"}, {"term_ko": "근력운동", "term_vi": "Tập thể dục sức mạnh", "def_ko": "근육을 강화하는 운동", "def_vi": "Bài tập giúp tăng cường cơ bắp"}, {"term_ko": "수면", "term_vi": "Giấc ngủ", "def_ko": "잠을 자는 상태", "def_vi": "Trạng thái ngủ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1558, '12', '최근에 입소한 치매 대상자가 2~3일 간 밤에 잠을 못 이룰 때 대처 방법은?', '["시설 규칙에 대해 설명한다.", "포만감을 느낄 수 있는 음식을 제공한다.", "누구에게나 적응 기간이 필요하다고 설명한다.", "취짐 전에 시원한 옥수수차를 충분히 마시게 한다.", "침대에 눕게 한 후에 가족에 대해 이야기를 나눈다."]'::jsonb, 5, NULL, NULL, '{"1": "시설 규칙에 대해 설명하는 것은 가이드를 제공할 수 있지만, 수면 문제 해결에는 직접적인 도움이 되지 않습니다.\n[정답]", "5": "침대에 눕게 한 후 가족에 대해 이야기를 나누는 것은 안정감을 주어 수면에 도움을 줄 수 있습니다.", "2": "포만감을 느낄 수 있는 음식을 제공하는 것은 수면 문제 해결에 큰 영향이 없습니다.", "3": "누구에게나 적응 기간이 필요하다고 설명하는 것만으로는 적절한 대처가 되지 않습니다.", "4": "취침 전에 시원한 옥수수차를 마시게 하는 것은 수면에 도움을 줄 수 있으나, 가족 이야기를 나누는 것만큼 효과적이지 않습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력과 사고력의 저하를 동반하는 질환", "def_vi": "Bệnh suy giảm trí nhớ và khả năng tư duy"}, {"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "도움이나 치료가 필요한 사람", "def_vi": "Người cần sự giúp đỡ hoặc điều trị"}, {"term_ko": "포만감", "term_vi": "Cảm giác no", "def_ko": "배가 찬 느낌", "def_vi": "Cảm giác dạ dày đầy"}, {"term_ko": "규칙", "term_vi": "Quy tắc", "def_ko": "정해진 법칙이나 원칙", "def_vi": "Những quy định hoặc nguyên tắc đã được thiết lập"}, {"term_ko": "안정감", "term_vi": "Cảm giác an toàn", "def_ko": "마음의 평온함", "def_vi": "Sự bình yên trong tâm hồn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1557, '12', '밤낮이 바뀐 치매 대상자의 수면을 돕는 방법으로 옳은 것은?', '["낮잠을 자는 동안 커튼을 쳐준다.", "취침 전에 따뜻한 녹차를 제공한다.", "낮에 졸고 있을 때 말을 걸지 않는다.", "수면 상태를 관찰하여 원인을 파악한다.", "포만감을 느낄 수 있도록 야식을 제공한다."]'::jsonb, 4, NULL, NULL, '{"1": "낮잠을 자는 동안 커튼을 쳐준다: 밤낮이 바뀐 환자에게 낮시간에 빛을 차단하는 것은 도움이 될 수 있으나, 이 방법은 직접적인 수면을 돕는 방법이 아닙니다.\n[정답]", "2": "취침 전에 따뜻한 녹차를 제공한다: 카페인 함량을 고려해 볼 때, 녹차는 수면을 방해할 수 있으므로 적절한 방법이 아닙니다.", "3": "낮에 졸고 있을 때 말을 걸지 않는다: 이 방법은 환자가 낮에 졸리지 않도록 하기 위한 노력에는 도움이 되지만, 수면 문제를 해결하는 데에는 도움이 되지 않습니다.", "4": "수면 상태를 관찰하여 원인을 파악한다: 수면 문제의 근본 원인을 이해하고 대처하기 위한 첫 단계로 매우 중요합니다.", "5": "포만감을 느낄 수 있도록 야식을 제공한다: 늦은 시간의 식사는 오히려 수면을 방해할 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억 및 사고 능력의 저하를 초래하는 질환", "def_vi": "Bệnh gây suy giảm khả năng nhớ và suy nghĩ"}, {"term_ko": "수면", "term_vi": "Giấc ngủ", "def_ko": "잠을 자는 상태", "def_vi": "Trạng thái ngủ"}, {"term_ko": "관찰", "term_vi": "Quan sát", "def_ko": "주의 깊게 살펴보는 것", "def_vi": "Việc nhìn hoặc xem một cách cẩn thận"}, {"term_ko": "원인", "term_vi": "Nguyên nhân", "def_ko": "어떤 일이 일어나는 이유", "def_vi": "Lý do cho những gì xảy ra"}, {"term_ko": "야식", "term_vi": "Đồ ăn vặt vào ban đêm", "def_ko": "밤에 주로 먹는 간단한 음식", "def_vi": "Thức ăn đơn giản thường ăn vào ban đêm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1556, '12', '치매 대상자가 갑자기 주머니에 있는 휴지를 먹는 증상은?', '["폭식증", "과식증", "이식증", "거식증", "금식증"]'::jsonb, 3, NULL, NULL, '{"1": "폭식증: 일회에 많이 먹는 행동으로, 본 문제와 관련이 없습니다.\n[정답]", "3": "이식증: 비정상적으로 비식용 물질을 먹는 증상이며, 치매와 관련이 있습니다.", "2": "과식증: 일반적인 과식을 의미하며, 치매와는 관계가 없습니다.", "4": "거식증: 식사를 거부하거나 먹지 않는 증상으로, 반대 개념입니다.", "5": "금식증: 식사를 하지 않는 상태로, 역시 문제와 관련이 없습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력이나 사고력의 기능이 저하되는 질환", "def_vi": "Là căn bệnh giảm chức năng ghi nhớ và suy nghĩ"}, {"term_ko": "주머니", "term_vi": "Túi", "def_ko": "물건을 담는 부분", "def_vi": "Phần chứa đồ vật"}, {"term_ko": "휴지", "term_vi": "Giấy vệ sinh", "def_ko": "냅킨이나 종이로 만든 것", "def_vi": "Vật làm bằng khăn giấy hoặc giấy"}, {"term_ko": "폭식증", "term_vi": "Chứng ăn uống quá độ", "def_ko": "저녁 대식증으로, 과도한 식사", "def_vi": "Ăn một cách thái quá"}, {"term_ko": "과식증", "term_vi": "Chứng ăn thái quá", "def_ko": "일반적인 먹는 양 이상의 식사", "def_vi": "Ăn nhiều hơn lượng bình thường"}, {"term_ko": "이식증", "term_vi": "Chứng ăn đồ không phải thực phẩm", "def_ko": "비식용 물질을 먹는 증상", "def_vi": "Triệu chứng ăn các vật không phải là thực phẩm"}, {"term_ko": "거식증", "term_vi": "Chứng biếng ăn", "def_ko": "식사를 거부하는 것이란 뜻", "def_vi": "Nghĩa là từ chối ăn"}, {"term_ko": "금식증", "term_vi": "Chứng nhịn ăn", "def_ko": "식사를 하지 않는 상태", "def_vi": "Trạng thái không ăn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1555, '12', '치매 대상자가 밤중에 잠에서 깨어 베개 솜을 뜯어먹고 있을 때 대처방법은?', '["수면제를 먹인다.", "장갑을 끼고 잠을 자게 한다.", "가족에게 세 베개를 사 오게 한다.", "솜 베개 대신 두꺼운 수건을 베게 한다.", "먹으면 안 된다고 설명하고 다른 베개로 바꿔준다."]'::jsonb, 4, NULL, NULL, '{"1": "수면제를 먹이는 것은 증상을 악화시킬 수 있습니다.\n[정답]", "4": "솜 베개 대신 두꺼운 수건을 베게 하는 것은 안전성을 높이고, 환자가 베개를 뜯어먹지 않도록 도와줍니다.", "2": "장갑을 끼고 잠을 자게 하는 것은 불편함을 초래할 수 있습니다.", "3": "가족에게 세 베개를 사 오게 하는 것은 문제를 해결하는 데 도움이 되지 않습니다.", "5": "먹으면 안 된다고 설명하는 것은 치매 환자에게 효과적이지 않을 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh sa sút trí tuệ", "def_ko": "기억력과 사고 능력의 감소", "def_vi": "giảm trí nhớ và khả năng suy nghĩ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1554, '12', '치매 대상자가 조금 전 식사한 것을 잊어버리고 계속 음식을 요구할 때 대처방법은?', '["과식을 하면 건강에 해롭다고 설명한다.", "먹고 난 식기를 보이는 곳에 그대로 둔다.", "배가 고픈지, 먹고 싶은 간식이 있는지 물어본다.", "함께 식사한 다른 대상자로부터 확인을 받게 한다.", "음식을 계속 요구하면 식사 제공을 중단한다고 말한다."]'::jsonb, 2, NULL, NULL, '{"1": "과식이 건강에 해롭다는 것은 사실이지만, 치매 환자에게 이를 설명하는 것은 효과적이지 않습니다. \n[정답]", "2": "식기를 보이는 장소에 두면 환자가 식사 후의 상황을 인식하는 데 도움이 됩니다.", "3": "배고픔을 확인하는 것은 중요하지만, 치매 환자는 자신의 상태를 정확히 이해하지 못할 수 있습니다.", "4": "다른 대상자의 확인은 환자에게 혼란을 줄 수 있습니다.", "5": "진행 중인 요구를 중단한다는 것은 부적절한 대처 방법이며, 환자를 더 혼란스럽게 할 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 사고력이 상실되는 상태", "def_vi": "trạng thái mất khả năng nhớ và suy nghĩ"}, {"term_ko": "대처", "term_vi": "Phương pháp đối phó", "def_ko": "적절하게 대응하는 것", "def_vi": "cách đứng ra đáp ứng"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "일정한 시간에 음식을 섭취하는 것", "def_vi": "việc tiêu thụ thực phẩm vào thời gian nhất định"}, {"term_ko": "간식", "term_vi": "Đồ ăn nhẹ", "def_ko": "주식 이외의 가벼운 음식", "def_vi": "thực phẩm nhẹ ngoài thức ăn chính"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1553, '12', '수저 사용이 어려운 치매 대상자의 식사를 돕는 방법으로 옳은 것은?', '["음식을 갈아 빨대로 먹게 한다.", "식사를 마칠 때까지 먹여 준다.", "경관을 통해 영양액을 제공한다.", "수저를 사용해서 스스로 먹을 때까지 지켜본다.", "손으로 집어 먹을 수 있는 음식을 준비한다."]'::jsonb, 5, NULL, NULL, '{"1": "음식을 갈아 빨대로 먹게 하는 것은 대체 방법이지만, 치매 환자가 손으로 집어 먹는 경험을 통해 스스로 식사하는 것이 더 좋다.\n[정답]", "5": "손으로 집어 먹을 수 있는 음식을 준비하면 치매 환자가 스스로 먹는 데 도움을 줄 수 있다.", "2": "식사를 마칠 때까지 먹여 주는 것은 환자의 자율성을 떨어뜨리고 의존성을 높일 수 있다.", "3": "경관을 통해 영양액을 제공하는 것은 심각한 상황에 해당되며, 일반적인 식사 보조와는 다르다.", "4": "수저를 사용해서 스스로 먹을 때까지 지켜보는 것은 환자의 독립적인 식사 능력을 개발하는 데 도움이 되지만, 아예 수저 사용이 어려운 경우에는 적절하지 않다."}'::jsonb, '[{"term_ko": "수저", "term_vi": "Muỗng", "def_ko": "숟가락(한국어)", "def_vi": "thìa(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1552, '12', '치매 대상자가 제공된 음식을 못 먹고 쳐다보고만 있을 때 대처방법은?', '["식사할 때까지 옆에 계속 있어 준다.", "계속 거부하면 음식을 치운다고 한다.", "식사하는 방법을 순서대로 가르쳐 준다.", "식사를 거르면 건강에 해롭다고 설명한다.", "스스로 먹을 때까지 음식을 그대로 놔둔다."]'::jsonb, 3, NULL, NULL, '{"1": "식사할 때까지 옆에 계속 있어 준다. - 이는 대상자가 긴장하지 않도록 도와줄 수 있으나, 직접적인 해결방법이 아닙니다.\n[정답]", "2": "식사하는 방법을 순서대로 가르쳐 준다. - 치매 대상자는 기억력이 떨어지기 때문에, 방법을 단계적으로 가르치는 것이 중요합니다.", "3": "계속 거부하면 음식을 치운다고 한다. - 이는 스트레스를 유발할 수 있으며, 권장되지 않습니다.", "4": "식사를 거르면 건강에 해롭다고 설명한다. - 이는 이해하기 어려운 설명일 수 있으며, 효과적이지 않습니다.", "5": "스스로 먹을 때까지 음식을 그대로 놔둔다. - 대상자의 자율성을 존중할 수 있지만, 적극적인 개입이 필요합니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력과 사고에 영향을 주는 질병", "def_vi": "Bệnh ảnh hưởng đến trí nhớ và suy nghĩ"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "도움을 받는 사람", "def_vi": "Người nhận sự giúp đỡ"}, {"term_ko": "대처방법", "term_vi": "Cách ứng phó", "def_ko": "해결책", "def_vi": "Giải pháp"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식을 먹는 것", "def_vi": "Sự ăn uống"}, {"term_ko": "거부", "term_vi": "Từ chối", "def_ko": "받아들이지 않음", "def_vi": "Không chấp nhận"}, {"term_ko": "건강", "term_vi": "Sức khoẻ", "def_ko": "신체와 정신의 상태", "def_vi": "Tình trạng thể chất và tinh thần"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1551, '12', '치매 대상자의 음식 섭취를 돕는 방법으로 옳은 것은?', '["배회가 있는 대상자는 섭취 열량을 줄인다.", "특정 음식을 좋아하면 계속 그 음식을 준다.", "배고픔을 호소할 때마다 음식을 충분히 준다.", "식사할 때 옆에 앉아서 생선 가시를 제거해 준다.", "치매 마리에는 갈거나 으깬 걸쭉한 음식을 준다."]'::jsonb, 5, NULL, NULL, '{"1": "배회가 있는 대상자는 섭취 열량을 줄이기보다는 적절한 열량을 섭취할 수 있도록 도와야 합니다.\n[정답]", "2": "특정 음식을 좋아한다고 계속 그 음식을 주는 것은 편식을 유발할 수 있으므로 그 자체로 옳지 않습니다.", "3": "배고픔을 호소할 때마다 음식을 충분히 주는 것보다 조금씩 자주 주는 것이 더 좋습니다.", "4": "식사할 때 옆에 앉아 가시를 제거해 주는 것보다 스스로 먹을 수 있도록 돕는 것이 중요합니다.", "5": "치매 환자에게는 갈거나 으깬 걸쭉한 음식을 주어야 안전하게 섭취할 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억 상실과 같은 정신적 기능 저하", "def_vi": "Sự suy giảm chức năng tâm thần như mất trí nhớ"}, {"term_ko": "음식", "term_vi": "Thực phẩm", "def_ko": "먹을 것", "def_vi": "Thứ để ăn"}, {"term_ko": "섭취", "term_vi": "Tiêu thụ", "def_ko": "먹는 것", "def_vi": "Việc ăn uống"}, {"term_ko": "열량", "term_vi": "Năng lượng", "def_ko": "에너지의 단위", "def_vi": "Đơn vị năng lượng"}, {"term_ko": "갈다", "term_vi": "Xay", "def_ko": "잘게 부수다", "def_vi": "Nghiền nát"}, {"term_ko": "으깨다", "term_vi": "Nghiền", "def_ko": "부서뜨리다", "def_vi": "Nát"}, {"term_ko": "걸쭉한", "term_vi": "Đặc", "def_ko": "부드러운", "def_vi": "Đặc, mềm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1550, '12', '치매 대상자가 식사 때마다 음식을 지나치게 많이 먹을 때 대처방법은?', '["하루에 두 끼만 제공한다.", "반찬 가짓수를 줄여 제공한다.", "매 식사 후에 소화제를 제공한다.", "작은 그릇에 담아 식사량을 조절한다.", "쓴맛이 나는 재료를 음식에 섞어 제공한다."]'::jsonb, 4, NULL, NULL, '{"1": "하루에 두 끼만 제공한다는 것은 영양 불균형을 초래할 수 있다.\n[정답]", "4": "작은 그릇에 담아 식사량을 조절하는 방법은 효과적이다.", "2": "반찬 가짓수를 줄여 제공하는 것은 영양 섭취에 좋지 않을 수 있다.", "3": "매 식사 후에 소화제를 제공하는 것은 근본적인 해결책이 아니다.", "5": "쓴맛이 나는 재료를 음식에 섞어 제공하는 것은 식욕을 떨어뜨릴 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh sa sút trí tuệ", "def_ko": "기억력이나 사고 능력이 감소하는 질병", "def_vi": "Bệnh giảm trí nhớ hoặc khả năng suy nghĩ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1548, '12', '방금 식사를 마친 치매 대상자가 계속 밥을 달라고 할 때 반응으로 적절한 것은?', '["\"계속해서 식사를 달라고 하시니 제가 너무 힘들어요.\"", "\"다 드셨다고요! 요즘 들어 자주 깜빡깜빡하시네요.\"", "\"밥 대신 뻥튀기, 떡 중에서 무엇을 드릴까요?\"", "\"다음 식사를 준비하고 있으니 조금만 기다리세요.\"", "\"식사가 부족하셨군요. 식사량이 점점 늘고 있네요.\""]'::jsonb, 4, NULL, NULL, '{"1": "치매 대상자가 힘들다는 표현은 적절치 않다.\n[정답]", "4": "다음 식사를 준비 중임을 알리며 기다리게 하는 것이 적절하다.", "2": "대상자의 상태를 비하하는 표현이다.", "3": "대체 식품을 제안하는 것은 좋지 않다.", "5": "식사의 부족을 언급하는 것은 불필요한 혼란을 줄 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Chứng mất trí nhớ", "def_ko": "망각증(한국어)", "def_vi": "Mất trí nhớ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1547, '12', '치매 대상자가 누워만 있으려고 할 때 대처방법은?', '["대상자가 원하는 대로 누워있게 한다.", "누워만 있으려고 하는 이유를 물어본다.", "게으른 습관은 건강을 헤친다고 설명한다.", "대상자가 좋아하는 화분에 물을 주게 한다.", "주기적으로 환경을 바꾸어 기분을 전환해준다."]'::jsonb, 4, NULL, NULL, '{"1": "대상자가 원하는 대로 누워있게 하는 것은 장기적으로 건강에 좋지 않기 때문에 신중해야 합니다.\n[정답]", "4": "대상자가 좋아하는 화분에 물을 주는 것은 그들의 관심을 끌고 기분 전환을 도울 수 있는 좋은 방법입니다.", "2": "누워만 있으려고 하는 이유를 물어보는 것도 중요하지만, 즉각적인 대처 방법이 아닙니다.", "3": "게으른 습관이 건강에 나쁘다고 설명하는 것은 오히려 대상자에게 스트레스를 줄 수 있습니다.", "5": "주기적으로 환경을 바꾸는 것도 중요한 방법이지만, 구체적인 행동 지침으로서는 화분에 물 주기가 더 효과적일 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력과 사고력을 손상시키는 질병", "def_vi": "Bệnh làm suy giảm trí nhớ và khả năng tư duy"}, {"term_ko": "대상자", "term_vi": "Người nhận trợ giúp", "def_ko": "도움을 받는 사람", "def_vi": "Người cần nhận sự hỗ trợ"}, {"term_ko": "간호", "term_vi": "Chăm sóc", "def_ko": "환자에게 돌보는 행위", "def_vi": "Hành động chăm sóc cho bệnh nhân"}, {"term_ko": "환경", "term_vi": "Môi trường", "def_ko": "주변의 상태나 상황", "def_vi": "Tình trạng hoặc hoàn cảnh xung quanh"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1546, '12', '치매 대상자가 신발장에 있는 신발을 모두 꺼내어 거실로 던지는 행동을 반복할 때 대처방법은?', '["\"어떤 신발을 찾길래 이러시는 거예요?\"", "\"신발을 거실에 던지시니 제가 너무 힘들어요!\"", "\"다 꺼내신 다음에는 다시 신발장에 넣으세요.\"", "\"꺼내놓은 신발 중에 안 신는 신발은 버릴게요.\"", "\"이 신발이 가장 예쁘네요. 이거 신고 함께 산책해요.\""]'::jsonb, 5, NULL, NULL, '{"1": "치매 환자의 신발에 대한 관심을 유도하는 질문이지만, 오히려 혼란을 줄 수 있다.\n[정답]", "5": "신발에 대한 긍정적인 반응을 보임으로써 환자의 행동을 안정시키고 친밀감을 형성할 수 있다.", "2": "감정적으로 반응하여 상황을 악화시킬 수 있다.", "3": "환자에게 불가능한 요구를 하고 있어 효과적이지 않다.", "4": "부정적인 과정을 포함하고 있어 환자에게 상처를 줄 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억과 인지 기능의 저하로 인한 상태", "def_vi": "Trạng thái suy giảm trí nhớ và chức năng nhận thức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1545, '12', '시설 치매대상자가 우리 며느리가 나 데리러 언제 와?라며 반복적으로 물을 때 대처방법은?', '["물을 때마다 며느리와 통화하게 한다.", "방금 왔다 갔으니 기억해보라고 한다.", "여기가 집이니 며느리를 기다리지 말라고 한다.", "며느리를 기다리도록 문 앞에 의자를 놓아 준다.", "달력에 적힌 며느리의 방문 일정을 보이며 알려준다."]'::jsonb, 5, NULL, NULL, '{"1": "며느리와 통화하게 하는 것은 환자의 불안감을 증가시킬 수 있다.\n[정답]", "5": "달력에 적힌 며느리의 방문 일정을 보이며 알려주는 것은 환자의 인지적 능력을 활용하여 안정감을 줄 수 있다.", "2": "방금 왔다는 말을 하면 환자가 혼란스러워 할 수 있다.", "3": "여기가 집이라고 말하는 것은 환자의 감정을 무시하는 것일 수 있다.", "4": "문 앞에 의자를 놓는 것은 효과적일 수 있지만, 근본적인 질문에 대한 대답이 아니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억과 인지에 영향을 미치는 질병", "def_vi": "Bệnh ảnh hưởng đến trí nhớ và nhận thức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1544, '12', '치매 대상자가 자신이 좋아하는 꽃무늬 스웨터를 접었다 폈다 하면서 잠을 자지 않을 때 대처방법은?', '["수건으로 바꾸어 주고 계속하게 한다.", "세탁해 주겠다며 스웨터를 가져간다.", "스웨터를 입고 자자며 다독인다.", "그런 행동을 하는 이유를 물어본다.", "늦었으니 내일 다시 하라고 한다."]'::jsonb, 3, NULL, NULL, '{"1": "수건으로 바꾸어 주고 계속하게 한다. - 수건으로 대체하는 것은 오히려 혼란을 줄 수 있습니다.\n[정답]", "3": "스웨터를 입고 자자며 다독인다. - 환자의 감정을 이해하고 안정감을 주는 방법입니다.", "2": "세탁해 주겠다며 스웨터를 가져간다. - 환자의 소중한 물건을 없애는 것은 좋지 않은 방법입니다.", "4": "그런 행동을 하는 이유를 물어본다. - 치매 환자는 이유를 잘 설명하기 어렵습니다.", "5": "늦었으니 내일 다시 하라고 한다. - 환자의 현재 요구를 무시하는 것이므로 부적절한 대처입니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력이나 사고 기능이 저하된 상태", "def_vi": "Trạng thái suy giảm trí nhớ hoặc khả năng tư duy"}, {"term_ko": "대처방법", "term_vi": "Phương pháp đối phó", "def_ko": "문제를 해결하기 위한 방법", "def_vi": "Cách để giải quyết vấn đề"}, {"term_ko": "안정감", "term_vi": "Cảm giác an toàn", "def_ko": "마음이 편안한 느낌", "def_vi": "Cảm giác bình an trong tâm trí"}, {"term_ko": "다독이다", "term_vi": "An ủi", "def_ko": "부드럽게 말하며 위로하다", "def_vi": "Nói nhẹ nhàng để khuyến khích"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1543, '12', '치매 대상자가 반복적으로 수건을 접었다 폈다 하며 콧노래를 할 때 대처방법은?', '["접고 있는 수건을 치운다.", "콧노래를 그만하라고 한다.", "왜 반복 행동을 하는지 물어본다.", "중단시키지 말고 조용히 지켜본다.", "안 보이는 곳에 가서 하라고 한다."]'::jsonb, 4, NULL, NULL, '{"1": "대상자가 반복적인 행동을 통해 안정감을 찾는 경우가 많으므로 수건을 치우는 것은 좋지 않습니다.\n[정답]", "4": "반복적인 행동은 때로 치매 환자에게 도움이 될 수 있으므로 중단시키기보다는 조용히 지켜보는 것이 바람직합니다.", "2": "치매 대상자에게 명령조로 이야기를 하는 것은 스트레스를 줄 수 있습니다.", "3": "대화가 잘 통하지 않는 치매 환자에게 물어보는 것은 의미가 없습니다.", "5": "이런 행동을 피하게 하려는 방법은 오히려 대상을 더욱 불안하게 만들 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력과 인지능력의 감소를 동반한 질병", "def_vi": "Bệnh gây suy giảm trí nhớ và khả năng nhận thức"}, {"term_ko": "대상자", "term_vi": "Người nhận dịch vụ", "def_ko": "서비스를 받는 사람", "def_vi": "Người nhận dịch vụ"}, {"term_ko": "반복", "term_vi": "Lặp lại", "def_ko": "같은 행동을 여러 번 하는 것", "def_vi": "Làm cùng một hành động nhiều lần"}, {"term_ko": "대처 방법", "term_vi": "Phương pháp ứng xử", "def_ko": "문제를 해결하기 위한 방법", "def_vi": "Cách giải quyết vấn đề"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1542, '12', '치매 대상자가 혼잣말을 하면서 책상을 계속 두드릴 때 대처방법은?', '["관심을 두지 않고 자리를 피한다.", "책상을 두드리는 이유를 물어본다.", "책상이 부서질 수 있다고 주의 준다.", "손뼉을 치며 좋아하는 노래를 함께 부른다.", "다른 어르신이 불편하니 조용히 하라고 한다."]'::jsonb, 4, NULL, NULL, '{"1": "환자의 행동을 무시하고 자리를 피하는 것은 바람직하지 않다. 직접적인 대화나 활동이 없으면 환자에게 고립감을 줄 수 있다.\n[정답]", "4": "손뼉을 치며 좋아하는 노래를 함께 부르는 것은 환자의 행동에 긍정적으로 반응하고, 공동의 활동을 통해 소통을 시도하는 방법이다.", "3": "책상이 부서질 수 있다고 주의 주는 것은 환자를 더욱 불안하게 만들 수 있다.", "5": "다른 어르신이 불편하니 조용히 하라고 하는 것은 환자를 배제하는 느낌을 줄 수 있으므로 좋지 않다.", "2": "책상을 두드리는 이유를 물어보는 것은 좋으나, 환자가 그 이유를 잘 설명하지 못할 수 있기 때문에 더 적절한 대처가 필요하다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "기억과 사고를 잃는 상태", "def_vi": "Trạng thái mất khả năng nhớ và suy nghĩ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1541, '12', '재가 치매대상자의 환경을 안전하게 관리하는 방법은?', '["다른 사람의 눈에 잘 띄지 않는 방으로 배정한다.", "노출된 온수파이프는 주방용 랩으로 감싸 둔다.", "냉장고에 과일 모양의 자석을 붙여 놓는다.", "유리그릇은 보관장에 넣고 보관장을 잠가 둔다.", "음식물이 담긴 쓰레기봉투는 부엌 안쪽에 둔다."]'::jsonb, 4, NULL, NULL, '{"1": "다른 사람의 눈에 잘 띄지 않는 방으로 배정하는 것은 치매 대상자의 안전성을 높이지 않습니다.\n[정답]", "2": "노출된 온수파이프는 주방용 랩으로 감싸 두어 물리적 상해를 예방할 수 있습니다.", "3": "냉장고에 과일 모양의 자석을 붙여놓는 것은 안전과 관련성이 낮습니다.", "4": "유리그릇은 보관장에 넣고 보관장을 잠가 두는 것이 치매대상자의 안전을 위해 필요합니다.", "5": "음식물이 담긴 쓰레기봉투를 부엌 안쪽에 두는 것은 악취 및 위생 문제를 야기할 수 있습니다."}'::jsonb, '[{"term_ko": "재가", "term_vi": "Tại nhà", "def_ko": "가정에서 제공되는 돌봄", "def_vi": "Chăm sóc được cung cấp tại nhà"}, {"term_ko": "치매", "term_vi": "Mất trí nhớ", "def_ko": "기억 상실증", "def_vi": "Rối loạn trí nhớ"}, {"term_ko": "환경", "term_vi": "Môi trường", "def_ko": "주위 상태", "def_vi": "Trạng thái xung quanh"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "위험이 없는 상태", "def_vi": "Tình trạng không có nguy hiểm"}, {"term_ko": "유리", "term_vi": "Thủy tinh", "def_ko": "깨지기 쉬운 재료", "def_vi": "Vật liệu dễ vỡ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1540, '12', '중증 치매대상자의 욕실을 안전하게 조성하는 방법은?', '["높이가 높은 욕조를 설치한다.", "온수기의 온도를 40도 이상 높여 놓는다.", "욕실에 문턱을 만들어 물이 넘치지 않게 한다.", "비누는 사용하기 쉽게 눈에 잘 띄는 곳에 둔다.", "거울에 덮개를 씌워 자신의 모습을 보고 놀라지 않게 한다."]'::jsonb, 5, NULL, NULL, '{"1": "높이가 높은 욕조는 위험할 수 있어 적절하지 않습니다.", "2": "온수기의 온도를 40도 이상 높이면 화상의 위험이 있습니다.", "3": "문턱이 있으면 넘어질 위험이 커질 수 있습니다.\n[정답]", "4": "비누는 사용하기 쉽게 눈에 잘 띄는 곳에 두는 것이 중요합니다.", "5": "거울에 덮개를 씌우는 것은 자신을 보고 놀라지 않게 할 수 있습니다."}'::jsonb, '[{"term_ko": "중증", "term_vi": "치매", "def_ko": "중증(Trung bình nặng)", "def_vi": "치매(Bệnh sa sút trí tuệ)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1539, '12', '낙상 우려가 있는 치매 대상자의 안전사고 예방을 위한 방법은?', '["밤에는 화장실 전등을 꺼둔다.", "복용하는 약은 식탁 위에 놓는다.", "방과 거실 사이에 단차를 설치한다.", "현관에 안 신는 신발을 놓아둔다.", "침대보다는 바닥에 요와 이불을 깔아 둔다."]'::jsonb, 5, NULL, NULL, '{"1": "밤에는 화장실 전등을 꺼두면 어둠으로 인해 낙상 위험이 커진다.\n[정답]", "5": "바닥에 요와 이불을 깔아 두면 침대에서 떨어지는 낙상을 예방할 수 있다.", "2": "복용하는 약을 식탁 위에 두면 치매 환자가 약을 놓칠 수 있어 위험하다.", "3": "방과 거실 사이에 단차를 설치하면 오히려 걸려 넘어질 위험이 있다.", "4": "현관에 안 신는 신발을 둔다면 신고 나가는 데 어려움을 겪을 수 있다."}'::jsonb, '[{"term_ko": "낙상", "term_vi": "치매", "def_ko": "낙하(우려) - ngã: nguy cơ ngã", "def_vi": "기억 상실증 - sa sút trí tuệ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1538, '12', '치매 대상자의 일상생활이 안전하도록 돕는 방법으로 옳은 것은?', '["방을 화려하고 다양하게 꾸민다.", "밤에도 낮처럼 환하게 불을 켜 둔다.", "난간, 출입구 등을 같은 색으로 칠한다.", "대상자의 눈높이에 맞추어 ''화장실'' 표시를 한다.", "현관 앞에 이동이 가능한 매트를 깔아 놓는다."]'::jsonb, 4, NULL, NULL, '{"1": "방을 화려하고 다양하게 꾸미면 오히려 혼란을 일으킬 수 있다.\n[정답]", "2": "밤에도 낮처럼 환하게 불을 켜 둬야 시각적인 안전이 확보된다.", "3": "난간이나 출입구를 같은 색으로 칠하면 구분하기 어려워질 수 있다.", "4": "대상자의 눈높이에 맞추어 ''화장실'' 표시를 하는 것은 인지적 도움을 준다.", "5": "현관 앞에 이동이 가능한 매트를 깔아 두면 넘어지는 사고를 유발할 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억 및 사고 기능에 문제가 있는 상태", "def_vi": "Trạng thái có vấn đề về trí nhớ và chức năng suy nghĩ"}, {"term_ko": "일상생활", "term_vi": "Cuộc sống hàng ngày", "def_ko": "매일 하는 일", "def_vi": "Những công việc hằng ngày"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "위험을 방지하는 상태", "def_vi": "Trạng thái ngăn ngừa nguy hiểm"}, {"term_ko": "눈높이", "term_vi": "Tầm mắt", "def_ko": "시각의 높이", "def_vi": "Độ cao của thị giác"}, {"term_ko": "표시", "term_vi": "Biển hiệu", "def_ko": "알아볼 수 있도록 나타내는 것", "def_vi": "Cách thể hiện để nhận biết"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1537, '12', '재가 치매대상자의 안전을 고려한 주거환경 관리 방법은?', '["현관문을 열어 대상자가 자유롭게 출입하게 한다.", "화장실 문은 밖에서도 열 수 있는 것으로 설치한다.", "방 안이 따뜻하도록 대상자 옆에 난로를 켜둔다.", "방에 큰 거울을 두어 자신의 모습을 인식하게 한다.", "현관 출입문은 투명한 유리로 설치하여 밖이 잘 보이게 한다."]'::jsonb, 2, NULL, NULL, '{"1": "현관문을 열어 대상을 자유롭게 출입하게 하는 것은 안전을 위협할 수 있습니다.\n[정답]", "2": "화장실 문을 밖에서도 열 수 있는 것으로 설치하면 긴급상황 시 신속하게 대처할 수 있습니다.", "3": "방 안이 따뜻하도록 난로를 켜두면 화재의 위험성이 높아집니다.", "4": "방에 큰 거울을 두면 혼란을 유발할 수 있습니다.", "5": "현관 출입문을 투명한 유리로 설치하면 외부의 자극으로 인해 불안감을 줄 수 있습니다."}'::jsonb, '[{"term_ko": "재가", "term_vi": "Tại gia", "def_ko": "집에서 돌보는 것", "def_vi": "Chăm sóc tại nhà"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1536, '12', '치매 대상자의 환경을 안전하게 조성하는 방법은?', '["가스선의 중간 밸브는 열어둔다.", "자극을 받지 않도록 차 안에서는 창문을 열어둔다.", "지남력 지원을 위해 시계, 달력, 가족사진을 가까이에 둔다.", "치매 대상자의 기능적인 손상을 고려하여 환경을 수시로 바꾼다.", "언어의 이해가 떨어지면, 그림보다는 글로 쓰인 단서를 사용한다."]'::jsonb, 3, NULL, NULL, '{"1": "가스선의 중간 밸브를 열어두는 것은 안전하지 않은 환경을 조성할 수 있습니다.", "2": "자극을 받지 않도록 차 안에서 창문을 여는 것은 오히려 위험할 수 있습니다.\n[정답]", "3": "지남력 지원을 위해 시계, 달력, 가족사진을 가까이에 두는 것은 치매 대상자에게 도움이 되는 안전한 환경을 제공합니다.", "4": "치매 대상자의 기능적인 손상을 고려하여 환경을 수시로 바꾸는 것은 혼란을 증대시킬 수 있습니다.", "5": "언어의 이해가 떨어지면, 그림보다는 글로 쓰인 단서를 사용하는 것은 오히려 이해를 어렵게 할 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력과 인지 기능의 저하로 일어나는 질환", "def_vi": "Bệnh gây suy giảm trí nhớ và chức năng nhận thức"}, {"term_ko": "지남력", "term_vi": "Khả năng định hướng", "def_ko": "시간, 장소, 사람 등을 인식하는 능력", "def_vi": "Khả năng nhận thức về thời gian, địa điểm, và con người"}, {"term_ko": "환경", "term_vi": "Môi trường", "def_ko": "둘러싼 물리적 상태나 주변", "def_vi": "Tình trạng vật lý xung quanh hoặc môi trường"}, {"term_ko": "가족사진", "term_vi": "Hình ảnh gia đình", "def_ko": "가족의 사진", "def_vi": "Ảnh của gia đình"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1535, '12', '치매 대상자의 운동 돕기 방법으로 옳은 것은?', '["모든 종류의 운동을 선택한다.", "균형을 잡을 수 있으면 앉아서 운동한다.", "운동은 심장에서 가까운 쪽부터 시작한다.", "매일 같은 시간대에 운동한다.", "운동하면서 대상자와 친숙해진다."]'::jsonb, 4, NULL, NULL, '{"1": "모든 종류의 운동을 선택하는 것은 부적절합니다. 대상자의 상태에 맞는 운동을 해야 합니다.\n[정답]", "4": "매일 같은 시간대에 운동하는 것은 일관성을 제공하여 정신적 안정감을 주며 좋습니다.", "3": "운동은 심장에서 먼 쪽부터 시작하는 것이 일반적입니다. 이는 심리적 안전을 보장하는 방법입니다.", "5": "운동 중 친숙해지는 것은 중요하지만 운동 방법 그 자체를 묻고 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Người bị sa sút trí tuệ", "def_ko": "기억과 사고를 방해하는 질병", "def_vi": "Bệnh nhân bị ảnh hưởng đến trí nhớ và nhận thức"}, {"term_ko": "운동", "term_vi": "Vận động", "def_ko": "신체를 움직이는 활동", "def_vi": "Hoạt động di chuyển cơ thể"}, {"term_ko": "균형", "term_vi": "Cân bằng", "def_ko": "몸의 안정적인 상태", "def_vi": "Tình trạng ổn định của cơ thể"}, {"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "보살핌을 받는 사람", "def_vi": "Người nhận sự chăm sóc"}, {"term_ko": "시간대", "term_vi": "Khoảng thời gian", "def_ko": "특정 시간", "def_vi": "Thời gian cụ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1534, '12', '치매 대상자의 운동을 돕는 방법은?', '["걷는 시간을 서서히 늘린다.", "산책로를 자주 바꾸어 걷게 한다.", "숨을 쉬기 힘들어 하면 쉬었다가 운동하게 한다.", "팔다리 관절을 빠르게 움직이며 운동하게 한다.", "심장병 대상자에게는 계단 오르내리기를 시킨다."]'::jsonb, 1, NULL, NULL, '{"1": "걷는 시간을 서서히 늘리는 것은 치매 환자에게 적절한 운동 강도를 유지하는 데 도움이 된다.\n[정답]", "2": "산책로를 자주 바꿔서 걷게 하는 것은 혼란을 초래할 수 있어 피해야 한다.", "3": "숨을 쉬기 힘들어 하면 쉬었다가 운동하게 하는 것은 사실이지만, 운동 지속성을 감소시킬 수 있다.", "4": "팔다리 관절을 빠르게 움직이는 것은 오히려 치매 대상자에게 부담을 줄 수 있다.", "5": "심장병 대상자에게 계단 오르내리기를 시키는 것은 치매 환자에게 적절하지 않다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력과 사고에 영향을 미치는 질환", "def_vi": "Bệnh ảnh hưởng đến trí nhớ và tư duy"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1533, '12', '치매 대상자의 옷을 갈아입히는 방법으로 옳은 것은?', '["선 자세에서 옷을 갈아입힌다.", "옷 입는 시간이 걸리면 전부 입혀준다.", "앞뒤를 구분하지 못하면 환자복을 입힌다.", "순서대로 못 입을 경우 겉옷부터 차례로 놓아둔다.", "갈아입기를 거부하면 목욕 시간을 이용한다."]'::jsonb, 5, NULL, NULL, '{"1": "선 자세에서 옷을 갈아입히는 것은 불안정할 수 있으므로 권장하지 않다.\n[정답]", "5": "갈아입기를 거부하면 목욕 시간을 이용해 편하게 옷을 입힐 수 있도록 하는 것이 올바른 방법이다.", "2": "옷 입는 시간이 걸린다고 해서 전부 입혀주는 것은 환자의 자립성을 무시하는 것이다.", "3": "앞뒤를 구분하지 못하는 환자에게는 환자복을 입히기보다 가능한 한 쉽게 입힐 수 있는 방법을 사용해야 한다.", "4": "순서대로 입혀주지 못하고 겉옷부터 놓는 것은 환자가 혼란스러울 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력, 사고력 등이 저하되는 증상", "def_vi": "Triệu chứng suy giảm trí nhớ, tư duy"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1532, '12', '치매 대상자의 옷 갈아입기를 돕는 방법으로 옳은 것은?', '["계절과 무관한 옷을 입힌다.", "장식이 많이 달린 옷을 입힌다.", "무늬가 화려한 옷을 입힌다.", "시간이 걸려도 혼자 입도록 격려한다.", "단추를 채우지 못하면 지퍼가 달린 옷을 입힌다."]'::jsonb, 4, NULL, NULL, '{"1": "계절과 무관한 옷을 입힌다: 치매 환자는 계절에 맞는 옷을 입는 것이 좋다.\n[정답]", "4": "시간이 걸려도 혼자 입도록 격려한다: 자율성을 높이고 스스로 할 수 있도록 지지하는 것이 올바른 방법이다.", "2": "장식이 많이 달린 옷을 입힌다: 장식이 많은 옷은 혼란을 초래할 수 있다.", "3": "무늬가 화려한 옷을 입힌다: 화려한 무늬는 인식에 방해가 될 수 있다.", "5": "단추를 채우지 못하면 지퍼가 달린 옷을 입힌다: 단추가 아닌 지퍼의 경우도 어려움이 있을 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "기억력과 인지 기능의 장애", "def_vi": "Rối loạn trí nhớ và chức năng nhận thức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1531, '12', '치매 대상자의 옷 입기를 돕는 방법으로 옳은 것은?', '["옷 입기를 거부하면 입히지 않는다.", "시간이 오래 걸리므로 직접 입혀준다.", "색상이 화려하고 장식이 달린 옷을 제공한다.", "수치심을 느끼지 않도록 혼자 입게 둔다.", "순서대로 입지 못하는 경우 속옷부터 순서대로 놓아준다."]'::jsonb, 5, NULL, NULL, '{"1": "옷 입기를 거부하는 경우 강제로 입히지 않도록 해야 하며, 대안적인 방법을 고려해야 합니다.\n[정답]", "5": "순서대로 입지 못하는 경우 속옷부터 차례로 놓아주는 방법이 적합합니다.", "2": "시간의 유무에 관계 없이 대상자가 스스로 할 수 있도록 돕는 것이 중요합니다.", "3": "화려한 옷은 치매 환자에게 혼란을 줄 수 있으므로 피하는 것이 좋습니다.", "4": "환자가 수치심을 느끼지 않도록 지켜보며 적절한 도움을 주는 것이 중요합니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 사고 능력이 저하되는 질병", "def_vi": "Bệnh suy giảm trí nhớ và khả năng tư duy"}, {"term_ko": "방식", "term_vi": "Cách", "def_ko": "방법", "def_vi": "phương pháp"}, {"term_ko": "순서", "term_vi": "Thứ tự", "def_ko": "차례", "def_vi": "thứ tự"}, {"term_ko": "속옷", "term_vi": "Đồ lót", "def_ko": "속옷", "def_vi": "quần áo trong"}, {"term_ko": "수치심", "term_vi": "Xấu hổ", "def_ko": "부끄러움", "def_vi": "sự xấu hổ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1530, '12', '치매 대상자의 옷 선택 시 옳은 것은?', '["계절과 무관한 옷", "색깔이 화려한 옷", "대상자가 좋아하는 옷", "지퍼가 뒤에 달린 옷", "장식이 많이 달린 옷"]'::jsonb, 3, NULL, NULL, '{"1": "계절과 무관한 옷: 계절에 맞는 옷을 선택하는 것이 중요하므로 적절하지 않음.", "2": "색깔이 화려한 옷: 과한 색감은 혼란을 초래할 수 있어 좋지 않음.\n[정답]", "3": "대상자가 좋아하는 옷: 환자의 선호를 존중하는 것이 중요하여 올바른 선택임.", "4": "지퍼가 뒤에 달린 옷: 입고 벗기기 불편하므로 적절하지 않음.", "5": "장식이 많이 달린 옷: 과한 장식은 혼란을 줄 수 있으므로 좋지 않음."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억 상실증(한국어)", "def_vi": "Bệnh không nhớ"}, {"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자(한국어)", "def_vi": "Người bệnh"}, {"term_ko": "선택", "term_vi": "Lựa chọn", "def_ko": "고르다(한국어)", "def_vi": "Chọn"}, {"term_ko": "옥색", "term_vi": "Màu sắc", "def_ko": "색깔(한국어)", "def_vi": "Màu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1529, '12', '치아가 없는 치매 대상자의 식후 구강위생 방법은?', '["차 또는 물을 마시도록 한다.", "소금물로 입안을 헹구게 한다.", "면봉으로 잇몸을 닦아준다.", "거즈를 감은 설압자에 물치약을 묻혀서 닦는다.", "치아가 없는 경우에는 구강위생을 하지 않는다."]'::jsonb, 1, NULL, NULL, '{"1": "구강위생을 위해 차나 물을 섭취하는 것은 입안의 세균을 줄일 수 있는 방법입니다.\n[정답]", "2": "소금물로 헹구는 것은 효과적이지만 치아가 없는 경우의 권장 사항은 아닙니다.", "3": "면봉으로 잇몸을 닦는 것은 특정 상황에서 도움이 될 수 있으나 일반적이지 않습니다.", "4": "물치약을 묻혀 닦는 것은 권장되지 않습니다.", "5": "구강위생 관리는 치아 유무와 관계없이 중요합니다."}'::jsonb, '[{"term_ko": "구강위생", "term_vi": "Vệ sinh miệng", "def_ko": "입안을 깨끗하게 유지하는 방법", "def_vi": "Phương pháp giữ cho miệng sạch sẽ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1528, '12', '치아가 없는 치매 대상자의 식후 구강위생 방법은?', '["차 또는 물을 마시도록 한다.", "소금물로 입안을 헹구게 한다.", "면봉으로 잇몸을 닦아준다.", "거즈를 감은 설압자에 물치약을 묻혀서 닦는다.", "치아가 없는 경우에는 구강위생을 하지 않는다."]'::jsonb, 1, NULL, NULL, '{"1": "차 또는 물을 마시도록 한다. 구강 건조를 예방하고 구강위생을 개선하는 방법입니다.\n[정답]", "2": "소금물로 입안을 헹구게 한다. 치아가 없더라도 구강세정이 도움이 되지만, 물이나 차에 비해 허용도가 낮습니다.", "3": "면봉으로 잇몸을 닦아준다. 이는 잇몸과 구강 내 세균 제거에 효과적일 수 있습니다.", "4": "거즈를 감은 설압자에 물치약을 묻혀서 닦는다. 구강위생 관리의 방법 중 하나이지만, 치아가 없을 경우 우선순위는 아닙니다.", "5": "치아가 없는 경우에는 구강위생을 하지 않는다. 이는 잘못된 인식으로, 구강 건강을 위해서 최소한의 관리가 필요합니다."}'::jsonb, '[{"term_ko": "치아", "term_vi": "Răng", "def_ko": "이(한국어)", "def_vi": "răng"}, {"term_ko": "구강위생", "term_vi": "Vệ sinh miệng", "def_ko": "구강 위생(한국어)", "def_vi": "vệ sinh miệng"}, {"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "치매(한국어)", "def_vi": "sa sút trí tuệ"}, {"term_ko": "면봉", "term_vi": "Bông gòn", "def_ko": "면봉(한국어)", "def_vi": "bông gòn"}, {"term_ko": "거즈", "term_vi": "Gạc", "def_ko": "거즈(한국어)", "def_vi": "gạc"}, {"term_ko": "설압자", "term_vi": "Dụng cụ ấn", "def_ko": "설압자(한국어)", "def_vi": "dụng cụ ấn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1527, '12', '누워서 지내는 치매 대상자의 양치질을 돕는 방법으로 옳은 것은?', '["치아에서 잇몸 방향으로 세심하게 닦는다.", "칫솔을 혀 안쪽까지 깊숙이 넣어 닦는다.", "입안을 차가운 물로 한번만 헹군다.", "대상자의 뺨에 물받이 그릇을 대준다.", "치아가 없는 경우에는 구강위생관리를 하지 않는다."]'::jsonb, 4, NULL, NULL, '{"1": "치아에서 잇몸 방향으로 세심하게 닦는 것은 올바른 방법이지만, 누워서 지내는 경우에는 좀 더 주의가 필요합니다.\n[정답]", "4": "대상자의 뺨에 물받이 그릇을 대주는 것은 침이 흘러나오거나 물이 튀는 것을 방지하기 위해 매우 중요합니다.", "2": "칫솔을 혀 안쪽까지 깊숙이 넣어 닦는 것은 역류를 유발할 수 있어 피해야 합니다.", "3": "입안을 차가운 물로 한번만 헹군다면 충분한 구강 세척이 이루어지지 않습니다.", "5": "치아가 없는 경우에도 구강 위생 관리는 여전히 중요합니다."}'::jsonb, '[{"term_ko": "구강 위생", "term_vi": "Vệ sinh miệng", "def_ko": "입안의 청결을 유지하는 것", "def_vi": "Giữ sạch sẽ trong miệng"}, {"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력, 사고능력이 저하되는 상태", "def_vi": "Tình trạng suy giảm trí nhớ, khả năng suy nghĩ"}, {"term_ko": "물받이 그릇", "term_vi": "Bát nhận nước", "def_ko": "흘러내린 물을 받는 그릇", "def_vi": "Cái bát để đựng nước chảy ra"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1526, '12', '치매 대상자의 구강위생을 돕는 방법으로 옳은 것은?', '["모가 딱딱한 칫솔을 사용한다.", "삼켜도 되는 어린이용 치약을 사용한다.", "의치는 항상 끼워 놓는다.", "의치는 매일 정해진 시간에 닦아준다.", "양치질을 거부할 경우 면봉으로 닦아준다."]'::jsonb, 2, NULL, NULL, '{"1": "보통 딱딱한 칫솔은 안전하지 않으며, 잇몸을 다칠 수 있습니다.\n[정답]", "2": "어린이용 치약은 삼켜도 안전하므로 치매 환자에게 적합합니다.", "3": "의치를 항상 끼워 놓는 것은 구강위생에 좋지 않습니다.", "4": "의치는 매일 일정하게 관리해야 하지만, 닦아주는 것이 중요합니다.", "5": "양치질을 거부할 경우 면봉으로도 닦을 수 있지만 최선의 방법은 아닙니다."}'::jsonb, '[{"term_ko": "구강위생", "term_vi": "Vệ sinh miệng", "def_ko": "입과 관련된 위생 관리", "def_vi": "Quản lý vệ sinh liên quan đến miệng"}, {"term_ko": "치매", "term_vi": "Mất trí nhớ", "def_ko": "기억과 정신 기능의 감소", "def_vi": "Sự giảm sút trí nhớ và chức năng tâm thần"}, {"term_ko": "의치", "term_vi": "Răng giả", "def_ko": "인공치아", "def_vi": "Răng giả"}, {"term_ko": "양치질", "term_vi": "Đánh răng", "def_ko": "이를 닦는 행위", "def_vi": "Hành động chải răng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1525, '12', '치매 대상자가 열이 나는데도 목욕을 시켜 달라고 할 때 대처방법은?', '["시원한 물로 목욕시킨다.", "해열제를 먹인 후 목욕시킨다.", "목욕 대신 물놀이를 하게 한다.", "미지근한 물수건으로 몸을 닦아 준다.", "고열의 위험성에 대해 자세히 설명한다."]'::jsonb, 4, NULL, NULL, '{"1": "시원한 물로 목욕시킨다. 목욕 시 체온 조절을 고려하지 않은 매우 위험한 방법입니다.\n[정답]", "4": "미지근한 물수건으로 몸을 닦아 준다. 체온을 조절하면서 개인위생을 유지할 수 있는 안전한 방법입니다.", "2": "해열제를 먹인 후 목욕시킨다. 약물 투여는 의료인의 처방이 필요하며, 안전하지 않을 수 있습니다.", "3": "목욕 대신 물놀이를 하게 한다. 환자의 현재 상태에 따라 다르지만, 고열이 있을 때는 피해야 할 방법입니다.", "5": "고열의 위험성에 대해 자세히 설명한다. 설명은 중요하지만, 즉각적인 행동 대응이 필요한 상황입니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억과 사고 능력이 저하된 상태", "def_vi": "Trạng thái suy giảm khả năng nhớ và suy nghĩ"}, {"term_ko": "열", "term_vi": "Sốt", "def_ko": "체온이 상승한 상태", "def_vi": "Tình trạng nhiệt độ cơ thể gia tăng"}, {"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "몸을 씻는 행위", "def_vi": "Hành động rửa cơ thể"}, {"term_ko": "미지근한", "term_vi": "Ấm", "def_ko": "따뜻한 정도", "def_vi": "Mức độ ấm"}, {"term_ko": "고열", "term_vi": "Sốt cao", "def_ko": "높은 체온 상태", "def_vi": "Trạng thái nhiệt độ cơ thể cao"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1524, '12', '치매 대상자가 물에 대한 거부반응을 보일 때 목욕 돕기 방법은?', '["작은 그릇에 물을 떠서 장난하게 해준다.", "목욕을 안 하면 간식을 안 준다고 경고한다.", "목욕을 하면 기분이 좋아진다며 설득한다.", "목욕을 거부하더라도 강제로 시행한다.", "수치심을 느끼지 않게 혼자 목욕하게 한다."]'::jsonb, 1, NULL, NULL, '{"1": "작은 그릇에 물을 떠서 장난하게 해주는 것은 치매 대상자의 거부감을 감소시키는 효과가 있다. \n[정답]", "2": "목욕을 안 하면 간식을 안 준다고 경고하는 것은 부정적인 방법으로, 대상자의 심리를 더 악화시킬 수 있다.", "3": "목욕을 하면 기분이 좋아진다며 설득하는 것이 허용될 수 있으나, 대체로 치매 대상자에게는 효과적이지 않다.", "4": "목욕을 거부하더라도 강제로 시행하는 것은 인권을 침해할 수 있다.", "5": "수치심을 느끼지 않게 혼자 목욕하게 하는 것은 치매 대상자의 안전과 안녕을 고려하지 않은 잘못된 접근이다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "NCTT", "def_ko": "인지 기능의 감소로 인한 기억 상실증", "def_vi": "Giảm sút chức năng nhận thức dẫn đến mất trí nhớ"}, {"term_ko": "거부반응", "term_vi": "Phản ứng từ chối", "def_ko": "어떤 것에 대한 반대의 감정이나 행동", "def_vi": "Cảm xúc hoặc hành vi phản đối một cái gì đó"}, {"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "몸을 씻는 행위", "def_vi": "Hành động rửa cơ thể"}, {"term_ko": "강제", "term_vi": "Bắt buộc", "def_ko": "억지로 하는 것", "def_vi": "Làm điều gì đó một cách miễn cưỡng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1523, '12', '치매 대상자의 목욕 돕기 방법으로 옳은 것은?', '["욕조 바닥에 미끄럼방지 매트를 깔아준다.", "욕실 바닥에 따뜻한 물을 뿌려둔다.", "목욕물의 온도는 대상자가 확인하게 한다.", "사생활 유지를 위해 혼자 목욕하게 한다.", "운동실조증이 있는 대상자는 탕 목욕보다 샤워를 시킨다."]'::jsonb, 1, NULL, NULL, '{"1": "욕조 바닥에 미끄럼방지 매트를 깔아준다: 목욕 시 안전을 위하여 미끄럼방지 매트를 사용하는 것은 매우 중요하다.\n[정답]", "2": "욕실 바닥에 따뜻한 물을 뿌려둔다: 이는 미끄러짐을 예방하는 데 도움이 되지만, 따뜻한 물이 바닥에 고여있으면 위험할 수 있다.", "3": "목욕물의 온도는 대상자가 확인하게 한다: 치매 환자는 온도 감각이 저하될 수 있으므로, 반드시 보호자가 확인해야 한다.", "4": "사생활 유지를 위해 혼자 목욕하게 한다: 치매 대상자는 혼자 목욕하는 것이 위험할 수 있으므로, 항상 도움을 줘야 한다.", "5": "운동실조증이 있는 대상자는 탕 목욕보다 샤워를 시킨다: 운동실조증 환자는 샤워가 안전하지만, 반드시 전문가의 판단이 필요하다."}'::jsonb, '[{"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "씻는 행위", "def_vi": "Hành động rửa"}, {"term_ko": "목욕물", "term_vi": "Nước tắm", "def_ko": "목욕하기 위해 사용하는 물", "def_vi": "Nước sử dụng để tắm"}, {"term_ko": "미끄럼방지", "term_vi": "Chống trơn", "def_ko": "미끄러운 것을 방지함", "def_vi": "Ngăn chặn sự trơn trượt"}, {"term_ko": "사생활", "term_vi": "Cuộc sống riêng tư", "def_ko": "개인적인 생활", "def_vi": "Cuộc sống cá nhân"}, {"term_ko": "운동실조증", "term_vi": "Rối loạn vận động", "def_ko": "운동 조정 문제가 있는 질병", "def_vi": "Bệnh gây ra vấn đề điều chỉnh vận động"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1522, '12', '치매 대상자의 목욕을 돕는 방법을 옳은 것은?', '["대상자를 욕조에 앉힌 후 물을 채운다.", "욕실 바닥에 따뜻한 물을 뿌린다.", "물에 대한 거부반응이 있더라도 목욕을 시킨다.", "목욕을 강요하지 말고 목욕과정을 단순화 시킨다.", "사생활 보호를 위해 욕실에 혼자 둔다."]'::jsonb, 3, NULL, NULL, '{"1": "대상자를 욕조에 앉힌 후 물을 채우는 것은 안전하지 않은 방법입니다.\n[정답]", "3": "물에 대한 거부반응이 있더라도 목욕을 강요하는 것은 바람직하지 않습니다.", "2": "욕실 바닥에 따뜻한 물을 뿌리는 것은 바람직하지 않습니다.", "4": "목욕을 강요하지 말고 목욕과정을 단순화 시키는 것은 좋은 방법입니다.", "5": "사생활 보호를 위해 욕실에 혼자 두는 것은 안전하지 않습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력 및 인지 기능의 장애가 있는 상태", "def_vi": "Tình trạng rối loạn trí nhớ và khả năng nhận thức"}, {"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "신체를 씻는 행위", "def_vi": "Hành động rửa cơ thể"}, {"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "돌봐야 할 환자", "def_vi": "Bệnh nhân cần được chăm sóc"}, {"term_ko": "강요하다", "term_vi": "Ép buộc", "def_ko": "억지로 하게 하다", "def_vi": "Buộc phải làm gì đó"}, {"term_ko": "사생활", "term_vi": "Quyền riêng tư", "def_ko": "개인의 생활이나 비밀", "def_vi": "Cuộc sống cá nhân hoặc bí mật"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1521, '12', '치매 대상자가 변비인 경우 돕는 방법으로 옳은 것은?', '["수분 섭취량을 줄인다.", "섬유질 음식섭취를 제한한다.", "대상자가 요구 시 즉시 관장을 한다.", "증상이 비슷한 다른 대상자의 변비약을 먹인다.", "일정한 시간 간겨긍로 변기에 앉혀 배변을 유도한다."]'::jsonb, 5, NULL, NULL, '{"1": "수분 섭취량을 줄이는 것은 변비를 악화시킬 수 있습니다.\n[정답]", "5": "일정한 시간 간격으로 변기에 앉혀 배변을 유도하는 것은 변비 예방과 관리에 효과적입니다.", "2": "섬유질 음식섭취를 제한하는 것은 변비에 좋지 않은 영향을 미칩니다.", "3": "대상자가 요구 시 즉시 관장을 하는 것은 불필요한 자극을 줄 수 있습니다.", "4": "증상이 비슷한 다른 대상자의 변비약을 먹이는 것은 개인의 건강 상태에 따라 다를 수 있으므로 위험할 수 있습니다."}'::jsonb, '[{"term_ko": "변비", "term_vi": "Táo bón", "def_ko": "대변이 단단해져서 배출이 어려운 상태", "def_vi": "Tình trạng khó khăn trong việc bài tiết phân do phân cứng lại"}, {"term_ko": "수분 섭취", "term_vi": "Lượng nước uống", "def_ko": "신체의 수분을 섭취하는 것", "def_vi": "Việc hấp thụ nước cho cơ thể"}, {"term_ko": "섬유질", "term_vi": "Chất xơ", "def_ko": "식이섬유가 풍부한 음식", "def_vi": "Thực phẩm giàu chất xơ"}, {"term_ko": "관장", "term_vi": "Thụt tháo", "def_ko": "대장에 약물을 주입하여 배변을 유도하는 방법", "def_vi": "Phương pháp đưa thuốc vào đại tràng để kích thích đi vệ sinh"}, {"term_ko": "배변", "term_vi": "Đi vệ sinh", "def_ko": "대변을 배출하는 행위", "def_vi": "Hành động bài tiết phân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1520, '12', '치매 대상자가 실금하여 옷이 젖은 것을 발견했을 때 대처 방법은?', '["상황을 기록하고 기저귀를 채운다.", "더러워진 옷을 갈아입히고 안정시킨다.", "하루 동안 수분섭취를 제한한다.", "소변이 마렵다고 하면 간이변기를 대준다.", "보호자와 유치도뇨관 삽입에 대해 의논한다."]'::jsonb, 2, NULL, NULL, '{"1": "상황을 기록하는 것은 중요하나, 기저귀를 채우는 것은 즉각적인 대처로 적절하지 않습니다.\n[정답]", "2": "더러워진 옷을 갈아입히고 안정시켜 주는 것이 가장 적절한 대처입니다.", "3": "수분 섭취 제한은 건강에 해로울 수 있으며, 해결 방법이 아닙니다.", "4": "간이변기를 제공하는 것은 필요할 때 좋은 방법이나 현재 상황에서 긴급하게 필요한 대처는 아닙니다.", "5": "유치도뇨관 삽입은 의료적인 절차이기 때문에, 보호자와 의논하는 것은 적절하나 현재의 즉각적인 대책이 아닙니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억과 인지 기능의 감퇴로 나타나는 질병", "def_vi": "Bệnh gây suy giảm khả năng ghi nhớ và chức năng nhận thức"}, {"term_ko": "실금", "term_vi": "Tiểu không tự chủ", "def_ko": "무의식적으로 소변을 보는 현상", "def_vi": "Hiện tượng đi tiểu một cách không kiểm soát"}, {"term_ko": "기저귀", "term_vi": "Bỉm", "def_ko": "소변을 흡수하는 패드", "def_vi": "Tấm lót thấm nước tiểu"}, {"term_ko": "보호자", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 사람", "def_vi": "Người chăm sóc bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1519, '12', '치매 대상자에게 요실금이 나타날 때 돕는 방법으로 옳은 것은?', '["수분섭취를 제한하여 소변량을 줄인다.", "배뇨 후 치골상부를 눌러준다.", "밤에는 기저귀를 채운다.", "실금을 하면 주의를 준다.", "낮에는 4시간, 밤에는 2시간 간격으로 배뇨훈련을 시킨다."]'::jsonb, 2, NULL, NULL, '{"1": "수분 섭취를 제한하는 것은 건강에 해로울 수 있습니다.\n[정답]", "2": "배뇨 후 치골상부를 눌러주는 방법은 실제로 소변 배출을 도울 수 있습니다.", "3": "밤에 기저귀를 채우는 방법은 일시적인 해결책이지만, 이 방법을 상시로 사용할 경우 위생 문제가 발생할 수 있습니다.", "4": "실금을 할 때 주의를 주는 것은 환자의 자존감을 해칠 수 있습니다.", "5": "배뇨훈련은 간격을 조절해야 하며, 일반적인 권장 간격은 다를 수 있습니다."}'::jsonb, '[{"term_ko": "요실금", "term_vi": "Tiểu không tự chủ", "def_ko": "소변을 스스로 조절하지 못하는 상태", "def_vi": "Tình trạng không kiểm soát được nước tiểu"}, {"term_ko": "치매", "term_vi": "Mất trí nhớ", "def_ko": "기억력과 사고력의 감퇴로 발생하는 질환", "def_vi": "Bệnh gây giảm trí nhớ và khả năng suy nghĩ"}, {"term_ko": "배뇨", "term_vi": "Đi tiểu", "def_ko": "소변을 봄", "def_vi": "Hành động bài tiết nước tiểu"}, {"term_ko": "훈련", "term_vi": "Đào tạo", "def_ko": "일정한 목표를 향해 연습하는 것", "def_vi": "Hành động thực hành với mục tiêu nhất định"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1518, '12', '요실금 대상자의 배설을 돕는 방법은?', '["침대 옆에 이동변기를 둔다.", "체중을 늘려 골반근육을 강화시킨다.", "활동을 제한하여 배뇨횟수를 조절한다.", "아랫배를 눌러 주어 방광을 완전히 비운다.", "소변을 볼 때 더운 물주머니를 복부에 대준다."]'::jsonb, 4, NULL, NULL, '{"1": "침대 옆에 이동변기를 두는 것은 편리할 수 있지만, 배설을 돕는 최적의 방법은 아닙니다.\n[정답]", "4": "아랫배를 눌러 주어 방광을 완전히 비우는 것은 요실금 대상자의 배설을 효과적으로 돕는 방법입니다.", "2": "체중을 늘려 골반근육을 강화하는 것은 도움이 될 수 있지만, 즉각적인 배설 도움에는 한계가 있습니다.", "3": "활동을 제한하여 배뇨횟수를 조절하는 것은 일반적인 접근 방식이지만, 배설을 돕는 직접적인 방법은 아닙니다.", "5": "소변을 볼 때 더운 물주머니를 복부에 대주는 것은 불편함을 줄일 수 있지만, 배설을 돕는 방법이라고 보기 어렵습니다."}'::jsonb, '[{"term_ko": "요실금", "term_vi": "Tiểu không tự chủ", "def_ko": "소변을 제어하지 못하는 상태", "def_vi": "Tình trạng không kiểm soát được việc tiểu tiện"}, {"term_ko": "배설", "term_vi": "Bài tiết", "def_ko": "신체에서 쓰레기나 노폐물이 나오는 과정", "def_vi": "Quá trình thải ra chất thải hoặc chất cặn bã từ cơ thể"}, {"term_ko": "골반근육", "term_vi": "Cơ vùng chậu", "def_ko": "골반 부위의 근육", "def_vi": "Cơ bắp trong khu vực xương chậu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1517, '12', '초기 치매 대상자의 배설관리 방법으로 옳은 것은?', '["변기 앞에 안전 손잡이를 설치한다.", "활동이 많은 낮 시간에는 기저귀를 채운다.", "식사 전후에는 매번 변기에 앉혀 변을 보게 한다.", "취침 전에는 반드시 화장실에 다녀오도록 한다.", "안전을 위해 야간에는 이동식 변기를 사용한다."]'::jsonb, 5, NULL, NULL, '{"1": "변기 앞에 안전 손잡이를 설치하는 것은 도움이 되지만, 필수적인 방법은 아님.\n[정답]", "5": "야간에는 안전을 위해 이동식 변기를 사용하는 것이 바람직하다.", "2": "낮 시간에 기저귀를 채우는 것은 적극적인 관리 방법이라고 보기 어려움.", "3": "식사 전후에 매번 변기 앉히는 것은 스트레스를 유발할 수 있음.", "4": "취침 전 화장실에 다녀오는 것은 좋지만 필수는 아님."}'::jsonb, '[{"term_ko": "초기", "term_vi": "Giai đoạn đầu", "def_ko": "시작 단계(한국어)", "def_vi": "Giai đoạn bắt đầu(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1516, '12', '치매 대상자가 기저귀 안으로 손을 자주 넣어 성기에 상처를 낼 때 대처방법은?', '["손에 장갑을 끼워준다.", "손톱을 짧게 깎아준다.", "부끄러운 행동임을 지적한다.", "하의를 벗겨 시원하게 해준다.", "계속하면 서비스를 중단하겠다고 말한다."]'::jsonb, 2, NULL, NULL, '{"1": "손에 장갑을 끼워주는 것은 일시적인 해결책이나, 근본적인 원인을 해결하지 못합니다.\n[정답]", "2": "손톱을 짧게 깎아주는 것은 환자가 기저귀 안에 손을 넣었을 때 상처를 방지하는 데 도움이 됩니다.", "3": "부끄러운 행동이라고 지적하는 것은 환자에게 추가적인 부정적 감정을 유발할 수 있습니다.", "4": "하의를 벗겨주는 것은 상황에 따라 적절할 수 있으나, 모든 환자에게 적용될 수 있는 방법이 아닙니다.", "5": "서비스를 중단하겠다고 말하는 것은 강압적이며, 환자의 정서에 부정적인 영향을 줄 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh sa sút trí tuệ", "def_ko": "노인성 정신질환으로 기억력과 일상생활 기능이 상실되는 상태", "def_vi": "Tình trạng mất trí nhớ và khả năng hoạt động hàng ngày của người già"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1515, '12', '치매 대상자의 배설을 돕는 방법으로 옳은 것은?', '["실금하면 4시간마다 이동변기를 대어 준다.", "변기를 차갑게 하여 변의를 자극한다.", "뒤처리 방법을 시범 보여 스스로 하게 한다.", "화장실 문 앞에 화분을 놓아 위치를 표시한다.", "취침 전에 물이나 음료를 충분히 마시게 한다."]'::jsonb, 3, NULL, NULL, '{"1": "실금하면 4시간마다 이동변기를 대어 주는 것은 배설 교육의 효과를 저하시킬 수 있습니다.\n[정답]", "3": "뒤처리 방법을 시범 보여 스스로 하게 하여 자존감을 높이고 독립성을 기르는 것이 좋습니다.", "2": "변기를 차갑게 하여 변의를 자극하는 것은 오히려 불편함을 초래할 수 있습니다.", "4": "화장실 문 앞에 화분을 놓아 위치를 표시하는 것은 실질적인 도움이 되지 않습니다.", "5": "취침 전에 물이나 음료를 충분히 마시게 하는 것은 수면 중 배뇨 문제를 유발할 수 있습니다."}'::jsonb, '[{"term_ko": "배설", "term_vi": "Tiểu tiện", "def_ko": "대소변을 버리는 행위", "def_vi": "Hành động đi vệ sinh"}, {"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "인지 기능이 저하되는 질병", "def_vi": "Bệnh suy giảm chức năng nhận thức"}, {"term_ko": "뒤처리", "term_vi": "Dọn dẹp", "def_ko": "청소 및 정리하는 과정", "def_vi": "Quá trình làm sạch và sắp xếp"}, {"term_ko": "자존감", "term_vi": "Giá trị bản thân", "def_ko": "자신의 가치에 대한 인식", "def_vi": "Nhận thức về giá trị của chính mình"}, {"term_ko": "독립성", "term_vi": "Tính độc lập", "def_ko": "스스로 할 수 있는 능력", "def_vi": "Khả năng tự làm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1514, '12', '치매 대상자의 배설 돕기로 옳은 것은?', '["정해진 시간에 배설을 하도록 강요한다.", "화장실 가까운 곳에 방을 배치한다.", "야간에 수분 섭취를 늘린다.", "벨트와 단추가 있는 바지를 입힌다.", "옷에 배설물이 묻었을 경우 주의시킨다."]'::jsonb, 2, NULL, NULL, '{"1": "환자에게 정해진 시간에 맞춰 배설을 강요하는 것은 치매 환자에게 스트레스를 줄 수 있습니다.\n[정답]", "2": "화장실 가까운 곳에 방을 배치하는 것은 치매 환자가 배설을 쉽게 할 수 있도록 도와줍니다.", "3": "야간에 수분 섭취를 늘리는 것은 수면에 방해가 될 수 있습니다.", "4": "벨트와 단추가 있는 바지는 치매 환자가 스스로 옷을 벗거나 입는 데 어려움을 줄 수 있습니다.", "5": "배설물이 묻었을 때 주의시키는 것은 오히려 환자에게 불안감을 줄 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억 및 사고의 기능 장애(한국어)", "def_vi": "Rối loạn chức năng của trí nhớ và tư duy"}, {"term_ko": "배설", "term_vi": "Bài tiết", "def_ko": "소변이나 대변을 보는 것(한국어)", "def_vi": "Thực hiện việc đi vệ sinh"}, {"term_ko": "강요하다", "term_vi": "Ép buộc", "def_ko": "힘으로 시키다(한국어)", "def_vi": "Buộc phải làm điều gì đó"}, {"term_ko": "수분", "term_vi": "Thủy nước", "def_ko": "물의 양(한국어)", "def_vi": "Lượng nước"}, {"term_ko": "방 배치", "term_vi": "Bố trí phòng", "def_ko": "방을 어떻게 배열하는가(한국어)", "def_vi": "Cách sắp xếp phòng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1513, '12', '대상자가 바지 뒷부분을 잡고 안절부절 못하며 구석진 곳을 찾을 때 대처방법은?', '["화장실로 데리고 간다.", "옷을 갈아입힌다.", "좋아하는 음식을 제공한다.", "함께 산책을 나간다.", "실내 온도를 낮추어 시원하게 해준다."]'::jsonb, 1, NULL, NULL, '{"1": "화장실로 데리고 간다. 이 방법은 대상자가 화장실을 필요로 하는 경우에 적절한 대처입니다.\n[정답]", "2": "옷을 갈아입힌다. 이 방법은 대상자의 불안감을 해소하는 데 도움이 되지 않습니다.", "3": "좋아하는 음식을 제공한다. 음식 제공은 불안감 해소와는 관련이 없습니다.", "4": "함께 산책을 나간다. 산책이 도움이 될 수 있지만, 긴급한 상황에는 부적절할 수 있습니다.", "5": "실내 온도를 낮추어 시원하게 해준다. 온도의 변화가 불안감을 해소하는 데 도움이 되지 않을 수 있습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Bệnh nhân", "def_ko": "특정 치료나 돌봄을 받는 사람", "def_vi": "Người nhận điều trị hoặc chăm sóc"}, {"term_ko": "안절부절 못하다", "term_vi": "Bồn chồn", "def_ko": "불안하거나 초조한 상태", "def_vi": "Tình trạng lo lắng hoặc hồi hộp"}, {"term_ko": "대처방법", "term_vi": "Phương pháp ứng phó", "def_ko": "문제를 해결하기 위한 방법", "def_vi": "Cách giải quyết vấn đề"}, {"term_ko": "화장실", "term_vi": "Nhà vệ sinh", "def_ko": "소변이나 대변을 보기 위한 장소", "def_vi": "Địa điểm đi vệ sinh"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1512, '12', '치매 대상자에게 원인을 알 수 없는 체중감소가 나타났을 때 돕는 방법은?', '["기름진 음식을 제공한다.", "음식을 수시로 제공한다.", "고열량의 액체음식을 제공한다.", "경관영양을 한다.", "식사량을 두 배로 늘린다."]'::jsonb, 3, NULL, NULL, '{"1": "기름진 음식을 제공하는 것은 오히려 소화에 부담을 줄 수 있다.\n[정답]", "2": "음식을 수시로 제공하는 것은 환자의 기호와 필요에 따라 좋지만, 과도할 경우 비만을 초래할 수 있다.", "3": "고열량의 액체음식을 제공하는 것은 체중 증가에 효과적이다.", "4": "경관영양을 하는 것은 극단적인 경우에 해당하며, 반드시 필요한 상황이다.", "5": "식사량을 두 배로 늘리는 것은 환자의 상태에 따라 부작용이 있을 수 있다."}'::jsonb, '[{"term_ko": "체중감소", "term_vi": "Giảm cân", "def_ko": "체중이 줄어드는 현상", "def_vi": "Hiện tượng giảm trọng lượng cơ thể"}, {"term_ko": "고열량", "term_vi": "Lượng calo cao", "def_ko": "높은 칼로리", "def_vi": "Calo cao"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1511, '12', '치매 대상자가 식사를 하지 않아 체중이 감소되었을 때 대처방법은?', '["의료진에게 알리고 원인을 파악한다.", "식사량을 평소보다 두 배 제공한다.", "걸쭉한 액체음식을 준다.", "고지방의 음식을 준다.", "큰 그릇에 한꺼번에 음식을 담아 제공한다."]'::jsonb, 1, NULL, NULL, '{"1": "의료진에게 알리고 원인을 파악한다.\n[정답]", "2": "식사량을 평소보다 두 배 제공한다.\n식사량을 늘리는 것이 좋다고 판단하더라도, 단순히 두 배로 늘리는 것은 체중 증가에 효과적이지 않을 수 있습니다.", "3": "걸쭉한 액체음식을 준다.\n걸쭉한 액체 음식으로도 도움이 될 수 있지만, 기본적으로 치료와 원인 파악이 우선입니다.", "4": "고지방의 음식을 준다.\n고지방 음식이 반드시 도움이 되는 것은 아니며 영양 균형이 중요합니다.", "5": "큰 그릇에 한꺼번에 음식을 담아 제공한다.\n이런 접근은 오히려 환자의 식욕을 감소시킬 우려가 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh sa sút trí tuệ", "def_ko": "기억력과 사고를 저하시키는 질병", "def_vi": "Bệnh làm giảm trí nhớ và khả năng tư duy"}, {"term_ko": "의료진", "term_vi": "Nhân viên y tế", "def_ko": "환자의 건강 상태를 치료하거나 관리하는 전문가", "def_vi": "Chuyên gia điều trị hoặc quản lý tình trạng sức khỏe của bệnh nhân"}, {"term_ko": "체중", "term_vi": "Cân nặng", "def_ko": "신체 질량의 양", "def_vi": "Khối lượng cơ thể"}, {"term_ko": "대처방법", "term_vi": "Cách ứng phó", "def_ko": "문제를 해결하기 위한 방법", "def_vi": "Phương pháp giải quyết vấn đề"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1510, '12', '치매 대상자의 식사를 돕는 방법으로 옳은 것은?', '["식탁에 앉힌 후 음식을 차려준다.", "여러 가지 음식을 한꺼번에 내어 놓는다.", "유리컵에 마실 물을 담아 놓는다.", "생선 가시는 미리 발라서 준다.", "경쾌한 음악을 틀어 식사 분위기를 조성한다."]'::jsonb, 4, NULL, NULL, '{"1": "식탁에 앉힌 후 음식을 차려주는 것은 기본적인 방법이지만, 이 자체로는 치매 환자의 식사 보조에 충분하지 않음.\n[정답]", "4": "생선 가시는 미리 발라서 주는 것이 안전하고 좋으며, 치매 환자의 식사를 돕는 바람직한 방법임.", "2": "여러 가지 음식을 한꺼번에 내어 놓으면 선택이 어려워 혼란을 줄 수 있음.", "3": "유리컵에 마실 물을 담아 놓는 것은 다치기 쉽고, 치매 환자가 다루기 힘들 수 있음.", "5": "경쾌한 음악을 틀어 식사 분위기를 조성하는 것은 좋지만, 직접적인 식사 보조와는 관계가 없음."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력이나 사고 능력이 저하된 상태", "def_vi": "Tình trạng suy giảm trí nhớ hoặc khả năng suy nghĩ"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식을 먹는 행위", "def_vi": "Hành động ăn uống"}, {"term_ko": "음식", "term_vi": "Thức ăn", "def_ko": "먹을 것", "def_vi": "Thực phẩm"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "위험이 없는 상태", "def_vi": "Tình trạng không có nguy hiểm"}, {"term_ko": "혼란", "term_vi": "Nhầm lẫn", "def_ko": "심리적으로 불안정한 상태", "def_vi": "Tình trạng tâm lý không ổn định"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1509, '12', '치매 대상자에게 식사를 제공할 때 돕는 방법으로 옳은 것은?', '["앞치마보다는 턱받이를 해준다.", "음식은 떠먹기 좋게 큼직하게 자른다.", "가벼운 숟가락과 젓가락을 사용하게 한다.", "한 가지 음식을 먹고 난 후 다른 음식을 내어 놓는다.", "식사 전 음식의 온도를 대상자가 확인하게 한다."]'::jsonb, 4, NULL, NULL, '{"1": "앞치마보다는 턱받이를 해주는 것이 더 효과적이다.\n[정답]", "2": "음식은 떠먹기 좋게 자르는 것이 중요하지만 큼직하게 자르는 것은 적절하지 않다.", "3": "가벼운 숟가락과 젓가락을 사용하는 것이 좋지만, 각각의 상황에 맞는 도구를 선택해야 한다.", "4": "한 가지 음식을 먹고 난 후 다른 음식을 내어 놓는 것이 바람직하다.", "5": "식사 전 음식의 온도를 대상자가 확인하는 것은 필요하지 않다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "기억 및 사고 능력의 감퇴", "def_vi": "Giảm khả năng ghi nhớ và tư duy"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1508, '12', '치매 대상자의 식사 돕기 방법으로 옳은 것은?', '["사발보다 접시를 사용한다.", "배고픔을 호소할 때마다 음식을 제공한다.", "사레에 자주 걸리면 묽은 음식을 제공한다.", "색깔이 있는 유리 그릇에 음식을 담아 제공한다.", "빨대와 플라스틱 덮개가 부착된 물컵을 준비한다."]'::jsonb, 5, NULL, NULL, '{"1": "사발보다 접시를 사용한다는 일반적으로 맞는 이야기지만, 치매 대상자의 상황에 따라 다를 수 있습니다.\n[정답]", "5": "빨대와 플라스틱 덮개가 부착된 물컵은 치매 대상자가 음료를 쉽게 섭취할 수 있도록 도와줍니다.", "3": "사레에 자주 걸리면 묽은 음식을 제공하는 것은 상황에 따라 적절할 수 있으나, 5번이 더 적합합니다.", "2": "배고픔을 호소할 때마다 음식을 제공하는 것은 지속적인 식사 지원에는 도움이 될 수 있지만, 주의가 필요합니다.", "4": "색깔이 있는 유리 그릇에 음식을 담아 제공하는 것은 치매 환자에게 혼란을 줄 수 있어 주의해야 합니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력이나 사고력이 떨어지는 질환", "def_vi": "Bệnh làm giảm khả năng ghi nhớ và suy nghĩ"}, {"term_ko": "사레", "term_vi": "Sặc", "def_ko": "음식이나 음료가 기도로 들어가는 것", "def_vi": "Thực phẩm hoặc đồ uống đi vào đường hô hấp"}, {"term_ko": "빨대", "term_vi": "Ống hút", "def_ko": "음료를 마시는 도구", "def_vi": "Dụng cụ dùng để uống"}, {"term_ko": "플라스틱", "term_vi": "Nhựa", "def_ko": "합성수지로 만들어진 물질", "def_vi": "Vật liệu tổng hợp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1507, '12', '치매 대상자의 식사를 돕는 방법으로 옳은 것은?', '["TV를 크게 틀어준다.", "식사 장소를 자주 바꿔준다.", "식사 시간은 자유롭게 정한다.", "무게감 있는 숟가락을 사용하게 한다.", "모든 음식은 믹서로 갈아서 제공한다."]'::jsonb, 4, NULL, NULL, '{"1": "TV를 크게 틀어주는 것은 오히려 주의 집중을 방해할 수 있습니다.\n[정답]", "4": "무게감 있는 숟가락을 사용하면 치매 대상자가 식사 시 안정감을 느끼며 식사를 할 수 있습니다.", "2": "식사 장소를 자주 바꿔주는 것은 혼란을 초래할 수 있습니다.", "3": "식사 시간을 자유롭게 정하면 규칙적인 식사가 어려워질 수 있습니다.", "5": "모든 음식은 믹서로 갈아서 제공하면 씹는 감각을 잃을 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력과 사고력이 감소하는 뇌의 질병", "def_vi": "Bệnh của não bộ khiến suy giảm trí nhớ và khả năng suy nghĩ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1506, '12', '치매 대상자가 음식을 손으로 먹는 등 장난을 칠 때 요양보호사의 행동으로 옳은 것은?', '["일시적으로 금식을 시킨다.", "단호하게 야단친다.", "여러 가지 음식을 내놓는다.", "안정 될 때까지 방에 가둔다.", "비닐로 된 식탁보를 깔아둔다."]'::jsonb, 5, NULL, NULL, '{"1": "일시적으로 금식을 시키는 것은 오히려 불안감을 증가시킬 수 있으므로 바람직하지 않습니다.", "2": "단호하게 야단치는 것은 치매 환자의 정서를 상하게 할 수 있으므로 적절하지 않습니다.", "3": "여러 가지 음식을 내놓는 것은 혼란을 초래할 수 있으므로 상황에 맞지 않습니다.\n[정답]", "5": "비닐로 된 식탁보를 깔아두면 청소가 용이하고, 대상자가 음식을 손으로 먹더라도 큰 문제가 되지 않습니다.", "4": "안정 될 때까지 방에 가두는 것은 인권 침해의 소지가 있으므로 바람직하지 않습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": null, "def_ko": "기억력 및 사고가 손상된 상태", "def_vi": null}, {"term_ko": "요양보호사", "term_vi": null, "def_ko": "노인이나 환자를 도와주는 직업", "def_vi": null}, {"term_ko": "장난", "term_vi": null, "def_ko": "심각한 것 아닌 재미있는 행동", "def_vi": null}, {"term_ko": "금식", "term_vi": null, "def_ko": "음식을 먹지 않는 상태", "def_vi": null}, {"term_ko": "야단치다", "term_vi": null, "def_ko": "큰 소리로 혼내다", "def_vi": null}, {"term_ko": "안정", "term_vi": null, "def_ko": "평온하고 고요한 상태", "def_vi": null}, {"term_ko": "가두다", "term_vi": null, "def_ko": "어떤 곳에 가두거나 닫다", "def_vi": null}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1505, '12', '치매 대상자의 식사 돕기 중 옳은 것은?', '["졸려할 때는 식사를 천천히 준다.", "작고 딱딱한 음식을 제공한다.", "소금이나 간장은 식탁 위에 두고 스스로 간을 맞추게 한다.", "사레가 자주 걸리면 좀 더 걸쭉한 액체음식을 제공한다.", "투명한 유리제품에 제공한다."]'::jsonb, 4, NULL, NULL, '{"1": "졸려할 때는 식사를 천천히 주는 것이 좋지만, 최적의 방법은 아닐 수 있다. \n[정답]", "4": "사레가 자주 걸리는 경우에는 걸쭉한 액체 음식을 제공하는 것이 안전하다.", "2": "작고 딱딱한 음식은 치매 환자에게 위험할 수 있다.", "3": "소금이나 간장을 스스로 맞추게 하는 것은 건강에 좋지 않은 영향을 미칠 수 있다.", "5": "투명한 유리제품은 깨질 위험이 있어 피하는 것이 좋다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억을 잃는 질병", "def_vi": "Bệnh mất khả năng nhớ"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식을 먹는 행위", "def_vi": "Hành động ăn uống"}, {"term_ko": "사레", "term_vi": "Nghẹn", "def_ko": "기도가 막히는 현상", "def_vi": "Hiện tượng tắc thở"}, {"term_ko": "액체", "term_vi": "Chất lỏng", "def_ko": "물질이 흐르는 상태", "def_vi": "Trạng thái của chất chảy"}, {"term_ko": "제품", "term_vi": "Sản phẩm", "def_ko": "어떤 물건", "def_vi": "Đồ vật nào đó"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1504, '12', '씹는 행위를 잊어버린 치매 대상자에게 고기를 제공할 때 올바른 방법은?', '["굵게 썰어서 제공한다.", "푹 삶아서 제공한다.", "갈아서 제공한다.", "구워서 제공한다.", "잘게 썰어서 제공한다."]'::jsonb, 3, NULL, NULL, '{"1": "굵게 썰어서 제공하면 치매 환자가 씹기에 어려움을 겪을 수 있습니다.\n[정답]", "2": "푹 삶아서 제공할 경우 질감이 부드럽지만 찢어 먹기 어려울 수 있습니다.", "3": "갈아서 제공하면 환자가 쉽게 먹을 수 있습니다.", "4": "구워서 제공할 경우 딱딱해져 씹기에 문제를 일으킬 수 있습니다.", "5": "잘게 썰어서 제공하면 일정 부분 도움이 되지만, 완전히 갈아주는 것보다는 여전히 어렵습니다."}'::jsonb, '[{"term_ko": "씹다", "term_vi": "Nhai", "def_ko": "물건을 입으로 물고 부수다(한국어)", "def_vi": "nhai"}, {"term_ko": "행위", "term_vi": "Hành vi", "def_ko": "어떤 일을 하는 것(한국어)", "def_vi": "hành động"}, {"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억과 사고에 장애가 생기는 질환(한국어)", "def_vi": "sự suy giảm trí nhớ"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "보호를 받는 사람(한국어)", "def_vi": "người được bảo vệ"}, {"term_ko": "고기", "term_vi": "Thịt", "def_ko": "동물의 살(한국어)", "def_vi": "thịt"}, {"term_ko": "제공하다", "term_vi": "Cung cấp", "def_ko": "주다(한국어)", "def_vi": "cung cấp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1503, '12', '치매 대상자의 식사를 돕는 방법으로 옳은 것은?', '["손으로 음식을 먹는 경우 턱받이를 해준다.", "의치가 느슨하면 의치를 뺴고 식사하게 한다.", "간식으로 알사탕과 떡을 제공한다.", "처방 받은 비타민은 음식에 섞어서 먹게 한다.", "휴대전화로 좋아하는 가요 영상을 보여 준다."]'::jsonb, 2, NULL, NULL, '{"1": "손으로 음식을 먹는 경우 턱받이를 해준다.\n턱받이는 음식물이 옷에 묻는 것을 방지할 수 있지만, 치매 대상자는 손으로 음식을 자주 먹을 경우 피부의 건강에도 영향을 미칠 수 있으므로 신중할 필요가 있습니다.", "2": "[정답] 의치가 느슨하면 의치를 뺴고 식사하게 한다.\n의치가 불편할 경우에는 제거하고 식사하는 것이 안전하고 편안할 수 있습니다.", "3": "간식으로 알사탕과 떡을 제공한다.\n딱딱한 간식은 치아에 부담을 줄 수 있어 적절하지 않을 수 있습니다.", "4": "처방 받은 비타민은 음식에 섞어서 먹게 한다.\n비타민의 성질에 따라 섞는 것이 오히려 효과를 떨어뜨릴 수 있습니다.", "5": "휴대전화로 좋아하는 가요 영상을 보여 준다.\n관심을 끌 수 있으나 식사 보조와는 직접적인 관련이 없습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력이나 사고능력이 감소하는 질환", "def_vi": "Bệnh liên quan đến suy giảm trí nhớ hoặc khả năng tư duy"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식을 먹는 행위", "def_vi": "Hành động ăn uống"}, {"term_ko": "의치", "term_vi": "Răng giả", "def_ko": "인공치아", "def_vi": "Răng được làm giả"}, {"term_ko": "턱받이", "term_vi": "Khăn ăn", "def_ko": "음식물이 옷에 묻지 않도록 하는 천", "def_vi": "Vải để ngăn thức ăn dính vào quần áo"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1502, '12', '치매 대상자의 식사 돕기 기본원칙으로 옳은 방법은?', '["혼자 먹을 수 있다면 자리를 비켜준다.", "사례가 자주 걸리면 수분이 없는 음식을 제공한다.", "초조해 하는 경우에도 정해진 식사는 제공한다.", "접시보다는 사발을 사용하여 덜 흘리게 한다.", "음식을 한꺼번에 섞어 제공한다."]'::jsonb, 4, NULL, NULL, '{"1": "혼자 먹을 수 있다면 자리를 비켜준다. - 독립성을 존중하나, 상황에 따라 도움을 줄 필요가 있다.\n[정답]", "4": "접시보다는 사발을 사용하여 덜 흘리게 한다. - 사발은 사용이 용이하고 흘릴 가능성을 줄여준다.", "2": "사례가 자주 걸리면 수분이 없는 음식을 제공한다. - 수분 섭취가 중요하므로 잘못된 방법이다.", "3": "초조해 하는 경우에도 정해진 식사는 제공한다. - 초조함을 해소하기 위해 유연하게 대처해야 한다.", "5": "음식을 한꺼번에 섞어 제공한다. - 식사의 즐거움을 해칠 수 있으므로 바람직하지 않다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억과 인지 기능이 감소하는 질환", "def_vi": "Bệnh suy giảm trí nhớ và chức năng tư duy"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식을 섭취하는 행위", "def_vi": "Hành động tiêu thụ thực phẩm"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "위협 없이 상태", "def_vi": "Trạng thái không có mối đe dọa"}, {"term_ko": "독립성", "term_vi": "Tính độc lập", "def_ko": "스스로 처리할 수 있는 능력", "def_vi": "Khả năng tự xử lý"}, {"term_ko": "유연하게", "term_vi": "Linh hoạt", "def_ko": "상황에 따라 조정하는 방식", "def_vi": "Phương pháp điều chỉnh theo tình huống"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1501, '12', '의치를 사용하는 치매 대상자가 식사 중 가장 조심해야 할 것은?', '["과식", "구토", "질식", "기침", "설사"]'::jsonb, 3, NULL, NULL, '{"1": "과식은 위장에 부담을 줄 수 있지만, 가장 큰 위험은 아닙니다.\n[정답]", "3": "질식은 의치를 사용하는 치매 대상자에게 매우 위험한 상황으로, 특히 응급 상황이 발생할 수 있습니다.", "2": "구토는 불편을 초래하지만, 바로 위험 요소라고 보기는 어렵습니다.", "4": "기침은 식사 중 발생할 수 있으나, 질식처럼 즉각적인 위험 요소는 아닙니다.", "5": "설사는 식사와 관련된 문제일 수 있으나, 당장 위험한 상황은 아닙니다."}'::jsonb, '[{"term_ko": "의치", "term_vi": "Răng giả", "def_ko": "치아 대체물(한국어)", "def_vi": "Vật thay thế cho răng"}, {"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력 및 사고력을 저하시켜 일상 생활에 영향을 미치는 질환(한국어)", "def_vi": "Bệnh làm giảm trí nhớ và khả năng tư duy, ảnh hưởng đến cuộc sống hàng ngày"}, {"term_ko": "질식", "term_vi": "Nghẹt thở", "def_ko": "호흡에 장애가 생기는 상태(한국어)", "def_vi": "Trạng thái khó thở"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1500, '12', '치매 대상자가 식사를 하지 않으려고 할 때 돕는 방법은?', '["식사해야 하는 이유를 설명한다.", "음식을 요청할 때까지 금식 시킨다.", "모든 음식을 섞어서 갈아준다.", "직접 식사를 준비하게 한다.", "약의 부작용인지 확인한다."]'::jsonb, 5, NULL, NULL, '{"1": "식사에 대한 이유를 설명하는 것은 도움을 줄 수 있지만, 바로 효과적이지 않을 수 있습니다.\n[정답]", "5": "약의 부작용을 확인하는 것은 중요한 단계입니다. 치매 환자의 식사 거부가 약물의 부작용 때문일 수 있기 때문에 확인이 필요합니다.", "2": "금식은 환자의 건강을 해칠 수 있으므로 적절하지 않습니다.", "3": "모든 음식을 섞어서 갈아주는 것은 환자의 기호를 무시할 수 있습니다.", "4": "환자에게 직접 식사를 준비하게 하는 것은 오히려 부담을 줄 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억 상실과 관련된 질병", "def_vi": "Bệnh liên quan đến sự suy giảm trí nhớ"}, {"term_ko": "반드시", "term_vi": "Nhất thiết", "def_ko": "반드시 필요하다", "def_vi": "Cần thiết phải"}, {"term_ko": "부작용", "term_vi": "Tác dụng phụ", "def_ko": "약물이 몸에 미치는 어떤 부정적인 효과", "def_vi": "Tác động tiêu cực của thuốc"}, {"term_ko": "금식", "term_vi": "Nhịn ăn", "def_ko": "음식을 먹지 않음", "def_vi": "Không ăn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1499, '12', '치매 대상자에게 일상생활 사고가 많이 발생하는 이유는?', '["상황을 분석하거나 평가를 잘한다.", "금방 잊어버린다.", "병으로 할 수 없게 된 일은 쉽게 포기한다.", "새로운 일을 쉽게 받아들인다.", "갑작스런 변화에 잘 대처한다."]'::jsonb, 2, NULL, NULL, '{"1": "치매 환자는 상황 분석이나 평가가 어려워 사고를 예방하기 어렵다.\n[정답]", "2": "치매는 기억력 저하를 유발하여 중요한 상황을 금방 잊어버리게 한다.", "3": "병으로 인해 일상적인 TASK를 쉽게 포기할 수 있다.", "4": "새로운 일을 받아들이는 데 어려움을 겪는 경우가 많다.", "5": "갑작스러운 변화에 대처하기가 어렵다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Mất trí nhớ", "def_ko": "기억을 잃어버리는 질병", "def_vi": "Bệnh mất trí nhớ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1498, '12', '시설 치매 대상자의 일상생활을 지원하는 방법으로 옳은 것은?', '["주변 환경을 자주 바꾸어 활력을 준다.", "습관적으로 해오던 일은 스스로 하게 한다.", "치매 증상이 호전되면 약물 용량을 줄여 준다.", "사소한 것이라도 요양보호사가 전적으로 돕는다.", "치매로 인해 일상생활을 할 수 없는 것이라고 설명한다."]'::jsonb, 2, NULL, NULL, '{"1": "주변 환경을 자주 바꾸면 오히려 혼란을 초래할 수 있으므로 바람직하지 않다.\n[정답]", "2": "습관적으로 해오던 일은 스스로 하게 하는 것이 자립을 돕는 방법이다.", "3": "치매 증상이 호전된 경우 약물 용량 조정은 반드시 의사와 상의해야 한다.", "4": "요양보호사는 필요할 때 지원하더라도, 가능한 한 대상자가 스스로 할 수 있도록 도와야 한다.", "5": "치매 대상자의 상황을 부정적이고 단정적으로 설명하는 것은 바람직하지 않다."}'::jsonb, '[{"term_ko": "시설", "term_vi": "Cơ sở", "def_ko": "시설(한국어)", "def_vi": "Cơ sở"}, {"term_ko": "치매", "term_vi": "Chứng mất trí", "def_ko": "치매(한국어)", "def_vi": "Chứng mất trí"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "대상자(한국어)", "def_vi": "Đối tượng"}, {"term_ko": "일상생활", "term_vi": "Cuộc sống hàng ngày", "def_ko": "일상생활(한국어)", "def_vi": "Cuộc sống hàng ngày"}, {"term_ko": "지원", "term_vi": "Hỗ trợ", "def_ko": "지원(한국어)", "def_vi": "Hỗ trợ"}, {"term_ko": "스스로", "term_vi": "Tự mình", "def_ko": "스스로(한국어)", "def_vi": "Tự mình"}, {"term_ko": "자립", "term_vi": "Tự lập", "def_ko": "자립(한국어)", "def_vi": "Tự lập"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1497, '12', '입소한 지 얼마 되지 않은 치매 대상자의 일상생활을 돕는 방법은?', '["새로운 습관을 갖도록 도와준다.", "안전을 위해 침상에서 절대 안정하게 한다.", "기분 전환을 위해 가구 위치를 매일 바꿔 준다.", "원한다면 집에서 쓰던 이불을 가져와 쓰게 한다.", "복용하던 치매약을 스스로 관리하게 한다."]'::jsonb, 4, NULL, NULL, '{"1": "새로운 습관을 갖도록 도와주는 것은 오히려 혼란을 줄 수 있습니다.\n[정답]", "4": "원한다면 집에서 쓰던 이불을 가져와 쓰게 하는 것은 안정감을 주고, 치매 환자의 정서적 지지를 도모합니다.", "2": "안전을 위해 침상에서 절대 안정하게 하는 것은 오히려 활동을 제한하여 부정적인 영향을 줄 수 있습니다.", "3": "기분 전환을 위해 가구 위치를 매일 바꿔 주는 것은 혼란을 초래할 수 있습니다.", "5": "복용하던 치매약을 스스로 관리하게 하는 것은 위험할 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 인지 기능이 저하되는 상태", "def_vi": "Trạng thái giảm trí nhớ và chức năng nhận thức"}, {"term_ko": "일상생활", "term_vi": "Cuộc sống hàng ngày", "def_ko": "매일 수행하는 기본적인 활동", "def_vi": "Các hoạt động cơ bản thực hiện hàng ngày"}, {"term_ko": "안정감", "term_vi": "Cảm giác an toàn", "def_ko": "감정적으로 안정된 상태", "def_vi": "Trạng thái cảm xúc ổn định"}, {"term_ko": "복용하다", "term_vi": "Uống", "def_ko": "약을 먹다", "def_vi": "Ăn thuốc"}, {"term_ko": "관리하다", "term_vi": "Quản lý", "def_ko": "책임을 가지고 다루다", "def_vi": "Xử lý có trách nhiệm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1496, '12', '치매약 처방이 바뀐 뒤 대상자가 불안해 하며 방 안을 왔다 갔다 할 때 돕는 방법은?', '["약의 용량을 늘려서 제공한다.", "이전에 복용하던 치매약을 준다.", "증상을 메모하여 병원에 가지고 간다.", "보호자의 허락을 받고 복용량을 줄인다.", "증상이 좋아지며 나타나는 현상이라고 안심시킨다."]'::jsonb, 3, NULL, NULL, '{"1": "약의 용량을 늘리는 것은 의료 전문가의 판단 없이 행할 수 없다.\n[정답]", "3": "증상을 메모하여 병원에 가지고 가는 것이 적절한 대처 방법이다.", "2": "이전에 복용하던 치매약을 주는 것은 현재의 처방과 다를 수 있어 위험하다.", "4": "보호자의 허락 없이 복용량을 조절하는 것은 법적으로나 윤리적으로 문제가 있다.", "5": "증상이 좋아지며 나타나는 현상이라는 것은 의사와의 상담 후 판단해야 한다."}'::jsonb, '[{"term_ko": "치매약", "term_vi": "Thuốc mất trí nhớ", "def_ko": "알츠하이머나 기타 형태의 치매를 치료하는 약", "def_vi": "Thuốc điều trị chứng mất trí nhớ như Alzheimer"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1495, '12', '치매 대상자의 가족에게 치매 약물 복용의 중요성을 올바르게 설명한 것은?', '["\"치매약 복용은 늦게 시작할수록 안전해요.\"", "\"치매약은 인지기능 개선에 도움이 돼요.\"", "\"치매약은 부작용이 없고, 완치가 가능해요.\"", "\"증상이 좋아지지 않으면 용량을 두 배로 늘려야 해요.\"", "\"치매약은 한 가지를 꾸준히 드셔야 증상을 늦출 수 있어요.\""]'::jsonb, 2, NULL, NULL, '{"1": "치매약 복용은 늦게 시작할수록 안전하다는 주장은 잘못된 정보입니다.\n[정답]", "2": "치매약은 인지기능 개선에 도움이 된다는 점이 맞습니다.", "3": "치매약은 부작용이 없고, 완치가 가능하다는 설명은 사실이 아닙니다.", "4": "증상이 좋아지지 않으면 용량을 두 배로 늘려야 한다는 것은 위험한 판단입니다.", "5": "치매약은 한 가지를 꾸준히 드셔야 증상을 늦출 수 있다는 것은 어느 정도 맞지만, 특정한 약물에 대한 의존성도 고려해야 합니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 사고 능력의 감소를 특징으로 하는 질환", "def_vi": "Bệnh đặc trưng bởi sự giảm khả năng ghi nhớ và tư duy"}, {"term_ko": "약물", "term_vi": "Thuốc", "def_ko": "의학적 치료를 위해 사용하는 물질", "def_vi": "Chất được sử dụng cho điều trị y tế"}, {"term_ko": "인지기능", "term_vi": "Chức năng nhận thức", "def_ko": "사고와 이해 능력", "def_vi": "Khả năng suy nghĩ và hiểu biết"}, {"term_ko": "부작용", "term_vi": "Tác dụng phụ", "def_ko": "약물 사용의 예기치 않은 반응", "def_vi": "Phản ứng bất ngờ khi sử dụng thuốc"}, {"term_ko": "완치", "term_vi": "Chữa khỏi", "def_ko": "질병이 완전히 치료되는 것", "def_vi": "Bệnh hoàn toàn được điều trị"}, {"term_ko": "용량", "term_vi": "Liều lượng", "def_ko": "약물의 천장 섭취량", "def_vi": "Lượng thuốc được sử dụng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1494, '12', '치매 가족과의 의사소통 기법 중 다음 설명에 해당하는 것은?• "힘내세요.", "포기하지 마시고 계속하시면 좋은 결과가 있을 거예요."라고 격려한다. • 다른 가족들이 비슷한 상황을 잘 극복한 긍정적인 사례 등을 전해주어 희망을 준다.', '["공감", "관심 전달", "힘 돋우기", "조언 및 정보제공", "나-메시지 전달법"]'::jsonb, 3, NULL, NULL, '{"1": "공감: 다른 사람의 감정을 이해하고 느끼는 것을 의미하지만, 이 문제에서는 격려의 구체적인 방법이므로 맞지 않습니다.", "2": "관심 전달: 상대방의 상황에 대한 관심을 보여주는 것이나, 격려의 방식에 직접적으로 관련이 없습니다.\n[정답]", "3": "힘 돋우기: 긍정적인 말을 통해 힘을 주고 격려하는 방식으로, 문제의 설명과 일치합니다.", "4": "조언 및 정보제공: 정보나 조언을 주는 것과 관련되지만, 격려와는 다른 개념입니다.", "5": "나-메시지 전달법: 자신의 감정을 표현하는 방법이지만, 문제의 내용과 관련이 없습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh sa sút trí tuệ", "def_ko": "기억력과 인지 기능이 저하되는 질병", "def_vi": "Bệnh suy giảm trí nhớ và chức năng nhận thức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1493, '12', '치매 가족과의 의사소통 기법으로 옳은 것은?', '["치매 가족이 표현한 내용 뒤에 숨겨진감정은 모른척 한다.", "다른 치매 가족들의 실패한 돌봄 사례들은 전해준다.", "기존의 돌봄 방법을 무시하고 다른 방법을 권유한다.", "잘못된 방법은 설명의 과정보다 충고나 지적을 먼저 한다.", "가족의 돌봄 방법이나 지식의 긍정적인 면을 인정해 준다."]'::jsonb, 5, NULL, NULL, '{"1": "치매 가족이 표현한 내용 뒤에 숨겨진 감정은 모른척 하는 것은 의사소통에 좋지 않다.\n[정답]", "5": "가족의 돌봄 방법이나 지식의 긍정적인 면을 인정해 주는 것이 효과적이다.", "3": "기존의 돌봄 방법을 무시하고 다른 방법을 권유하는 것은 가족의 신뢰를 떨어뜨릴 수 있다.", "4": "잘못된 방법은 설명의 과정보다 충고나 지적을 먼저 하는 것은 비효율적이다.", "2": "다른 치매 가족들의 실패한 돌봄 사례들을 전해주는 것은 도움이 되지 않는다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력 및 사고력의 저하를 동반하는 질환", "def_vi": "Bệnh kèm theo sự suy giảm trí nhớ và khả năng tư duy"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "상대방과 정보를 주고받는 과정", "def_vi": "Quá trình trao đổi thông tin với nhau"}, {"term_ko": "돌봄", "term_vi": "Chăm sóc", "def_ko": "신체적, 정서적으로 지원하는 행위", "def_vi": "Hành động hỗ trợ về thể chất và tình cảm"}, {"term_ko": "긍정적인", "term_vi": "Tích cực", "def_ko": "좋은, 긍정적", "def_vi": "Tốt, tích cực"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1492, '12', '치매 가족에게 관심 전달을 하기 위한 의사소통 기법으로 옳은 것은?', '["방어적인 자세를 취한다.", "옆이나 뒤에서 이야기한다.", "마주 보며 큰 목소리로 이야기한다.", "''나는 당신을 존중한다.''고 표현한다.", "친근감을 표현하기 위해 밀착하여 대화한다."]'::jsonb, 4, NULL, NULL, '{"1": "방어적인 자세를 취하는 것은 의사소통을 오히려 방해할 수 있다.\n[정답]", "4": "''나는 당신을 존중한다.''고 표현하는 것은 긍정적인 의사소통 기법이다.", "2": "옆이나 뒤에서 이야기하는 것은 상대방에게 불안감을 줄 수 있다.", "3": "마주 보며 큰 목소리로 이야기하면 의사소통이 원활해질 수도 있으나, 큰 목소리는 공격적으로 들릴 수 있다.", "5": "친근감을 표현하기 위해 밀착하여 대화하는 것은 개인적인 공간을 침해할 수 있기 때문에 바람직하지 않다."}'::jsonb, '[{"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "주고받는 의견이나 감정을 나누는 것", "def_vi": "Chia sẻ ý kiến hoặc cảm xúc"}, {"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력과 사고의 능력이 감소하는 질병", "def_vi": "Bệnh suy giảm trí nhớ và khả năng suy nghĩ"}, {"term_ko": "방어적인", "term_vi": "Có tính phòng thủ", "def_ko": "상대방의 공격이나 비판에 방어하는 것", "def_vi": "Bảo vệ khỏi sự công kích hoặc chỉ trích"}, {"term_ko": "존중", "term_vi": "Tôn trọng", "def_ko": "상대방의 가치를 인정하는 것", "def_vi": "Nhận thức giá trị của người khác"}, {"term_ko": "친근감", "term_vi": "Cảm giác thân thiện", "def_ko": "가까이 다가가고 싶거나 다정한 감정을 느끼는 것", "def_vi": "Cảm thấy gần gũi và muốn tiếp xúc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1491, '12', '치매 가족과의 의사소통 방법으로 옳은 것은?', '["요양보호사의 관점에서 치매가족을 이해한다.", "치매 가족의 기분이 좋다, 나쁘다 정도만 파악한다.", "가족의 대상자를 돌보는 능력을 최대한 지지한다.", "치매가족이 절망적인 감정을 숨길 수 있도록 조언한다.", "고개를 끄덕이는 등의 비언어적인 표현은 사용하지 않는다."]'::jsonb, 3, NULL, NULL, '{"1": "요양보호사가 치매 가족의 입장을 이해하는 것은 중요하지만, 이 방법은 무엇이 옳은지를 묻는 질문에서는 부적절합니다.\n[정답]", "3": "가족의 돌봄 능력을 지지하는 것은 효과적인 의사소통의 중요한 부분입니다.", "2": "기분의 정도만 파악하는 것은 소통의 깊이를 부족하게 합니다.", "4": "절망적인 감정을 숨기도록 하는 것은 건강한 소통이 아닙니다.", "5": "비언어적 표현은 의사소통에서 매우 중요하므로 사용하지 않는 것은 바람직하지 않습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억 및 사고에 영향을 미치는 질병", "def_vi": "Bệnh ảnh hưởng đến trí nhớ và tư duy"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1490, '12', '치매 가족이 느끼는 부담 중 신체적 부담에 해당하는 것은?', '["죄책감", "소외감", "불안감", "수면장애", "무기력감"]'::jsonb, 4, NULL, NULL, '{"1": "죄책감: 정서적 부담으로 분류됩니다.", "2": "소외감: 정서적 부담으로, 대인관계에서 오는 스트레스입니다.", "3": "불안감: 정서적 부담으로, 미래에 대한 걱정에서 기인합니다.\n[정답]", "4": "수면장애: 신체적 증상으로 치매 환자를 돌보는 과정에서 발생하는 신체적 부담입니다.", "5": "무기력감: 정서적 부담으로, 힘든 상황에 대한 반응입니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억과 사고 능력이 감소하는 상태", "def_vi": "Tình trạng giảm trí nhớ và khả năng suy nghĩ"}, {"term_ko": "부담", "term_vi": "Gánh nặng", "def_ko": "스트레스나 압박감", "def_vi": "Sự căng thẳng hoặc áp lực"}, {"term_ko": "신체적", "term_vi": "Về thể chất", "def_ko": "신체와 관련된", "def_vi": "Liên quan đến cơ thể"}, {"term_ko": "수면장애", "term_vi": "Rối loạn giấc ngủ", "def_ko": "잠을 제대로 자지 못하는 상태", "def_vi": "Tình trạng không thể ngủ đúng cách"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1489, '12', '치매 가족이 느끼는 부담 중 신체적 부담에 해당하는 것은?', '["죄책감", "소외감", "불안감", "수면장애", "무기력감"]'::jsonb, 4, NULL, NULL, '{"1": "죄책감은 정서적 부담에 해당한다.", "2": "소외감 역시 정서적 부담이다.", "3": "불안감은 주로 심리적 부담으로 분류된다.\n[정답]", "4": "수면장애는 신체적 상태에 직접적인 영향을 미치는 문제이다.", "5": "무기력감은 정서적인 반응으로 볼 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력과 사고력을 잃는 질병", "def_vi": "Bệnh mất trí nhớ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1488, '12', '치매 가족이 느끼는 부담에 대한 설명으로 옳은 것은?', '["치매 대상자가 나아질 것 같지 않은 무기력감을 느낀다.", "치매 대상자를 돌보는 것에 정서적 안도감을 느낀다.", "사회적 접촉이 늘어나면서 사회적 역할이 많아진다.", "가족의 상호이해와 협동으로 가족관계가 긍정적으로 변한다.", "전문가의 지원으로 역기능적 상호작용의 연쇄과정이 발생한다."]'::jsonb, 1, NULL, NULL, '{"1": "치매 대상자가 나아질 것 같지 않은 무기력감을 느낀다.\n[정답] 치매에 대한 부정적인 인식으로 인해 가족 구성원들이 느끼는 무기력감과 부담을 적절히 설명합니다.", "2": "치매 대상자를 돌보는 것에 정서적 안도감을 느낀다.\n정서적 안도감이 아닌 부담을 느낌이 강조되는 문제입니다.", "3": "사회적 접촉이 늘어나면서 사회적 역할이 많아진다.\n오히려 사회적 접촉이 줄어들며 역할이 제한되는 경향이 있습니다.", "4": "가족의 상호이해와 협동으로 가족관계가 긍정적으로 변한다.\n부담이 증가하면서 관계가 부정적으로 변할 수 있습니다.", "5": "전문가의 지원으로 역기능적 상호작용의 연쇄과정이 발생한다.\n전문가 지원은 보통 긍정적인 영향을 미칩니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억이나 사고가 망가지는 질병", "def_vi": "Bệnh gây suy giảm trí nhớ hoặc tư duy"}, {"term_ko": "무기력감", "term_vi": "Cảm giác bất lực", "def_ko": "힘이 없고 무기력한 느낌", "def_vi": "Cảm giác không có sức mạnh hoặc khả năng"}, {"term_ko": "정서적", "term_vi": "Cảm xúc", "def_ko": "감정에 관한", "def_vi": "Liên quan đến tình cảm"}, {"term_ko": "상호이해", "term_vi": "Hiểu biết lẫn nhau", "def_ko": "서로의 이해", "def_vi": "Sự hiểu biết giữa hai hay nhiều người"}, {"term_ko": "전문가", "term_vi": "Chuyên gia", "def_ko": "특정 분야의 전문가", "def_vi": "Người có kiến thức chuyên sâu trong một lĩnh vực"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1487, '11', '치매 노인의 환경적 자극의 질과 조정을 위한 방법으로 옳은 것은?', '["만남을 촉진하는 공간 배치를 한다.", "꽃 향기 등으로 감성을 자극한다.", "스스로 식사할 수 있는 환경을 만든다.", "걸려 넘어질 수 있는 바닥의 턱을 없앤다.", "의자, 탁자와 같은 소품을 여러 곳에 배치한다."]'::jsonb, 2, NULL, NULL, '{"1": "만남을 촉진하는 공간 배치는 중요한 요소지만, 이 문제에서 요구하는 환경적 자극의 질과는 다소 거리가 있습니다.\n[정답]", "2": "꽃 향기 등으로 감성을 자극하면 치매 노인의 정서 및 인지적 반응을 긍정적으로 유도할 수 있습니다.", "3": "스스로 식사할 수 있는 환경을 만드는 것은 좋지만, 환경적 자극의 질 조정과는 직접적인 관련이 없습니다.", "4": "걸려 넘어질 수 있는 바닥의 턱을 없애는 것은 안전을 위한 조치이나, 자극의 질과는 관계가 없습니다.", "5": "의자, 탁자와 같은 소품을 여러 곳에 배치하는 것은 공간의 활용에 관한 것이지, 자극의 질과는 관련이 적습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력 및 인지 능력이 감소하는 노인성 질환", "def_vi": "Bệnh suy giảm trí nhớ và khả năng nhận thức ở người già"}, {"term_ko": "환경", "term_vi": "Môi trường", "def_ko": "주변의 상황과 조건", "def_vi": "Các tình huống và điều kiện xung quanh"}, {"term_ko": "자극", "term_vi": "Kích thích", "def_ko": "감각이나 반응을 일으키는 것", "def_vi": "Điều gợi ra cảm giác hay phản ứng"}, {"term_ko": "질", "term_vi": "Chất lượng", "def_ko": "무엇의 성질이나 상태", "def_vi": "Tính chất hoặc trạng thái của cái gì"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1486, '11', '장기요양기관에서 생활하는 치매대상자의 환경지원 지침 영역으로 다음 내용에 해당되는 것은?• 스스로 식사할 수 있는 환경을 조성한다. • 요리, 빨래, 장보기 등 활동을 할 수 있는 환경을 만든다.', '["지남력 지원", "자기 선택을 위한 지원", "기능적인 능력 지원", "환경적 자극의 질과 조정", "대상자의 교류를 위한 지원"]'::jsonb, 3, NULL, NULL, '{"1": "지남력 지원: 지남력을 향상시키기 위한 방법, 문제의 내용과는 무관하다.", "2": "자기 선택을 위한 지원: 치매환자가 자신의 선택을 할 수 있도록 돕는 방법, 해당 내용과 부분적으로 관련 있다.\n[정답]", "3": "기능적인 능력 지원: 스스로 식사하고 활동할 수 있는 환경을 조성하는 것이면 기능적 능력을 지원하는 것에 해당한다.", "4": "환경적 자극의 질과 조정: 환경 자극의 질을 조정하는 것에 관한 것으로, 문제의 주제와는 다소 차이가 있다.", "5": "대상자의 교류를 위한 지원: 다른 사람과의 소통을 지원하는 것, 문제의 핵심과는 다르다."}'::jsonb, '[{"term_ko": "장기요양기관", "term_vi": "Cơ sở chăm sóc dài hạn", "def_ko": "장기적으로 요양 및 치료를 제공하는 기관", "def_vi": "Nơi cung cấp chăm sóc và điều trị dài hạn"}, {"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력과 사고능력이 감소하는 질병", "def_vi": "Bệnh suy giảm trí nhớ và khả năng tư duy"}, {"term_ko": "환경지원", "term_vi": "Hỗ trợ môi trường", "def_ko": "지원을 통해 환경을 조성하는 것", "def_vi": "Tạo điều kiện môi trường thông qua hỗ trợ"}, {"term_ko": "기능적인 능력", "term_vi": "Khả năng chức năng", "def_ko": "필요한 작용을 수행할 수 있는 능력", "def_vi": "Khả năng thực hiện các chức năng cần thiết"}, {"term_ko": "자기 선택", "term_vi": "Lựa chọn cá nhân", "def_ko": "개인이 직접 선택하는 것", "def_vi": "Việc tự lựa chọn của cá nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1485, '11', '다음 내용에 해당하는 치매노인 환경지원 지침의 영역은?• 대상자가 생활하는 공간 입구에 이름표를 붙인다. • 시계나 달력을 잘 보이는 곳에 걸어둔다.', '["지남력 지원", "기능적인 능력지원", "자기 선택을 위한 지원", "안전, 안심을 위한 지원", "환경적 자극의 질과 조정"]'::jsonb, 1, NULL, NULL, '{"1": "대상자가 지남력을 유지하도록 돕기 위해 환경을 조정하는 방안이다.\n[정답]", "2": "기능적인 능력을 유지할 수 있도록 돕는 것과는 관련이 없다.", "3": "자기 선택을 위한 지원과 관련된 내용은 아니다.", "4": "안전과 안심을 위한 지원은 해당 내용과는 관련이 없다.", "5": "환경적 자극의 질과 조정은 다른 측면이다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력과 사고력의 기능이 저하되는 질병", "def_vi": "Bệnh suy giảm trí nhớ và khả năng tư duy"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1484, '11', '재가에서 청소하는 방법으로 옳은 것은?', '["방바닥의 먼지는 빗자루로 제거한다.", "양변기의 물때는 솔에 식초를 묻혀 닦는다.", "습기가 많은 화장실은 문을 닫아 놓는다.", "사용하지 않는 물건은 옮기거나 처분한다.", "쓰레기통에서 냄새가 나는 경우 방향제를 뿌린다."]'::jsonb, 2, NULL, NULL, '{"1": "방바닥의 먼지는 빗자루로 제거하는 것은 기본적인 청소법이지만, 재가 청소에서는 진공청소기를 사용하는 것이 일반적입니다.\n[정답]", "2": "양변기의 물때는 솔에 식초를 묻혀 닦는 것이 효과적인 청소 방법입니다.", "3": "습기가 많은 화장실은 문을 닫아 놓으면 더욱 습해질 수 있으므로, 적절한 환기가 필요합니다.", "4": "사용하지 않는 물건은 옮기거나 처분하는 것이 맞지만, 이 방법이 청소 방법으로 보기는 어렵습니다.", "5": "쓰레기통에서 냄새가 나는 경우 방향제를 뿌리는 것보다는 쓰레기를 제때 비우는 것이 중요합니다."}'::jsonb, '[{"term_ko": "재가", "term_vi": "Tại nhà", "def_ko": "가정에서 요양 서비스가 제공되는 것", "def_vi": "Dịch vụ chăm sóc được cung cấp tại nhà"}, {"term_ko": "청소", "term_vi": "Dọn dẹp", "def_ko": "더러운 것을 치우는 것", "def_vi": "Làm sạch những thứ bẩn"}, {"term_ko": "양변기", "term_vi": "Bồn cầu", "def_ko": "욕실에서 사용하는 화장실 기구", "def_vi": "Thiết bị vệ sinh trong nhà tắm"}, {"term_ko": "물때", "term_vi": "Vết bẩn", "def_ko": "물이 마르면서 남는 더러운 자국", "def_vi": "Dấu bẩn còn lại khi nước khô"}, {"term_ko": "식초", "term_vi": "Giấm", "def_ko": "발효를 통해 만들어진 액체", "def_vi": "Chất lỏng được làm từ sự lên men"}, {"term_ko": "환기", "term_vi": "Thông gió", "def_ko": "공기가 순환하는 것", "def_vi": "Sự lưu thông không khí"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1483, '11', '재가 방문 시 청소하는 방법으로 옳은 것은?', '["배수구에 소독제 원액을 부어준다.", "시트나 침구는 가능한 낮에 정리한다.", "주변정돈 시 요양보호사가 알아서 정리한다.", "실내 청소를 할 때 젖은 걸레로 먼지를 제거한다.", "음식물 쓰레기는 모아 두었다가 일주일에 한 번 버린다."]'::jsonb, 4, NULL, NULL, '{"1": "배수구에 소독제 원액을 부어주는 것은 부당하며, 적절히 희석하여 사용해야 한다.\n[정답]", "4": "실내 청소를 할 때 젖은 걸레로 먼지를 제거해야 청결을 유지할 수 있다.", "2": "시트나 침구는 낮에 정리하기 보다는 사용 후 즉시 정리하는 것이 바람직하다.", "3": "주변정돈 시 요양보호사가 아닌 환자가 직접 정리하는 것이 최선이다.", "5": "음식물 쓰레기는 즉시 처리하는 것이 위생적이다."}'::jsonb, '[{"term_ko": "재가", "term_vi": "Tại gia", "def_ko": "가정에서 요양을 제공받는 것", "def_vi": "Nhận được sự chăm sóc tại nhà"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1482, '11', '대상자의 쾌적하고 안전한 실내 환경을 만드는 방법으로 옳은 것은?', '["커튼으로 자연채광을 차단한다.", "전체난방 보다는 국소난방을 한다.", "환기 시에는 직접환기방법을 사용한다.", "가스레인지는 대상자의 손이 닿지 않는 높이로 조정한다.", "현관이나 계단에 발밑을 비추는 조명을 설치한다."]'::jsonb, 5, NULL, NULL, '{"1": "커튼으로 자연채광을 차단하면 실내 환경이 어두워져 쾌적하지 않다.\n[정답]", "5": "현관이나 계단에 발밑을 비추는 조명을 설치하면 안전사고를 예방할 수 있다.", "2": "전체난방보다 국소난방은 오히려 쾌적하지 않을 수 있다.", "3": "환기 시 직접환기방법은 불필요한 외부 공기를 유입시켜 쾌적하지 않을 수 있다.", "4": "가스레인지는 대상자의 손이 닿지 않는 높이에 조정하는 것이 좋지만 주의해야 할 점이 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người đối diện", "def_ko": "환자(한국어)", "def_vi": "Bệnh nhân"}, {"term_ko": "쾌적", "term_vi": "Thoải mái", "def_ko": "편안함(한국어)", "def_vi": "Sự thoải mái"}, {"term_ko": "환경", "term_vi": "Môi trường", "def_ko": "주위 상황(한국어)", "def_vi": "Môi trường"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "위험이 없는 상태(한국어)", "def_vi": "An toàn"}, {"term_ko": "조명", "term_vi": "Ánh sáng", "def_ko": "빛(한국어)", "def_vi": "Ánh sáng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1481, '11', '대상자의 안전하고 쾌적한 실내 환경을 조성하는 방법으로 옳은 것은?', '["현관이나 계단의 문턱을 낮춘다.", "가구 모서리에 덧대기를 한다.", "다리 간격이 좁은 식탁을 사용한다.", "안전손잡이는 마비가 있는 쪽으로 설치한다.", "환기 시에는 대상자가 바람을 직접 쐬게 한다."]'::jsonb, 2, NULL, NULL, '{"1": "현관이나 계단의 문턱을 낮추는 것은 안전에 도움이 되지만, 직접적인 쾌적함과는 다소 거리가 있다.\n[정답]", "2": "가구 모서리에 덧대기를 하는 것은 사고를 예방하고 안전한 환경을 조성하는 방법이다.", "3": "다리 간격이 좁은 식탁은 오히려 불편함을 초래할 수 있다.", "4": "안전손잡이는 마비가 없는 쪽으로 설치해야 하며, 마비 있는 쪽은 불안정할 수 있어 주의가 필요하다.", "5": "환기 시 대상자가 직접 바람을 쐬는 것은 건강에 좋지 않을 수 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người chăm sóc", "def_ko": "환자, 대상", "def_vi": "Bệnh nhân, đối tượng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1480, '11', '쾌적하고 안전한 실내 환경을 조성하는 방법으로 옳은 것은?', '["야간에는 수면을 위해 전체 소등한다.", "실내에 직사광선이 들어오게 한다.", "여름에는 제습기, 겨울에는 가습기를 사용한다.", "배설물을 치울 때는 간접 조명을 사용한다.", "여름은 16~18도, 겨울은 25~26도의 실내온도를 유지한다."]'::jsonb, 3, NULL, NULL, '{"1": "야간에는 수면을 위해 전체 소등하는 것은 안전과 관련하여 문제가 될 수 있습니다.\n[정답]", "3": "여름에는 제습기, 겨울에는 가습기를 사용하여 실내 환경의 습도를 조절하는 것은 매우 효과적입니다.", "2": "실내에 직사광선이 들어오게 하는 것은 온도를 불편하게 할 수 있습니다.", "4": "배설물을 치울 때 간접 조명을 사용하면 안전이 저하될 수 있습니다.", "5": "여름온도를 16~18도로 설정하는 것은 오히려 건강에 좋지 않을 수 있습니다."}'::jsonb, '[{"term_ko": "쾌적", "term_vi": "안전", "def_ko": "편안한, dễ chịu", "def_vi": "안전한, an toàn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1479, '11', '대상자의 쾌적하고 안전한 실내 환경을 위한 방법으로 옳은 것은?', '["전기코드는 바닥에 고정시킨다.", "밤에는 거실과 화장실 조명을 끈다.", "욕실에 작은 나무 발판을 설치한다.", "몸이 충분히 잠기도록 깊은 욕조를 선택한다.", "하루 3번, 2~3시간 간격으로 창문을 열어 환기한다."]'::jsonb, 5, NULL, NULL, '{"1": "전기코드를 바닥에 고정시키는 것은 안전하지만, 가장 쾌적한 환경을 만드는 방법은 아닙니다.\n[정답]", "5": "하루 3번, 2~3시간 간격으로 창문을 열어 환기하는 것은 실내 공기를 쾌적하게 유지하는 가장 효과적인 방법입니다.", "3": "욕실에 작은 나무 발판을 설치하는 것은 안전에 도움이 될 수 있지만, 쾌적한 환경을 만드는 데에는 제한적입니다.", "4": "몸이 충분히 잠기도록 깊은 욕조를 선택하는 것은 편안함을 줄 수 있으나, 안전성을 고려하지 않아 위험할 수 있습니다.", "2": "밤에 거실과 화장실 조명을 끄는 것은 안전을 해칠 수 있는 행동입니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Người nhận chăm sóc"}, {"term_ko": "쾌적", "term_vi": "Dễ chịu", "def_ko": "쾌적한 상태", "def_vi": "Trạng thái thoải mái"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "위험이 없는 상태", "def_vi": "Tình trạng không có nguy hiểm"}, {"term_ko": "환경", "term_vi": "Môi trường", "def_ko": "주위의 상황", "def_vi": "Tình huống xung quanh"}, {"term_ko": "환기", "term_vi": "Thông gió", "def_ko": "공기의 흐름을 좋게 하다", "def_vi": "Cải thiện luồng không khí"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1478, '11', '대상자의 주거환경을 안전하게 관리하는 방법은?', '["화장실은 멀리 둔다.", "현관 입구를 좁게 만든다.", "대상자의 방에 비상벨을 달아둔다.", "창가에 작은 화분을 여러 개 놓는다.", "계단은 일직선의 계단으로 설치한다."]'::jsonb, 3, NULL, NULL, '{"1": "화장실을 멀리 두는 것은 안전과 관련이 없으며, 오히려 불편함을 초래할 수 있다.", "2": "현관 입구를 좁게 만드는 것은 접근성을 줄이며 위험할 수 있다.\n[정답]", "3": "대상자의 방에 비상벨을 달아두는 것은 안전을 위해 매우 중요하다.", "4": "창가에 작은 화분을 여러 개 놓는 것은 안전과 관계없이 장식적인 요소로, 사고를 유발할 수 있다.", "5": "계단은 일직선으로 설치하는 것이 아니라, 안전성을 고려하여 설계해야 한다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người nhận chăm sóc", "def_ko": "환자를 받는 사람", "def_vi": "Người được chăm sóc"}, {"term_ko": "주거환경", "term_vi": "Môi trường sống", "def_ko": "주거 공간의 안전 및 환경", "def_vi": "An toàn và môi trường sống"}, {"term_ko": "비상벨", "term_vi": "Chuông báo khẩn cấp", "def_ko": "긴급 상황을 알리는 장치", "def_vi": "Thiết bị báo động trong tình huống khẩn cấp"}, {"term_ko": "화분", "term_vi": "Chậu cây", "def_ko": "식물을 심는 용기", "def_vi": "Đồ dùng để trồng cây"}, {"term_ko": "접근성", "term_vi": "Khả năng tiếp cận", "def_ko": "접근할 수 있는 정도", "def_vi": "Mức độ tiếp cận"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1477, '11', '대상자의 안전한 주거환경으로 옳은 것은?', '["필요한 물품은 높은 곳에 정리해 둔다.", "방과 거실을 구분하기 위해 문턱을 둔다.", "현관에 신발을 신고 벗을 수 있게 의자를 놓아둔다.", "화장실은 안을 볼 수 있는 유리문으로 설치한다.", "싱크대는 손이 닿지 않는 높이로 조정한다."]'::jsonb, 3, NULL, NULL, '{"1": "필요한 물품은 높은 곳에 정리해 둠으로써 오히려 안전에 위협이 될 수 있습니다.", "2": "방과 거실을 구분하기 위한 문턱은 넘어질 위험을 증가시킬 수 있습니다.\n[정답]", "3": "현관에 신발을 신고 벗을 수 있게 의자를 두는 것은 안전성을 높이는 좋은 방법입니다.", "4": "화장실은 안을 볼 수 있는 유리문으로 설치할 경우 사생활이 침해될 수 있습니다.", "5": "싱크대는 손이 닿지 않는 높이로 조정하면 사용이 불편해질 수 있습니다."}'::jsonb, '[{"term_ko": "안전", "term_vi": "An toàn", "def_ko": "안전(한국어)", "def_vi": "An toàn(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1476, '11', '대상자가 안전하게 화장실을 이용할 수 있도록 돕는 방법으로 옳은 것은?', '["화장실 문고리는 막대형으로 한다.", "화장실 표시는 입구 아래쪽에 한다.", "화장실 조명의 조도는 낮게 유지한다.", "화장실 복도에 화분을 두어 미관을 좋게 한다.", "화장실에 갈 때 신고 벗기 쉽게 슬리퍼를 신긴다."]'::jsonb, 1, NULL, NULL, '{"1": "막대형 문고리는 손이 약한 노인이거나 장애인을 위해 사용하기 쉽습니다.\n[정답]", "2": "입구 아래쪽에 표지하면 시각적으로 불편함을 초래할 수 있습니다.", "3": "조도가 낮으면 화장실을 사용할 때 위험할 수 있습니다.", "4": "화분은 이동 시 장애가 될 수 있으므로 두지 않는 것이 좋습니다.", "5": "신고 벗기 쉬운 슬리퍼는 안전을 고려한 선택이 아닙니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người dùng", "def_ko": "이용의 객체(한국어)", "def_vi": "Đối tượng sử dụng"}, {"term_ko": "화장실", "term_vi": "Nhà vệ sinh", "def_ko": "개인 화장실(한국어)", "def_vi": "Phòng tắm cá nhân"}, {"term_ko": "조명", "term_vi": "Ánh sáng", "def_ko": "빛(한국어)", "def_vi": "Ánh sáng"}, {"term_ko": "복도", "term_vi": "Hành lang", "def_ko": "긴 통로(한국어)", "def_vi": "Hành lang"}, {"term_ko": "막대형", "term_vi": "Kiểu thanh", "def_ko": "긴 막대 모양(한국어)", "def_vi": "Dạng thanh"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1475, '11', '재가대상자에게 일상업무 대행을 지원하는 방법으로 옳은 것은?', '["약국에서 대상자의 약품을 대신 받아준다.", "대상자 가족의 물품을 택배로 보낸다.", "대상자 집에 방문한 아들의 옷을 세탁한다.", "배우자의 심부름을 해준다.", "요양보호사의 사적인 업무를 함께 본다."]'::jsonb, 1, NULL, NULL, '{"1": "약국에서 대상자의 약품을 대신 받아주는 것은 재가대상자의 일상업무 대행을 지원하는 올바른 방법입니다.\n[정답]", "2": "가족의 물품을 택배로 보내는 것은 재가대상자의 업무가 아니므로 부적절합니다.", "3": "아들의 옷을 세탁하는 것은 개인적인 일로, 재가대상자와의 관련이 없습니다.", "4": "배우자의 심부름을 해주는 것은 해당 업무에 해당하지 않습니다.", "5": "요양보호사의 사적인 업무를 돕는 것은 전문적인 서비스 제공과 관련이 없습니다."}'::jsonb, '[{"term_ko": "재가대상자", "term_vi": "Người chăm sóc tại nhà", "def_ko": "가정에서 요양 서비스를 받는 사람", "def_vi": "Người nhận dịch vụ điều dưỡng tại nhà"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1474, '11', '대상자의 관공서 업무대행 시 요양보호사의 올바른 태도는?', '["대행 경비에 서비스 비용을 추가하여 요구한다.", "대상자의 요구가 있을 경우 업무 담당자를 연계하여 준다.", "필요한 정보나 자료는 업무대행 중 대상자에게 전화로 확인한다.", "불만족하여 재요청 시는 정중히 거절한다.", "업무 대행 후 처리 결과만 전달한다."]'::jsonb, 2, NULL, NULL, '{"1": "대행 경비에 서비스 비용을 추가하여 요구하는 것은 부당한 행동입니다.\n[정답]", "2": "대상자의 요구가 있을 경우 업무 담당자를 연계하여 주는 것은 올바른 태도입니다.", "3": "필요한 정보나 자료를 업무대행 중 대상자에게 전화로 확인하는 것은 기본적으로 바람직하지 않습니다.", "4": "불만족하여 재요청 시 정중히 거절하는 것은 서비스 제공자로서 적절한 태도가 아닙니다.", "5": "업무 대행 후 처리 결과만 전달하는 것은 불완전한 서비스입니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자, 서비스 요청자", "def_vi": "Người yêu cầu dịch vụ"}, {"term_ko": "관공서", "term_vi": "Cơ quan nhà nước", "def_ko": "정부 기관", "def_vi": "Cơ quan của chính phủ"}, {"term_ko": "업무대행", "term_vi": "Đại diện công việc", "def_ko": "업무 수행", "def_vi": "Thực hiện công việc"}, {"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "돌보는 사람", "def_vi": "Người chăm sóc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1473, '11', '대상자와 외출 시 동행하는 방법으로 옳은 것은?', '["외출 시 필요한 준비물은 대상자가 챙기도록 한다.", "대상자의 개인물품은 분실할 수도 있음을 미리 알려준다.", "요양보호사의 자동차를 이용한다.", "외출장소 및 시간은 요양보호사가 정한다.", "오출 후 대상자의 만족 정도를 확인한다."]'::jsonb, 5, NULL, NULL, '{"1": "외출 시 필요한 준비물은 대개 요양보호사가 챙기므로 대상자가 혼자 챙기는 것은 바람직하지 않다.", "2": "대상자의 개인물품 분실 가능성은 알고 있지만 미리 알려주는 것은 필요하지 않다.\n[정답]", "3": "요양보호사는 요청이나 상황에 따라 자동차를 이용할 수 있지만 반드시 그렇지는 않다.", "4": "외출장소 및 시간은 대상자와 협의하여 정하는 것이 적절하다.", "5": "외출 후 대상자의 만족 정도를 확인하는 것은 중요한 점검 사항으로 올바른 행동이다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자 또는 돌봄을 받는 사람", "def_vi": "người bệnh hoặc người nhận sự chăm sóc"}, {"term_ko": "동행", "term_vi": "Đi cùng", "def_ko": "함께 가는 것", "def_vi": "đi cùng nhau"}, {"term_ko": "개인물품", "term_vi": "Đồ dùng cá nhân", "def_ko": "개인 소지품", "def_vi": "đồ cá nhân"}, {"term_ko": "분실", "term_vi": "Mất mát", "def_ko": "잃어버리는 것", "def_vi": "hành động đã mất"}, {"term_ko": "만족 정도", "term_vi": "Mức độ hài lòng", "def_ko": "만족하는 정도", "def_vi": "mức độ hài lòng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1472, '11', '대상자의 일상업무를 대행하기 전 확인해야 할 사항으로 옳은 것은?', '["경제적 능력 상태를 확인한다,", "함께 할 동료가 있는지 확인한다.", "업무 대행 전에 준비할 자료나 경비를 점검한다,", "어무 대행을 대신해 줄 사람이 있는지 확인한다.", "가족이 추가로 요구한 사항이 있는지 확인한다."]'::jsonb, 3, NULL, NULL, '{"1": "경제적 능력 상태를 확인하는 것은 중요하지만, 대행 전에 확인할 주된 사항은 아닙니다.\n[정답]", "3": "업무 대행 전에 준비할 자료나 경비를 점검하는 것은 필수적입니다.", "2": "함께 할 동료가 있는지 확인하는 것도 중요하지만, 직접적인 대행 업무와는 관련이 없습니다.", "4": "어무 대행을 대신해 줄 사람이 있는지 확인하는 것은 상황에 따라 달라질 수 있습니다.", "5": "가족이 추가로 요구한 사항이 있는지 확인하는 것도 중요하지만, 우선적으로 준비해야 할 사항과는 거리가 있습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "환자나 도움을 받는 사람", "def_vi": "Người bệnh hoặc người nhận sự chăm sóc"}, {"term_ko": "일상업무", "term_vi": "Công việc hàng ngày", "def_ko": "일상의 작업이나 활동", "def_vi": "Công việc hoặc hoạt động trong cuộc sống hàng ngày"}, {"term_ko": "대행", "term_vi": "Thay thế", "def_ko": "다른 사람의 일을 대신하다", "def_vi": "Làm công việc của người khác"}, {"term_ko": "확인", "term_vi": "Xác nhận", "def_ko": "정확히 알거나 검토하다", "def_vi": "Biết hoặc xem xét một cách chính xác"}, {"term_ko": "준비", "term_vi": "Chuẩn bị", "def_ko": "필요한 것을 미리 갖추다", "def_vi": "Có sẵn những điều cần thiết trước"}, {"term_ko": "자료", "term_vi": "Tài liệu", "def_ko": "필요한 정보나 문서", "def_vi": "Thông tin hoặc văn bản cần thiết"}, {"term_ko": "경비", "term_vi": "Chi phí", "def_ko": "비용이나 지출", "def_vi": "Chi phí hoặc chi tiêu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1471, '11', '재가 대상자와 병원방문 동행 시 돕는 방법으로 옳은 것은?', '["진료 당일에는 복용하던 약을 중단하게 한다.", "요양보호사가 아는 병원으로 모시고 간다.", "장기요양인정서와 주민등록본을 준비한다.", "대상자의 신체 상태를 고려하여 이동보조기구를 준비한다.", "진료 후 알게 된 대상자의 상태를 기관장에게 비밀로 한다."]'::jsonb, 4, NULL, NULL, '{"1": "대상자의 약 복용 중단은 의료진의 판단에 따라야 하므로 부적절합니다.\n[정답]", "2": "대상자의 편안함을 위해 아는 병원으로 가는 것이 적절하지 않을 수 있습니다.", "3": "필요한 서류는 준비해야 하지만, 이를 선택할 때 주의해야 합니다.", "4": "이동보조기구 준비는 대상자의 신체 상태에 따른 적절한 조치입니다.", "5": "진료 후 대상자의 상태는 비밀이 아닙니다. 관련 정보는 공유되어야 합니다."}'::jsonb, '[{"term_ko": "재가", "term_vi": "Chăm sóc tại nhà", "def_ko": "가정에서 요양을 받는 것", "def_vi": "Nhận chăm sóc tại ngôi nhà"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "요양이나 치료를 받는 사람", "def_vi": "Người nhận chăm sóc hoặc điều trị"}, {"term_ko": "신체 상태", "term_vi": "Tình trạng thể chất", "def_ko": "몸의 건강 상태", "def_vi": "Tình trạng sức khỏe của cơ thể"}, {"term_ko": "이동보조기구", "term_vi": "Thiết bị hỗ trợ di chuyển", "def_ko": "이동을 돕는 도구", "def_vi": "Công cụ giúp di chuyển"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1470, '11', '대상자가 진료를 받기 위해 병원을 방문할 때 동행하는 방법으로 옳은 것은?', '["비용을 아끼기 위해서", "방충효과각 약해지기 때문에", "오랫동안 사용하기 위해서", "냄새를 억제하기 위해서", "화학변화를 일으켜 옷감이 변질되므로"]'::jsonb, 3, NULL, NULL, '{"1": "비용을 아끼기 위해서: 동행의 목적이 아닙니다.\n[정답]", "3": "오랫동안 사용하기 위해서: 대상자의 필요에 따라 동행이 필요할 수 있습니다.", "2": "방충효과가 약해지기 때문에: 동행의 목적과 관련이 없습니다.", "4": "냄새를 억제하기 위해서: 동행의 목적인 이 설명은 적절하지 않습니다.", "5": "화학변화를 일으켜 옷감이 변질되므로: 동행의 목적과 관계가 없습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1469, '11', '대상자의 옷을 보관할 때 한 가지 종류의 방충제를 사용해야 하는 가장 중요한 이유는?', '["비용을 아끼기 위해서", "방충효과가 약해지기 때문에", "오랫동안 사용하기 위해서", "냄새를 억제하기 위해서", "화학변화를 일으켜 옷감이 변질되므로"]'::jsonb, 5, NULL, NULL, '{"1": "비용을 아끼기 위해서: 방충제를 사용하려는 주된 이유가 아닙니다.\n[정답]", "2": "방충효과가 약해지기 때문에: 방충제를 여러 가지 사용하는 것이 방충효과를 감소시킬 수 있습니다.", "3": "오랫동안 사용하기 위해서: 여러 종류의 방충제를 사용하면 오히려 문제가 발생할 수 있습니다.", "4": "냄새를 억제하기 위해서: 방충제의 기본 목적과는 거리가 있습니다.", "5": "화학변화를 일으켜 옷감이 변질되므로: 방충제가 여러 가지일 경우 화학적 반응이 일어나 옷감이 변질될 수 있습니다."}'::jsonb, '[{"term_ko": "방충제", "term_vi": "Thuốc chống côn trùng", "def_ko": "해충을 막기 위한 화학물질", "def_vi": "Hóa chất để ngăn côn trùng"}, {"term_ko": "변질", "term_vi": "Biến chất", "def_ko": "질이 나빠지거나 변하는 것", "def_vi": "Sự xấu đi hoặc thay đổi chất lượng"}, {"term_ko": "비용", "term_vi": "Chi phí", "def_ko": "지불해야 하는 금액", "def_vi": "Số tiền phải trả"}, {"term_ko": "효과", "term_vi": "Hiệu quả", "def_ko": "특정한 결과를 만들어내는 능력", "def_vi": "Khả năng tạo ra kết quả nhất định"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1468, '11', '대상자의 의류를 관리하는 방법으로 옳은 것은?', '["다리미가 앞으로 나갈 때는 앞쪽에 힘을 준다.", "의류가 눅눅해지면 직사광선을 쏘인다.", "곰팡이가 생기면 2시간 이상 그늘에 건조시킨다.", "견 블라우스를 보관 시에는 방충제를 넣어둔다.", "방충제는 보관용기의 아래쪽 구석에 넣어둔다."]'::jsonb, 4, NULL, NULL, '{"1": "다리미 사용 시 힘을 주는 방향에 대한 설명은 올바르지 않습니다.\n[정답]", "2": "의류가 눅눅해졌을 때 직사광선에 노출하는 것은 적절하지 않습니다.", "3": "곰팡이가 발생했을 경우 건조시키는 방법이 잘못되었습니다.", "4": "견 블라우스를 보관할 때 방충제를 사용하는 것은 올바른 방법입니다.", "5": "방충제를 보관할 때 위치가 잘못된 설명입니다."}'::jsonb, '[{"term_ko": "의류", "term_vi": "Quần áo", "def_ko": "옷(한국어)", "def_vi": "đồ mặc(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1467, '11', '다음 중 의류의 제품별 건조 방법으로 옳은 것은?', '["흰색 면직물 - 그늘에서 건조한다.", "청바지류 - 지퍼를 열고 뒤집어서 건조한다.", "니트류 - 옷걸이에 걸어서 건조한다.", "함성섬유류 - 햇빛에 건조한다.", "색상, 무늬가 있는 의류 - 햇빛에 건조한다."]'::jsonb, 2, NULL, NULL, '{"1": "흰색 면직물은 그늘에서 건조하는 것이 옳지 않다. 햇빛에 건조해야 색상을 유지할 수 있다.\n[정답]", "2": "청바지류는 지퍼를 열고 뒤집어서 건조하는 것이 적절하다. 이렇게 해야 형태가 변형되지 않는다.", "3": "니트류는 옷걸이에 걸어서 건조하는 것이 좋지 않고, 평평하게 놓고 건조해야 한다.", "4": "함성섬유류는 햇빛에서 건조하면 변색될 수 있으니 그늘에서 건조하는 것이 권장된다.", "5": "색상, 무늬가 있는 의류는 햇빛에 건조하면 색이 바랠 수 있다."}'::jsonb, '[{"term_ko": "의류", "term_vi": "건조", "def_ko": "옷, hàng hóa may mặc", "def_vi": "말리기, làm khô"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1466, '11', '대상자 옷을 세탁하는 방법으로 옳은 것은?', '["삶을 때 뚜겅을 덮고 삶는다.", "탈수시간을 길게하여 건조시간ㅇ르 줄인다.", "립스틱 얼룩은 초벌 세탁 후 아세톤을 묻혀 지운다.", "옷이 푹 잠기도록 비눗물을 넣어서 삶는다.", "세탁물은 비눗물을 여러번 헹군 후에 탈수한다."]'::jsonb, 1, NULL, NULL, '{"1": "삶을 때 뚜겅을 덮고 삶는다. - 옷이 고르게 세탁되며 위생적인 방법이다.\n[정답]", "2": "탈수시간을 길게하여 건조시간을 줄인다. - 탈수 시간이 길어지면 옷 손상이 우려된다.", "3": "립스틱 얼룩은 초벌 세탁 후 아세톤을 묻혀 지운다. - 아세톤은 특정 원단에 손상을 줄 수 있다.", "4": "옷이 푹 잠기도록 비눗물을 넣어서 삶는다. - 비누의 농도가 너무 높으면 옷에 잔여물이 남을 수 있다.", "5": "세탁물은 비눗물을 여러 번 헹군 후에 탈수한다. - 그러나 비누가 잔여물로 남을 가능성이 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자(한국어)", "def_vi": "Bệnh nhân"}, {"term_ko": "세탁", "term_vi": "Giặt", "def_ko": "세탁하다(한국어)", "def_vi": "Giặt"}, {"term_ko": "비눗물", "term_vi": "Nước xà phòng", "def_ko": "비누와 물의 혼합물(한국어)", "def_vi": "Hỗn hợp xà phòng và nước"}, {"term_ko": "탈수", "term_vi": "Vắt nước", "def_ko": "오염물을 제거하기 위하여 물기를 짜내다(한국어)", "def_vi": "Ép nước để loại bỏ tạp chất"}, {"term_ko": "아세톤", "term_vi": "Acetone", "def_ko": "특정 물질(한국어)", "def_vi": "Chất bằng với aceton"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1465, '11', '대상자의 의류를 세탁하는 방법으로 옳은 것은?', '["혈액이나 체액은 더운 물로 제거 후 찬물로 헹군다.", "튀김기름 얼룩은 알코올로 제거한 후 세탁한다.", "면직물 속옷은 삶고 난 후 세탁한다.", "파운데이션 얼룩은 알코올이 함유된 화장수로 지운다.", "냄새가 심한 세탁물은 붕산수에 담갔다 헹군다."]'::jsonb, 4, NULL, NULL, '{"1": "혈액이나 체액은 더운 물로 제거 후 찬물로 헹군다. - 혈액이나 체액은 찬물로 헹구어야 얼룩이 덜 남는다.\n[정답]", "2": "튀김기름 얼룩은 알코올로 제거한 후 세탁한다. - 튀김기름 얼룩은 알코올로 제거하기에는 적합하지 않다.", "3": "면직물 속옷은 삶고 난 후 세탁한다. - 삶은 후 세탁하지 않고, 세탁기를 사용하여 세탁한다.", "4": "파운데이션 얼룩은 알코올이 함유된 화장수로 지운다. - 파운데이션 얼룩은 알코올로 효과적으로 지울 수 있다.", "5": "냄새가 심한 세탁물은 붕산수에 담갔다 헹군다. - 붕산수로 헹구는 방법이 정확하지 않다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자 또는 돌봄을 받는 사람", "def_vi": "người bệnh hoặc người nhận sự chăm sóc"}, {"term_ko": "의류", "term_vi": "Quần áo", "def_ko": "옷", "def_vi": "quần áo"}, {"term_ko": "세탁", "term_vi": "Giặt", "def_ko": "세탁하기", "def_vi": "giặt"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1464, '11', '변실금이 있는 대상자의 속옷을 세탁하는 방법으로 옳은 것은?', '["본세탁 전에 애벌빨래를 한다.", "삶을 때에는 뚜껑을 열고 삶는다.", "비눗물에 세탁물이 깊이 잠길 정도로 넣고 삶는다.", "얼룩을 제거한 후 표백제에 오래 담가 둔다.", "붕산수에 담갔다가 여러 번 헹구어 말린다."]'::jsonb, 1, NULL, NULL, '{"1": "변실금으로 인해 오염된 속옷은 본세탁 전에 애벌빨래를 통해 초기 오염 물질을 제거해야 합니다.\n[정답]", "2": "삶을 때에는 뚜껑을 열고 삶아야 고온의 증기가 효과적으로 작용하여 오염 물질이 제거됩니다.", "3": "비눗물에 세탁물이 깊이 잠길 정도로 넣고 삶는 것은 정확한 세탁 방법이 아닙니다.", "4": "얼룩을 제거한 후 표백제에 오래 담가 두는 것은 옷감 손상을 초래할 수 있습니다.", "5": "붕산수에 담갔다가 여러 번 헹구어 말리는 것은 일반적인 세탁 방법이 아닙니다."}'::jsonb, '[{"term_ko": "변실금", "term_vi": "Incontinence", "def_ko": "정해진 시간에 의식적으로 대변을 보고 못하는 상태(한국어)", "def_vi": "Tình trạng không thể kiểm soát việc đi vệ sinh theo giờ định sẵn"}, {"term_ko": "속옷", "term_vi": "Quần lót", "def_ko": "몸에 입는 속의 옷(한국어)", "def_vi": "Quần áo mặc ở bên trong"}, {"term_ko": "세탁", "term_vi": "Giặt", "def_ko": "더러운 것을 씻어내는 것(한국어)", "def_vi": "Hành động rửa sạch vết bẩn"}, {"term_ko": "얼룩", "term_vi": "Vết bẩn", "def_ko": "더러운 부분(한국어)", "def_vi": "Phần bẩn"}, {"term_ko": "표백제", "term_vi": "Chất tẩy trắng", "def_ko": "옷감을 하얗게 만드는 화학물질(한국어)", "def_vi": "Hóa chất làm trắng vải"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1463, '11', '다음 중 옷을 세탁하는 방법으로 옳은 것은?', '["오염이 심할 때에는 불리거나 부분세탁을 병용한다.", "얼룩이 많은 옷은 모아서 한꺼번에 세탁한다.", "혈흔이 묻은 옷은 뜨거운 물에 세탁한다.", "속옷은 충분히 헹구어 그늘에 말린다.", "커피 얼룩은 샴푸를 이용하여 세탁한다."]'::jsonb, 1, NULL, NULL, '{"1": "오염이 심할 때에는 불리거나 부분세탁을 병용한다. [정답] 이는 특정 오염에 적합한 세탁 방법으로 옳습니다.", "2": "얼룩이 많은 옷은 모아서 한꺼번에 세탁한다. 이는 오히려 얼룩이 더 깊어질 수 있어 잘못된 방법입니다.", "3": "혈흔이 묻은 옷은 뜨거운 물에 세탁한다. 빨리 제거해야 하지만 뜨거운 물은 오히려 혈흔을 고착시킬 수 있어 잘못된 방법입니다.", "4": "속옷은 충분히 헹구어 그늘에 말린다. 이는 좋은 방법이지만, 세탁 방법을 두고 하는 질문에서 옳지 않습니다.", "5": "커피 얼룩은 샴푸를 이용하여 세탁한다. 이는 잘못된 방법으로, 전문 세정제를 사용하는 것이 바람직합니다."}'::jsonb, '[{"term_ko": "오염", "term_vi": "Ô nhiễm", "def_ko": "더러워짐(한국어)", "def_vi": "Sự bẩn thỉu"}, {"term_ko": "부분세탁", "term_vi": "Giặt một phần", "def_ko": "부분적으로 세탁하는 것(한국어)", "def_vi": "Giặt một phần"}, {"term_ko": "혈흔", "term_vi": "Vết máu", "def_ko": "피의 자국(한국어)", "def_vi": "Dấu vết của máu"}, {"term_ko": "뜨거운 물", "term_vi": "Nước nóng", "def_ko": "높은 온도의 물(한국어)", "def_vi": "Nước với nhiệt độ cao"}, {"term_ko": "속옷", "term_vi": "Đồ lót", "def_ko": "내부 옷(한국어)", "def_vi": "Quần áo bên trong"}, {"term_ko": "샴푸", "term_vi": "Shampoo", "def_ko": "머리 감는 물질(한국어)", "def_vi": "Chất tẩy rửa tóc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1462, '11', '다음 중 옷을 세탁하는 방법으로 옳은 것은?', '["수선이 필요한 경우 세탁 후 수선한다.", "세탁물에 실금, 하혈이 있으면 재빨리 세탁한다.", "옷의 종류와 색상에 따라 분류하여 세탁한다.", "땀 얼룩이 묻은 옷은 그늘에서 말린 후 세탁한다.", "립스틱 얼룩은 표백제를 희석한 물에 담갔다 세탁한다."]'::jsonb, 3, NULL, NULL, '{"1": "수선이 필요한 경우에는 세탁 전에 수선하는 것이 일반적입니다.\n[정답]", "3": "옷의 종류와 색상에 따라 분류하여 세탁하는 것이 올바른 방법입니다.", "2": "세탁물에 실금이나 하혈이 있을 경우, 재빨리 세탁하기보다는 적절한 처리 후 세탁하는 것이 좋습니다.", "4": "땀 얼룩은 즉시 세탁이 필요하며, 그늘에서 말리는 것이 가장 좋습니다.", "5": "립스틱 얼룩은 표백제가 아닌 얼룩 제거제로 처리해야 합니다."}'::jsonb, '[{"term_ko": "세탁", "term_vi": "Giặt", "def_ko": "세탁(한국어)", "def_vi": "Giặt"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1461, '11', '대상자의 침구를 선택하고 관리하는 방법으로 옳은 것은?', '["시트는 색이 진하고 습기를 흡수하지 않는 재질을 사용한다.", "베개는 깃털이나 솜으로 된 소재를 선택한다.", "베개 높이는 척추와 머리가 수평이 되게 한다.", "감염대상자의 경우 베개를 매일 교환한다.", "시트는 정해진 날짜에만 바꾼다."]'::jsonb, 3, NULL, NULL, '{"1": "시트는 색이 진하고 습기를 흡수하지 않는 재질을 사용한다. - 잘못된 정보입니다. 시트는 습기를 흡수할 수 있는 재질이 바람직합니다.\n[정답]", "2": "베개는 깃털이나 솜으로 된 소재를 선택한다. - 자주 사용되는 소재지만, 특정 상황에 따라 선호되지 않을 수 있습니다.", "3": "베개 높이는 척추와 머리가 수평이 되게 한다. - 적절한 높이의 베개가 척추 정렬에 중요한 역할을 합니다.", "4": "감염대상자의 경우 베개를 매일 교환한다. - 감염 위험이 높은 경우 매일 교환이 필요하지만, 모든 상황에서 그러한 것은 아닙니다.", "5": "시트는 정해진 날짜에만 바꾼다. - 필요에 따라 자주 바꾸어 주는 것이 좋습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Người nhận chăm sóc"}, {"term_ko": "침구", "term_vi": "Ga trải giường", "def_ko": "침대에 사용하는 직물", "def_vi": "Vải sử dụng cho giường"}, {"term_ko": "관리", "term_vi": "Quản lý", "def_ko": "관리와 보존", "def_vi": "Quản lý và bảo vệ"}, {"term_ko": "베개", "term_vi": "Gối", "def_ko": "머리를 받치는 기구", "def_vi": "Đồ vật đỡ đầu"}, {"term_ko": "척추", "term_vi": "Cột sống", "def_ko": "등뼈", "def_vi": "Xương sống"}, {"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "세균이나 바이러스에 감염되는 것", "def_vi": "Nhiễm vi khuẩn hoặc virus"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1460, '11', '침대에서 생활하는 대상자의 욕창을 예방하는 방법으로 옳은 것은?', '["풀을 먹인 시트를 사용한다.", "두겁고 재봉선이 있는 시트로 선택한다.", "시트의 주름을 반듯하고 팽팽하게 펴준다.", "베개는 습기와 열을 흡수하는 재질을 사용한다.", "침대 시트가 젖었을 때에는 체위변경을 한다."]'::jsonb, 3, NULL, NULL, '{"1": "풀을 먹인 시트는 욕창 예방과는 관련이 없습니다.\n[정답]", "3": "시트의 주름을 반듯하고 팽팽하게 펴주는 것은 압박을 최소화하고 욕창을 예방하는 데 중요합니다.", "2": "두껍고 재봉선이 있는 시트는 오히려 압력을 증가시킬 수 있습니다.", "4": "베개는 습기와 열을 흡수하는 재질이어야 하나 욕창 예방과 직접적인 연관은 적습니다.", "5": "침대 시트가 젖었을 때 체위변경이 필요하지만, 시트 주름을 펴주는 것이 더욱 중요합니다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Loét", "def_ko": "피부가 눌려서 손상되는 것(한국어)", "def_vi": "Vết thương do áp lực trên da(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1459, '11', '대상자의 침구류 관리 방법으로 옳은 것은?', '["두껍고 무거운 이불을 사용한다.", "매트리스는 푹신한 것이 좋다.", "시트의 크기는 매트리스와 같게 한다.", "양모와 오리털 이불은 그늘에서 말린다.", "습기를 흡수하는 매트리스를 사용한다."]'::jsonb, 4, NULL, NULL, '{"1": "두껍고 무거운 이불은 관리와 사용에 불편함을 줄 수 있습니다.\n[정답]", "4": "양모와 오리털 이불은 그늘에서 말리는 것이 적합하여 옳은 방법입니다.", "2": "매트리스는 개인의 선호에 따라 결정되지만 푹신한 것만이 좋은 것은 아닙니다.", "3": "시트의 크기는 매트리스보다 약간 더 크게 하는 것이 이상적입니다.", "5": "습기를 흡수하는 매트리스는 위생적인 측면에서 문제를 일으킬 수 있습니다."}'::jsonb, '[{"term_ko": "침구류", "term_vi": "Chăn ga", "def_ko": "침대에 사용하는 다양한 물품(한국어)", "def_vi": "Các vật dụng khác nhau sử dụng trên giường ngủ(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1458, '11', '야간 외출 시 대상자의 복장으로 바람직한 것은?', '["단추가 많은 하의를 입힌다.", "장식이 많은 상의를 입힌다.", "몸에 꽉 끼는 옷을 입힌다.", "밝은 색의 겉옷을 입힌다.", "신고 벗기 쉬운 슬리퍼를 신긴다."]'::jsonb, 4, NULL, NULL, '{"1": "단추가 많은 하의를 입히는 것은 쉽게 벗겨질 수 있어 바람직하지 않다.", "2": "장식이 많은 상의를 입히는 경우 실용적이지 않으며 외출 시 불편할 수 있다.\n[정답]", "4": "밝은 색의 겉옷을 입히는 것은 야간에 시인성을 높여 안전을 증진할 수 있다.", "3": "몸에 꽉 끼는 옷은 편안함을 해칠 수 있으므로 적합하지 않다.", "5": "신고 벗기 쉬운 슬리퍼는 안전성을 고려했을 때 바람직하지 않다."}'::jsonb, '[{"term_ko": "복장", "term_vi": "Trang phục", "def_ko": "옷차림(한국어)", "def_vi": "Trang phục(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1457, '11', '대상자의 의복과 신발을 선택할 때 옳은 것은?', '["저녁 외출 시에는 어두운 색의 옷이 좋다.", "노인의 체형보다 큰 디자인이어야 한다.", "움직이는 데 불편이 없고 과도한 장식을 피한다.", "신발은 굽이 낮고 폭이 좁은 것이 좋다.", "시원하게 뒤가 트인 슬리퍼가 좋다."]'::jsonb, 3, NULL, NULL, '{"1": "저녁 외출 시 어두운 색의 옷이 좋지 않은 경우가 많습니다. 일반적으로 활동이나 안전을 고려할 때 밝은 색이 더 효과적입니다.\n[정답]", "3": "대상자가 움직일 때 편안해야 하며, 과도한 장식을 피해야 하는 것이 맞습니다.", "2": "노인의 체형보다 큰 디자인은 불편함을 줄 수 있으므로 적절하지 않습니다.", "4": "신발은 굽이 낮고 폭이 넓은 것이 좋습니다. 좁은 신발은 발에 압박을 줄 수 있습니다.", "5": "시원한 슬리퍼는 때때로 안전하지 않을 수 있으므로 권장되지 않습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자 또는 돌보아야 할 사람", "def_vi": "Người bệnh hoặc người cần được chăm sóc"}, {"term_ko": "의복", "term_vi": "Trang phục", "def_ko": "옷", "def_vi": "Quần áo"}, {"term_ko": "신발", "term_vi": "Giày", "def_ko": "발을 보호하고 지탱하는 용품", "def_vi": "Sản phẩm bảo vệ và hỗ trợ chân"}, {"term_ko": "디자인", "term_vi": "Thiết kế", "def_ko": "외형이나 양식", "def_vi": "Hình dạng hoặc kiểu dáng"}, {"term_ko": "장식", "term_vi": "Trang trí", "def_ko": "꾸밈 또는 액세서리", "def_vi": "Sự trang trí hoặc phụ kiện"}, {"term_ko": "굽", "term_vi": "Gót", "def_ko": "신발의 높이 부분", "def_vi": "Phần cao của giày"}, {"term_ko": "폭", "term_vi": "Chiều rộng", "def_ko": "넓이", "def_vi": "Kích thước rộng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1456, '11', '대상자의 의복을 관리하는 기본원칙으로 옳은 것은?', '["속옷은 2~3일에 한 번 갈아입는 것이 좋다.", "얼룩이나 더러움이 심한 옷은 즉시 세탁한다.", "낡은 의류는 요양보호사가 판단하여 버린다.", "평소에 늘 입는 옷은 수납장 깊이 정리해 둔다.", "감염이 의심되는 대상자의 의류는 무조건 버린다."]'::jsonb, 2, NULL, NULL, '{"1": "속옷은 2~3일에 한 번 갈아입는 것이 좋다. - 일반적으로 속옷은 하루에 한 번 갈아입는 것이 기본 원칙입니다.\n[정답]", "2": "얼룩이나 더러움이 심한 옷은 즉시 세탁한다. - 의복 관리의 기본 원칙으로 올바른 선택입니다.", "3": "낡은 의류는 요양보호사가 판단하여 버린다. - 의류의 처리는 고객의 동의를 받아야 합니다.", "4": "평소에 늘 입는 옷은 수납장 깊이 정리해 둔다. - 자주 입는 옷은 쉽게 접근할 수 있도록 정리해야 합니다.", "5": "감염이 의심되는 대상자의 의류는 무조건 버린다. - 감염 의심 시 세탁이나 소독이 필요하며, 무조건 버리는 것은 아닙니다."}'::jsonb, '[{"term_ko": "의복", "term_vi": "관리", "def_ko": "옷, trang phục", "def_vi": "관리하다, quản lý"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1455, '11', '주방의 위생관리 방법으로 옳은 것은?', '["냉장실을 자주 환기하여 냄새를 제거한다.", "변색된 음식은 가열한 후 냉장 보관한다.", "소독제 원액을 배수구에 부어 악취를 없앤다.", "싱크대 곰팡이는 주방용 세저제로 닦는다.", "수세미는 소독제를 희석한 물에 담가 두었다가 건조한다."]'::jsonb, 5, NULL, NULL, '{"1": "냉장실을 자주 환기하는 것은 좋지만, 냄새를 제거하는 방법으로는 부족합니다.\n[정답]", "2": "변색된 음식은 가열해도 안전하지 않기 때문에 냉장 보관이 적절하지 않습니다.", "3": "소독제 원액을 직접 배수구에 부으면 독성이 있을 수 있어서 위험합니다.", "4": "싱크대의 곰팡이는 주방용 세제로 닦는 것보다는 전문 세제를 사용하는 것이 효과적입니다.", "5": "수세미는 소독제를 희석한 물에 담가 두었다가 건조하는 것이 올바른 위생 관리 방법입니다."}'::jsonb, '[{"term_ko": "주방", "term_vi": "Nhà bếp", "def_ko": "주방(한국어)", "def_vi": "Nơi nấu nướng hoặc chế biến thực phẩm"}, {"term_ko": "위생", "term_vi": "Vệ sinh", "def_ko": "청결(한국어)", "def_vi": "Sự sạch sẽ"}, {"term_ko": "소독제", "term_vi": "Thuốc tẩy", "def_ko": "소독약(한국어)", "def_vi": "Chất tẩy rửa diệt khuẩn"}, {"term_ko": "변색", "term_vi": "Thay đổi màu sắc", "def_ko": "색이 변함(한국어)", "def_vi": "Màu sắc không bình thường"}, {"term_ko": "세제", "term_vi": "Chất tẩy rửa", "def_ko": "세정제(한국어)", "def_vi": "Đồ dùng để làm sạch"}, {"term_ko": "수세미", "term_vi": "Miếng bọt biển", "def_ko": "주방용 스펀지(한국어)", "def_vi": "Đồ dụng làm sạch"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1454, '11', '식기 및 주방용품의 위생관리로 옳은 것은?', '["고무장갑은 사용 후 겉면만 세제로 씻는다.", "행주는 세척한 뒤 삶아서 건조한 후 보고나한다.", "기름기가 많은 그릇은 세제로 여러번 닦는다.", "수세미는 그물형보다 스펀지형이 위생적이다.", "유통기한이 지난 식재료는 냉동실에 얼린다."]'::jsonb, 2, NULL, NULL, '{"1": "고무장갑은 사용 후 안쪽도 잘 씻어야 하며, 겉면만 세제로 씻는 것은 위생적이지 않음.\n[정답]", "2": "행주는 세척한 뒤 삶아서 건조하면 위생적으로 관리할 수 있음.", "3": "기름기가 많은 그릇은 세제를 사용하되 여러 번 닦는 것보다는 흡수력이 좋은 수세미로 한 번 닦아내는 것이 더 효과적임.", "4": "수세미는 그물형보다 스펀지형이 일반적으로 세척력이 높지만, 각기 장단점이 있어 사용 목적에 따라 다름.", "5": "유통기한이 지난 식재료는 냉동실에 얼려도 안전하지 않으므로 폐기해야 함."}'::jsonb, '[{"term_ko": "식기", "term_vi": "Dụng cụ ăn", "def_ko": "그릇(한국어)", "def_vi": "Đồ dùng ăn uống"}, {"term_ko": "위생", "term_vi": "Vệ sinh", "def_ko": "청결(한국어)", "def_vi": "Sạch sẽ"}, {"term_ko": "관리", "term_vi": "Quản lý", "def_ko": "운영(한국어)", "def_vi": "Điều hành"}, {"term_ko": "행주", "term_vi": "Khăn bếp", "def_ko": "주방타올(한국어)", "def_vi": "Khăn dùng trong nhà bếp"}, {"term_ko": "세척", "term_vi": "Rửa", "def_ko": "씻다(한국어)", "def_vi": "Làm sạch"}, {"term_ko": "유통기한", "term_vi": "Hạn sử dụng", "def_ko": "유통 기간(한국어)", "def_vi": "Thời gian sử dụng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1453, '11', '식기 및 주방의 위생관리 방법으로 옳은 것은?', '["곰팡이가 발생한 싱크대는 희석한 알코올로 닦아준다.", "냉장실 선반은 희석한 락스로 닦고 건조한다.", "앞치마는 조리용과 청소용을 구분없이 함께 사용한다.", "냉장고를 청소하는 동안 꺼내둔 식품은 서늘한 곳에 모아둔다.", "고무장갑을 1개로 쓰는 경우에는 세제로 깨끗이 씻어 사용한다."]'::jsonb, 1, NULL, NULL, '{"1": "곰팡이가 발생한 싱크대는 희석한 알코올로 닦아준다. [정답] 이는 곰팡이를 제거하는 적절한 방법입니다.", "2": "냉장실 선반은 희석한 락스로 닦고 건조한다. 이는 올바른 위생관리 방법이지만 냉장실에서는 원래 식품이 잔류할 수 있습니다.", "3": "앞치마는 조리용과 청소용을 구분없이 함께 사용한다. 이는 위생상 바람직하지 않습니다.", "4": "냉장고를 청소하는 동안 꺼내둔 식품은 서늘한 곳에 모아둔다. 이는 안전지침이 아닙니다.", "5": "고무장갑을 1개로 쓰는 경우에는 세제로 깨끗이 씻어 사용한다. 고무장갑은 세척하여 재사용하기 어려운 경우가 많습니다."}'::jsonb, '[{"term_ko": "식기", "term_vi": "Dụng cụ ăn uống", "def_ko": "식사를 위한 그릇과 기구", "def_vi": "Bát đĩa và đồ dùng cho bữa ăn"}, {"term_ko": "위생", "term_vi": "Vệ sinh", "def_ko": "청결하게 유지되는 상태", "def_vi": "Tình trạng được giữ sạch sẽ"}, {"term_ko": "곰팡이", "term_vi": "Nấm mốc", "def_ko": "곰팡이류의 세균", "def_vi": "Vi khuẩn thuộc nhóm nấm mốc"}, {"term_ko": "희석", "term_vi": "Pha loãng", "def_ko": "농도를 낮추는 것", "def_vi": "Làm giảm nồng độ"}, {"term_ko": "조리용", "term_vi": "Dùng để nấu ăn", "def_ko": "요리하기 위한 목적", "def_vi": "Mục đích để nấu ăn"}, {"term_ko": "청소용", "term_vi": "Dùng để dọn dẹp", "def_ko": "청소하기 위한 목적", "def_vi": "Mục đích để dọn dẹp"}, {"term_ko": "고무장갑", "term_vi": "Găng tay cao su", "def_ko": "고무로 만들어진 장갑", "def_vi": "Găng tay làm bằng cao su"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1452, '11', '도마와 칼이 한 개 밖에 없는 경우 사용 순서로 옳은 것은?', '["채소,과일 - 닭고기 - 육류 - 생선류", "채소,과일 - 육류 - 생선류 - 닭고기", "육류 - 채소,과일 - 닭고기 - 생선류", "생선류 - 채소,과일 - 육류 - 닭고기", "육류 - 닭고기 - 생선류 - 채소,과일"]'::jsonb, 2, NULL, NULL, '{"1": "채소와 과일을 먼저 다룬 후, 고기류를 다루는 것은 위생에 좋지 않다.\n[정답]", "2": "채소와 과일을 먼저 다루고, 그 다음에 육류와 생선류를 다룰 경우 식중독의 위험이 줄어든다.", "3": "육류를 먼저 다루는 것은 위생적이지 않다.", "4": "생선류를 먼저 다루는 것은 위생적이지 않다.", "5": "채소와 과일을 마지막에 다루는 것은 좋지 않다."}'::jsonb, '[{"term_ko": "도마", "term_vi": "Thớt", "def_ko": "나무나 플라스틱으로 만든 요리 도구", "def_vi": "Dụng cụ nấu ăn làm bằng gỗ hoặc nhựa"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1451, '11', '안전한 식품을 섭취하는 방법으로 옳은 것은?', '["계란 및 생선류는 살짝 가열하여 조리한다.", "음식이 부족하지 않도록 많은 양을 조리한다.", "과일은 100ppm 농도로 희석된 소독액으로 소독한다.", "조리된 음식, 육류, 생선은 같은 칸에 보관한다.", "냉동식품은 실온에서 해동시킨다."]'::jsonb, 3, NULL, NULL, '{"1": "계란과 생선류는 충분히 익혀서 조리해야 안전합니다.\n[정답]", "3": "과일은 소독액으로 소독하는 것이 안전한 섭취 방법입니다.", "2": "음식이 부족하지 않도록 조리하는 것도 중요하지만, 안전한 조리를 위한 방법은 아닙니다.", "4": "조리된 음식과 육류, 생선은 오염을 방지하기 위해 따로 보관해야 합니다.", "5": "냉동식품은 냉장고에서 해동해야 안전합니다."}'::jsonb, '[{"term_ko": "안전", "term_vi": "식품", "def_ko": "안전(한국어) / an toàn(베트남어)", "def_vi": "식품(한국어) / thực phẩm(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1450, '11', '다음 중 식중독을 유발하는 원인으로 옳은 것은?', '["고기를 60도로 요리했다.", "생육과 조리된 음식을 구분하여 보관한다.", "음식물이 남지 않도록 적당량만 조리한다.", "조리한 식품을 실온에 2시간 이상 방치하지 않는다.", "도마, 칼은 가열과 비가열 식품용으로 구분하여 사용한다."]'::jsonb, 1, NULL, NULL, '{"1": "고기를 60도로 요리하여도 식중독을 유발할 수 있는 균이 살아남을 수 있습니다. [정답]", "2": "생육과 조리된 음식을 구분하여 보관하는 것은 식중독 예방에 매우 중요합니다.", "3": "음식물이 남지 않도록 조리하는 것은 위생적이나 식중독과는 직접적으로 관련이 없습니다.", "4": "조리한 식품을 실온에 2시간 이상 방치하는 것은 식중독의 위험을 증가시킵니다.", "5": "도마와 칼을 구분하여 사용하는 것은 안전한 조리를 위한 접근이나, 직접적인 식중독 유발 원인은 아닙니다."}'::jsonb, '[{"term_ko": "식중독", "term_vi": "Ngộ độc thực phẩm", "def_ko": "음식에 의해 발생하는 질병", "def_vi": "Bệnh do thực phẩm gây ra"}, {"term_ko": "원인", "term_vi": "Nguyên nhân", "def_ko": "어떤 일이 일어나는 이유", "def_vi": "Lý do xảy ra sự việc"}, {"term_ko": "예방", "term_vi": "Phòng ngừa", "def_ko": "사전에 방지하다", "def_vi": "Ngăn chặn trước"}, {"term_ko": "균", "term_vi": "Vi khuẩn", "def_ko": "미생물의 종류", "def_vi": "Loại vi sinh vật"}, {"term_ko": "조리", "term_vi": "Chế biến", "def_ko": "음식 만들기", "def_vi": "Làm thức ăn"}, {"term_ko": "실온", "term_vi": "Nhiệt độ phòng", "def_ko": "방 온도", "def_vi": "Nhiệt độ thông thường"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1449, '11', '다음 중 식품을 보관하는 방법으로 옳은 것은?', '["생선은 통째로 냉동실에 보관한다.", "망고, 아보카도는 냉장실에 보관한다.", "오래 두고 먹는 달걀은 냉장실 문쪽에 보관한다.", "육류는 잘게 썰어 냉동 보관한다.", "냉장보관 시 음식을 담은 용기의 간격을 띄어 놓는다."]'::jsonb, 5, NULL, NULL, '{"1": "생선은 통째로 냉동실에 보관하면 품질이 저하될 수 있다.\n[정답]", "5": "냉장보관 시 음식을 담은 용기의 간격을 띄어 놓으면 공기가 순환되어 음식의 신선도가 유지된다.", "2": "망고와 아보카도는 일반적으로 상온에서 숙성 후 냉장 보관하는 것이 좋다.", "3": "달걀은 냉장실 문쪽에 보관하면 온도 변화로 인해 품질이 나빠질 수 있다.", "4": "육류는 통째로 냉동 보관하는 것이 품질 유지에 더 효과적이다."}'::jsonb, '[{"term_ko": "식품", "term_vi": "Thực phẩm", "def_ko": "음식(한국어)", "def_vi": "thực phẩm(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1448, '11', '다음 중 식중독이 발생할 가능성이 높은 경우는?', '["두부는 냉장 보관한다.", "달걀은 비벼 씻어서 보관한다.", "먹고 남은 음식은 즉시 버린다.", "생선과 조개류는 냉동 보관한다.", "육류는 냉장실에서 해동하거나 전자레인지를 이용한다."]'::jsonb, 2, NULL, NULL, '{"1": "두부는 냉장 보관하여야 안전하게 유지된다.\n[정답]", "2": "달걀은 반드시 깨끗하게 씻어야 하지만, 비비는 방식은 오히려 오염을 초래할 수 있다.", "3": "먹고 남은 음식은 즉시 처분하는 것이 바람직하며, 이는 식중독 예방에 필수적이다.", "4": "생선과 조개류는 냉동 보관하여 안전하게 식품을 유지할 수 있다.", "5": "육류는 냉장실에서 안전하게 해동해야 하며, 전자레인지를 사용할 경우 균일하게 해동하지 못할 수 있다."}'::jsonb, '[{"term_ko": "식중독", "term_vi": "Ngộ độc thực phẩm", "def_ko": "음식으로 인해 발생하는 질병", "def_vi": "Bệnh xảy ra do thực phẩm"}, {"term_ko": "비비다", "term_vi": "Chà xát", "def_ko": "서로 문지르다", "def_vi": "Làm sạch bằng cách cọ xát"}, {"term_ko": "보관하다", "term_vi": "Bảo quản", "def_ko": "저장하다", "def_vi": "Lưu trữ"}, {"term_ko": "확신하다", "term_vi": "Tin chắc", "def_ko": "확실하게 믿다", "def_vi": "Tin tưởng một cách chắc chắn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1447, '11', '감자와 고구마를 보관하는 방법으로 옳은 것은?', '["통풍이 잘 되며 서늘하고 어두운 곳에 보관한다.", "끓는 물에 데쳐 냉동보관한다.", "표면에 식용유를 발라 냉장보관한다.", "신문지에 하나씩 포장하여 냉장ㅂ관한다.", "물을 뿌린 신문지에 싸서 실온에 보관한다."]'::jsonb, 1, NULL, NULL, '{"1": "통풍이 잘 되며 서늘하고 어두운 곳에 보관한다. - 감자와 고구마는 적절한 보관 환경이 필요하므로 올바른 방법이다.\n[정답]", "2": "끓는 물에 데쳐 냉동보관한다. - 감자와 고구마는 데치면 영양소가 손실될 수 있어 잘못된 방법이다.", "3": "표면에 식용유를 발라 냉장보관한다. - 식용유를 바르면 부패가 촉진될 수 있어 잘못된 방법이다.", "4": "신문지에 하나씩 포장하여 냉장보관한다. - 냉장보관이 적합하지 않아서 잘못된 방법이다.", "5": "물을 뿌린 신문지에 싸서 실온에 보관한다. - 적절하지 않은 보관 방법으로 잘못된 방법이다."}'::jsonb, '[{"term_ko": "감자", "term_vi": "Khoai tây", "def_ko": "감자(한국어)", "def_vi": "Khoai tây (베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1446, '11', '다음 중 식품을 위생적으로 보관하는 방법은?', '["열대과일은 냉잦ㅇ 보관한다.", "달걀은 물로 깨끗이 씻어 보관한다.", "생선은 통째로 소금을 뿌려 냉장보관한다.", "채소는 이물질 제거 후 밀폐용기에 담아 냉장보관한다.", "해동한 식품은 다시 냉동하여 재사용한다."]'::jsonb, 4, NULL, NULL, '{"1": "열대과일은 냉장 보관하는 것이 일반적으로 적절하나, 특정 과일은 상온에서 보관할 수 있습니다.", "2": "달걀은 물로 씻을 경우 세균이 침투할 수 있어, 세척하지 않고 보관하는 것이 좋습니다.\n[정답]", "4": "채소는 이물질 제거 후 밀폐용기에 담아 냉장보관하는 것이 위생적인 방법입니다.", "3": "생선은 소금을 뿌린 뒤 곧바로 냉장 보관하는 것이 바람직하지 않으며, 소금처리 후 오랫동안 냉장 하면 품질이 떨어질 수 있습니다.", "5": "해동한 식품은 재냉동이 안전하지 않으며, 반드시 조리 후 소비해야 합니다."}'::jsonb, '[{"term_ko": "위생", "term_vi": "Vệ sinh", "def_ko": "청결을 유지하는 것", "def_vi": "Duy trì sự sạch sẽ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1445, '11', '대상자의 집 냉장고에서 부패한 계란찜을 발견했을 때 올바른 대처방법은?', '["끓여서 다시 먹을 수 있도록 한다.", "냉장고의 온도와 다른 음식의 상태를 점검한다.", "상한 부분만 버리고 다시 냉장 보관한다.", "즉시 폐기한 후 나중에 설명한다.", "가능한 빨리 섭취하도록 알려준다."]'::jsonb, 2, NULL, NULL, '{"1": "끓여서 다시 먹을 수 있도록 하는 것은 잘못된 방법입니다. 부패한 음식은 안전하지 않으므로 섭취해서는 안 됩니다.\n[정답]", "2": "냉장고의 온도와 다른 음식의 상태를 점검하는 것은 올바른 대처 방법입니다. 이는 위생적이고 안전한 음식 관리를 위해 필수적입니다.", "3": "상한 부분만 버리고 다시 냉장 보관하는 것은 적절하지 않습니다. 부패는 음식 전체에 퍼질 수 있기 때문입니다.", "4": "즉시 폐기한 후 나중에 설명하는 것은 대처 방법이긴 하지만, 음식 안전 관점에서 필요할 경우 점검이 우선시 되어야 합니다.", "5": "가능한 빨리 섭취하도록 알려주는 것은 부패한 음식을 권장하는 잘못된 조치입니다."}'::jsonb, '[{"term_ko": "부패", "term_vi": "Hư hỏng", "def_ko": "음식의 상태가 나빠지는 것", "def_vi": "Trạng thái bị xấu đi của thực phẩm"}, {"term_ko": "냉장고", "term_vi": "Tủ lạnh", "def_ko": "음식을 차갑게 보관하는 기계", "def_vi": "Thiết bị bảo quản thực phẩm lạnh"}, {"term_ko": "온도", "term_vi": "Nhiệt độ", "def_ko": "어떤 대상을 이루고 있는 열의 정도", "def_vi": "Độ nóng của một đối tượng"}, {"term_ko": "음식", "term_vi": "Thực phẩm", "def_ko": "사람이 섭취하는 것", "def_vi": "Những thứ mà con người ăn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1444, '11', '질환에 따라 섭취해야 할 음식으로 옳은 것은?', '["당뇨병: 꿀, 육류", "고혈압: 젓갈류, 장아찌", "골다공증: 미역, 두부", "만성신부전: 많은 양의 물", "변비: 콜라, 녹차"]'::jsonb, 3, NULL, NULL, '{"1": "당뇨병 환자는 꿀과 육류를 피해야 합니다. 당뇨병 관리에 적합하지 않은 식사입니다.", "2": "고혈압 환자는 젓갈류와 장아찌와 같은 나트륨 함량이 높은 음식은 피해야 합니다.\n[정답]", "3": "골다공증은 칼슘이 풍부한 미역과 두부를 섭취하는 것이 좋습니다.", "4": "만성신부전 환자는 수분 섭취를 제한해야 하므로 많은 양의 물은 부적합합니다.", "5": "변비에는 섬유소가 풍부한 음식을 섭취해야 하며, 콜라와 녹차는 적합하지 않습니다."}'::jsonb, '[{"term_ko": "질환", "term_vi": null, "def_ko": "병", "def_vi": null}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1443, '11', '변비로 고생하는 대상자의 식사 원칙으로 옳은 것은?', '["보리, 검정콩, 미역을 섭취한다.", "생과일 대신 과일 통조림을 섭취한다.", "비타민 D와 칼슘보충제를 함께 복용한다.", "가급적 도정을 많이 한 곡류를 섭취한다.", "식이섬유의 흡수를 위해 수분 섭취를 제한한다."]'::jsonb, 1, NULL, NULL, '{"1": "보리, 검정콩, 미역은 식이섬유가 풍부하여 변비 개선에 도움을 줍니다.\n[정답]", "2": "생과일 대신 과일 통조림은 섬유질이 상대적으로 적어 변비 해소에 도움이 되지 않습니다.", "3": "비타민 D와 칼슘보충제는 변비에 특별한 영향을 미치지 않습니다.", "4": "도정을 많이 한 곡류는 섬유질이 적어 변비에 좋지 않습니다.", "5": "수분 섭취는 오히려 변비 예방에 필요하므로 제한해서는 안 됩니다."}'::jsonb, '[{"term_ko": "변비", "term_vi": "Táo bón", "def_ko": "배변이 어려운 상태", "def_vi": "Tình trạng khó đi tiêu"}, {"term_ko": "식사 원칙", "term_vi": "Nguyên tắc ăn uống", "def_ko": "건강한 식사를 위한 규칙", "def_vi": "Quy tắc cho bữa ăn lành mạnh"}, {"term_ko": "식이섬유", "term_vi": "Chất xơ", "def_ko": "식물에서 발견되는 영양소", "def_vi": "Dinh dưỡng có trong thực vật"}, {"term_ko": "비타민", "term_vi": "Vitamin", "def_ko": "몸에 필요한 유기 화합물", "def_vi": "Hợp chất hữu cơ cần thiết cho cơ thể"}, {"term_ko": "칼슘", "term_vi": "Canxi", "def_ko": "뼈와 이의 건강에 필요한 미네랄", "def_vi": "Khoáng chất cần thiết cho xương và răng"}, {"term_ko": "수분", "term_vi": "Nước", "def_ko": "몸의 기능을 유지하는 물", "def_vi": "Nước cần thiết cho chức năng của cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1442, '11', '다음 중 변비 완화에 도움이 되는 식품은?', '["돼지고기", "커피, 콜라", "홍차, 녹차", "초콜릿, 치즈", "잡곡류. 생과일, 생채소"]'::jsonb, 5, NULL, NULL, '{"1": "돼지고기는 식이섬유가 적어 변비 완화에 비효율적입니다.\n[정답]", "5": "잡곡류, 생과일, 생채소는 식이섬유가 풍부하여 변비 완화에 효과적입니다.", "2": "커피와 콜라는 이뇨 작용이 있지만 변비에 직접적인 도움이 되지 않습니다.", "3": "홍차와 녹차는 카페인이 들어 있어 사실상 탈수 효과가 있어 변비에 좋지 않습니다.", "4": "초콜릿과 치즈는 변비를 악화시킬 수 있는 식품입니다."}'::jsonb, '[{"term_ko": "변비", "term_vi": "Táo bón", "def_ko": "장이 제대로 기능하지 않아 대변이 딱딱해지는 상태", "def_vi": "Tình trạng ruột không hoạt động đúng cách gây ra phân cứng"}, {"term_ko": "완화", "term_vi": "Giảm nhẹ", "def_ko": "증상을 덜어주는 것", "def_vi": "Làm nhẹ triệu chứng"}, {"term_ko": "식품", "term_vi": "Thực phẩm", "def_ko": "먹을 수 있는 것", "def_vi": "Những thứ có thể ăn"}, {"term_ko": "잡곡류", "term_vi": "Ngũ cốc hỗn hợp", "def_ko": "섞인 곡물", "def_vi": "Các loại ngũ cốc trộn lẫn"}, {"term_ko": "생과일", "term_vi": "Trái cây tươi", "def_ko": "갓 따온 과일", "def_vi": "Trái cây vừa hái"}, {"term_ko": "생채소", "term_vi": "Rau sống", "def_ko": "신선한 채소", "def_vi": "Rau tươi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1441, '11', '음식물을 삼키는 데에 어려움이 있는 대상자의 식사를 돕는 방법은?', '["국수를 돌돌 말아서 먹게 한다.", "과일은 건더기 없이 주스로 먹인다.", "익힌 챗소보다 신선한 생채소를 먹인다.", "물을 마실 때 점도 증진제를 사용하지 않는다.", "한 번에 조금씩 떠 먹이고 여러 번에 걸쳐 삼키게 한다."]'::jsonb, 5, NULL, NULL, '{"1": "국수를 돌돌 말아서 먹게 하면 삼키기 어려울 수 있습니다.\n[정답]", "5": "한 번에 조금씩 떠 먹이고 여러 번에 걸쳐 삼키게 하면 안전하게 식사를 도울 수 있습니다.", "2": "과일을 주스로 먹이는 것은 영양소 섭취에는 도움이 되지만 식사는 본래의 형태를 유지하는 것이 좋습니다.", "3": "익힌 챗소보다 신선한 생채소를 먹이는 것은 소화에 불리할 수 있습니다.", "4": "물을 마실 때 점도 증진제를 사용하는 것이 일반적으로 도움이 될 수 있습니다."}'::jsonb, '[{"term_ko": "음식물", "term_vi": "Thức ăn", "def_ko": "음식", "def_vi": "Thức ăn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1440, '11', '삼킴 자애를 가진 대상자의 식사를 돕는 방법으로 옳은 것은?', '["밥을 국인 물에 말아 먹인다.", "사과를 숟가락으로 긁어 먹인다.", "계란은 반숙보다 완숙으로 한다.", "채소는 신맛이 강한 소스를 뿌려 먹인다.", "떠먹이는 것보다 마시는 형태의 유제품을 먹인다."]'::jsonb, 2, NULL, NULL, '{"1": "밥을 국인 물에 말아 먹이는 것은 삼킴 자애를 가진 대상자에게 위험할 수 있습니다.\n[정답]", "2": "사과를 숟가락으로 긁어 먹이는 것은 삼킴 자애를 가진 대상자가 안전하게 음식을 섭취하는 방법입니다.", "3": "계란은 반숙보다 완숙으로 하는 것은 사실상 영향이 적습니다.", "4": "채소는 신맛이 강한 소스를 뿌려 먹이는 것은 삼킴 장애가 있는 대상자에게 적합하지 않습니다.", "5": "떠먹이는 것보다 마시는 형태의 유제품을 먹이는 것은 삼킴에 도움을 줄 수 있지만, 모든 형태에 따라 다를 수 있습니다."}'::jsonb, '[{"term_ko": "삼킴 자애", "term_vi": null, "def_ko": "인 swallowing difficulties(한국어)", "def_vi": null}, {"term_ko": "안전", "term_vi": null, "def_ko": "안전한 것 safe(한국어)", "def_vi": null}, {"term_ko": "사과", "term_vi": null, "def_ko": "apple(한국어)", "def_vi": null}, {"term_ko": "숟가락", "term_vi": null, "def_ko": "spoon(한국어)", "def_vi": null}, {"term_ko": "반숙", "term_vi": null, "def_ko": "soft-boiled(한국어)", "def_vi": null}, {"term_ko": "완숙", "term_vi": null, "def_ko": "hard-boiled(한국어)", "def_vi": null}, {"term_ko": "채소", "term_vi": null, "def_ko": "vegetable(한국어)", "def_vi": null}, {"term_ko": "소스", "term_vi": null, "def_ko": "sauce(한국어)", "def_vi": null}, {"term_ko": "형태", "term_vi": null, "def_ko": "form(한국어)", "def_vi": null}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1439, '11', '고혈압이 있는 대상자에게 섭취를 제한해야 하는 음식은?', '["저지방 우유", "빵, 베이컨", "보리밥, 삶은 양배추", "현미밥, 콩나물국", "카레가루를 입혀 구운 삼치"]'::jsonb, 2, NULL, NULL, '{"1": "저지방 우유는 고혈압 환자에게 권장되는 음식입니다.\n[정답]", "2": "빵, 베이컨은 나트륨 함량이 높아 섭취를 제한해야 합니다.", "3": "보리밥과 삶은 양배추는 고혈압 환자에게 좋습니다.", "4": "현미밥과 콩나물국도 권장됩니다.", "5": "카레가루를 입혀 구운 삼치는 나트륨이 적지만, 조리 방법에 따라 다를 수 있습니다."}'::jsonb, '[{"term_ko": "고혈압", "term_vi": "대상자", "def_ko": "높은 huyết áp", "def_vi": "bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1438, '11', '고혈압 대상자가 섭취할 음식으로 옳은 것은?', '["찐 고구마", "강된장", "깻잎장아찌", "삼겹살 구이", "자반 고등어조림"]'::jsonb, 1, NULL, NULL, '{"1": "찐 고구마는 식이섬유와 칼륨이 풍부해 고혈압 관리에 도움이 됩니다.\n[정답]", "2": "강된장은 나트륨이 많아 고혈압에 좋지 않습니다.", "3": "깻잎장아찌 또한 나트륨이 포함되어 있어 고혈압에 부적합합니다.", "4": "삼겹살 구이는 지방 함량이 높아 고혈압 환자에게 좋지 않습니다.", "5": "자반 고등어조림은 염분이 많아 고혈압에 좋지 않습니다."}'::jsonb, '[{"term_ko": "고혈압", "term_vi": "Tăng huyết áp", "def_ko": "높은 혈압 상태", "def_vi": "Tình trạng huyết áp cao"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1437, '11', '당뇨병 대상자의 식사 관리로 옳은 것은?', '["혈당지수가 높은 식품을 제공한다.", "포만감을 주는 식이섬유 섭취를 제한한다.", "식사 때마다 튀김이나 볶음 요리를 제공한다.", "향신료를 이용하여 음식을 싱겁게 조리한다.", "배고픔을 느끼지 않도록 식사를 자주 하게 한다."]'::jsonb, 4, NULL, NULL, '{"1": "혈당지수가 높은 식품은 혈당을 급격하게 높일 수 있어 잘못된 선택입니다.\n[정답]", "4": "향신료를 이용해 음식을 싱겁게 조리하면 나트륨 섭취를 줄이는데 도움이 됩니다.", "2": "포만감을 주는 식이섬유는 오히려 섭취를 권장해야 합니다.", "3": "튀김이나 볶음 요리는 지방이 많아 건강에 좋지 않으므로 피해야 합니다.", "5": "식사를 자주 하는 것은 좋지만 그 양과 내용에 따라 조절이 필요합니다."}'::jsonb, '[{"term_ko": "당뇨병", "term_vi": "식사", "def_ko": "성인병, bệnh tiểu đường", "def_vi": "식사, bữa ăn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1436, '11', '당뇨병 대상자의 혈당 관리에 도움이 되는 혈당지수가 낮은 식품은?', '["수박", "흰밥", "찐감자", "미역", "식빵"]'::jsonb, 4, NULL, NULL, '{"1": "수박: 혈당 지수가 비교적 높아 혈당 관리에 적합하지 않음.\n[정답]", "4": "미역: 혈당 지수가 낮아 당뇨병 관리에 도움이 되는 식품.", "2": "흰밥: 혈당 지수가 높아 피해야 할 식품.", "3": "찐감자: 혈당 지수가 높아 당뇨 관리에 적절하지 않음.", "5": "식빵: 혈당 지수가 높아 적합하지 않음."}'::jsonb, '[{"term_ko": "당뇨병", "term_vi": "Bệnh tiểu đường", "def_ko": "병으로 인슐린 분비의 이상 또는 세포의 저항으로 혈당이 상승하는 질병", "def_vi": "Bệnh khiến độ đường trong máu tăng do sự bất thường trong tiết insulin hoặc sự kháng insulin của tế bào"}, {"term_ko": "혈당", "term_vi": "Đường huyết", "def_ko": "혈액에 있는 포도당의 양", "def_vi": "Lượng glucose trong máu"}, {"term_ko": "식품", "term_vi": "Thực phẩm", "def_ko": "섭취할 수 있는 음식의 종류", "def_vi": "Loại thực phẩm có thể tiêu thụ"}, {"term_ko": "지수", "term_vi": "Chỉ số", "def_ko": "비교의 기준이 되는 수치나 등급", "def_vi": "Con số hoặc thứ hạng được sử dụng làm tiêu chuẩn so sánh"}, {"term_ko": "관리", "term_vi": "Quản lý", "def_ko": "상태를 잘 유지하도록 돌보거나 조정하는 것", "def_vi": "Hành động chăm sóc hoặc điều chỉnh để duy trì tình trạng tốt"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1435, '11', '당뇨병 대상자의 식품섭취 방법으로 옳은 것은?', '["식사 전 술을 마신다.", "커피, 탄산음료수를 자주 마신다.", "흰밥보다 잡곡밥을 섭취한다.", "생과일보다 광리주스를 섭취한다.", "설탕이나 꿀 등 단순당을 주로 섭취한다."]'::jsonb, 3, NULL, NULL, '{"1": "식사 전 술을 마신다. - 술은 혈당에 영향을 미칠 수 있어 당뇨병 환자에게 좋지 않다.\n[정답]", "3": "흰밥보다 잡곡밥을 섭취한다. - 잡곡밥은 섬유소가 많고 혈당 조절에 도움이 된다.", "2": "커피, 탄산음료수를 자주 마신다. - 당뇨병 환자는 단 음료를 피하는 것이 좋다.", "4": "생과일보다 광리주스를 섭취한다. - 생과일에는 섬유소가 있어 좋다.", "5": "설탕이나 꿀 등 단순당을 주로 섭취한다. - 단순당은 혈당을 급격히 올릴 수 있다."}'::jsonb, '[{"term_ko": "당뇨병", "term_vi": "Bệnh tiểu đường", "def_ko": "병 상태(한국어)", "def_vi": "Tình trạng bệnh"}, {"term_ko": "대상자", "term_vi": "Người nhận", "def_ko": "특정 개인(한국어)", "def_vi": "Cá nhân cụ thể"}, {"term_ko": "식품섭취", "term_vi": "Thực phẩm tiêu thụ", "def_ko": "음식 섭취 활동(한국어)", "def_vi": "Hoạt động tiêu thụ thực phẩm"}, {"term_ko": "잡곡밥", "term_vi": "Cơm gạo lứt", "def_ko": "여러 곡물의 혼합(한국어)", "def_vi": "Hỗn hợp nhiều loại ngũ cốc"}, {"term_ko": "혈당", "term_vi": "Đường huyết", "def_ko": "혈액 중의 포도당(한국어)", "def_vi": "Glucose trong máu"}, {"term_ko": "단순당", "term_vi": "Đường đơn", "def_ko": "쉽게 소화되는 당(한국어)", "def_vi": "Đường dễ tiêu hóa"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1434, '11', '당뇨병 대상자의 식사 돕기 방법으로 옳은 것은?', '["단순당질 섭취를 제한한다.", "해조류의 섭취를 줄인다.", "식사를 많이 하여 체중을 늘린다.", "동물성 지방 섭취를 많이 한다.", "혈당지수가 높은 식품을 선택한다."]'::jsonb, 1, NULL, NULL, '{"1": "단순당질 섭취를 제한하는 것은 당뇨병 관리에 필수적입니다.\n[정답]", "2": "해조류의 섭취를 줄이는 것은 특정 상황에서 필요할 수 있지만, 일반적으로 해조류는 영양소가 풍부하여 권장됩니다.", "3": "식사를 많이 하여 체중을 늘리는 것은 당뇨병 관리에 적합하지 않습니다.", "4": "동물성 지방 섭취를 많이 하는 것은 건강에 좋지 않으며, 당뇨병 관리에 도움이 되지 않습니다.", "5": "혈당지수가 높은 식품을 선택하는 것은 당뇨병에 해롭습니다."}'::jsonb, '[{"term_ko": "단순당질", "term_vi": "Carbohydrate đơn giản", "def_ko": "단순한 설탕과 같은 간단한 형태의 탄수화물", "def_vi": "dạng carbohydrate đơn giản như đường"}, {"term_ko": "해조류", "term_vi": "Rong biển", "def_ko": "바다에서 나는 식물", "def_vi": "thực vật mọc dưới biển"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식을 먹는 것", "def_vi": "việc ăn uống"}, {"term_ko": "체중", "term_vi": "Cân nặng", "def_ko": "신체의 무게", "def_vi": "trọng lượng cơ thể"}, {"term_ko": "동물성 지방", "term_vi": "Chất béo động vật", "def_ko": "동물에서 유래한 지방", "def_vi": "chất béo có nguồn gốc từ động vật"}, {"term_ko": "혈당지수", "term_vi": "Chỉ số đường huyết", "def_ko": "혈당을 오르는 속도를 나타내는 지수", "def_vi": "chỉ số thể hiện tốc độ tăng đường huyết"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1433, '11', '영양밀도를 높이고 먹기 쉽게 조리하는 방법으로 옳은 것은?', '["나물류는 미리 무쳐서 놓는다.", "식품 자체의 맛보다 양념 맛을 강조한다.", "샐러듣드레싱으로 마요네즈를 이용한다.", "쑥갓나물 무침에 삶아서 으깬 두부를 넣는다.", "사태나 양지는 결 방향으로 잘라 높은 온도로 단시간 조리한다."]'::jsonb, 4, NULL, NULL, '{"1": "나물류는 미리 무쳐서 놓으면 풍미가 증가하지만 영양밀도에는 한계가 있습니다.\n[정답]", "4": "쑥갓나물 무침에 삶아서 으깬 두부를 넣으면 단백질과 영양밀도를 높일 수 있는 좋은 방법입니다.", "2": "식품 자체의 맛보다 양념 맛을 강조하는 것은 영양학적으로 바람직하지 않습니다.", "3": "샐러드 드레싱으로 마요네즈를 이용하면 칼로리는 높아지지만 영양밀도 향상에는 도움이 되지 않습니다.", "5": "사태나 양지는 결 방향으로 잘라 높은 온도로 단시간 조리하면 식감이 좋지만 영양밀도와는 직접적인 연관이 없습니다."}'::jsonb, '[{"term_ko": "영양밀도", "term_vi": "Mật độ dinh dưỡng", "def_ko": "영양 밀도가 높다는 뜻입니다.", "def_vi": "nghĩa là có mật độ dinh dưỡng cao."}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1432, '11', '음식 조리 시 나트륨을 줄이는 방법으로 옳은 것은?', '["국수 등 면을 삶을 때는 소금을 첨가한다.", "건더기보다는 국물 위주로 제공한다.", "쌈장을 만들 때 데쳐서 으깬 두부를 넣는다.", "양배추, 오이보다는 절인 배추를 이용한다.", "간을 맞출 때는 간장보다 소금을 이용한다."]'::jsonb, 3, NULL, NULL, '{"1": "면을 삶을 때 소금을 첨가하면 나트륨이 증가하므로 잘못된 정보입니다.\n[정답]", "3": "데쳐서 으깬 두부를 넣으면 나트륨 섭취를 줄일 수 있는 방법입니다.", "2": "국물 위주로 제공하면 일반적으로 나트륨 섭취가 늘어날 수 있습니다.", "4": "절인 배추는 나트륨이 많이 포함되어 있어 바람직하지 않습니다.", "5": "간장보다 소금은 더 많은 나트륨을 포함하고 있어 잘못된 선택입니다."}'::jsonb, '[{"term_ko": "나트륨", "term_vi": "Natri", "def_ko": "소금의 주요 성분", "def_vi": "Thành phần chính của muối"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1431, '11', '고혈압을 예방하기 위해 소금 섭취를 줄이는 방법은?', '["간을 점차적으로 진하게 한다.", "음식이 뜨거울 때 간을 맞춘다.", "두부와 가공식품은 끓는 물에 데쳐서 사용한다.", "고추장, 된장, 간장을 이용하여 음식을 조리한다.", "다른 맛이나 향이 나는 양념과 채소를 쓰지 않는다."]'::jsonb, 3, NULL, NULL, '{"1": "간을 진하게 하는 것은 소금 섭취를 줄이지 않습니다.\n[정답]", "3": "두부와 가공식품을 끓는 물에 데쳐서 사용하면 소금 섭취를 줄일 수 있습니다.", "2": "음식이 뜨거울 때 간을 맞추는 것은 권장되지 않습니다.", "4": "고추장, 된장, 간장을 사용하는 것은 소금을 추가하는 방법입니다.", "5": "다른 맛이나 향이 나는 양념과 채소를 사용하지 않는 것은 요리의 다양성을 제한합니다."}'::jsonb, '[{"term_ko": "고혈압", "term_vi": "Huyết áp cao", "def_ko": "높은 혈압(한국어)", "def_vi": "Huyết áp cao(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1430, '11', '대상자를 위한 음식의 조리 방법으로 옳은 것은?', '["볶기 - 저온에서 오랜 시간 볶는다.", "굽기 - 생선구이는 바싹하게 오래 굽는다.", "삶기 - 조리수를 많이 잡아 삶은 후 물은 버린다.", "나물 - 데쳐서 참기름이나 들기름을 넣어 무친다.", "튀기기 - 낮은 온도에서 조리하여 재료를 부드럽게 한다."]'::jsonb, 4, NULL, NULL, '{"1": "볶기는 고온에서 빠르게 조리하는 것이 일반적이며, 저온에서 오랜 시간 볶는 것은 음식의 질감을 떨어뜨릴 수 있습니다.\n[정답]", "4": "나물은 데쳐서 참기름이나 들기름을 넣어 무치는 것이 올바른 조리법입니다.", "2": "굽기는 생선이 바삭해질 정도로 조리하는 것이 일반적이며, 바싹하게 오래 굽는 것은 육즙을 잃게 합니다.", "3": "삶기는 조리수의 양을 최소한으로 하여 영양소를 보존하는 조리법입니다.", "5": "튀기기는 고온에서 조리하여 바삭함을 주는 것이 일반적입니다."}'::jsonb, '[{"term_ko": "조리", "term_vi": "Chế biến", "def_ko": "요리하다(한국어)", "def_vi": "chế biến(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1429, '11', '치아 손실이 있는 재가대상자의 식사를 조리하는 방법은?', '["감자는 바싹 튀겨 소금을 뿌린다.", "흰떡은 큼직하게 썰어 기름에 볶는다.", "양배추는 센 불로 익힌 후 약불로 줄여서 찐다.", "문어는 물을 충분히 붓고 오랫동안 삶는다.", "소고기는 납작하게 저며서 말려 육포로 만든다."]'::jsonb, 3, NULL, NULL, '{"1": "감자는 바싹 튀겨 소금을 뿌리는 방법은 치아가 없는 대상자가 먹기에 어려움이 있다.\n[정답]", "3": "양배추는 센 불로 익힌 후 약불로 줄여서 찌는 방법은 부드럽고 소화가 잘 되어 안전한 식사 조리 방법이다.", "2": "흰떡은 큼직하게 썰어 기름에 볶는 것은 치아 손실 대상자에게 적합하지 않다.", "4": "문어는 물을 충분히 붓고 오랫동안 삶는 방법은 질긴 식감을 남길 수 있다.", "5": "소고기는 납작하게 저며서 말려 육포로 만들면 쉽게 씹지 못할 수 있다."}'::jsonb, '[{"term_ko": "치아", "term_vi": "Răng", "def_ko": "이(한국어)", "def_vi": "Răng"}, {"term_ko": "손실", "term_vi": "Mất", "def_ko": "잃음(한국어)", "def_vi": "Mất"}, {"term_ko": "재가대상자", "term_vi": "Đối tượng cư trú tại nhà", "def_ko": "방문 요양을 받는 대상자(한국어)", "def_vi": "Đối tượng nhận chăm sóc tại nhà"}, {"term_ko": "조리", "term_vi": "Nấu ăn", "def_ko": "요리하다(한국어)", "def_vi": "Nấu ăn"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식(한국어)", "def_vi": "Bữa ăn"}, {"term_ko": "양배추", "term_vi": "Bắp cải", "def_ko": "배추(한국어)", "def_vi": "Bắp cải"}, {"term_ko": "센 불", "term_vi": "Lửa lớn", "def_ko": "강한 불(한국어)", "def_vi": "Lửa lớn"}, {"term_ko": "약불", "term_vi": "Lửa nhỏ", "def_ko": "작은 불(한국어)", "def_vi": "Lửa nhỏ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1428, '11', '식사를 준비하면서 재가대상자에게 설명한 것으로 옳은 것은?', '["\"국 끓이고 남은 재료를 제가 먹을게요.\"", "\"두부 사고 남은 돈은 딸에게 주었어요.\"", "\"냉장고에 있던 우유는 오래된 것 같아서 버렸어요.\"", "\"어르신은 편찮으시니까 흰죽만 드시는 것이 좋겠어요.\"", "\"혈당이 높으니 어르신이 좋아하는 잡곡밥을 해 드릴게요.\""]'::jsonb, 5, NULL, NULL, '{"1": "''국 끓이고 남은 재료를 제가 먹을게요.''는 어르신의 건강과 관계없는 개인적인 언급입니다.", "2": "''두부 사고 남은 돈은 딸에게 주었어요.''는 재가대상자와 관련이 없는 가족 이야기입니다.", "3": "''냉장고에 있던 우유는 오래된 것 같아서 버렸어요.''는 식사 준비에 대한 긍정적인 설명이 아닙니다.", "4": "''어르신은 편찮으시니까 흰죽만 드시는 것이 좋겠어요.''는 올바른 조언이지만 식사 준비에 대한 직접적인 설명이 아닙니다.\n[정답]", "5": "''혈당이 높으니 어르신이 좋아하는 잡곡밥을 해 드릴게요.''는 어르신의 건강 상태를 고려한 올바른 설명입니다."}'::jsonb, '[{"term_ko": "재가대상자", "term_vi": "Người có nhu cầu được chăm sóc tại nhà", "def_ko": "재가에서 서비스를 받는 대상자", "def_vi": "Người đang nhận dịch vụ tại nhà"}, {"term_ko": "편찮으시다", "term_vi": "Bệnh", "def_ko": "아프다", "def_vi": "Bị đau"}, {"term_ko": "잡곡밥", "term_vi": "Cơm nhiều loại ngũ cốc", "def_ko": "여러 가지 곡물이 섞인 밥", "def_vi": "Cơm làm từ nhiều loại ngũ cốc"}, {"term_ko": "혈당", "term_vi": "Đường huyết", "def_ko": "혈액의 당 성분", "def_vi": "Đường trong máu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1427, '11', '식사 준비를 위한 올바른 식재료 구매 방법은?', '["값싼 식재료는 대량으로 구매한다.", "유통기한을 넘긴 할인식품을 구매한다.", "대상자와 구매목록을 상의하지 않는다.", "구매 시 보관방법 및 보고나상태를 확인한다.", "식단은 식재료를 구입 후 작성한다."]'::jsonb, 4, NULL, NULL, '{"1": "값싼 식재료는 대량으로 구매하는 것이 비용 절감에 도움을 줄 수 있지만, 품질이 중요하므로 주의해야 합니다.", "2": "유통기한을 넘긴 할인식품을 구매하는 것은 건강에 위험할 수 있으므로 피해야 합니다.", "3": "대상자와 구매목록을 상의하지 않는 것은 식사 준비에 중요한 정보를 놓칠 수 있습니다.\n[정답]", "4": "구매 시 보관방법 및 보고나 상태를 확인하는 것은 식품 안전을 위해 필수적입니다.", "5": "식단은 식재료를 구입 후 작성하는 것이 아니라 미리 계획해야 효율적입니다."}'::jsonb, '[{"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "식사를 준비하는 과정", "def_vi": "Quá trình chuẩn bị bữa ăn"}, {"term_ko": "식재료", "term_vi": "Nguyên liệu thực phẩm", "def_ko": "요리를 위해 필요한 재료", "def_vi": "Nguyên liệu cần thiết để nấu ăn"}, {"term_ko": "구매", "term_vi": "Mua sắm", "def_ko": "물품을 사는 행위", "def_vi": "Hành động mua hàng"}, {"term_ko": "유통기한", "term_vi": "Hạn sử dụng", "def_ko": "식품이 안전하게 소비될 수 있는 기한", "def_vi": "Thời gian mà thực phẩm có thể được tiêu thụ an toàn"}, {"term_ko": "보관방법", "term_vi": "Phương pháp bảo quản", "def_ko": "식품을 저장하는 방법", "def_vi": "Cách lưu trữ thực phẩm"}, {"term_ko": "상태", "term_vi": "Trạng thái", "def_ko": "상황이나 상태", "def_vi": "Tình trạng hoặc trạng thái"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1426, '11', '식사를 준비하기 위한 장보기 방법으로 옳은 것은?', '["한 번에 많은 양의 식품을 구입한다.", "가족이 먹고 싶은 음식을 확인하여 구입한다.", "요양보호사 자신에게 필요한 물품을 함께 구입한다.", "물품구매 후 경비 결산은 한 달에 한 번 한다.", "대상자의 건강상태를 고려하여 식단을 작성한다."]'::jsonb, 5, NULL, NULL, '{"1": "한 번에 많은 양의 식품을 구입하는 것은 식품의 신선도와 품질을 고려했을 때 바람직하지 않다.\n[정답]", "2": "가족이 먹고 싶은 음식을 확인하여 구입하는 것은 중요한 사항이나, 특히 요양보호사로서의 역할을 고려할 때 대상자의 건강 상태를 더 우선해야 한다.", "3": "요양보호사 자신에게 필요한 물품을 함께 구입하는 것은 비효율적일 수 있다.", "4": "물품구매 후 경비 결산을 한 달에 한 번 하는 것은 적절하지 않다. 주기적으로 점검하는 것이 좋다.", "5": "대상자의 건강상태를 고려하여 식단을 작성하는 것은 가장 중요한 사항이다."}'::jsonb, '[{"term_ko": "장보기", "term_vi": "Mua sắm", "def_ko": "쇼핑(한국어)", "def_vi": "Mua sắm(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1425, '11', '식사 준비를 위한 장보기 수칙으로 옳은 것은?', '["대상자의 질병 상태와 상관없이 구매한다.", "요양보호사 마음대로 구매한다.", "냉장고 안의 품목을 확인한다.", "가공식품 위주로 구매한다.", "전문 재래시장 이용을 삼간다."]'::jsonb, 3, NULL, NULL, '{"1": "대상자의 질병 상태에 따라 식사 재료가 달라져야 하므로 잘못된 설명이다.", "2": "요양보호사는 대상자의 건강을 고려하여 구매해야 하므로 잘못된 설명이다.\n[정답]", "3": "냉장고 안의 품목을 확인하는 것은 필요한 재료를 구매하기 위해 중요하다.", "4": "가공식품 위주로 구매하는 것은 건강에 좋지 않을 수 있으므로 잘못된 설명이다.", "5": "전문 재래시장이 아닌 곳에서 구매해도 되며, 상황에 따라 다르므로 잘못된 설명이다."}'::jsonb, '[{"term_ko": "식사", "term_vi": "준비", "def_ko": "식사(한국어) / bữa ăn: bữa ăn(베트남어)", "def_vi": "준비(한국어) / chuẩn bị: chuẩn bị(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1424, '11', '대상자에게 일상생활 지원을 할 때 지켜야 할 기본원칙은?', '["대상자의 욕구보다 주변 정리를 우선으로 한다.", "서비스 제공에 대해 상세하게 기록한다.", "요양보호사의 생활방식과 가치관을 우선한다.", "물품을 요양보호사가 알아서 적당히 쓴다.", "인지능력이 없는 경우 설명하지 않는다."]'::jsonb, 2, NULL, NULL, '{"1": "대상자의 욕구를 우선해야 하며, 주변 정리는 그 다음이다.\n[정답]", "2": "서비스 제공에 대해 상세하게 기록하는 것은 매우 중요하다.", "3": "요양보호사의 개인적인 생활방식이나 가치관은 대상자에게 강요해서는 안 된다.", "4": "물품 사용에 있어서는 대상자의 동의를 구해야 한다.", "5": "인지능력이 없는 경우에도 상항에 따라 적절한 설명이 필요하다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người nhận dịch vụ", "def_ko": "지원을 받는 사람", "def_vi": "Người nhận sự hỗ trợ"}, {"term_ko": "일상생활", "term_vi": "Cuộc sống hàng ngày", "def_ko": "매일의 삶에서 필요한 활동", "def_vi": "Những hoạt động cần thiết trong cuộc sống hàng ngày"}, {"term_ko": "기본원칙", "term_vi": "Nguyên tắc cơ bản", "def_ko": "기본적인 규칙", "def_vi": "Quy tắc cơ bản"}, {"term_ko": "서비스", "term_vi": "Dịch vụ", "def_ko": "제공되는 도움", "def_vi": "Sự trợ giúp được cung cấp"}, {"term_ko": "기록하다", "term_vi": "Ghi chép", "def_ko": "작성하다", "def_vi": "Viết lại"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1423, '11', '일상생활 지원의 기본 원칙으로 옳은 것은?', '["요양보호사의 판단으로 결정한다.", "대상자의 물품을 임의대로 배치한다.", "위생을 위해 일회용품을 사용한다.", "대상자의 가족을 지원한다.", "대상자의 특성과 욕구를 파악하여 서비스를 제공한다."]'::jsonb, 5, NULL, NULL, '{"1": "요양보호사는 대상자의 입장을 최우선으로 고려해야 하므로 판단만으로 결정할 수 없습니다.\n[정답]", "5": "대상자의 특성과 욕구를 파악하고 이를 바탕으로 서비스를 제공하는 것이 일상생활 지원의 기본 원칙입니다.", "2": "대상자의 물품을 임의대로 배치하는 것은 대상자의 권리를 침해할 수 있습니다.", "3": "위생을 위해 일회용품을 사용하는 것이 좋지만 기본 원칙이라고 하기엔 부족합니다.", "4": "대상자의 가족을 지원하는 것도 중요하지만 그것이 전부는 아닙니다."}'::jsonb, '[{"term_ko": "일상생활", "term_vi": "Hoạt động hàng ngày", "def_ko": "일상 속에서 하는 모든 활동", "def_vi": "Mọi hoạt động xảy ra trong cuộc sống hàng ngày"}, {"term_ko": "지원", "term_vi": "Hỗ trợ", "def_ko": "돕다, 보조하다", "def_vi": "Giúp đỡ, hỗ trợ"}, {"term_ko": "특성", "term_vi": "Đặc điểm", "def_ko": "특징, 성격", "def_vi": "Tính chất, tính cách"}, {"term_ko": "욕구", "term_vi": "Nhu cầu", "def_ko": "원하는 것", "def_vi": "Những thứ mong muốn"}, {"term_ko": "위생", "term_vi": "Vệ sinh", "def_ko": "청결", "def_vi": "Sạch sẽ"}, {"term_ko": "일회용품", "term_vi": "Sản phẩm dùng một lần", "def_ko": "한 번만 쓸 수 있는 물건", "def_vi": "Vật phẩm chỉ dùng một lần"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1422, '10', '치매 대상자가 길을 잃었을 때 실종을 방지하기 위해 사용하는 복지용구는?', '["배회감지기", "목욕리프트", "경사로", "안전손잡이", "실버카"]'::jsonb, 1, NULL, NULL, '{"1": "배회감지기는 치매 대상자들이 길을 잃지 않도록 도와주는 기구입니다.\n[정답]", "2": "목욕리프트는 욕실에서 안전하게 목욕할 수 있도록 도와주는 용구입니다.", "3": "경사로는 휠체어 사용자가 이동하기 용이하도록 만들어진 구조물입니다.", "4": "안전손잡이는 이동 시 안전성을 제공하는 장치입니다.", "5": "실버카는 노인들이 보행 시 사용하도록 돕는 보조기구입니다."}'::jsonb, '[{"term_ko": "배회감지기", "term_vi": "Cảm biến đi lang thang", "def_ko": "길을 잃는 것을 감지하여 알림", "def_vi": "Phát hiện việc lạc đường và thông báo"}, {"term_ko": "목욕리프트", "term_vi": "Thang tắm", "def_ko": "안전하게 목욕할 수 있도록 돕는 기구", "def_vi": "Thiết bị hỗ trợ tắm an toàn"}, {"term_ko": "경사로", "term_vi": "Dốc nghiêng", "def_ko": "휠체어 사용자를 위한 구조물", "def_vi": "Cấu trúc dành cho người sử dụng xe lăn"}, {"term_ko": "안전손잡이", "term_vi": "Tay cầm an toàn", "def_ko": "이동 시 도움을 주는 장치", "def_vi": "Thiết bị hỗ trợ sự an toàn khi di chuyển"}, {"term_ko": "실버카", "term_vi": "Xe lăn dành cho người già", "def_ko": "노인을 위한 보조기구", "def_vi": "Thiết bị hỗ trợ đi lại cho người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1421, '10', '침대를 사용하는 대상자를 돕는 방법으로 옳은 것은?', '["자주 사용하는 물건은 침대 가까이 둔다.", "바퀴의 잠금장치는 항상 열린 상태로 둔다.", "대상자가 내려오기 쉽도록 침대 난간을 항상 내려 놓는다.", "등판, 다리판 작동 손잡이는 신속하게 작동한다.", "안전을 위해 잠금장치 후 이동한다."]'::jsonb, 1, NULL, NULL, '{"1": "자주 사용하는 물건은 침대 가까이 두어 쉽게 접근할 수 있게 한다.\n[정답]", "2": "바퀴의 잠금장치는 항상 열린 상태로 두는 것은 안전하지 않다.", "3": "대상자가 내려오기 쉽도록 침대 난간을 항상 내려 놓는 것은 도움이 되지 않는다.", "4": "등판, 다리판 작동 손잡이는 신속하게 작동해야 하지만 안전도 고려해야 한다.", "5": "안전을 위해 잠금장치 후 이동하는 것이 일반적으로 안전하다."}'::jsonb, '[{"term_ko": "침대", "term_vi": "Giường", "def_ko": "침대(한국어)", "def_vi": "Giường (베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1420, '10', '수동침대를 사용하는 대상자를 돕는 방법으로 옳은 것은?', '["등판, 다리판 작동을 위해 크랭크는 항상 펴서 둔다.", "침대에 오를 때는 침대 난간을 잡고 오른다.", "이동하지 않을 때는 바퀴의 잠금 장치를 잠근다.", "사용하지 않을 때는 높납이를 높게 한다.", "침대 이동 시 침대 난간을 잡고 이동한다."]'::jsonb, 3, NULL, NULL, '{"1": "등판 및 다리판 작동을 위해 크랭크를 펴서 두는 것은 올바른 방법이 아닙니다.\n[정답]", "3": "이동하지 않을 때는 바퀴의 잠금 장치를 잠그는 것이 안전합니다.", "2": "침대에 오를 때는 침대 난간을 잡고 오르는 것이 일반적인 권장 방법입니다.", "4": "사용하지 않을 때는 높납이를 높게 하는 것은 불필요할 수 있습니다.", "5": "침대 이동 시 침대 난간을 잡고 이동하는 것은 올바른 방법이 아닙니다."}'::jsonb, '[{"term_ko": "수동침대", "term_vi": "Giường thủ công", "def_ko": "수동으로 조작하는 침대", "def_vi": "Giường điều khiển bằng tay"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1419, '10', '거동이 불편한 대상자가 사용하는 자세변환용 쿠션의 조건으로 적합한 것은?', '["마찰이 적은 소재로 표면이 미끄러워야 한다.", "커버는 분리되지 않아야 한다.", "쿠션의 재질이 딱딱해야 한다.", "쿠션에 부착된 지퍼는 감춰져 있어야 한다.", "커버는 소독할 수 있고 변색이 잘 되어야 한다."]'::jsonb, 4, NULL, NULL, '{"1": "마찰이 적은 소재는 중요하지만, 표면이 미끄럽다면 오히려 안전하지 않다.\n[정답]", "2": "커버는 분리되지 않아야 하며, 위생적인 관리가 필요하기 때문에 지퍼가 감춰져 있어야 한다.", "3": "쿠션의 재질은 부드러워야 하며 딱딱해서는 안 된다.", "4": "쿠션에 부착된 지퍼는 감춰져 있어야 한다. 따라서 고른 안전성을 위해 지퍼가 드러나지 않는 것이 이상적이다.", "5": "커버는 소독할 수 있어야 하지만 변색이 잘 되어서는 안 된다."}'::jsonb, '[{"term_ko": "거동", "term_vi": "Hành động", "def_ko": "움직임(한국어)", "def_vi": "Di chuyển(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1418, '10', '욕창예방 매트리스를 사용하는 방법으로 옳은 것은?', '["하루 12시간만 사용한다.", "하루에 한 번씩 기구에 올라가 정상 동작을 확인한다.", "매트리스는 찜질기와 함께 사용한다.", "등과 엉덩이 밑에 손을 넣어 환자를 부양하는지 확인한다.", "매트리스 셀과 커버는 알코올로 적신 천으로 깨끗이 닦는다."]'::jsonb, 4, NULL, NULL, '{"1": "하루 12시간만 사용한다는 것은 부족한 사용 시간으로, 권장 사항이 아닙니다.\n[정답]", "2": "하루에 한 번씩 기구에 올라가 정상 동작을 확인하는 것은 필요 없는 행동입니다.", "3": "매트리스는 찜질기와 함께 사용해서는 안 되며, 서로의 효과를 저하할 수 있습니다.", "4": "등과 엉덩이 밑에 손을 넣어 환자를 부양하는지 확인하는 것은 올바른 방법입니다.", "5": "매트리스 셀과 커버는 알코올로 적신 천으로 닦는 것이 바람직하지 않으며, 특정 세정제를 사용해야 합니다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Loét", "def_ko": "피부가 손상되어 생긴 염증", "def_vi": "Viêm do tổn thương da"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1417, '10', '체중으로 인한 압력을 분산시키고 통풍을 원활하게 하기 위한 복지용구는?', '["욕창예방 매트리스", "휠체어", "목욕리프트", "자세변환 용구", "이동욕조"]'::jsonb, 1, NULL, NULL, '{"1": "욕창예방 매트리스는 체중을 분산시키고 통풍을 원활하게 하여 욕창을 예방합니다.\n[정답]", "2": "휠체어는 이동을 돕는 기구이며, 압력을 분산시키는 기능은 없습니다.", "3": "목욕리프트는 목욕 시 도움을 주는 용구지만, 압력을 분산시키는 역할과는 관련이 없습니다.", "4": "자세변환 용구는 자세를 바꾸는 데 도움을 주지만, 통풍과 체중 분산과는 직접적인 관계가 없습니다.", "5": "이동욕조는 목욕과 관련된 용구로, 체중 분산과 관련성은 없습니다."}'::jsonb, '[{"term_ko": "욕창예방 매트리스", "term_vi": "Nệm phòng ngừa loét", "def_ko": "욕창을 예방하기 위한 매트리스", "def_vi": "Nệm giúp ngăn ngừa loét"}, {"term_ko": "체중", "term_vi": "Trọng lượng", "def_ko": "몸의 무게", "def_vi": "Cân nặng của cơ thể"}, {"term_ko": "압력", "term_vi": "Áp lực", "def_ko": "물체나 단위 면적에 가해지는 힘", "def_vi": "Lực tác động lên một vật thể hoặc diện tích"}, {"term_ko": "통풍", "term_vi": "Thông gió", "def_ko": "공기가 잘 통하는 상태", "def_vi": "Tình trạng không khí lưu thông tốt"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1416, '10', '욕창예방 방석의 사용, 관리 방법으로 옳은 것은?', '["커버는 한 달에 한 번 세탁한다.", "공기를 주입하면 뺄 수 없으므로 주의한다.", "열탕으로 소독하거나 햇볕에 말려서 사용한다.", "특정 부위에 신체 압력을 주기 위한 특수방석이다.", "소독할 때는 공기를 빼고 흐르는 물로 씻고 건조시킨다."]'::jsonb, 5, NULL, NULL, '{"1": "커버는 한 달에 한 번 세탁하는 것이 아니라, 상황에 따라 더 자주 세탁해야 합니다.\n[정답]", "5": "소독할 때는 공기를 빼고 흐르는 물로 씻고 건조시켜야 안전하게 사용할 수 있습니다.", "2": "공기를 주입하면 뺄 수 없다는 것은 사실이 아닙니다. 공기 주입 후 밸브를 통해 공기를 빼는 것이 가능합니다.", "3": "열탕 소독이나 햇볕에 말리는 방법은 해당 방석에 적합하지 않을 수 있습니다.", "4": "특정 부위에 신체 압력을 주기 위한 특수 방석의 기능과는 관련이 없습니다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Loét", "def_ko": "피부가 손상되는 상태(한국어)", "def_vi": "Trạng thái tổn thương da"}, {"term_ko": "방석", "term_vi": "Đệm", "def_ko": "앉거나 눕는 데 사용하는 패드(한국어)", "def_vi": "Đệm sử dụng để ngồi hoặc nằm"}, {"term_ko": "세탁", "term_vi": "Giặt", "def_ko": "더러운 것을 깨끗이 하다(한국어)", "def_vi": "Làm sạch những thứ bẩn"}, {"term_ko": "소독", "term_vi": "Khử trùng", "def_ko": "병원균을 죽이는 과정(한국어)", "def_vi": "Quá trình giết chết vi khuẩn"}, {"term_ko": "압력", "term_vi": "Áp lực", "def_ko": "힘이 가해지는 정도(한국어)", "def_vi": "Độ dư sức ép"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1415, '10', '이동욕조를 사용하는 방법으로 옳은 것은?', '["욕조 바닥면이 매끄러워야 한다.", "두 사람이 함께 사용할 수 있다.", "대상자가 욕조를 잡고 일어나게 한다.", "평평하고 이물질 없는 장소에서 사용한다.", "응급상황 발생 시에는 즉시 공기밸브를 열어준다."]'::jsonb, 4, NULL, NULL, '{"1": "욕조 바닥면이 매끄러워야 한다. - 매끄러운 바닥면은 안전과 직결되지 않으므로 별로 중요하지 않습니다.\n[정답]", "2": "두 사람이 함께 사용할 수 있다. - 이동욕조는 일반적으로 1인이 사용하므로 잘못된 정보입니다.", "3": "대상자가 욕조를 잡고 일어나게 한다. - 이는 올바른 사용 방법이 아닙니다.", "4": "평평하고 이물질 없는 장소에서 사용한다. - 안전을 위해 필요한 조건입니다.", "5": "응급상황 발생 시에는 즉시 공기밸브를 열어준다. - 이는 올바른 응급 대처가 아닙니다."}'::jsonb, '[{"term_ko": "이동욕조", "term_vi": "Bồn tắm di động", "def_ko": "이동할 수 있는 욕조", "def_vi": "Bồn tắm có thể di chuyển"}, {"term_ko": "평평하다", "term_vi": "Bằng phẳng", "def_ko": "고르다", "def_vi": "Đều"}, {"term_ko": "이물질", "term_vi": "Vật lạ", "def_ko": "불순물", "def_vi": "Tạp chất"}, {"term_ko": "응급상황", "term_vi": "Tình huống khẩn cấp", "def_ko": "급히 대처해야 하는 상황", "def_vi": "Tình huống cần xử lý khẩn cấp"}, {"term_ko": "공기밸브", "term_vi": "Van khí", "def_ko": "공기를 조절하는 밸브", "def_vi": "Van điều chỉnh không khí"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1414, '10', '목욕리프트에 대한 설명으로 옳은 것은?', '["철제로 된 튼튼한 재질이어야 한다.", "높낮이가 수동으로 조절되어야 한다.", "다리가 불편한 대상자가 목욕할 때 편리하다.", "안전을 위해 등받이 각도가 고정된 것이어야 한다.", "혼자서 앉을 수 없는 대상자는 사용할 수 없다."]'::jsonb, 3, NULL, NULL, '{"1": "목욕리프트는 다양한 소재로 제작될 수 있으며, 반드시 철제로 만들어야 하는 것은 아닙니다.\n[정답]", "2": "목욕리프트는 전동식이 많으며, 높낮이가 수동으로 조절되어야 하는 것은 아닙니다.", "3": "다리가 불편한 대상자가 목욕할 때 사용하기에 매우 편리합니다.", "4": "등받이 각도가 고정된 것은 안전을 위해 권장되지만, 반드시 모든 모델이 그렇게 설계된 것은 아닙니다.", "5": "혼자서 앉을 수 없는 대상자도 특별한 방법으로 지원을 받아 사용할 수 있으므로 부정확한 설명입니다."}'::jsonb, '[{"term_ko": "목욕리프트", "term_vi": "Ghế tắm", "def_ko": "목욕을 돕기 위해 사용하는 장치", "def_vi": "Thiết bị hỗ trợ việc tắm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1413, '10', '거동이 불편한 대상자의 안전을 위해 적절한 목욕의자는?', '["팔걸이가 없는 의자", "등받이가 낮은 의자", "구멍이나 흠이 없는 의자", "앉는 자리가 미끄럽지 않은 의자", "두 발이 바닥에 닿지 않는 높이의 의자"]'::jsonb, 4, NULL, NULL, '{"1": "팔걸이가 없는 의자는 지지력이 부족해 안전하지 않을 수 있다.", "2": "등받이가 낮은 의자는 편안함을 제공하지 못할 수 있다.\n[정답]", "3": "구멍이나 흠이 없는 의자는 위생적이며, 안전성을 높인다.", "4": "앉는 자리가 미끄럽지 않은 의자는 안전성을 높여주는 중요한 요소이며, 따라서 가장 적절하다.", "5": "두 발이 바닥에 닿지 않는 높이의 의자는 불안정성을 유발할 수 있다."}'::jsonb, '[{"term_ko": "거동", "term_vi": "Hành động", "def_ko": "움직임(한국어)", "def_vi": "di chuyển(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1412, '10', '휴대용 경사로 선정 시 고려해야 할 사항으로 옳은 것은?', '["색상", "균형감", "디자인", "회사명", "청결성"]'::jsonb, 2, NULL, NULL, '{"1": "색상은 선택의 중요한 요소가 아닙니다.\n[정답]", "2": "균형감은 안전과 직결되므로 매우 중요합니다.", "3": "디자인은 기능성보다 덜 중요합니다.", "4": "회사명은 제품 선택의 중요한 요소가 아닙니다.", "5": "청결성은 사용 후 고려할 수 있는 사항일 뿐, 선택 시 직접적인 고려요소는 아닙니다."}'::jsonb, '[{"term_ko": "휴대용", "term_vi": "Di động", "def_ko": "이동할 수 있는(한국어)", "def_vi": "Có thể di chuyển(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1411, '10', '거동이 불편한 대상자의 생활공간에 안전손잡이를 설치해야 하는 이유는?', '["근력과 지구력 향상", "스트레칭과 운동능력 강화", "근육의 유연성과 신장성 향상", "유산소 운동과 폐기능 강화", "자립성 향상과 신체 균형 유지"]'::jsonb, 5, NULL, NULL, '{"1": "근력과 지구력 향상은 일상적인 운동이나 활동에 의한 결과이지 안전손잡이 설치와는 직접적인 연관성이 없다.\n[정답]", "5": "자립성 향상과 신체 균형 유지가 안전손잡이를 설치하는 가장 중요한 이유로, 안전손잡이는 대상자가 이동할 때 균형을 유지하고 자립적으로 행동할 수 있도록 도와준다.", "2": "스트레칭과 운동능력 강화는 안전손잡이와의 관계가 명확하지 않다.", "3": "근육의 유연성과 신장성 향상은 안전손잡이 설치의 목적과는 거리가 멀다.", "4": "유산소 운동과 폐기능 강화는 안전손잡이와 관련이 없다."}'::jsonb, '[{"term_ko": "거동", "term_vi": "Hành động", "def_ko": "행동이나 움직임", "def_vi": "Hành vi hoặc chuyển động"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "서비스를 받는 사람", "def_vi": "Người nhận dịch vụ"}, {"term_ko": "안전손잡이", "term_vi": "Tay nắm an toàn", "def_ko": "넘어지지 않도록 도와주는 장치", "def_vi": "Thiết bị giúp ngăn ngừa ngã"}, {"term_ko": "자립성", "term_vi": "Tính tự lập", "def_ko": "스스로 할 수 있는 능력", "def_vi": "Khả năng tự mình làm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1410, '10', '지팡이를 사용할 때 안전을 위해 점검해야 하는 것은?', '["청결 상태", "손잡이 끈 유무", "손잡이 마모 정도", "페인트 도장 상태", "바닥 끝 고무의 닳은 정도"]'::jsonb, 5, NULL, NULL, '{"1": "지팡이의 청결 상태는 중요하나 안전과 직접적인 관련이 적다.\n[정답]", "5": "바닥 끝 고무가 닳은 정도는 지팡이의 미끄러짐과 관련이 있어 안전에 직접적인 영향을 미친다.", "2": "손잡이 끈 유무는 보조 장치 점검이 필요하지만 기본적인 안전 요소는 아니다.", "3": "손잡이 마모 정도는 중요하나 바닥 끝 고무의 상태가 더 직접적인 영향을 미친다.", "4": "페인트 도장 상태는 미관상의 문제일 뿐이다."}'::jsonb, '[{"term_ko": "지팡이", "term_vi": "Gậy", "def_ko": "보조 도구로 사용하는 막대기", "def_vi": "Cái được sử dụng như một công cụ hỗ trợ"}, {"term_ko": "청결", "term_vi": "Sạch sẽ", "def_ko": "깨끗함", "def_vi": "Sự sạch sẽ"}, {"term_ko": "손잡이", "term_vi": "Tay cầm", "def_ko": "잡는 부분", "def_vi": "Phần cầm"}, {"term_ko": "마모", "term_vi": "Mòn", "def_ko": "닳음", "def_vi": "Bị mòn"}, {"term_ko": "페인트", "term_vi": "Sơn", "def_ko": "물감", "def_vi": "Sơn"}, {"term_ko": "고무", "term_vi": "Cao su", "def_ko": "고무", "def_vi": "Cao su"}, {"term_ko": "닳다", "term_vi": "Mòn", "def_ko": "닳다", "def_vi": "Bị mòn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1409, '10', '지팡이를 안전하게 사용하는 방법으로 옳은 것은?', '["사용 시 안전을 위해 청결 상태를 점검한다.", "팔꿈치를 직각으로 구부린 높이가 안정적이다.", "지팡이 길이는 바닥면에서 둔부까지로 맞춘다.", "대상자가 설 수 없는 경우 네발 지팡이를 선택한다.", "불편한 쪽 발의 앞 15CM, 옆 15CM 지점에 지팡이 끝을 내민다."]'::jsonb, 3, NULL, NULL, '{"1": "사용 시 안전을 위해 청결 상태를 점검하는 것은 중요하지만, 지팡이를 안전하게 사용하는 방법으로는 적합하지 않습니다.\n[정답]", "2": "팔꿈치를 직각으로 구부린 높이는 안정적이지 않으며, 사용자의 신체에 따라 다를 수 있습니다.", "3": "지팡이 길이는 바닥면에서 둔부까지로 맞추는 것이 맞습니다. 이는 안전한 지팡이 사용을 위한 기본 원칙입니다.", "4": "대상자가 설 수 없는 경우 네발 지팡이를 선택하는 것은 적절하지 않으며, 적절한 보행 보조기를 선택해야 합니다.", "5": "불편한 쪽 발의 앞 15CM, 옆 15CM 지점에 지팡이 끝을 내미는 것은 올바른 사용 방법이 아닙니다."}'::jsonb, '[{"term_ko": "지팡이", "term_vi": "Gậy", "def_ko": "보행 보조 도구", "def_vi": "thiết bị hỗ trợ đi lại"}, {"term_ko": "청결", "term_vi": "Sạch sẽ", "def_ko": "깨끗함", "def_vi": "sự sạch sẽ"}, {"term_ko": "팔꿈치", "term_vi": "Khuỷu tay", "def_ko": "팔의 굽힌 부분", "def_vi": "phần khủy tay"}, {"term_ko": "안정적", "term_vi": "Ổn định", "def_ko": "안전성이 있는 상태", "def_vi": "trạng thái có độ an toàn"}, {"term_ko": "둔부", "term_vi": "Mông", "def_ko": "엉덩이", "def_vi": "mông"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1408, '10', '지팡이를 안전하게 사용하는 방법으로 옳은 것은?', '["사용 시 안전을 위해 청결 상태를 점검한다.", "팔꿈치를 직각으로 구부린 높이가 안정적이다.", "지팡이 길이는 바닥면에서 둔부까지로 맞춘다.", "대상자가 설 수 없는 경우 네발 지팡이를 선택한다.", "불편한 쪽 발의 앞 15CM, 옆 15CM 지점에 지팡이 끝을 내민다."]'::jsonb, 3, NULL, NULL, '{"1": "사용 시 청결 상태를 점검하는 것은 중요하지만 지팡이의 안전한 사용 방법에 직접적으로 관련된 설명은 아닙니다.\n[정답]", "2": "팔꿈치를 직각으로 구부린 높이는 안정적이지만, 지팡이의 적절한 길이가 더 중요합니다.", "3": "지팡이 길이는 바닥면에서 둔부까지 맞춰야 합니다. 이는 올바른 자세 유지에 도움이 됩니다.", "4": "대상자가 설 수 없는 경우 네발 지팡이를 선택하는 것이 일반적이나, 질문에서는 지팡이를 사용하는 방법에 대한 것이므로 해당 선택지는 부적절합니다.", "5": "불편한 쪽 발 근처에 지팡이 끝을 내미는 것은 잘못된 방법입니다. 지팡이는 바닥면에서 둔부까지 맞춰야 합니다."}'::jsonb, '[{"term_ko": "지팡이", "term_vi": "Gậy", "def_ko": "지원 도구(한국어)", "def_vi": "Dụng cụ hỗ trợ"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "위험이 없고 보호된 상태(한국어)", "def_vi": "Trạng thái không có nguy hiểm"}, {"term_ko": "팔꿈치", "term_vi": "Khuỷu tay", "def_ko": "팔과 손 사이의 관절(한국어)", "def_vi": "Khớp giữa tay và cánh tay"}, {"term_ko": "설 수 없다", "term_vi": "Không thể đứng", "def_ko": "서 있지 못하다(한국어)", "def_vi": "Không đứng được"}, {"term_ko": "네발 지팡이", "term_vi": "Gậy bốn chân", "def_ko": "네 개의 다리를 가진 지팡이(한국어)", "def_vi": "Gậy có bốn chân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1407, '10', '다음 중 보행자 설명으로 옳은 것은?', '["실내에서만 사용하는 보행 보조도구이다.", "지팡이보다 안전성이 약하다.", "요양보호사는 항상 대상자 가까이 있어야 한다.", "뒤로 잘 넘어지는 사람에게 유용하다.", "뇌졸증으로 반신마비의 대상자가 사용하기에 적합하다."]'::jsonb, 3, NULL, NULL, '{"1": "보행 보조도구는 실외에서도 사용할 수 있습니다.", "2": "일반적으로 지팡이보다 안전성이 높은 편입니다.\n[정답]", "3": "요양보호사는 항상 대상자 가까이 있어야 하며, 이로 인해 안전을 확보할 수 있습니다.", "4": "보행자는 뒤로 넘어지는 데 도움을 주지 않기 때문에 그와 관련된 설명은 잘못되었습니다.", "5": "뇌졸증으로 반신마비 대상자가 사용하기에는 그 용도가 조금 다를 수 있습니다."}'::jsonb, '[{"term_ko": "보행자", "term_vi": "Người đi bộ", "def_ko": "걷기에 도움을 주는 기구", "def_vi": "Thiết bị hỗ trợ đi bộ"}, {"term_ko": "지팡이", "term_vi": "Gậy", "def_ko": "손으로 잡고 지지하는 도구", "def_vi": "Công cụ được giữ và hỗ trợ"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "돌봄 받는 사람", "def_vi": "Người được chăm sóc"}, {"term_ko": "안전성", "term_vi": "Độ an toàn", "def_ko": "안전의 정도", "def_vi": "Mức độ an toàn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1406, '10', '복지용구를 소독, 관리하는 방법으로 옳은 것은?', '["목욕의자 - 열탕소독 한다.", "수동침대 - 흐르는 물로 씻어 건조시킨다.", "휠체어 - 소독용 알코올을 적신 천으로 닦는다.", "목욕리프트 - 소독액이나 뜨거운 물로 씻는다.", "성인용 보행기 - 세제로 닦고 햇볕에 말린다."]'::jsonb, 3, NULL, NULL, '{"1": "목욕의자는 열탕소독이 비현실적임.\n[정답]", "3": "휠체어는 소독용 알코올을 적신 천으로 닦는 것이 올바른 방법임.", "2": "수동침대는 흐르는 물로 씻으나, 소독에 대한 언급이 부족함.", "4": "목욕리프트는 적절한 소독 방법을 제시하지 않음.", "5": "성인용 보행기는 햇볕에 말리는 것이 아니라, 다른 소독 방법으로 관리해야 함."}'::jsonb, '[{"term_ko": "복지용구", "term_vi": "Dụng cụ hỗ trợ", "def_ko": "복지 분야에서 사용하는 도구나 장비", "def_vi": "Công cụ hoặc thiết bị được sử dụng trong lĩnh vực phúc lợi"}, {"term_ko": "소독", "term_vi": "Khử trùng", "def_ko": "병원균을 죽이는 과정을 의미", "def_vi": "Quá trình tiêu diệt vi khuẩn"}, {"term_ko": "관리", "term_vi": "Quản lý", "def_ko": "도구나 장비를 잘 다루는 것", "def_vi": "Sử dụng và chăm sóc công cụ hoặc thiết bị tốt"}, {"term_ko": "전신", "term_vi": "Toàn thân", "def_ko": "모든 신체 부위를 포함하여", "def_vi": "Bao gồm tất cả các bộ phận của cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1405, '10', '휠체어가 잘 굴러가지 않고 잠금장치가 고정되지 않을 때 먼저 점검해야 하는 곳은?', '["앞바퀴", "받침쇠", "발 받침대", "타이어 공기압", "바퀴 손잡이"]'::jsonb, 4, NULL, NULL, '{"1": "앞바퀴는 휠체어의 방향 전환에 영향을 미치지만 잠금장치와는 관련이 없습니다.\n[정답]", "4": "타이어 공기압이 낮으면 휠체어의 이동이 어려울 수 있으며, 잠금장치가 제대로 작동하지 않을 수 있습니다.", "2": "받침쇠는 휠체어의 구조물로, 잠금장치와는 직접적인 관계가 없습니다.", "3": "발 받침대는 사용자의 편안함을 위한 부분으로, 이동성과는 직접 관련이 없습니다.", "5": "바퀴 손잡이는 이동 시 조작에 도움을 주지만 잠금장치의 고정과는 관련이 없습니다."}'::jsonb, '[{"term_ko": "휠체어", "term_vi": "Xe lăn", "def_ko": "휠체어(한국어)", "def_vi": "xe lăn(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1404, '10', '휠체어를 관리하는 방법으로 옳은 것은?', '["사용하지 않을 때에는 잠금장치를 풀어둔다.", "뒷바퀴 공기압이 낮을수록 잠금장치가 잘 걸린다.", "뒷바퀴 공기압이 너무 높으면 충격을 흡수하지 못한다.", "적정 공기압은 엄지로 눌렀을 때 들어가지 않아야 한다.", "휠체어를 편 상태에서 보관한다."]'::jsonb, 3, NULL, NULL, '{"1": "사용하지 않을 때에는 잠금장치를 풀어두면 안전하지 않으므로 잘못된 설명입니다.\n[정답]", "3": "뒷바퀴 공기압이 너무 높으면 충격을 흡수하지 못하므로 올바른 설명입니다.", "2": "뒷바퀴 공기압이 낮아도 잠금장치가 잘 걸리는 것은 아니므로 잘못된 설명입니다.", "4": "적정 공기압은 엄지로 눌렀을 때 들어가지 않아야 하지만 이는 한도에 따라 달라질 수 있어 해석이 모호합니다.", "5": "휠체어를 편 상태에서 보관하면 안전하고 적절하지만, 보관 방법에는 여러 가지가 있으므로 다소 잘못된 설명이 될 수 있습니다."}'::jsonb, '[{"term_ko": "휠체어", "term_vi": "Xe lăn", "def_ko": "전동 또는 수동으로 이동하는 의자", "def_vi": "Ghế di chuyển tự động hoặc bằng tay"}, {"term_ko": "공기압", "term_vi": "Áp suất lốp", "def_ko": "타이어 내부의 압력", "def_vi": "Áp suất bên trong lốp"}, {"term_ko": "잠금장치", "term_vi": "Khóa", "def_ko": "안전을 위한 기계장치", "def_vi": "Thiết bị cơ khí để đảm bảo an toàn"}, {"term_ko": "충격", "term_vi": "Sốc", "def_ko": "외부 힘이 가해지는 상태", "def_vi": "Trạng thái khi lực bên ngoài tác động"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1403, '10', '복지용구 중에서 요실금 팬티를 사용하는 방법으로 옳은 것은?', '["요실금 팬티는 세탁 후 반복사용이 가능하다.", "실금량이 적을 때는 말려서 재사용한다.", "요실금 팬티 위에 일반 팬티를 덧입힌다.", "신체보다 한두 치수 큰 것으로 사용한다.", "흘림량이 500ML 이상인 대상자에게 사용한다."]'::jsonb, 1, NULL, NULL, '{"1": "요실금 팬티는 세탁 후 반복사용이 가능하다. [정답] 요실금 팬티는 세탁하여 반복적으로 사용할 수 있습니다.", "2": "실금량이 적을 때는 말려서 재사용한다. 이 방법은 권장되지 않습니다.", "3": "요실금 팬티 위에 일반 팬티를 덧입힌다. 이는 바람직하지 않은 방법입니다.", "4": "신체보다 한두 치수 큰 것으로 사용한다. 적절한 사이즈를 선택해야 합니다.", "5": "흘림량이 500ML 이상인 대상자에게 사용한다. 요실금 팬티는 흘림량이 적은 경우에 더 적합합니다."}'::jsonb, '[{"term_ko": "요실금 팬티", "term_vi": "Quần lót tiểu không tự chủ", "def_ko": "배뇨를 제어하지 못하는 사람을 위한 팬티", "def_vi": "Quần lót dành cho người không kiểm soát được tiểu tiện"}, {"term_ko": "재사용", "term_vi": "Tái sử dụng", "def_ko": "다시 사용하는 것", "def_vi": "Sử dụng lại"}, {"term_ko": "치수", "term_vi": "Kích thước", "def_ko": "사이즈", "def_vi": "Kích cỡ"}, {"term_ko": "흘림량", "term_vi": "Lượng tiểu", "def_ko": "누수되는 양", "def_vi": "Lượng nước tiểu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1402, '10', '간이변기를 사용하여 침상 배설을 하는 대상자를 돕는 방법은?', '["대상자 스스로 변기 위에 앉게 한다.", "팔걸이와 등받이에 기대어 힘을 주게 한다.", "변의가 확실하지 않으면 장시간 대어 준다.", "열량으로 소독할 수 있는 변기를 사용한다.", "협조할 수 없는 대상자는 옆으로 누워 사용한다."]'::jsonb, 4, NULL, NULL, '{"1": "대상자가 스스로 변기 위에 앉는 것이 아니라, 보호자가 도와야 하는 경우입니다.\n[정답]", "2": "팔걸이와 등받이에 기대어 힘을 주도록 하는 것은 적절하나, 소독이 우선이기 때문에 변기의 청결이 중요합니다.", "3": "변의가 확실하지 않은 경우 장시간 대기하는 것은 좋지 않습니다.", "4": "열량으로 소독할 수 있는 변기를 사용하는 것이 가장 올바른 방법입니다.", "5": "협조할 수 없는 대상자가 옆으로 누워 사용하도록 하는 것은 위험할 수 있습니다."}'::jsonb, '[{"term_ko": "간이변기", "term_vi": "Bồn cầu di động", "def_ko": "이동 가능한 화장실(한국어)", "def_vi": "Nhà vệ sinh có thể di chuyển(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1401, '10', '화장실까지 이동하기 어려운 대상자의 배설을 돕기 위한 이동변기로 적절한 것은?', '["팔걸이와 등받이가 없는 것", "바퀴가 붙어있어 이동하기 쉬운 것", "양변기 시트에 올려놓을 수 있는 것", "본체와 변기통이 일체형인 것", "뜨거운 물로 세척할 수 있는 것"]'::jsonb, 5, NULL, NULL, '{"1": "팔걸이와 등받이가 없는 것은 안전성과 편안함을 제공하지 않을 수 있어 적절하지 않다.\n[정답]", "2": "바퀴가 붙어있어 이동하기 쉬운 것은 이동성을 고려할 때 긍정적이나, 해당 문제에서 요구하는 조건을 충족하지 않는다.", "3": "양변기 시트에 올려놓을 수 있는 것은 고정되지 않아 안전성이 떨어질 수 있다.", "4": "본체와 변기통이 일체형인 것은 위생관리에 용이하여 적절하다.", "5": "뜨거운 물로 세척할 수 있는 것은 위생적으로 매우 중요하며, 배설물의 처리 과정에서 매우 유용하다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자, 혹은 보호가 필요한 사람", "def_vi": "Người bệnh hoặc người cần được chăm sóc"}, {"term_ko": "배설", "term_vi": "Phân bài", "def_ko": "소변이나 대변을 처리하는 것", "def_vi": "Việc xử lý nước tiểu hoặc phân"}, {"term_ko": "이동", "term_vi": "Di chuyển", "def_ko": "움직이는 것", "def_vi": "Hành động di chuyển"}, {"term_ko": "위생", "term_vi": "Vệ sinh", "def_ko": "청결 상태", "def_vi": "Tình trạng sạch sẽ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1400, '10', '노인장기요양보험 급여로 대여할 수 있는 복지용구는?', '["이동변기", "목욕의자", "안전손잡이", "성인용보행기", "욕창예방 매트리스"]'::jsonb, 5, NULL, NULL, '{"1": "이동변기는 대여 가능합니다.", "2": "목욕의자도 대여 가능합니다.", "3": "안전손잡이 역시 대여 가능합니다.\n[정답]", "5": "욕창예방 매트리스는 대여할 수 있는 복지용구가 아닙니다.", "4": "성인용보행기도 대여 가능합니다."}'::jsonb, '[{"term_ko": "급여", "term_vi": "Chế độ trợ cấp", "def_ko": "급스러운 이익(보장)", "def_vi": "Lợi ích khẩn cấp"}, {"term_ko": "복지용구", "term_vi": "Thiết bị hỗ trợ", "def_ko": "도움이 되는 기구", "def_vi": "Thiết bị giúp đỡ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1399, '10', '다음 주 노인장기요양보험 급여로 대여할 수 있는 복지용구는?', '["지팡이", "간이변기", "안전손잡이", "수동 휠체어", "욕창예방 방석"]'::jsonb, 4, NULL, NULL, '{"1": "지팡이는 보조기구로 사용할 수 있지만, 대여 항목에 포함되지 않습니다.\n[정답]", "4": "수동 휠체어는 노인장기요양보험에서 대여할 수 있는 복지용구입니다.", "2": "간이변기는 특정 조건 하에 사용 가능하지만, 기본적으로 대여항목에 포함되지 않습니다.", "3": "안전손잡이는 보조기구에 해당하지만, 대여 목록에 없습니다.", "5": "욕창예방 방석은 치료적 기능이 있지만, 대여 대상에 포함되지 않습니다."}'::jsonb, '[{"term_ko": "노인장기요양보험", "term_vi": "Bảo hiểm chăm sóc dài hạn cho người cao tuổi", "def_ko": "노인 및 장애인을 위한 장기 요양 및 돌봄 보험", "def_vi": "Bảo hiểm dành cho người cao tuổi và người khuyết tật"}, {"term_ko": "복지용구", "term_vi": "Thiết bị hỗ trợ", "def_ko": "요양 보조 기기", "def_vi": "Thiết bị hỗ trợ trong chăm sóc"}, {"term_ko": "지팡이", "term_vi": "Gậy", "def_ko": "보행을 돕는 도구", "def_vi": "Dụng cụ hỗ trợ đi lại"}, {"term_ko": "간이변기", "term_vi": "Bồn vệ sinh kiểu đơn giản", "def_ko": "이동이나 사용이 용이한 화장실", "def_vi": "Nhà vệ sinh dễ di chuyển"}, {"term_ko": "안전손잡이", "term_vi": "Tay vịn an toàn", "def_ko": "미끄러지지 않도록 돕는 도구", "def_vi": "Dụng cụ giúp không bị trượt"}, {"term_ko": "수동 휠체어", "term_vi": "Xe lăn tay", "def_ko": "사람이 직접 밀어 이동하는 휠체어", "def_vi": "Xe lăn mà người dùng tự đẩy"}, {"term_ko": "욕창예방 방석", "term_vi": "Đệm phòng ngừa loét", "def_ko": "욕창을 예방하는 기구", "def_vi": "Dụng cụ phòng ngừa loét"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1398, '10', '노인장기요양보험 급여로 대여할 수 있는 복지용구는?', '["목욕의자", "배회감지기", "지팡이", "이동변기", "성인용 비행기"]'::jsonb, 2, NULL, NULL, NULL, '[{"term_ko": "복지용구", "term_vi": "Thiết bị phúc lợi", "def_ko": "도움이 되는 장비", "def_vi": "Thiết bị hỗ trợ"}, {"term_ko": "노인장기요양보험", "term_vi": "Bảo hiểm chăm sóc dài hạn cho người cao tuổi", "def_ko": "노인을 위한 의료보장제도", "def_vi": "Hệ thống bảo hiểm y tế cho người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1397, '10', '다음 중 노인장기요양보험 급여로 구입 가능한 복지용구는?', '["전동침대", "수동침대", "요실금팬티", "이동욕조", "배회감지기"]'::jsonb, 3, NULL, NULL, '{"1": "전동침대는 노인장기요양보험 급여로 구입할 수 있는 항목입니다.\n[정답]", "3": "요실금팬티는 개인의 위생을 위한 용구로 급여에 해당하지 않습니다.", "2": "수동침대 또한 노인장기요양보험 급여로 구입 가능합니다.", "4": "이동욕조는 노인의 목욕을 돕기 위한 용구로 급여에 포함됩니다.", "5": "배회감지기는 안전을 위한 장비지만, 급여 항목에는 포함되지 않습니다."}'::jsonb, '[{"term_ko": "노인장기요양보험", "term_vi": "복지용구", "def_ko": "장기 chăm sóc cho người cao tuổi", "def_vi": "thiết bị hỗ trợ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1396, '10', '노인장기요양 보험 급여로 구입할 수 있는 복지용구는?', '["수동 휠체어", "목욕리프트", "백회감지기", "이동욕조", "안전손잡이"]'::jsonb, 5, NULL, NULL, '{"1": "수동 휠체어는 노인에게 필요한 복지용구 중 하나입니다.\n[정답]", "2": "목욕리프트는 노인이 목욕 중 안전하게 이동할 수 있도록 도와주는 장비입니다.", "3": "백회감지기는 안전과 관련이 있지만, 급여로 구입할 수 있는 복지용구는 아닙니다.", "4": "이동욕조는 노인이 편리하게 목욕할 수 있도록 도와주는 장비입니다.", "5": "안전손잡이는 노인들이 안전하게 이동하는 데 도움을 주지만, 급여로 구입할 수 없습니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "노인(한국어)", "def_vi": "Người lớn tuổi"}, {"term_ko": "장기요양", "term_vi": "Chăm sóc dài hạn", "def_ko": "장기요양(한국어)", "def_vi": "Dịch vụ chăm sóc lâu dài"}, {"term_ko": "보험", "term_vi": "Bảo hiểm", "def_ko": "보험(한국어)", "def_vi": "Bảo hiểm"}, {"term_ko": "급여", "term_vi": "Trợ cấp", "def_ko": "급여(한국어)", "def_vi": "Trợ cấp"}, {"term_ko": "복지용구", "term_vi": "Thiết bị phúc lợi", "def_ko": "복지용구(한국어)", "def_vi": "Thiết bị phúc lợi"}, {"term_ko": "수동 휠체어", "term_vi": "Xe lăn cầm tay", "def_ko": "수동휠체어(한국어)", "def_vi": "Xe lăn cầm tay"}, {"term_ko": "목욕리프트", "term_vi": "Thang tắm", "def_ko": "목욕리프트(한국어)", "def_vi": "Thang tắm"}, {"term_ko": "안전손잡이", "term_vi": "Tay cầm an toàn", "def_ko": "안전손잡이(한국어)", "def_vi": "Tay cầm an toàn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1395, '10', '오른쪽 다리가 불편한 대상자의 보행기 사용 방법은?', '["보행기와 오른쪽 다리가 함께 - 왼쪽 다리", "보행기와 왼쪽 다리가 함께 - 오른쪽 다리", "보행기 - 오른쪽 다리 - 왼쪽 다리", "보행기 - 왼쪽 다리 - 오른쪽 다리", "오른쪽 다리 - 왼쪽 다리 - 보행기"]'::jsonb, 1, NULL, NULL, '{"1": "보행기와 오른쪽 다리가 함께 이동하는 것이 적절하며, 왼쪽 다리가 그 뒤를 따릅니다.\n[정답]", "2": "보행기와 왼쪽 다리가 함께 이동하는 것은 하지 않아야 합니다.", "3": "보행기와 오른쪽 다리가 함께 이동하는 순서가 아닙니다.", "4": "보행기와 왼쪽 다리가 동시에 이동하는 것은 올바른 방법이 아닙니다.", "5": "오른쪽 다리를 먼저 내리고 나서 보행기를 사용하는 것은 적절하지 않습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자, 병원에 있는 사람", "def_vi": "Bệnh nhân, người được chăm sóc"}, {"term_ko": "보행기", "term_vi": "Khung hỗ trợ đi bộ", "def_ko": "보행 보조기구", "def_vi": "Thiết bị hỗ trợ đi bộ"}, {"term_ko": "불편한", "term_vi": "Không thoải mái", "def_ko": "어려움이 있는", "def_vi": "Gặp khó khăn"}, {"term_ko": "방법", "term_vi": "Phương pháp", "def_ko": "수단, 절차", "def_vi": "Cách thức, quy trình"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1394, '10', '양족 다리가 약한 대상자의 보행기 사용 방법으로 옳은 것은?', '["오른발 - 왼발 - 보행기", "왼발 - 오른발 - 보행기", "보행기 - 오른발 - 왼발", "보행기 - 양쪽 발을 동시에", "양쪽 발을 동시에 - 보행기"]'::jsonb, 3, NULL, NULL, '{"1": "오른발 - 왼발 - 보행기: 다리를 교차하여 보행기를 사용하는 방법은 부적절합니다.", "2": "왼발 - 오른발 - 보행기: 잘못된 순서로 보행기를 사용할 때, 균형을 잃을 수 있습니다.\n[정답]", "3": "보행기 - 오른발 - 왼발: 보행기를 먼저 이동한 후, 오른발과 왼발을 순서대로 이동하는 방법이 안전합니다.", "4": "보행기 - 양쪽 발을 동시에: 두 발을 동시에 이동하는 것은 균형을 잃을 위험이 큽니다.", "5": "양쪽 발을 동시에 - 보행기: 잘못된 순서로, 보행기를 사용한 후에는 균형을 잃을 수 있습니다."}'::jsonb, '[{"term_ko": "보행기", "term_vi": "Xe đi lại", "def_ko": "이동 보조 기구", "def_vi": "Thiết bị hỗ trợ di chuyển"}, {"term_ko": "약한", "term_vi": "Yếu", "def_ko": "힘이 부족한", "def_vi": "Thiếu sức"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "도움을 필요로 하는 사람", "def_vi": "Người cần hỗ trợ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1393, '10', '오른쪽 다리가 불편한 대상자가 계단을 내려갈 때 순서로 옳은 것은?', '["왼쪽 다리 - 지팡이 - 오른쪽 다리", "왼쪽 다리 - 오른쪽 다리 - 지팡이", "오른쪽 다리 - 지팡이 - 왼쪽 다리", "지팡이 - 왼쪽 다리 - 오른쪽 다리", "지팡이 - 오른쪽 다리 - 왼쪽 다리"]'::jsonb, 5, NULL, NULL, '{"1": "왼쪽 다리로 먼저 내려가는 것은 불편한 오른쪽 다리에 부담을 줄 수 있습니다.\n[정답]", "5": "지팡이를 먼저 사용하여 균형을 잡고, 오른쪽 다리를 먼저 내린 후 왼쪽 다리로 따라 내려가는 것이 안전합니다.", "2": "오른쪽 다리로 내려가는 것은 더욱 불안정하게 만들 수 있습니다.", "3": "오른쪽 다리로 시작하면 안전하지 않습니다.", "4": "지팡이 사용이 먼저 이루어져야 하므로, 순서가 바르지 않습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người tham gia", "def_ko": "환자, 피험자", "def_vi": "Bệnh nhân, đối tượng thử nghiệm"}, {"term_ko": "다리", "term_vi": "Chân", "def_ko": "우리 몸의 일부로, 걷고 움직이는 데 사용", "def_vi": "Một phần của cơ thể, được sử dụng để đi và di chuyển"}, {"term_ko": "계단", "term_vi": "Cầu thang", "def_ko": "여러 단으로 구성된 이동수단", "def_vi": "Phương tiện di chuyển được tạo thành từ nhiều bậc"}, {"term_ko": "지팡이", "term_vi": "Gậy", "def_ko": "균형을 잡기 위해 사용하는 도구", "def_vi": "Dụng cụ được sử dụng để giữ thăng bằng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1392, '10', '오른쪽 편마비 대상자가 평지를 이동할 때 지팡이 사용 순서로 옳은 것은?', '["지팡이 - 왼쪽 다리 - 오른쪽 다리", "지팡이 - 오른쪽 다리 -왼쪽 다리", "왼쪽 다리 - 지팡이 - 오른쪽 다리", "왼쪽 다리 - 오른쪽 다리 - 지팡이", "오른쪽 다리 - 지팡이 - 왼쪽 다리"]'::jsonb, 2, NULL, NULL, '{"1": "지팡이 사용 시, 균형을 유지하기 어려우므로 다른 다리부터 시작하는 것은 위험합니다.\n[정답]", "2": "오른쪽 다리와 지팡이를 함께 사용하여 이동하는 방식이로, 편마비 대상자에게 적합합니다.", "3": "왼쪽 다리 먼저 움직일 경우, 지팡이의 지지점을 잃게 되어 이동이 힘들 수 있습니다.", "4": "오른쪽 다리와 지팡이를 동시에 사용하지 않아 비효율적입니다.", "5": "오른쪽 다리부터 시작하는 것은 편마비 대상자에게 안전하지 않습니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽으로 몸이 마비된 상태", "def_vi": "Trạng thái liệt một bên cơ thể"}, {"term_ko": "지팡이", "term_vi": "Gậy chống", "def_ko": "보행 시 사용하는 보조기구", "def_vi": "Thiết bị hỗ trợ khi đi bộ"}, {"term_ko": "평지", "term_vi": "Mặt đất bằng phẳng", "def_ko": "고르지 않은 땅이나 바닥이 아닌 평탄한 땅", "def_vi": "Đất không có gồ ghề, bằng phẳng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1391, '10', '왼쪽 편마비 대상자가 지팡이를 이용하여 버스를 탈 때 순서로 옳은 것은?', '["지팡이 - 오른발 - 왼발", "지팡이 - 왼발 - 오른발", "왼발 - 지팡이 - 오른발", "오른발 - 지팡이 - 왼발", "왼발 - 오른발 - 지팡이"]'::jsonb, 1, NULL, NULL, '{"1": "지팡이를 사용하여 안정성을 확보한 후 오른발로 먼저 올라가고, 이어서 왼발을 올리는 순서가 가장 안전합니다.\n[정답]", "2": "왼발로 먼저 올라가는 방법은 편마비 대상자에게 위험할 수 있습니다.", "3": "왼발을 먼저 들고 지팡이를 뒤로 두는 것은 균형을 잃을 위험이 있습니다.", "4": "오른발을 먼저 올리는 것은 편마비 대상자에게 적절하지 않습니다.", "5": "지팡이를 마지막에 사용하는 것은 안정성을 떨어트릴 수 있습니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Bệnh liệt nửa người", "def_ko": "한쪽 신체가 마비된 상태", "def_vi": "Tình trạng bị liệt một bên cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1390, '10', '왼쪽 편마비 대상자가 지팡이 없이 계단을 올라갈 때 순서로 옳은 것은?', '["오른쪽 다리 - 왼쪽 다리 - 계단 손잡이", "오른쪽 다리 - 계단 손잡이 - 왼쪽 다리", "왼쪽 다리 - 오른쪽 다리 - 계단 손잡이", "계단 손잡이 - 오른쪽 다리 - 왼쪽 다리", "계단 손잡이 - 왼쪽 다리 - 오른쪽 다리"]'::jsonb, 4, NULL, NULL, '{"1": "오른쪽 다리를 먼저 내딛는 것은 안전하지 않으며, 왼쪽 편마비를 가진 환자에게 적절하지 않습니다.", "2": "오른쪽 다리를 밟은 후 계단 손잡이를 사용하는 것은 불안정할 수 있습니다.\n[정답]", "3": "왼쪽 다리가 올라가기는 하지만 순서가 잘못되어 있습니다.", "4": "계단 손잡이를 먼저 잡고 오른쪽 다리를 올리는 것은 안전하게 계단을 오르는 방법입니다.", "5": "계단 손잡이를 잡고 왼쪽 다리를 올리는 것은 편마비 환자에게 안전하지 않습니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 신체의 기능이 소실된 상태(한국어)", "def_vi": "Tình trạng mất chức năng ở một bên cơ thể"}, {"term_ko": "계단", "term_vi": "Cầu thang", "def_ko": "사람이나 물체가 올라가거나 내려가는데 사용되는 구조물(한국어)", "def_vi": "Cấu trúc được sử dụng để lên hoặc xuống cho người hoặc vật"}, {"term_ko": "손잡이", "term_vi": "Tay nắm", "def_ko": "물건을 잡고 지탱하는 데 사용되는 물체(한국어)", "def_vi": "Đồ vật được sử dụng để cầm nắm và hỗ trợ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1389, '10', '왼쪽 편마비 대상자가 지팡이를 사용하여 보행할 때 돕는 방법은?', '["왼손으로 지팡이를 잡게 한다.", "지팡이를 앞에 놓고 왼쪽 발부터 이동한다.", "대상자로부터 비스듬히 20cm 뒤에서 속도를 맞춰 걷는다.", "왼쪽 발의 앞 15cm, 옆 15cm 지점에 지팡이 끝을 놓는다.", "지팡이 쪽에 건강한 발을 놓고 불편한 발을 축으로 방향을 바꾼다."]'::jsonb, 2, NULL, NULL, '{"1": "왼손으로 지팡이를 잡게 한다: 왼쪽 편마비가 있는 환자가 오른손으로 지팡이를 잡는 것이 일반적입니다.\n[정답]", "2": "지팡이를 앞에 놓고 왼쪽 발부터 이동한다: 이는 올바른 지팡이 사용법으로, 편마비 쪽에 지팡이를 먼저 놓고 건강한 발을 후속으로 이동하여 균형을 유지하는 방식입니다.", "3": "대상자로부터 비스듬히 20cm 뒤에서 속도를 맞춰 걷는다: 지팡이를 사용하는 대상자와의 적절한 거리 유지가 중요하지만, 속도를 맞추는 것이 우선이 아닙니다.", "4": "왼쪽 발의 앞 15cm, 옆 15cm 지점에 지팡이 끝을 놓는다: 지팡이를 놓는 위치가 부적절합니다.", "5": "지팡이 쪽에 건강한 발을 놓고 불편한 발을 축으로 방향을 바꾼다: 이 방법은 뒤틀림을 유발할 수 있으므로 바람직하지 않습니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "반신 불구(한국어)", "def_vi": "Tình trạng mất khả năng vận động của một bên cơ thể."}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1388, '10', '자동차에 앉아있는 편마비 대상자를 휠체어로 옮기는 순서는?', '["가 - 나 - 다 - 라 - 마", "가 - 나 - 라 - 다 - 마", "나 - 가 - 라 - 다 - 마", "나 - 가 - 다 - 라 - 마", "나 - 라 - 다 - 가 - 마"]'::jsonb, 3, NULL, NULL, '{"1": "안전벨트를 풀어주는 것이 첫 단계입니다. 이는 대상자를 휠체어로 옮기는 데 필요합니다.\n[정답]", "3": "휠체어를 자동차에 평행하게 놓고 잠금장치를 잠근 후 발 받침대를 접는 것이 중요합니다. 이는 안정성을 확보하는 단계입니다.", "2": "대상자의 두 발이 바닥을 충분히 지지하게 하는 것은 무게 중심을 유지하기 위한 단계입니다.", "4": "대상자 다리를 한쪽씩 자동차 밖으로 내리는 것은 옮기는 과정에서 필수적인 단계입니다.", "5": "마지막으로 마비된 쪽 무릎을 지지하면서 몸을 돌려 휠체어에 앉히는 것이 완료 단계입니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Người bị liệt nửa người", "def_ko": "한쪽 팔다리가 마비됨(편 liệt)", "def_vi": "Bị tê liệt chỉ một bên của cơ thể"}, {"term_ko": "안전벨트", "term_vi": "Dây an toàn", "def_ko": "자동차 안전장치", "def_vi": "Thiết bị an toàn của xe ô tô"}, {"term_ko": "휠체어", "term_vi": "Xe lăn", "def_ko": "이동 보조용 기구", "def_vi": "Thiết bị hỗ trợ di chuyển"}, {"term_ko": "잠금장치", "term_vi": "Thiết bị gắn chặt", "def_ko": "고정 장치", "def_vi": "Thiết bị giữ cố định"}, {"term_ko": "발 받침대", "term_vi": "Bệ chân", "def_ko": "다리 받치기", "def_vi": "Đế giữ chân"}, {"term_ko": "무릎", "term_vi": "Đầu gối", "def_ko": "사람의 다리 관절", "def_vi": "Khớp của chân người"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1387, '10', '편마비 대상자를 휠체어에서 자동차로 옮길 때 앉히는 순서로 옳은 것은?', '["엉덩이 - 양쪽 다리 동시에", "엉덩이 - 건강한 다리 - 마비된 다리", "마비된 다리 - 엉덩이 - 건강한 다리", "건강한 다리 - 엉덩이 - 마비된 다리", "마비된 다리 - 건강한 다리 - 엉덩이"]'::jsonb, 2, NULL, NULL, '{"1": "엉덩이를 가장 먼저 옮기는 것은 바람직하지 않음.\n[정답]", "2": "엉덩이 - 건강한 다리 - 마비된 다리 순으로 옮기는 것이 안전함.", "3": "마비된 다리를 기준으로 하는 것은 오류임.", "4": "건강한 다리를 먼저 올리는 것은 마비된 쪽에 부담을 줄 수 있음.", "5": "마비된 다리를 먼저 이동하는 것은 위험함."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 몸의 팔이나 다리가 마비되는 것", "def_vi": "Tình trạng mất khả năng vận động một bên cơ thể"}, {"term_ko": "엉덩이", "term_vi": "Mông", "def_ko": "몸의 아래쪽 부분", "def_vi": "Phần dưới cơ thể"}, {"term_ko": "다리", "term_vi": "Chân", "def_ko": "사람의 하체", "def_vi": "Phần cơ thể ở dưới"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1386, '10', '대상자를 휠체어에서 자동차로 이동할 때 돕는 방법은?', '["휠체어를 자동차와 수직으로 놓는다.", "무릎으로 대상자의 마비측 무릎을 지지하고 일으킨다.", "엉덩이를 마지막에 자동차 시트에 앉힌다.", "대상자의 건강한 손으로 자동차 시트를 짚게 한다.", "대상자와 동승하는 경우 대상자의 앞자리에 앉는다."]'::jsonb, 2, NULL, NULL, '{"1": "휠체어를 자동차와 수직으로 놓으면 이동이 원활하지 않다.\n[정답]", "2": "무릎으로 대상자의 마비측 무릎을 지지하고 일으키는 것은 올바른 방법이다.", "3": "엉덩이를 마지막에 자동차 시트에 앉히는 것은 순서가 아니라 방법에 대한 설명이 부족하다.", "4": "대상자의 건강한 손으로 자동차 시트를 짚게 하는 것은 도움을 줄 수 있지만 이동 방식에는 부적절하다.", "5": "대상자와 동승하는 경우 앞자리에 앉는 것은 유용할 수 있지만 이동 방법에 대한 설명이 아니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1385, '10', '대상자를 휠체어에서 이동변기로 옮기는 순서로 옳은 것은?', '["가 - 라 - 나 - 다", "가 - 다 - 라 - 나", "가 - 라 - 다 - 나", "다 - 가 - 라 - 나", "다 - 라 - 나 - 가"]'::jsonb, 2, NULL, NULL, '{"1": "이동 방법을 설명하고 휠체어의 잠금장치를 잠그는 것은 필수적인 첫 단계입니다.\n[정답]", "2": "건강한 다리에 힘을 주게 하여 엉덩이를 이동시켜 앉히는 단계입니다.", "3": "발받침대를 접고 대상자의 두 발을 바닥에 내려놓게 하는 과정이 필요합니다.", "4": "건강한 손으로 이동변기의 먼 쪽 손잡이를 잡게 하는 것이 중요합니다.", "5": "제대로 된 순서를 따라야 목적지로 안전하게 이동할 수 있습니다."}'::jsonb, '[{"term_ko": "이동변기", "term_vi": "휠체어", "def_ko": "이사 vệ sinh di động", "def_vi": "xe lăn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1384, '10', '대상자의 안전을 위해 휠체어를 뒤로 이동해야 하는 경우는?', '["언덕을 오를 때, 언덕을 내려갈 때", "언덕을 오를 때, 문턱을 내려갈 때", "문턱을 내려갈 때, 언덕을 내려갈 때", "문턱을 내려갈 때, 문턱을 오를 때", "문턱을 오를 때, 언덕을 내려갈 때"]'::jsonb, 3, NULL, NULL, '{"1": "언덕을 오를 때, 언덕을 내려갈 때는 휠체어가 불안정해질 수 있어 위험합니다.\n[정답]", "3": "문턱을 내려갈 때, 언덕을 내려갈 때는 휠체어를 뒤로 이동해야 안전합니다.", "2": "언덕을 오를 때, 문턱을 내려갈 때는 휠체어의 균형이 깨질 수 있습니다.", "4": "문턱을 내려갈 때, 문턱을 오를 때는 휠체어의 안정성을 해칠 수 있습니다.", "5": "문턱을 오를 때, 언덕을 내려갈 때는 휠체어를 뒤로 이동할 필요가 없습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người tham gia", "def_ko": "환자 또는 고객", "def_vi": "Bệnh nhân hoặc khách hàng"}, {"term_ko": "휠체어", "term_vi": "Xe lăn", "def_ko": "장애인을 위한 이동 수단", "def_vi": "Phương tiện di chuyển cho người khuyết tật"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "위험 요소가 없는 상태", "def_vi": "Tình trạng không có yếu tố nguy hiểm"}, {"term_ko": "언덕", "term_vi": "Đồi", "def_ko": "경사가 있는 땅", "def_vi": "Mặt đất có độ dốc"}, {"term_ko": "문턱", "term_vi": "Ngưỡng cửa", "def_ko": "출입문이나 방의 바닥과 바닥 사이의 경계", "def_vi": "Ranh giới giữa sàn của cửa ra vào hoặc giữa hai phòng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1383, '10', '스스로 자세를 움직일 수 없는 대상자가 휠체어에 앉아있을 때 올바른 자세는?', '["몸통이 한쪽으로 기울어져 있다.", "발 받침대에 발이 올라가 있다.", "잠금장치가 풀어진 상태에서 쉬고 있다.", "휠체어 끝에 앉아서 얼굴은 바닥을 향해 있다.", "욕창예방 방석 없이 3시간 이상 휠체어에 앉아있다."]'::jsonb, 2, NULL, NULL, '{"1": "몸통이 한쪽으로 기울어져 있다: 올바른 자세가 아닙니다.\n[정답]", "2": "발 받침대에 발이 올라가 있다: 올바른 자세입니다.", "3": "잠금장치가 풀어진 상태에서 쉬고 있다: 올바른 자세가 아닙니다.", "4": "휠체어 끝에 앉아서 얼굴은 바닥을 향해 있다: 올바른 자세가 아닙니다.", "5": "욕창예방 방석 없이 3시간 이상 휠체어에 앉아있다: 올바른 자세가 아닙니다."}'::jsonb, '[{"term_ko": "자세", "term_vi": "Tư thế", "def_ko": "자세(한국어)", "def_vi": "tư thế (베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1382, '10', '휠체어를 펴는 순서로 옳은 것은?', '["잠금 장치 - 팔걸이 펼침 - 시트 누름 - 발 받침대 내림", "잠금 장치 - 발 받침대 내림 - 시트 누름 - 팔걸이 펼침", "잠금 장치 - 시트 누름 - 팔걸이 펼침 - 발 받침대 내림", "팔걸이 펼침 - 시트 누름 - 발 받침대 내림 - 잠금 장치", "발 받침대 내림 - 잠금 장치 - 시트 누름 - 팔걸이 펼침"]'::jsonb, 1, NULL, NULL, '{"1": "잠금 장치 - 팔걸이 펼침 - 시트 누름 - 발 받침대 내림\n[정답]", "2": "잠금 장치 - 발 받침대 내림 - 시트 누름 - 팔걸이 펼침", "3": "잠금 장치 - 시트 누름 - 팔걸이 펼침 - 발 받침대 내림", "4": "팔걸이 펼침 - 시트 누름 - 발 받침대 내림 - 잠금 장치", "5": "발 받침대 내림 - 잠금 장치 - 시트 누름 - 팔걸이 펼침"}'::jsonb, '[{"term_ko": "휠체어", "term_vi": "Xe lăn", "def_ko": "휠체어(한국어)", "def_vi": "Xe lăn (베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1381, '10', '오른쪽으로 누워있는 왼쪽 편마비 대상자의 욕창발생 부위는?', '["천골", "목뒤", "오른쪽 귀", "복장 뼈", "발등"]'::jsonb, 3, NULL, NULL, '{"1": "천골: 보통 인체의 압력이 많이 가해지는 부위로, 옆으로 누워 있을 경우에는 발생 가능성이 있다. 그러나 왼쪽 편마비 대상자의 경우 더 중요하지 않은 부위이다.\n[정답]", "3": "오른쪽 귀: 왼쪽 편마비 대상자가 오른쪽으로 누워있을 때 압력이 가해져 욕창 발생 가능성이 높은 부위이다.", "2": "목뒤: 일반적으로 압력이 덜 가해지는 부위로, 욕창 발생 가능성이 낮다.", "4": "복장 뼈: 뼈 부분이 아니라 일반적으로 욕창 발생 부위가 아닌 곳이다.", "5": "발등: 발가락이나 발바닥보다 더 압력이 덜 가해지는 부분으로, 욕창 발생 가능성이 낮다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Loét", "def_ko": "피부의 손상(한국어)", "def_vi": "Vết thương trên da"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1380, '10', '대상자의 아래 증상을 완화시킬 수 있는 자세로 옳은 것은?', '["엎드린 자세", "서있는 자세", "앉은 자세", "바로 누운 자세", "옆으로 누운 자세"]'::jsonb, 1, NULL, NULL, '{"1": "엎드린 자세는 등과 어깨의 부담을 줄일 수 있어 통증 완화에 도움을 줄 수 있다.\n[정답]", "2": "서있는 자세는 하중이 균일하지 않아 통증이 악화될 수 있다.", "3": "앉은 자세는 장시간 유지 시 통증을 유발할 수 있다.", "4": "바로 누운 자세는 허리에 압박을 줄 수 있어 통증을 유발할 수 있다.", "5": "옆으로 누운 자세는 압력을 특정 부위에 가해 욕창을 초래할 수 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1378, '10', '장기간 침상생활을 하는 대상자의 관절강직과 변형을 예방하는 방법은?', '["탄력스타킹 착용", "체위변경", "방수포 사용", "공기침대 사용", "뜨거운 물주머니 찜질"]'::jsonb, 2, NULL, NULL, '{"1": "탄력스타킹 착용은 하지정맥 혈전증 예방에 도움이 되지만 관절강직 예방에는 효과적이지 않다.\n[정답]", "2": "체위변경은 장시간 같은 자세로 있는 것을 방지하여 관절의 강직과 변형을 예방하는 중요한 방법이다.", "3": "방수포 사용은 기저귀나 침대의 오염을 예방하는 데 좋지만 관절강직 예방과는 직접적인 관련이 없다.", "4": "공기침대 사용은 욕창 예방에 도움이 되나, 관절 강직 예방에는 효과가 적다.", "5": "뜨거운 물주머니 찜질은 일시적으로 통증 완화에 도움을 줄 수 있지만 관절강직 예방에 대한 효과는 미미하다."}'::jsonb, '[{"term_ko": "장기간", "term_vi": "Thời gian dài", "def_ko": "오랜 시간 동안", "def_vi": "Trong thời gian dài"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1377, '10', '체위변경의 목적으로 옳은 것은?', '["페 확장이 감소된다.", "관절의 움직임이 제한된다.", "부종과 혈전을 예방한다.", "욕창이 심해진다.", "고정된 자세를 만들어 준다."]'::jsonb, 3, NULL, NULL, '{"1": "체위변경은 폐의 확장을 돕는 데 기여하므로 확장이 감소된다라는 설명은 틀립니다.\n[정답]", "3": "체위변경은 부종과 혈전을 예방하는 데 효과적입니다.", "2": "체위변경은 관절의 움직임을 촉진시켜 제한이 되지 않도록 도와줍니다.", "4": "체위변경은 욕창을 예방하는 데 도움을 주기 때문에 심해진다는 것은 잘못된 설명입니다.", "5": "고정된 자세보다 다양한 체위를 유지하는 것이 체위변경의 목적이므로 이는 틀린 설명입니다."}'::jsonb, '[{"term_ko": "체위변경", "term_vi": "Thay đổi tư thế", "def_ko": "환자의 자세를 바꾸는 것", "def_vi": "Thay đổi vị trí của bệnh nhân"}, {"term_ko": "부종", "term_vi": "Phù nề", "def_ko": "몸의 일부에 액체가 고인 상태", "def_vi": "Tình trạng tích tụ dịch tại một phần cơ thể"}, {"term_ko": "혈전", "term_vi": "Huyết khối", "def_ko": "혈액이 고여 생긴 덩어리", "def_vi": "Khối máu đông hình thành trong mạch máu"}, {"term_ko": "욕창", "term_vi": "Loét", "def_ko": "계속 압력이 가해져 피부가 손상된 상태", "def_vi": "Tình trạng da bị tổn thương do áp lực liên tục"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1376, '10', '편마비 대상자를 옆에서 보조하면서 일으켜 세울 때 순서로 옳은 것은?가. 대퇴부를 지지하던 손을 가슴 부위로 옮겨 상체를 펴게 한다. 나. 요양보호사의 발을 대상자의 마비된 발 바로 뒤에 놓는다. 다. 마비된 대퇴부와 반대쪽 허리를 부축하여 일으켜 세운다. 라. 대상자를 침대 끝에 앉혀 양 발을 무릎보다 뒤쪽에 놓는다.', '["라-나-다-가", "나-라-가-다", "가-나-라-다", "가-라-나-다", "가-다-나-라"]'::jsonb, 1, NULL, NULL, '{"1": "위의 설명과 일치하므로 옳은 순서입니다.", "2": "나-라-가-다: 순서가 잘못되었습니다.", "3": "가-나-라-다: 순서가 잘못되었습니다.", "4": "가-라-나-다: 순서가 잘못되었습니다.", "5": "가-다-나-라: 순서가 잘못되었습니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Bệnh liệt nửa người", "def_ko": "신체의 한쪽이 마비된 상태", "def_vi": "Tình trạng liệt bên một cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1375, '10', '편마비 대상자의 상체를 일으킬 때 돕는 방법으로 옳은 것은?', '["한꺼번에 신속히 일으킨다.", "대상자의 마비된 쪽에 선다.", "양손을 가슴위에 올려놓는다.", "대상자의 양쪽 무릎을 곧게 편다.", "팔을 대상자의 목 밑에 깊숙하게 넣어 등과 어깨를 지지한다."]'::jsonb, 5, NULL, NULL, '{"1": "한꺼번에 신속히 일으키는 것은 위험할 수 있다.\n[정답]", "5": "팔을 대상자의 목 밑에 깊숙하게 넣어 등과 어깨를 지지하는 것은 올바른 방법이다.", "2": "대상자의 마비된 쪽에 서는 것은 바람직하지 않다.", "3": "양손을 가슴 위에 올려놓는 것은 지지력을 줄 수 없다.", "4": "대상자의 양쪽 무릎을 곧게 펴는 것은 필요하지 않다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 팔이나 다리의 운동이 제한된 상태(한국어)", "def_vi": "Trạng thái hạn chế vận động của một bên tay hoặc chân (베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1373, '10', '편마비 대상자를 옆으로 돌려 눕히려고 할 때 지지해야 할 부분은?', '["어깨와 엉덩이", "목과 어깨", "양쪽 팔", "허리와 엉덩이", "한쪽 팔과 다리"]'::jsonb, 2, NULL, NULL, '{"1": "어깨와 엉덩이는 지지해야 할 부분이 아닙니다.\n[정답]", "2": "목과 어깨는 편마비 대상자를 지지하는 올바른 부분입니다.", "3": "양쪽 팔은 편마비 대상자의 지지를 위해 적절하지 않습니다.", "4": "허리와 엉덩이 역시 올바른 지지 부분이 아닙니다.", "5": "한쪽 팔과 다리는 지지해야 할 주요 부위가 아닙니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 몸이 마비된 상태", "def_vi": "Tình trạng bị liệt một bên cơ thể"}, {"term_ko": "지지하다", "term_vi": "Hỗ trợ", "def_ko": "지탱하거나 받쳐주다", "def_vi": "Đỡ hoặc nâng đỡ"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자", "def_vi": "Bệnh nhân"}, {"term_ko": "눕히다", "term_vi": "Đặt nằm", "def_ko": "눕게 하다", "def_vi": "Để nằm xuống"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1372, '10', '침대에 누워있는 왼쪽 편마비 대상자를 건강한 쪽으로 돌려 눕히는 순서로 옳은 것은?가. 엉덩이와 아래쪽 어깨를 움직여 편안하게 해준다. 나. 무릎을 세우고 양손을 가슴 위에 포개 놓는다. 다. 엉덩이와 어깨를 지지하여 돌려 눕힌다. 라. 대상자의 오른쪽에 선다.', '["가-다-라-나", "나-라-가-다", "다-가-나-라", "라-가-나-다", "라-나-다-가"]'::jsonb, 1, NULL, NULL, '{"1": "엉덩이와 아래쪽 어깨를 움직여 편안하게 해준다.\n[정답] (다) 엉덩이와 어깨를 지지하여 돌려 눕힌다.\n(나) 무릎을 세우고 양손을 가슴 위에 포개 놓는다.\n(라) 대상자의 오른쪽에 선다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa", "def_ko": "한쪽 몸의 마비 상태", "def_vi": "Trạng thái liệt ở một bên cơ thể"}, {"term_ko": "자세", "term_vi": "Tư thế", "def_ko": "특정한 위치 또는 방향", "def_vi": "Vị trí hoặc hướng cụ thể"}, {"term_ko": "대상자", "term_vi": "Người nhận chăm sóc", "def_ko": "돌봄 받는 사람", "def_vi": "Người được chăm sóc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1371, '10', '대상자를 옆으로 돌려 눕히는 방법으로 옳은 것은?', '["요양보호사는 돌려 눕히려는 반대쪽에 선다.", "엉덩이 - 어깨 - 얼굴의 순으로 돌려 눕힌다.", "눕히려는 반대쪽의 손을 위로 올린다.", "눕는 방향과 반대쪽 발을 다른 발 위에 올려놓는다.", "엉덩이를 앞으로 이동시켜 자세를 편안하게 한다."]'::jsonb, 5, NULL, NULL, '{"1": "요양보호사는 돌려 눕히려는 반대쪽에 선다.\n[정답]", "2": "엉덩이 - 어깨 - 얼굴의 순으로 돌려 눕힌다.", "3": "눕히려는 반대쪽의 손을 위로 올린다.", "4": "눕는 방향과 반대쪽 발을 다른 발 위에 올려놓는다.", "5": "엉덩이를 앞으로 이동시켜 자세를 편안하게 한다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자 또는 돌봄을 받는 사람", "def_vi": "Người nhận sự chăm sóc"}, {"term_ko": "눕히다", "term_vi": "Nằm", "def_ko": "눕게 하다(옮기다)", "def_vi": "Đặt nằm"}, {"term_ko": "엉덩이", "term_vi": "Mông", "def_ko": "엉덩이 부위", "def_vi": "Phần mông"}, {"term_ko": "자세", "term_vi": "Tư thế", "def_ko": "체위, 자세", "def_vi": "Tư thế"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1370, '10', '침대 위에서 이동 시 대상자를 끌어당기거나 한꺼번에 많이 이동하지 않고, 조금씩 나누어 이동하는 이유는?', '["관절구축 예방", "욕창예방", "낙상예방", "근육수축 예방", "호흡곤란 예방"]'::jsonb, 4, NULL, NULL, '{"1": "관절구축 예방은 장기간 비활동으로 인해 관절이 굳는 것을 방지하는 방법입니다. 하지만 이는 주된 이유는 아닙니다.\n[정답]", "4": "근육수축 예방은 대상자의 근육이 과도하게 긴장하거나 수축하지 않도록 하여 부상을 방지하는 방법입니다.", "2": "욕창 예방은 장시간 같은 자세로 있을 때 생기는 피부 손상을 방지하기 위한 것이므로 이와는 관련이 적습니다.", "3": "낙상 예방은 대상자의 안전을 위해 중요하지만, 이동 시에 한꺼번에 많이 이동하는 것과의 직접적인 연관성은 낮습니다.", "5": "호흡곤란 예방 역시 중요한 사항이나 여기서는 근육 수축 예방이 더 관련이 높습니다."}'::jsonb, '[{"term_ko": "이동", "term_vi": "Di chuyển", "def_ko": "이동(한국어)", "def_vi": "di chuyển(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1369, '10', '오른쪽 편마비 대상자가 왼쪽으로 쏠려 누워 있을 때 침대 중앙으로 이동시키는 순서로 옳은 것은?가. 요양보호사는 대상자의 오른쪽에 선다. 나. 목에서 겨드랑이와 허리 아래에 손을 넣어 상반신을 이동시킨다. 다. 대상자의 두 팔을 가슴 위에 포갠다. 라. 하반신은 허리와 엉덩이 밑을 받쳐서 이동시킨다. 마. 머리에 베개를 받치고 침대 시트를 바르게 한다.', '["가 - 나 - 다 - 라 - 마", "나 - 가 - 다 - 마 - 라", "다 - 가 - 나 - 라 - 마", "나 - 다 - 가 - 마 - 라", "가 - 다 - 나 - 라 - 마"]'::jsonb, 2, NULL, NULL, '{"1": "요양보호사가 대상자의 오른쪽에 서는 것은 편마비 환자에게 적절한 위치가 아닙니다.\n[정답]", "2": "요양보호사는 먼저 목에서 겨드랑이와 허리 아래에 손을 넣어 상반신을 이동시키고, 이후에 대상자의 두 팔을 가슴 위에 포갠 후, 하반신을 옮기는 방법이 안전합니다.", "3": "이 순서는 비효율적이며 안전하지 않습니다.", "4": "이 순서도 적절하지 않습니다.", "5": "요양보호사가 먼저 오른쪽에 서는 것은 편마비 환자 이동 시 부적절한 위치입니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 몸이 마비된 상태", "def_vi": "Tình trạng tê liệt một bên cơ thể"}, {"term_ko": "상반신", "term_vi": "Thân trên", "def_ko": "허리 위의 몸", "def_vi": "Phần cơ thể trên hông"}, {"term_ko": "하반신", "term_vi": "Thân dưới", "def_ko": "허리 아래의 몸", "def_vi": "Phần cơ thể dưới hông"}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 전문가", "def_vi": "Chuyên gia chăm sóc bệnh nhân"}, {"term_ko": "베개", "term_vi": "Gối", "def_ko": "머리를 받치는 물건", "def_vi": "Vật kê đầu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1368, '10', '침상 내에서 대상자의 잔존기능을 유지하며 안전하게 이동하는 방법은?', '["이동 시 동작은 한번에 신속하게 시행한다.", "대상자의 동의를 구한 뒤 천천히 이동한다.", "변경 가능한 체위를 보호자와 상의한다.", "의식 상태가 있는 대상자에게만 설명한다.", "편마비 대상자는 전적으로 도와준다."]'::jsonb, 5, NULL, NULL, '{"1": "이동 시 동작은 한번에 신속하게 시행하는 것은 좋지 않으며, 신중하게 접근해야 합니다.\n[정답]", "5": "편마비 대상자는 전적으로 도와주는 것이 필요합니다.", "2": "대상자의 동의를 구한 뒤 천천히 이동하는 것이 안전하며, 동의를 받는 것이 중요합니다.", "3": "변경 가능한 체위를 보호자와 상의하는 것은 필요하지만, 직접적인 이동 방법에는 해당되지 않습니다.", "4": "의식 상태가 있는 대상자에게만 설명하는 것은 바람직하지 않으며, 가능한 모든 대상자에게 설명이 필요합니다."}'::jsonb, '[{"term_ko": "잔존기능", "term_vi": "Chức năng còn lại", "def_ko": "남아있는 기능", "def_vi": "Chức năng còn lại"}, {"term_ko": "대상자", "term_vi": "Người dùng", "def_ko": "환자", "def_vi": "Bệnh nhân"}, {"term_ko": "동의", "term_vi": "Đồng ý", "def_ko": "동의", "def_vi": "Sự đồng ý"}, {"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "편측만 마비됨", "def_vi": "Liệt một bên"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1367, '10', '대상자를 이동시킬 때 요양보호사의 신체손상을 예방하는 방법은?', '["무릎을 펴고 허리를 구부린다.", "신체의 작은 근육을 사용한다.", "발을 벌리고 서서 지지면을 넓게 한다.", "무릎을 펴고 무게중심을 높게 둔다.", "배에 힘을 배고 척추를 구부린다."]'::jsonb, 2, NULL, NULL, '{"1": "무릎을 펴고 허리를 구부리면 허리에 부담이 가중되어 부상을 초래할 수 있다.\n[정답]", "2": "신체의 작은 근육을 사용하면 부상의 위험을 줄일 수 있다.", "3": "발을 벌리고 지지면을 넓히면 안정성을 증가시킬 수 있지만, 작은 근육 사용이 더 효과적이다.", "4": "무릎을 펴고 무게중심을 높게 둔다면 균형을 잃기 쉽다.", "5": "배에 힘을 주고 척추를 구부리면 오히려 부상을 유발할 수 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người đối tượng", "def_ko": "환자(한국어)", "def_vi": "Bệnh nhân"}, {"term_ko": "이동", "term_vi": "Di chuyển", "def_ko": "움직이다(한국어)", "def_vi": "Di chuyển"}, {"term_ko": "신체", "term_vi": "Cơ thể", "def_ko": "몸(한국어)", "def_vi": "Cơ thể"}, {"term_ko": "근육", "term_vi": "Cơ bắp", "def_ko": "근육(한국어)", "def_vi": "Cơ bắp"}, {"term_ko": "무게중심", "term_vi": "Trọng tâm", "def_ko": "무게의 중심(한국어)", "def_vi": "Trọng tâm"}, {"term_ko": "부상", "term_vi": "Chấn thương", "def_ko": "상처(한국어)", "def_vi": "Chấn thương"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1366, '10', '대상자를 이동시킬 때 요양보호사가 신체정렬을 유지하는 목적은?', '["신속한 이동을 할 수 있다.", "관절의 굳어짐을 증가시킨다.", "근육의 사용을 감소시킨다.", "관절의 변형을 증가시킨다.", "편안함을 제공하고 손상의 위험을 줄인다."]'::jsonb, 3, NULL, NULL, '{"1": "신속한 이동을 할 수 있다는 것은 잘못된 진술이다.\n[정답]", "3": "근육의 사용이 감소되지 않도록 신체의 정렬을 유지하는 것이 중요하다.", "2": "관절의 굳어짐은 감소시켜야 한다.", "4": "관절의 변형이 증가하지 않도록 해야 한다.", "5": "편안함을 제공하고 손상의 위험을 줄이는 것이 목적이다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Người nhận dịch vụ chăm sóc"}, {"term_ko": "이동", "term_vi": "Di chuyển", "def_ko": "움직이다", "def_vi": "Di chuyển từ nơi này sang nơi khác"}, {"term_ko": "신체정렬", "term_vi": "Sắp xếp cơ thể", "def_ko": "바른 자세", "def_vi": "Tư thế cơ thể đúng"}, {"term_ko": "관절", "term_vi": "Khớp", "def_ko": "관절", "def_vi": "Khớp của cơ thể"}, {"term_ko": "근육", "term_vi": "Cơ", "def_ko": "근육", "def_vi": "Các mô trong cơ thể"}, {"term_ko": "손상", "term_vi": "Chấn thương", "def_ko": "손해", "def_vi": "Tổn thương xảy ra"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1365, '10', '오른쪽 편마비 대상자의 하의를 입히는 순서로 옳은 것은?가. 왼쪽 발을 하의에 넣게 한다. 나. 오른쪽 발을 하의에 넣게 한다. 다. 바지의 양쪽 허리선을 잡고 올려서 입힌다. 라. 무릎을 세우고 엉덩이를 들어 올리게 한다.', '["가 - 나 - 라 - 다", "가 - 나 - 다 - 라", "나 - 가 - 라 - 다", "나 - 가 - 다 - 라", "라 - 나 - 가 - 다"]'::jsonb, 5, NULL, NULL, '{"1": "왼쪽 발을 하의에 넣는 것이 먼저입니다. 오른쪽 편마비이므로 왼쪽부터 시작해야 합니다. \n[정답]", "5": "무릎을 세우고 엉덩이를 들어 올리는 행동이 먼저 필요합니다. 그 후 오른쪽 발, 왼쪽 발 순으로 하의를 착용하고 바지를 올리는 것이 적절합니다.", "3": "나 - 가 - 라 - 다의 순서는 하의 착용 순서에 맞지 않습니다. 하의를 입힐 때 무릎을 세우고 엉덩이를 들어 올리는 것이 먼저입니다.", "4": "나 - 가 - 다 - 라도 잘못된 순서입니다. 하의를 착용하려면 꼭 먼저 무릎을 세우고 엉덩이를 들어 올려야 합니다.", "2": "가 - 나 - 다 - 라의 순서는 올바르지 않으며, 무릎을 세우고 엉덩이를 들어 올리는 과정을 포함해야합니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "반쪽 몸이 마비된 상태", "def_vi": "Tình trạng bị liệt một nửa cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1364, '10', '왼쪽 편마비 대상자의 하의를 버기는 순서로 옳은 것은?가. 오른쪽 다리의 하의를 벗긴다. 나. 왼쪽 다리의 하의를 벗긴다. 다. 두 다리를 모아 무릎을 세운다. 라. 무릎으로 마비된 쪽의 발을 지지하고, 엉덩이를 들어 올리게 한다.', '["가 - 다 - 라 - 나", "가 - 라 - 다 - 나", "나 - 다 - 라 - 가", "다 - 라 - 나 - 가", "다 - 라 - 가 - 나"]'::jsonb, 3, NULL, NULL, '{"1": "오른쪽 다리의 하의를 먼저 벗기는 것은 잘못된 순서이다.\n[정답]", "2": "왼쪽 다리의 하의를 벗기기 전에 무릎을 세워야 한다는 점을 강조한다.", "3": "무릎을 세우고 엉덩이를 들어 올리는 것이 마비된 쪽의 다리를 더 쉽게 벗길 수 있다.", "4": "다시 오른쪽 다리의 하의를 벗기는 것은 잘못된 순서다.", "5": "무릎을 세우는 단계가 없이 하의를 벗기는 것은 부적절하다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Bệnh liệt nửa người", "def_ko": "한쪽 몸이 마비된 상태(한국어)", "def_vi": "Tình trạng tê liệt một bên cơ thể"}, {"term_ko": "무릎", "term_vi": "Đầu gối", "def_ko": "무릎관절(한국어)", "def_vi": "Khớp gối"}, {"term_ko": "하의", "term_vi": "Quần", "def_ko": "하체의 의류(한국어)", "def_vi": "Trang phục phần dưới cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1363, '10', '엉덩이를 들 수 없는 대상자의 하의를 갈아입히는 방법으로 옳은 것은?', '["침상머리를 높여 앉힌 후 입힌다.", "다리를 모아 무릎을 세운 후 벗긴다.", "똑바로 누운 상태에서 한꺼번에 벗긴다.", "좌우로 체위를 변경하며 한쪽씩 벗긴다.", "한 손으로 대상자의 허리를 지지한 후 입힌다."]'::jsonb, 5, NULL, NULL, '{"1": "침상머리를 높여 앉힌 후 입힌다. - 대상자의 엉덩이를 들 수 없기 때문에 적절하지 않은 방법입니다.\n[정답]", "5": "한 손으로 대상자의 허리를 지지한 후 입힌다. - 대상자의 하의를 갈아입히는 가장 안전하고 효과적인 방법입니다.", "2": "다리를 모아 무릎을 세운 후 벗긴다. - 엉덩이를 들 수 없으므로 잘못된 방법입니다.", "3": "똑바로 누운 상태에서 한꺼번에 벗긴다. - 무리한 방법으로, 안전하지 않습니다.", "4": "좌우로 체위를 변경하며 한쪽씩 벗긴다. - 엉덩이를 들 수 없는 경우에 적합하지 않습니다."}'::jsonb, '[{"term_ko": "엉덩이", "term_vi": "Mông", "def_ko": "엉덩이(한국어)", "def_vi": "Mông (베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1362, '10', '수액이 있는 왼쪽 편마비 대상자의 단추 있는 옷을 벗길 때 순서로 옳은 것은?', '["오른쪽 팔 - 수액주머니 - 왼쪽 팔", "오른쪽 팔 - 왼쪽 팔 - 수액주머니", "왼쪽 팔 - 수액주머니 - 오른쪽 팔", "수액주머니 - 오른쪽 팔 - 왼쪽 팔", "수액주머니 - 왼쪽 팔 - 오른쪽 팔"]'::jsonb, 4, NULL, NULL, '{"1": "오른쪽 팔을 먼저 벗기면 왼쪽 편마비로 인해 불편함이 있을 수 있다.\n[정답]", "4": "수액주머니를 먼저 제거한 뒤, 오른쪽 팔을 벗기고 마지막으로 왼쪽 팔을 벗겨야 안전하다.", "2": "왼쪽 팔을 먼저 벗기면 수액주머니에 손상을 줄 수 있다.", "3": "왼쪽 팔을 먼저 벗기면 수액주머니를 다치게 할 위험이 있다.", "5": "수액주머니를 고려하지 않고 순서를 정하면 위험할 수 있다."}'::jsonb, '[{"term_ko": "수액", "term_vi": "Dung dịch truyền", "def_ko": "액체 영양분이 포함된 의료용액", "def_vi": "Dung dịch dinh dưỡng có chứa các chất lỏng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1361, '10', '오른쪽 편마비 대상자의 앞이 막힌 상의를 벗기는 순서는?', '["왼쪽 팔 - 머리 - 오른쪽 팔", "왼쪽 팔 - 오른쪽 팔 - 머리", "오른쪽 팔 - 머리 - 왼쪽 팔", "오른쪽 팔 - 왼쪽 팔 - 머리", "머리 - 왼쪽 팔 - 오른쪽 팔"]'::jsonb, 1, NULL, NULL, '{"1": "왼쪽 팔을 먼저 들어준 후 머리를 벗기는 것이 마비된 오른쪽 팔에 부담을 주지 않아 올바른 방법입니다.\n[정답]", "2": "오른쪽 팔을 벗긴 후 머리를 먼저 벗기면 마비된 팔에 부담이 가해질 수 있습니다.", "3": "오른쪽 팔을 먼저 벗기는 것은 잘못된 순서입니다.", "4": "오른쪽 팔을 벗긴 후 왼쪽 팔을 벗기는 것은 비효율적입니다.", "5": "머리부터 벗기는 것은 마비된 팔에 불편을 초래합니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "반쪽 몸이 마비된 상태", "def_vi": "Tình trạng mất cảm giác một nửa cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1360, '10', '왼쪽 편마비 대상자에게 앞이 막힌 상의를 입히는 순서는?', '["왼쪽 팔 - 머리 - 오른쪽 팔", "왼쪽 팔 - 오른쪽 팔 - 머리", "오른쪽 팔 - 머리 - 왼쪽 팔", "오른쪽 팔 - 왼쪽 팔 - 머리", "머리 - 왼쪽 팔 - 오른쪽 팔"]'::jsonb, 1, NULL, NULL, '{"1": "왼쪽 팔에 옷을 먼저 입히면 편마비로 인해 오른쪽 팔로 도움을 줄 수 있어 원활하게 입힐 수 있습니다. [정답]", "2": "왼쪽 팔과 오른쪽 팔을 동시에 다루면 불편할 수 있습니다.", "3": "오른쪽 팔부터 시작하면 왼쪽 팔 입히기가 어려울 수 있습니다.", "4": "오른쪽 팔부터 입히면 다시 왼쪽으로 이동해야 하므로 비효율적입니다.", "5": "머리부터 입히면 편마비 환자의 팔 작동에 방해가 되어 입히기 힘듭니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽에만 마비가 있는 상태", "def_vi": "Tình trạng bị liệt chỉ một bên"}, {"term_ko": "상위", "term_vi": "Áo", "def_ko": "위쪽에 입는 옷", "def_vi": "Trang phục mặc trên cơ thể"}, {"term_ko": "입히다", "term_vi": "Mặc", "def_ko": "옷을 착용하게 하다", "def_vi": "Đưa trang phục lên người"}, {"term_ko": "순서", "term_vi": "Thứ tự", "def_ko": "어떤 것이 먼저인지의 차례", "def_vi": "Sự sắp xếp thứ tự"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1359, '10', '오른쪽 편마비 대상자의 옷 갈아입히는 방법으로 옳은 것은?', '["오른쪽부터 벗고 오른쪽부터 입는다.", "오른쪽부터 벗고 왼쪽부터 입는다.", "왼쪽부터 벗고 왼쪽부터 입는다.", "왼쪽부터 벗고 오른쪽부터 입는다.", "대상자가 원하는 쪽부터 벗고 입힌다."]'::jsonb, 1, NULL, NULL, '{"1": "오른쪽부터 벗고 오른쪽부터 입는다. - 오른쪽 편마비 대상자에게 적합한 방법입니다.\n[정답]", "2": "오른쪽부터 벗고 왼쪽부터 입는다. - 오른쪽은 우선 벗지만, 왼쪽부터 입는 것은 비효율적입니다.", "3": "왼쪽부터 벗고 왼쪽부터 입는다. - 편마비에 적합하지 않은 방법입니다.", "4": "왼쪽부터 벗고 오른쪽부터 입는다. - 잘못된 순서입니다.", "5": "대상자가 원하는 쪽부터 벗고 입힌다. - 사용자의 필요를 고려하나, 편마비 환자에게는 위험할 수 있습니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 신체가 마비된 상태", "def_vi": "Tình trạng một bên cơ thể bị liệt"}, {"term_ko": "옷 갈아입히다", "term_vi": "Thay áo", "def_ko": "옷을 입고 벗는 것", "def_vi": "Thay đổi quần áo"}, {"term_ko": "대상자", "term_vi": "Người nhận dịch vụ", "def_ko": "요양 서비스를 받는 사람", "def_vi": "Người nhận dịch vụ chăm sóc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1358, '10', '편마비 대상자의 옷 갈아입히는 순서로 옳은 것은?', '["벗을 때는 불편한 쪽부터 벗긴다.", "입을 때는 불편한 쪽부터 입힌다.", "요양보호사가 편한 쪽부터 입힌다.", "대상자가 원하는 쪽부터 입힌다.", "어느 쪽이든 상관없다."]'::jsonb, 2, NULL, NULL, '{"1": "벗을 때는 불편한 쪽부터 벗긴다. - 옷을 벗을 때는 편한 쪽부터 벗기는 것이 일반적이다.\n[정답]", "2": "입을 때는 불편한 쪽부터 입힌다. - 편마비 환자에게는 불편한 쪽부터 옷을 입히는 것이 적절하다.", "3": "요양보호사가 편한 쪽부터 입힌다. - 요양보호사는 불편한 쪽을 먼저 입혀야 한다.", "4": "대상자가 원하는 쪽부터 입힌다. - 환자 의사보다 효과적인 방법이 더 중요하다.", "5": "어느 쪽이든 상관없다. - 옷 입히는 순서를 무시하는 것은 바람직하지 않다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "반쪽이 마비된 상태", "def_vi": "Trạng thái bị liệt một bên"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1357, '10', '편마비 대상자의 옷을 선택하는 방법으로 옳은 것은?', '["상의와 하의가 연결된 옷이 좋다.", "허리와 소매가 조이는 옷이 좋다.", "앞여밈이 있거나 단추 있는 옷이 좋다.", "신축성이 없는 옷이 좋다.", "무겁고 두꺼운 옷이 좋다."]'::jsonb, 3, NULL, NULL, '{"1": "상의와 하의가 연결된 옷은 편마비 환자가 입기 어렵기 때문에 적합하지 않습니다.\n[정답]", "3": "앞여밈이 있거나 단추 있는 옷은 편리하게 입을 수 있어 적합합니다.", "2": "허리와 소매가 조이는 옷은 불편할 수 있습니다.", "4": "신축성이 없는 옷은 착용이 어렵고 불편할 수 있습니다.", "5": "무겁고 두꺼운 옷은 입기 힘들고 이동에 불편을 줄 수 있습니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "반쪽 몸이 마비됨(한국어)", "def_vi": "Bị liệt một bên cơ thể"}, {"term_ko": "상의", "term_vi": "Áo trên", "def_ko": "윗옷(한국어)", "def_vi": "Trang phục phần trên"}, {"term_ko": "하의", "term_vi": "Quần", "def_ko": "아랫옷(한국어)", "def_vi": "Trang phục phần dưới"}, {"term_ko": "조이다", "term_vi": "Chật", "def_ko": "꽉 끼다(한국어)", "def_vi": "Bị chật"}, {"term_ko": "신축성", "term_vi": "Độ co giãn", "def_ko": "늘어나는 성질(한국어)", "def_vi": "Tính đàn hồi"}, {"term_ko": "무겁다", "term_vi": "Nặng", "def_ko": "체중이 많이 나가다(한국어)", "def_vi": "Nặng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1356, '10', '침상을 정리하는 방법으로 옳은 것은?', '["창문을 닫고 더러워진 시트를 벗긴다.", "이불을 기온과 보호자의 요구에 따라 조절한다.", "방수포 밑에 반시트를 깔아둔다.", "시트 중앙선이 침대 중앙에 오도록 한다.", "침상배설을 하는 대상자는 방수포만 깔아둔다."]'::jsonb, 4, NULL, NULL, '{"1": "창문을 닫고 더러워진 시트를 벗기는 것은 침상의 정리 방법 중 첫 단계일 수 있지만, 정답이 아닙니다.\n[정답]", "2": "이불을 기온과 보호자의 요구에 따라 조절하는 것은 침상 정리의 중요한 요소입니다.", "3": "방수포 밑에 반시트를 깔아두는 것은 잘못된 방법입니다.", "4": "시트 중앙선이 침대 중앙에 오도록 하는 것은 침상을 정리할 때 가장 기본적인 방법이므로 정답입니다.", "5": "침상배설을 하는 대상자는 방수포만 깔아두는 것은 적절하지 않습니다."}'::jsonb, '[{"term_ko": "침상", "term_vi": "Giường", "def_ko": "침대(한국어)", "def_vi": "Giường ngủ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1355, '10', '침상 목욕 시 신체 부위에 따른 목욕 방법으로 옳은 것은?', '["유방은 위아래로 번갈아 가며 닦는다.", "둔부는 엉덩이 사이와 항문 주위를 닦는다.", "복부는 배꼽을 중심으로 시계 반대 방향으로 닦는다.", "팔은 어깨 - 손끝 방향, 다리는 허버지 - 발끝 방향으로 닦는다.", "뼈가 돌출된 등에 피부발적이 보이면 목욕 후 등 마사지를 한다."]'::jsonb, 2, NULL, NULL, '{"1": "유방은 위아래로 번갈아 가며 닦는다. (잘못된 방법) \n[정답]", "2": "둔부는 엉덩이 사이와 항문 주위를 닦는다. (올바른 방법)", "3": "복부는 배꼽을 중심으로 시계 반대 방향으로 닦는다. (잘못된 방법)", "4": "팔은 어깨 - 손끝 방향, 다리는 허벅지 - 발끝 방향으로 닦는다. (잘못된 방법)", "5": "뼈가 돌출된 등에 피부발적이 보이면 목욕 후 등 마사지를 한다. (잘못된 방법)"}'::jsonb, '[{"term_ko": "침상", "term_vi": "Giường", "def_ko": "침대 위", "def_vi": "trên giường"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1354, '10', '침상 목욕 시 복부를 배꼽을 중심으로 시계방향으로 닦아주는 이유는?', '["혈액순환을 위해서", "욕창을 예방하기 위해서", "소화기능을 돕기 위해서", "긴장감을 완화하기 위해서", "장운동을 촉진하기 위해서"]'::jsonb, 5, NULL, NULL, '{"1": "혈액순환을 위해서\n복부 목욕 시에는 직접적인 혈액순환과 관련이 적습니다.\n[정답]", "2": "장운동을 촉진하기 위해서\n복부를 시계방향으로 닦는 것은 장운동을 자극하여 소화에 도움이 됩니다.", "3": "소화기능을 돕기 위해서\n장운동 촉진과 연관이 있지만, 직접적인 목적은 아닙니다.", "4": "긴장감을 완화하기 위해서\n일반적으로 긴장감 완화와는 관련이 부족합니다.", "5": "욕창을 예방하기 위해서\n욕창 예방은 바른 자세와 피부 관리가 중요합니다."}'::jsonb, '[{"term_ko": "침상 목욕", "term_vi": "Tắm trên giường", "def_ko": "침대에서 하는 목욕", "def_vi": "Tắm cho bệnh nhân nằm trên giường"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1353, '10', '침상 목욕으 돕는 방법 중 올바른 것은?', '["눈은 바깥에서 안쪽으로 닦는다.", "몸의 중심부에서 말초 부위로 닦는다.", "복부는 배꼽을 중심으로 시계방향으로 닦는다.", "목욕 후 등마사지는 삼간다.", "목욕을 마친 후 식사를 하게 한다."]'::jsonb, 3, NULL, NULL, '{"1": "눈은 바깥에서 안쪽으로 닦는다. - 고르지 않은 방법입니다. 눈은 안쪽에서 바깥쪽으로 닦아야 합니다.\n[정답]", "2": "몸의 중심부에서 말초 부위로 닦는다. - 최적의 방법이 아닙니다. 말초 부위에서 중심으로 닦는 것이 권장됩니다.", "3": "복부는 배꼽을 중심으로 시계방향으로 닦는다. - 올바른 방법입니다.", "4": "목욕 후 등마사지는 삼간다. - 권장되지 않는 방법입니다. 보통 마사지는 좋습니다.", "5": "목욕을 마친 후 식사를 하게 한다. - 맞지 않는 방법입니다. 식사는 목욕 전후로 주의해야 합니다."}'::jsonb, '[{"term_ko": "침상 목욕", "term_vi": "Tắm trên giường", "def_ko": "침대에서 하는 목욕", "def_vi": "Tắm cho bệnh nhân nằm trên giường"}, {"term_ko": "올바른", "term_vi": "Đúng", "def_ko": "정확한", "def_vi": "Chính xác"}, {"term_ko": "복부", "term_vi": "Bụng", "def_ko": "배", "def_vi": "Phần bụng"}, {"term_ko": "배꼽", "term_vi": "Rốn", "def_ko": "배꼽", "def_vi": "Rốn"}, {"term_ko": "시계방향", "term_vi": "Chiều kim đồng hồ", "def_ko": "시계 방향", "def_vi": "Hướng kim đồng hồ"}, {"term_ko": "등마사지", "term_vi": "Massage lưng", "def_ko": "등 마사지", "def_vi": "Xoa bóp lưng"}, {"term_ko": "식사", "term_vi": "Ăn uống", "def_ko": "음식을 먹다", "def_vi": "Ăn uống"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1352, '10', '여성 대상자의 침상 목욕 돕기로 옳은 것은?', '["유방은 원을 그리듯이 닦는다.", "어깨에서 손목 쪽으로 닦는다.", "허벅지에서 발끝 쪽으로 닦는다.", "옆으로 눕게 하여 둔부에서 목 뒤까지 닦는다.", "회음부는 항문에서 요도 방향으로 닦는다."]'::jsonb, 1, NULL, NULL, '{"1": "유방은 원을 그리듯이 닦는다. 이 방법은 적절한 방법입니다. [정답]", "2": "어깨에서 손목 쪽으로 닦는다. 이는 일반적으로 올바른 방법이지만, 유방 세정에는 적합하지 않습니다.", "3": "허벅지에서 발끝 쪽으로 닦는다. 일반적인 세정법이지만 여성 대상자에게는 비위생적일 수 있습니다.", "4": "옆으로 눕게 하여 둔부에서 목 뒤까지 닦는다. 이 방법은 올바르지 않습니다. 둔부는 직접적으로 세정하여야 합니다.", "5": "회음부는 항문에서 요도 방향으로 닦는다. 이 방법은 잘못된 방법입니다. 회음부 세정은 요도에서 항문 방향으로 닦아야 합니다."}'::jsonb, '[{"term_ko": "여성 대상자", "term_vi": "Người nữ", "def_ko": "여성 환자", "def_vi": "Bệnh nhân nữ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1351, '10', '침상 목욕을 돕는 방법으로 옳은 것은?', '["얼굴은 입 주위부터 닦는다.", "유방은 위에서 아래로 닦는다.", "양쪽 상지는 손목 쪽에서 팔 쪽으로 닦는다.", "다리는 허벅지에서 발끝으로 닦는다.", "복부는 배꼽을 중심으로 시계 반대방향으로 닦는다."]'::jsonb, 3, NULL, NULL, '{"1": "얼굴은 입 주위부터 닦는 것이 아니라, 코에서 귀쪽으로 닦아야 합니다.\n[정답]", "3": "양쪽 상지는 손목 쪽에서 팔 쪽으로 닦는 것이 올바른 방법입니다.", "2": "유방은 위에서 아래로 닦지 않고, 아래에서 위로 닦아야 합니다.", "4": "다리는 허벅지에서 발끝으로 닦는 것이 맞습니다.", "5": "복부는 배꼽을 중심으로 시계 방향으로 닦아야 합니다."}'::jsonb, '[{"term_ko": "침상", "term_vi": "Giường ngủ", "def_ko": "침대에서 누워 있는 상태", "def_vi": "trạng thái nằm trên giường"}, {"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "몸을 씻는 행위", "def_vi": "hành động rửa cơ thể"}, {"term_ko": "유방", "term_vi": "Ngực", "def_ko": "여성의 가슴", "def_vi": "ngực của phụ nữ"}, {"term_ko": "복부", "term_vi": "Bụng", "def_ko": "배 부분", "def_vi": "phần bụng"}, {"term_ko": "시계 반대방향", "term_vi": "Ngược chiều kim đồng hồ", "def_ko": "시계와 반대 방향", "def_vi": "ngược chiều của kim đồng hồ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1350, '10', '대상자의 통 목욕을 돕는 방법으로 옳은 것은?', '["물의 온도는 18~20도로 맞춘다.", "목욕 직전 따뜻한 우유나 차를 마시도록 한다.", "목욕 중 창문을 열어 수증기를 없앤다.", "몸통 - 팔 - 다리 - 회음부 순서로 닦아낸다.", "목욕 후 오일 등 피부유연제를 발라준다."]'::jsonb, 5, NULL, NULL, '{"1": "물의 온도는 개인의 피부 상태 및 환경에 따라 다를 수 있으므로, 36도 이상으로 맞추는 것이 일반적이다.\n[정답]", "5": "목욕 후 오일 등 피부유연제를 사용하여 피부를 보호하고 보습하는 것이 중요하다.", "2": "따뜻한 음료를 마시는 것은 도움이 될 수 있지만 필수는 아니다.", "3": "목욕 중에 창문을 열면 오히려 체온 저하가 우려되므로 바람이 차가운 경우에는 하지 않는 것이 좋다.", "4": "목욕 시 세척 순서는 다소 다를 수 있으며, 일반적으로 몸통부터 시작하는 것이 좋다."}'::jsonb, '[{"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "목욕(한국어)", "def_vi": "Tắm(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1349, '10', '편마비 대상자의 통목욕을 돕는 방법으로 옳은 것은?', '["건강한 쪽 겨드랑이를 잡고 욕조로 이동시킨다.", "마비된 쪽 다리부터 욕조에 들어가게 한다.", "말초에서 중심 방향으로 닦아 준다.", "마비된 쪽 손으로 안전손잡이를 잡게 한다.", "욕조에서 머리를 감긴 후 밖으로 나오게 한다."]'::jsonb, 3, NULL, NULL, '{"1": "건강한 쪽 겨드랑이를 잡고 욕조로 이동시킨다. (잘못된 방법입니다, 통목욕 시 안전을 위해서는 마비된 쪽이 아닌 안전한 쪽을 잡는 것이 좋습니다.)\n[정답]", "2": "마비된 쪽 다리부터 욕조에 들어가게 한다. (오류입니다, 먼저 건강한 쪽 다리를 넣는 것이 안전합니다.)", "3": "말초에서 중심 방향으로 닦아 준다. (정확한 방법으로, 원활한 혈류를 유지하게 도와줍니다.)", "4": "마비된 쪽 손으로 안전손잡이를 잡게 한다. (잘못된 방법입니다, 마비된 쪽 손의 힘이 약할 수 있어 안전하지 않습니다.)", "5": "욕조에서 머리를 감긴 후 밖으로 나오게 한다. (위험할 수 있는 방법이며, 일반적으로 욕조에 들어가기 전에 머리를 감기는 것이 바람직합니다.)"}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽이 마비된 상태", "def_vi": "Tình trạng bị liệt một bên"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1348, '10', '편마비 대상자의 통목욕을 돕는 방법으로 옳은 것은?', '["실내 온도를 30~40도로 맞춘다.", "혈압이 높으면 물의 온도를 뜨겁게 한다.", "요양보호사의 발끝으로 물의 온도를 확인한다.", "욕조 턱 높이와 목욕의자 높이를 같게 맞춘다.", "목욕 후 선 채로 옷을 입힌다."]'::jsonb, 4, NULL, NULL, '{"1": "실내 온도를 30~40도로 맞추는 것은 저온으로 인한 체온 감소를 조절하기 위한 것이지만, 적정 온도는 상황에 따라 다를 수 있다.\n[정답]", "4": "욕조 턱 높이와 목욕의자 높이를 같게 맞추면 대상자가 안전하게 목욕할 수 있다.", "2": "혈압이 높으면 물의 온도를 뜨겁게 하는 것은 위험할 수 있다.", "3": "요양보호사의 발끝으로 물의 온도를 확인하는 것은 안전한 방법이 아니다.", "5": "목욕 후 선 채로 옷을 입히는 것은 넘어질 위험이 있어 바람직하지 않다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa", "def_ko": "한쪽 신체가 마비된 상태", "def_vi": "Tình trạng liệt một bên cơ thể"}, {"term_ko": "통목욕", "term_vi": "Tắm toàn thân", "def_ko": "전신 목욕", "def_vi": "Tắm cho toàn bộ cơ thể"}, {"term_ko": "욕조", "term_vi": "Bồn tắm", "def_ko": "목욕을 위한 큰 용기", "def_vi": "Thiết bị lớn dùng để tắm"}, {"term_ko": "턱", "term_vi": "Bậc", "def_ko": "높이", "def_vi": "Chiều cao"}, {"term_ko": "높이", "term_vi": "Chiều cao", "def_ko": "높음", "def_vi": "Độ cao"}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 사람", "def_vi": "Người chăm sóc bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1347, '10', '오른쪽 편마비 대상자가 통목욕을 할 때 돕는 방법은?', '["식사 직전이나 직후에 실시한다.", "욕실로 이동 시에는 왼쪽을 지지한다.", "욕조 안에 미끄럼방지 매트를 깔아둔다.", "욕조에 30분 정도 담그게 한다.", "욕조의 중앙에 중심을 잡고 앉게 한다."]'::jsonb, 3, NULL, NULL, '{"1": "식사 직전이나 직후에 목욕을 실시하는 것은 피해야 합니다.\n[정답]", "2": "욕실로 이동할 때 왼쪽을 지지해야 안전합니다.", "3": "욕조 안에 미끄럼방지 매트를 깔아두는 것은 안전을 위한 필수 사항입니다.", "4": "욕조에 30분 동안 담그는 것은 장시간 노출에 대한 위험이 있습니다.", "5": "욕조의 중앙에 중심을 잡고 앉게 하는 것은 균형 유지에 도움이 되지 않습니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한 쪽 몸이 마비된 상태", "def_vi": "Trạng thái bị yếu một bên cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1346, '10', '편마비 대상자의 통 목욕 시 욕조에 들어가고 나가는 방법으로 옳은 것은?', '["건강한 쪽으로 먼저 들어가고 마비된 쪽으로 먼저 나온다.", "마비된 쪽으로 먼저 들어가고 건강한 쪽으로 먼저 나온다.", "건강한 쪽으로 먼저 들어가고 건강한 쪽으로 먼저 나온다.", "마비된 쪽으로 먼저 들어가고 마비된 쪽으로 먼저 나온다.", "어느 쪽이든 상관없다."]'::jsonb, 3, NULL, NULL, '{"1": "건강한 쪽으로 먼저 들어가고 마비된 쪽으로 먼저 나온다. : 잘못된 방법입니다. 이렇게 할 경우 마비된 쪽으로 나올 때 낙상의 위험이 있습니다.\n[정답]", "2": "마비된 쪽으로 먼저 들어가고 건강한 쪽으로 먼저 나온다. : 잘못된 방법입니다. 마비된 쪽으로 먼저 들어가는 것은 불안정합니다.", "3": "건강한 쪽으로 먼저 들어가고 건강한 쪽으로 먼저 나온다. : 올바른 방법입니다. 안전성을 최우선으로 고려한 접근입니다.", "4": "마비된 쪽으로 먼저 들어가고 마비된 쪽으로 먼저 나온다. : 잘못된 방법입니다. 이는 환자를 불안정하게 할 수 있습니다.", "5": "어느 쪽이든 상관없다. : 잘못된 접근입니다. 안전을 고려해야 합니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Bại liệt nửa người", "def_ko": "한쪽 몸이 마비된 상태", "def_vi": "Tình trạng liệt một bên cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1345, '10', '통 목욕 시 욕조에 들어가기 전에 씻기는 순서로 옳은 것은?', '["팔 - 몸통 - 회음부 - 다리", "팔 - 몸통 - 다리 - 회음부", "회음부 - 다리 - 팔 - 몸통", "다리 - 회음부 - 팔 - 몸통", "다리 - 팔 - 몸통 - 회음부"]'::jsonb, 5, NULL, NULL, '{"1": "팔, 몸통, 회음부, 다리 순서로 씻는 것은 일반적인 순서가 아닙니다.", "2": "팔, 몸통, 다리, 회음부 순서도 비효율적입니다.", "3": "회음부를 가장 먼저 씻는 것은 hygiene 관점에서 바람직하지 않습니다.", "4": "다리, 회음부, 팔, 몸통 순서 또한 일반적이지 않습니다.\n[정답]", "5": "다리, 팔, 몸통, 회음부 순서가 올바른 씻는 순서입니다. 다리부터 시작해 상반신으로 이동하고 마지막에 회음부를 씻어야 위생적입니다."}'::jsonb, '[{"term_ko": "욕조", "term_vi": "Bồn tắm", "def_ko": "목욕용 수조", "def_vi": "Bồn chứa nước để tắm"}, {"term_ko": "씻다", "term_vi": "Rửa", "def_ko": "깨끗하게 하다", "def_vi": "làm sạch"}, {"term_ko": "회음부", "term_vi": "Vùng kín", "def_ko": "생식기와 항문 사이의 부위", "def_vi": "Vùng giữa cơ quan sinh dục và hậu môn"}, {"term_ko": "다리", "term_vi": "Chân", "def_ko": "인간의 하체 부분", "def_vi": "Phần dưới cơ thể của con người"}, {"term_ko": "팔", "term_vi": "Tay", "def_ko": "인간의 상체 부분", "def_vi": "Phần trên cơ thể của con người"}, {"term_ko": "몸통", "term_vi": "Thân", "def_ko": "신체의 중심 부분", "def_vi": "Phần trung tâm của cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1344, '10', '대상자의 통목욕을 돕는 방법으로 옳은 것은?', '["욕조물에 30분 정도 담근 후 씻긴다.", "목욕물의 온도는 22~26도를 유지한다.", "욕조에 들어가기 전에 목욕의자에 앉혀 머리를 감긴다.", "체온이 유지되도록 몸에 따뜻한 물을 자주 뿌려준다.", "혈액순환을 위해 몸의 중심에서 말초 방향으로 닦는다."]'::jsonb, 4, NULL, NULL, '{"1": "욕조물에 30분 정도 담근 후 씻기는 것은 과다한 수압과 체온 저하를 초래할 수 있습니다.\n[정답]", "4": "체온이 유지되도록 몸에 따뜻한 물을 자주 뿌려주는 것이 중요합니다.", "2": "목욕물의 온도는 22~26도는 너무 낮아도 체온 저하의 위험이 있습니다.", "3": "욕조에 들어가기 전에 목욕의자에 앉혀 머리를 감기는 것은 위생 문제로 바람직하지 않습니다.", "5": "혈액순환을 위해 몸의 중심에서 말초 방향으로 닦는 것은 잘못된 방법입니다."}'::jsonb, '[{"term_ko": "통목욕", "term_vi": "Tắm toàn thân", "def_ko": "전신을 목욕하는 것", "def_vi": "Tắm cho toàn bộ cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1343, '10', '목욕 돕기 방법으로 옳은 것은?', '["기분이 불쾌하거나 피로할 때 목욕을 한다.", "욕실에 손잡이를 붙인다.", "목욕은 1시간 이상 여유있게 한다.", "목욕 중에는 말을 걸지 않는다.", "식사 직전에 목욕을 한다."]'::jsonb, 2, NULL, NULL, '{"1": "기분이 좋지 않거나 피로할 때는 목욕을 피하는 것이 좋습니다.\n[정답]", "2": "욕실에 손잡이를 설치하는 것은 안전성을 높이는 좋은 방법입니다.", "3": "목욕은 편안한 시간을 위해 여유있게 진행해야 하지만 1시간 이상 계속할 필요는 없습니다.", "4": "목욕 중에 이용자의 안정을 위해 대화를 자제하는 것이 좋습니다.", "5": "식사 직전에 목욕을 하는 것은 소화에 좋지 않을 수 있습니다."}'::jsonb, '[{"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "목욕(한국어)", "def_vi": "Tắm(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1342, '10', '대상자의 목욕 돕기 방법으로 옳은 것은?', '["목욕 전에 대, 소변을 보게 한다.", "욕실 문을 열어 놓는다.", "심장에서 가까운 곳부터 물이 닿도록 한다.", "목욕을 거부하는 치매 대상자는 강제로 목욕을 시킨다.", "안전사고 예방을 위해 대상자를 전적으로 돕는다."]'::jsonb, 1, NULL, NULL, '{"1": "목욕 전에 대, 소변을 보게 하는 것은 위생과 안전을 고려한 올바른 방법입니다.\n[정답]", "2": "욕실 문을 열어 놓는 것은 사생활 보호에 대한 배려가 부족합니다.", "3": "심장에서 가까운 곳부터 물이 닿도록 하는 방법은 목욕 시 안전하게 물 온도를 조절하는 데 도움이 됩니다.", "4": "목욕을 거부하는 치매 대상자는 강제로 목욕을 시키는 것은 정신적 스트레스를 유발할 수 있어 바람직하지 않습니다.", "5": "안전사고 예방을 위해 대상자를 전적으로 돕는 것은 대상자의 자율성을 해칠 수 있습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người nhận", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1341, '10', '대상자의 면도를 도울 때 피부손상을 예방하는 방법은?', '["수염이 자란 반대 방향으로 면도한다.", "면도크림은 수염이 난 방향으로 바른다.", "짧게 나누어 일정한 속도로 면도한다.", "면도할 부위의 거품을 깨끗이 씻어낸 후 면도한다.", "수염의 강도가 강한 부위에서 약한 부위의 순으로 면도한다."]'::jsonb, 3, NULL, NULL, '{"1": "면도 방향이 중요하지만, 수염이 자란 반대 방향으로 면도할 경우 피부가 면도기와 닿을 때 자극을 받을 수 있다.\n[정답]", "3": "면도를 짧게 나누어 일정한 속도로 하는 것이 피부 손상을 예방하는 데 효과적이다.", "2": "면도크림은 수염 방향에 따라 바르지만 이에 따른 피부손상 예방 효과는 제한적이다.", "4": "면도 후 거품을 깨끗이 씻어내는 것이 아니라, 면도 전과 후에 모두 깨끗하게 씻어내야 한다.", "5": "수염의 강도가 강한 부위에서 약한 부위로 면도하는 것은 오히려 피부 자극을 증가시킬 수 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người dùng", "def_ko": "환자 또는 서비스 이용자", "def_vi": "Bệnh nhân hoặc người sử dụng dịch vụ"}, {"term_ko": "면도", "term_vi": "Cạo râu", "def_ko": "수염을 깎는 행위", "def_vi": "Hành động cạo tóc trên mặt"}, {"term_ko": "피부손상", "term_vi": "Tổn thương da", "def_ko": "피부에 발생하는 손상", "def_vi": "Tổn thương xảy ra trên da"}, {"term_ko": "면도크림", "term_vi": "Kem cạo", "def_ko": "면도 전 피부에 바르는 크림", "def_vi": "Kem bôi lên da trước khi cạo"}, {"term_ko": "거품", "term_vi": "Bọt", "def_ko": "면도크림이 발라진 후 생기는 기포", "def_vi": "Bọt hình thành sau khi thoa kem cạo"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1340, '10', '대상자에게 면도 돕기를 할 때 옳은 것은?', '["침상에 반듯하게 누운 상태로 면도한다.", "주름진 피부는 위로 잡아당겨 면도한다.", "면도 전 따뜻한 물수건으로 덮어 건조함을 완화한다.", "면도날은 얼굴피부와 90도 정도의 각도를 유지한다.", "전기면도기 사용을 피한다."]'::jsonb, 3, NULL, NULL, '{"1": "침상에 반듯하게 누운 상태로 면도하는 것은 올바르지 않다. 대상자는 편안하게 있는 것이 중요하다.", "2": "주름진 피부를 위로 잡아당겨 면도하는 것은 피부를 상하게 할 수 있으므로 주의해야 한다.\n[정답]", "3": "면도 전 따뜻한 물수건으로 덮어 건조함을 완화하는 것은 피부 건강에 좋다.", "4": "면도날은 얼굴 피부와 90도 정도의 각도를 유지하는 것은 위험할 수 있다. 각도를 조절해야 한다.", "5": "전기면도기 사용을 피하는 것은 잘못된 정보이다. 전기면도기를 사용할 수 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1339, '10', '대사자의 세수를 돕는 방법으로 옳은 것은?', '["침대를 수평으로 하여 눕힌다.", "귓바퀴와 귀의 뒷면은 닦지 않는다.", "숸에 비누를 묻혀 눈 주변을 닦는다.", "비염 예방을 위해 코 안쪽 코털도 모두 깎아준다.", "안경은 하루에 한 번 이상 깨끗하게 닦는다."]'::jsonb, 5, NULL, NULL, '{"1": "침대를 수평으로 하여 눕힌다: 대사자의 편안한 세수를 돕기 위해서 필요한 조치이나 세수 도우미와 관련이 뚜렷하지 않다.", "2": "귓바퀴와 귀의 뒷면은 닦지 않는다: 위생 관점에서 잘못된 정보로, 세수 시 귀 주변도 닦아야 한다.", "3": "숸에 비누를 묻혀 눈 주변을 닦는다: 눈 주위는 민감하기 때문에 비누를 직접 사용해선 안 된다.\n[정답]", "4": "비염 예방을 위해 코 안쪽 코털도 모두 깎아준다: 코 안쪽 코털을 깎는 것은 위생에 좋지만 해당 문장은 세수와 직접적 관련이 없다.", "5": "안경은 하루에 한 번 이상 깨끗하게 닦는다: 세수와 관련된 위생 관리의 중요한 요소로 올바른 지침이다."}'::jsonb, '[{"term_ko": "대사자", "term_vi": "Người hỗ trợ", "def_ko": "환자를 도와주는 사람", "def_vi": "Người giúp người bệnh"}, {"term_ko": "세수", "term_vi": "Rửa mặt", "def_ko": "얼굴을 씻는 행위", "def_vi": "Hành động rửa mặt"}, {"term_ko": "귓바퀴", "term_vi": "Vành tai", "def_ko": "귀의 바깥 부분", "def_vi": "Phần bên ngoài của tai"}, {"term_ko": "비염", "term_vi": "Viêm mũi", "def_ko": "코의 염증", "def_vi": "Viêm của mũi"}, {"term_ko": "안경", "term_vi": "Kính", "def_ko": "시력을 보조하는 기구", "def_vi": "Thiết bị hỗ trợ thị lực"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1338, '10', '대상자의 세수를 돕는 방법으로 옳은 것은?', '["눈썹은 면도칼로 다듬어 준다.", "면봉으로 귀 안쪽의 귀지를 닦아낸다.", "코 안과 코 볼, 둘레를 세심히 닦는다.", "입술과 그 주변을 알코올 솜으로 닦는다.", "사용한 수건의 면으로 양쪽 눈을 번갈아 가며 닦는다."]'::jsonb, 3, NULL, NULL, '{"1": "눈썹은 면도칼로 다듬어 주지 않아야 한다. 면도칼은 안전하지 않다.\n[정답]", "3": "코 안과 코 볼, 둘레를 세심히 닦아주는 것이 올바른 방법이다.", "2": "면봉으로 귀 안쪽을 다루는 것은 위험할 수 있다.", "4": "입술과 그 주변은 알코올 솜으로 닦지 않고 부드러운 천으로 닦아야 한다.", "5": "사용한 수건의 면으로 양쪽 눈을 번갈아 가며 닦는 것은 위생적으로 좋지 않다."}'::jsonb, '[{"term_ko": "세수", "term_vi": "Tắm rửa", "def_ko": "얼굴을 씻다(세 mặt)", "def_vi": "Rửa mặt"}, {"term_ko": "눈썹", "term_vi": "Lông mày", "def_ko": "눈의 털", "def_vi": "Lông trên mắt"}, {"term_ko": "면도칼", "term_vi": "Dao cạo", "def_ko": "면도를 하는 도구", "def_vi": "Dụng cụ cạo"}, {"term_ko": "귀지", "term_vi": "Ráy tai", "def_ko": "귀 안의 오염물질", "def_vi": "Vật bẩn trong tai"}, {"term_ko": "입술", "term_vi": "Môi", "def_ko": "입의 부위", "def_vi": "Phần của miệng"}, {"term_ko": "알코올", "term_vi": "Cồn", "def_ko": "소독하는 물질", "def_vi": "Chất khử trùng"}, {"term_ko": "눈", "term_vi": "Mắt", "def_ko": "시각 기관", "def_vi": "Cơ quan thị giác"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1337, '10', '침상에 누워있는 대상자의 세수를 돕는 방법으로 옳은 것은?', '["코 안은 알코올 솜으로 닦는다.", "귀 입구와 귓바퀴, 뒷면을 닦는다.", "눈의 바깥쪽에서 안쪽으로 닦는다.", "깊숙한 곳의 귀지는 면봉으로 제거한다.", "이마 - 눈 - 귀 - 코 순으로 닦는다."]'::jsonb, 2, NULL, NULL, '{"1": "코 안은 알코올 솜으로 닦는다. (코 안을 알코올로 닦는 것은 피부 자극과 감염 위험이 있으므로 부적절하다.)\n[정답]", "2": "귀 입구와 귓바퀴, 뒷면을 닦는다. (귀를 청결히 유지하는 것은 중요하며, 이 방법이 올바르다.)", "3": "눈의 바깥쪽에서 안쪽으로 닦는다. (눈은 바깥쪽에서 안쪽으로 닦는 것이 좋지만, 이 문제가 묻는 세수의 내용과는 다소 다르다.)", "4": "깊숙한 곳의 귀지는 면봉으로 제거한다. (귀지를 깊숙히 제거하는 것은 오히려 귀를 손상시킬 수 있다.)", "5": "이마 - 눈 - 귀 - 코 순으로 닦는다. (세수의 절차로는 다소 부적절하다.)"}'::jsonb, '[{"term_ko": "침상", "term_vi": "Giường", "def_ko": "침대(한국어)", "def_vi": "Giường"}, {"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자(한국어)", "def_vi": "Bệnh nhân"}, {"term_ko": "세수", "term_vi": "Rửa mặt", "def_ko": "얼굴을 씻는 것(한국어)", "def_vi": "Rửa mặt"}, {"term_ko": "귓바퀴", "term_vi": "Sụn tai", "def_ko": "귀의 일부분(한국어)", "def_vi": "Phần sụn của tai"}, {"term_ko": "귀", "term_vi": "Tai", "def_ko": "귀(한국어)", "def_vi": "Tai"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1336, '10', '남성 대상자의 회음부를 청결하게 하는 방법은?', '["둔부 밑에 변기를 넣은 다음 아래에 방수포를 깐다.", "차가운 물을 음부에 끼얹은 다음 비누로 닦는다.", "음경을 수건으로 잡고 피부가 겹치는 부분과 음낭의 뒷면을 닦는다.", "변기를 빼낸 후 둔부에 남아 있는 물기를 젖은 수건으로 닦아낸다.", "목욕담요를 마름모꼴로 펴서 대상자의 무릎 아래를 덮는다."]'::jsonb, 3, NULL, NULL, '{"1": "둔부 아래에 변기를 두고 방수포를 깐다면 오히려 청결 유지에 방해가 될 수 있습니다.\n[정답]", "3": "음경을 수건으로 잡고 피부가 겹치는 부분과 음낭의 뒷면을 닦는 방법이 가장 적절합니다.", "2": "차가운 물을 음부에 끼얹는 것은 피부에 불쾌감을 줄 수 있으며, 비누를 사용하기 전에 이렇게 하는 것은 좋지 않습니다.", "4": "변기를 빼낸 후 둔부에 남아 있는 물기를 닦는 것은 청결을 유지하는 방법이지만, 음부 청결 관리의 주체가 아닙니다.", "5": "목욕담요를 마름모꼴로 펴는 것은 개별적인 청결과는 관련이 없습니다."}'::jsonb, '[{"term_ko": "회음부", "term_vi": "Vùng bìu", "def_ko": "생식기와 항문 사이의 부위(한국어)", "def_vi": "Đoạn giữa bộ phận sinh dục và hậu môn"}, {"term_ko": "변기", "term_vi": "Nồi tiểu", "def_ko": "소변을 보는 용기(한국어)", "def_vi": "Chậu đi tiểu"}, {"term_ko": "비누", "term_vi": "Xà phòng", "def_ko": "세척제(한국어)", "def_vi": "Chất tẩy rửa"}, {"term_ko": "음경", "term_vi": "Dương vật", "def_ko": "남성의 성기(한국어)", "def_vi": "Bộ phận sinh dục nam"}, {"term_ko": "음낭", "term_vi": "Bìu", "def_ko": "남성의 성기를 보호하는 주머니 모양의 피부(한국어)", "def_vi": "Túi da bảo vệ dương vật"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1335, '10', '회음부 청결을 돕는 방법으로 옳은 것은?', '["작업공간의 확보를 위해 스크린을 치지 않는다.", "회음부에 염증이 있으면 연고를 발라준다.", "따뜻한 물을 음부에 끼얹는 다음 비눗물을 묻힌다.", "물수건으로 뒤쪽에서 앞쪽으로 닦는다.", "청결을 위해 처음부터 끝까지 요양보호사가 닦아준다."]'::jsonb, 3, NULL, NULL, '{"1": "스크린을 치지 않으면 개인의 사생활 보호에 문제가 생길 수 있다. 따라서 잘못된 방법이다.\n[정답]", "2": "염증이 있을 경우 연고 사용은 추천되지 않으며, 의료인의 처방이 필요하다.", "3": "따뜻한 물을 음부에 끼얹은 다음 비눗물을 묻힌다. 이는 올바른 청결 방법이다.", "4": "물수건으로 닦을 때는 앞에서 뒤쪽으로 닦아야 하며, 반대는 잘못된 방법이다.", "5": "청결을 위해 요양보호사가 처음부터 끝까지 닦아주는 것은 환자의 자율성을 침해할 수 있다."}'::jsonb, '[{"term_ko": "회음부", "term_vi": "Perineum", "def_ko": "인체의 생식기와 항문 사이의 부위", "def_vi": "Vùng giữa cơ quan sinh dục và hậu môn"}, {"term_ko": "비눗물", "term_vi": "Nước xà phòng", "def_ko": "비누와 물이 섞인 것", "def_vi": "Hỗn hợp giữa xà phòng và nước"}, {"term_ko": "청결", "term_vi": "Vệ sinh", "def_ko": "더러움이 없는 상태", "def_vi": "Trạng thái không có bụi bẩn"}, {"term_ko": "자율성", "term_vi": "Quyền tự chủ", "def_ko": "스스로 결정할 수 있는 능력", "def_vi": "Khả năng tự quyết định"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1334, '10', '여성 대상자의 회음부를 청결하게 하는 방법으로 옳은 것은?', '["침대 머리를 높인 상태에서 돕는다.", "소독제로 손을 닦은 후 멸균장갑을 착용한다.", "누워서 다리를 쭉 편 상태에서 닦는다.", "목욕담요를 마름모꼴로 펴서 아랫단 가운데 부분으로 회음부를 덮어준다.", "회음부에 분비물이 있으면 좌욕을 하게 한다."]'::jsonb, 4, NULL, NULL, '{"1": "침대 머리를 높인 상태에서 돕는 것은 회음부 청결과 직접적인 관련이 없다.\n[정답]", "4": "목욕담요를 마름모꼴로 펴서 아랫단 가운데 부분으로 회음부를 덮어주면 청결 유지에 도움이 된다.", "3": "누워서 다리를 쭉 편 상태에서 닦는 것은 적절한 자세이나, 청결 방법으로는 부족하다.", "2": "소독제로 손을 닦은 후 멸균장갑을 착용하는 것은 기본적인 위생 절차이나, 회음부 청결 방법 자체가 아니다.", "5": "회음부에 분비물이 있을 경우 좌욕은 도움이 되지만, 기본적인 청결 방법으로는 회음부를 덮는 방법이 더 맞다."}'::jsonb, '[{"term_ko": "회음부", "term_vi": "Âm hộ", "def_ko": "여성 생식기의 하부 부분", "def_vi": "Phần dưới của cơ quan sinh dục nữ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1333, '10', '회음부 청결을 위해 닦아주는 순서로 옳은 것은?', '["요도 - 질- 항문", "질 - 요도 - 항문", "질 - 항문 - 요도", "항문 - 요도 - 질", "항문 - 질 - 요도"]'::jsonb, 1, NULL, NULL, '{"1": "요도 - 질 - 항문 순서가 청결을 유지하기에 적절합니다.", "2": "질 - 요도 - 항문은 순서가 잘못되었습니다.", "3": "질 - 항문 - 요도 또한 청결 유지에 부적절한 순서입니다.", "4": "항문 - 요도 - 질은 청결을 해칠 위험이 큽니다.", "5": "항문 - 질 - 요도도 순서적으로 올바르지 않습니다."}'::jsonb, '[{"term_ko": "회음부", "term_vi": "Vùng hậu môn sinh dục", "def_ko": "생식기와 항문 사이의 부위", "def_vi": "Khu vực giữa cơ quan sinh dục và hậu môn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1332, '10', '여성 대상자의 회음부 청결을 통해 예방할 수 있는 질환은?', '["자궁암", "치질", "요실금", "요로감염", "매독"]'::jsonb, 4, NULL, NULL, '{"1": "자궁암은 회음부 청결과 직접적인 관련이 없습니다.\n[정답]", "4": "요로감염은 회음부 청결을 통해 효과적으로 예방할 수 있습니다.", "2": "치질은 회음부와는 관련성 있지만, 청결로 예방되지는 않습니다.", "3": "요실금은 근육과 관련된 문제로 청결이 예방에 큰 영향을 미치지 않습니다.", "5": "매독은 성병으로, 청결과 직접적인 연관이 없습니다."}'::jsonb, '[{"term_ko": "회음부", "term_vi": "Perineum", "def_ko": "여성의 생식기와 항문 사이의 부위", "def_vi": "Vùng giữa cơ quan sinh dục nữ và hậu môn"}, {"term_ko": "청결", "term_vi": "Vệ sinh", "def_ko": "깨끗하게 하는 것", "def_vi": "Làm sạch"}, {"term_ko": "요로감염", "term_vi": "Nhiễm trùng đường tiết niệu", "def_ko": "소변이 감염되는 것", "def_vi": "Nhiễm trùng trong đường tiết niệu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1331, '10', '대상자가 부끄럽다며 회음부 씻는 것을 거부할 때 대처방법은?', '["대상자가 요청할 때까지 기다린다.", "보호자에게 연락하여 도움을 요청한다.", "청결을 위해 본인 의사와 관계없이 씻긴다.", "전용 물수건을 제공하여 스스로 씻을 수 있게 한다.", "대상자를 존중하여 거부 의사를 받아드린다."]'::jsonb, 4, NULL, NULL, '{"1": "대상자의 요청을 기다리는 것은 수동적인 대처로, 청결 문제 해결에 효과적이지 않습니다.\n[정답]", "4": "전용 물수건을 제공하여 스스로 씻을 수 있게 하는 방법은 대상자의 자율성을 존중하면서 청결을 유지할 수 있는 좋은 방법입니다.", "2": "보호자에게 도움을 요청하는 것은 상황에 따라 유용할 수 있으나, 대상자의 의사를 존중해야 합니다.", "3": "본인 의사와 관계없이 씻기는 것은 대상자의 동의를 무시하는 행동으로 바람직하지 않습니다.", "5": "거부 의사를 받아들이는 것 또한 중요하지만, 청결을 유지하는 방법을 제시해야 할 필요가 있습니다."}'::jsonb, '[{"term_ko": "회음부", "term_vi": null, "def_ko": "신체의 생식 기관과 항문 사이의 부분", "def_vi": null}, {"term_ko": "부끄럽다", "term_vi": null, "def_ko": "쑥쓰럽거나 수치스러운 느낌", "def_vi": null}, {"term_ko": "청결", "term_vi": null, "def_ko": "깨끗함", "def_vi": null}, {"term_ko": "자율성", "term_vi": null, "def_ko": "스스로 선택할 권리", "def_vi": null}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1330, '10', '대상자의 발톱이 살 안쪽으로 심하게 파고들어 상처가 났을 경우 대처방법은?', '["온찜질을 해준다.", "간호사에게 보고한다.", "발톱을 짧게 잘라준다.", "붕대로 발톱을 감싸준다.", "발톱을 둥글게 잘라준다."]'::jsonb, 2, NULL, NULL, '{"1": "온찜질은 발톱 문제에 도움이 되지 않습니다.\n[정답]", "2": "간호사에게 보고하는 것이 중요합니다.", "3": "발톱을 짧게 자르는 것은 위험할 수 있습니다.", "4": "붕대로 감싸는 것은 상처에 대한 올바른 대처가 아닙니다.", "5": "발톱을 둥글게 자르는 방법은 권장되지 않습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "치료를 받는 사람", "def_vi": "Người nhận điều trị"}, {"term_ko": "발톱", "term_vi": "Móng chân", "def_ko": "손가락의 끝에 있는 굳은 부분", "def_vi": "Phần cứng ở đầu ngón tay"}, {"term_ko": "상처", "term_vi": "Vết thương", "def_ko": "피부에 난 손상", "def_vi": "Tổn thương trên da"}, {"term_ko": "간호사", "term_vi": "Y tá", "def_ko": "환자의 건강을 돌보는 전문인", "def_vi": "Người chăm sóc sức khỏe cho bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1329, '10', '대상자 발의 청결을 돕는 방법으로 옳은 것은?', '["가능하면 대상자를 앉힌다.", "발가락 사이를 알코올로 닦는다.", "발을 씻기 전에 발톱을 자른다.", "무좀이 있는 발은 젖은 수건으로 감싸둔다.", "살 안쪽으로 심하게 파고든 발톱은 잘라낸다."]'::jsonb, 1, NULL, NULL, '{"1": "가능하면 대상자를 앉힌다. 대상자의 안정성을 높이고 청결을 돕기 위한 기본적인 행동입니다.\n[정답]", "2": "발가락 사이를 알코올로 닦는다. 발가락 사이를 청결하게 하기 위해 적절하지 않으며 피부 자극을 줄 수 있습니다.", "3": "발을 씻기 전에 발톱을 자른다. 이 방법은 청결을 위한 올바른 순서지만, 발을 씻기 전에 해야 하는 것은 아닙니다.", "4": "무좀이 있는 발은 젖은 수건으로 감싸둔다. 이는 오히려 상태를 악화시킬 수 있으므로 권장되지 않습니다.", "5": "살 안쪽으로 심하게 파고든 발톱은 잘라낸다. 이는 위험할 수 있으며 전문적인 처치가 필요할 수 있습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자(한국어)", "def_vi": "Bệnh nhân(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1328, '10', '대상자의 손과 발을 관리하는 방법으로 옳은 것은?', '["모직으로 된 양말을 신긴다.", "발의 티눈은 손톱깎이로 제거한다.", "따뜻한 물에 손과 발을 10~15분간 담근다.", "두꺼워진 발톱은 식초물에 담갔다가 자른다.", "발콥 주위에 염증이 있을 경우 소독을 해준다."]'::jsonb, 3, NULL, NULL, '{"1": "모직으로 된 양말은 통기성이 좋지 않아 발에 땀이나 습기가 차서 피부 문제를 일으킬 수 있습니다.\n[정답]", "3": "따뜻한 물에 손과 발을 10~15분간 담그는 것은 혈액순환을 촉진하고 피부를 부드럽게 하여 관리에 적합합니다.", "2": "발의 티눈은 손톱깎이로 제거할 경우 상처를 낼 수 있어 적절하지 않습니다.", "4": "두꺼워진 발톱은 식초물에 담근 후 자르기 보다는 전문적인 도움을 받는 것이 좋습니다.", "5": "발콥 주위에 염증이 있을 경우 소독을 해주는 것은 좋지만, 정확한 치료가 필요해 즉시 전문의를 찾아야 합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "환자", "def_vi": "Bệnh nhân"}, {"term_ko": "손과 발", "term_vi": "Tay và chân", "def_ko": "손과 발", "def_vi": "Tay và chân"}, {"term_ko": "티눈", "term_vi": "Mắt cá chân", "def_ko": "피부의 굳은살", "def_vi": "Mụn cóc trên da"}, {"term_ko": "소독", "term_vi": "Khử trùng", "def_ko": "감염 예방을 위한 청결 행위", "def_vi": "Hành động làm sạch để ngăn ngừa nhiễm trùng"}, {"term_ko": "혈액순환", "term_vi": "Tuần hoàn máu", "def_ko": "혈액이 몸 속을 흐르는 과정", "def_vi": "Quy trình máu lưu thông trong cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1327, '10', '노인의 피부 건조를 예방하는 방법으로 옳은 것은?', '["수분 섭취량을 줄인다.", "지성용 비누를 사용한다.", "오일이나 로션을 주기적으로 발라준다.", "실내를 따뜻하고 건조하게 한다.", "매일 뜨거운 물로 목욕을 한다."]'::jsonb, 3, NULL, NULL, '{"1": "수분 섭취량을 줄이는 것은 피부 건조를 악화시킬 수 있습니다.\n[정답]", "3": "오일이나 로션을 주기적으로 발라주는 것은 피부의 수분을 유지하는 데 도움이 됩니다.", "2": "지성용 비누는 피부를 더욱 건조하게 만들 수 있습니다.", "4": "실내를 따뜻하고 건조하게 하는 것은 피부 건조를 유발할 수 있습니다.", "5": "매일 뜨거운 물로 목욕하는 것은 피부의 기름을 제거하여 건조를 악화시킵니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "고령의 사람", "def_vi": "Người lớn tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1326, '10', '침상에 누워 지내는 대상자의 머리를 손질하는 방법으로 옳은 것은?', '["머리카락이 엉켰을 경우 잘라 낸다.", "모발 끝에서 두피 방향을 빗질한다.", "거울을 제공하여 머리 모양을 확인하게 한다.", "탈모 예방을 위해 이틀에 한 번씩 빗질한다.", "요양보호사의 기호에 따라 머리 모양을 정리한다."]'::jsonb, 3, NULL, NULL, '{"1": "머리카락이 엉켰을 경우 잘라 낸다. 잘라내는 것은 바람직하지 않다.\n[정답]", "2": "모발 끝에서 두피 방향을 빗질한다. 이 방법이 올바른 방법이다.", "3": "거울을 제공하여 머리 모양을 확인하게 한다. 대상자가 스스로 확인할 수 있게 돕는 것은 중요하다.", "4": "탈모 예방을 위해 이틀에 한 번씩 빗질한다. 이는 빈도가 부족하다.", "5": "요양보호사의 기호에 따라 머리 모양을 정리한다. 대상자의 선호를 무시하는 것은 바람직하지 않다."}'::jsonb, '[{"term_ko": "침상", "term_vi": "Giường", "def_ko": "침대(한국어)", "def_vi": "giường"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1325, '10', '대상자의 머리카락이 엉켰을 경우 올바른 손질 방법은?', '["세게 잡아당겨 빗질한다.", "물을 적신 후 큰 빗으로 빗긴다.", "두피세정제를 발라 빗긴다.", "참빗으로 빗어 머리카락을 펴준다.", "가족의 동의를 얻어 엉킨 머리카락을 자른다."]'::jsonb, 2, NULL, NULL, '{"1": "머리카락을 세게 잡아당기면 통증을 유발할 수 있어 잘못된 방법입니다.\n[정답]", "2": "물을 적신 후 큰 빗으로 빗는 방법은 엉킨 머리카락을 부드럽게 풀 수 있는 올바른 방법입니다.", "3": "두피세정제를 발라서 빗는 것은 좋은 방법이지만, 세정제 없이 물을 적신 상태에서 빗는 것이 더 효과적입니다.", "4": "참빗으로 빗는 방법은 잘못된 방법이 아니지만, 두피와 머리카락을 부드럽게 다루는 것이 우선입니다.", "5": "가족의 동의를 얻어 머리카락을 자르는 것은 엉킨 머리카락을 자르는 극단적인 방법으로, 가능한 지양해야 합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자 또는 돌봄을 받는 사람", "def_vi": "Người nhận sự chăm sóc hoặc chăm sóc"}, {"term_ko": "머리카락", "term_vi": "Tóc", "def_ko": "인간의 머리에서 자라는 털", "def_vi": "Sợi tóc mọc trên đầu người"}, {"term_ko": "엉키다", "term_vi": "Rối", "def_ko": "서로 얽히거나 엮이다", "def_vi": "Bị vướng hoặc mắc vào nhau"}, {"term_ko": "손질", "term_vi": "Chăm sóc", "def_ko": "다듬거나 관리하는 것", "def_vi": "Cắt tỉa hoặc quản lý"}, {"term_ko": "세정제", "term_vi": "Chất tẩy rửa", "def_ko": "청결을 위해 쓰는 약물", "def_vi": "Chất dùng để làm sạch"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1324, '10', '드라이샴푸를 이용하여 머리를 감기는 방법으로 옳은 것은?', '["물과 샴푸를 1:1로 섞어서 사용한다.", "샴푸를 머리에 바르고 수건으로 덮어 둔다.", "샴푸 거품을 두피에 발라 흡수시킨 후 물로 헹군다.", "샴푸를 머리카락에 발라 거품을 낸 후 수건으로 닦아낸다.", "머리카락에 물을 적신 후, 샴푸를 바르고 빗으로 빗어준다."]'::jsonb, 4, NULL, NULL, '{"1": "물과 샴푸를 1:1로 섞는 방법은 드라이샴푸의 사용법이 아닙니다.\n[정답]", "4": "드라이샴푸는 머리카락에 바르고 수건으로 닦아내는 방법으로 사용합니다.", "2": "샴푸를 머리에 바르고 수건으로 덮어 두는 방법은 적합하지 않습니다.", "3": "샴푸 거품을 두피에 발라 흡수시킨 후 물로 헹구는 것은 일반 샴푸 사용법입니다.", "5": "머리카락에 물을 적신 후, 샴푸를 바르고 빗으로 빗는 방법은 드라이샴푸가 아닌 일반 샴푸에 해당합니다."}'::jsonb, '[{"term_ko": "드라이샴푸", "term_vi": "Dầu gội khô", "def_ko": "물 없이 사용하는 샴푸", "def_vi": "Dầu gội không cần nước"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1323, '10', '침상에 누워있는 대상자의 머리를 감기는 방법으로 옳은 것은?', '["눈과 귀에 수건을 올려 덮는다.", "수건으로 가슴부터 허리까지 감싼다.", "대상자의 어깨가 침대 모서리에 오도록 한다.", "뒷머리는 목을 좌우로 돌리면서 헹군다.", "린스를 한 후 수건으로 닦아 말린다."]'::jsonb, 4, NULL, NULL, '{"1": "눈과 귀에 수건을 올려 덮는다. 이 방법은 적절하지 않으며, 대상자의 시야를 가릴 수 있어 위험할 수 있습니다.\n[정답]", "2": "수건으로 가슴부터 허리까지 감싼다. 이는 보호를 위한 방법으로 잘못된 방법입니다.", "3": "대상자의 어깨가 침대 모서리에 오도록 한다. 올바른 방법이지만 가장 좋은 방법은 아닙니다.", "4": "뒷머리는 목을 좌우로 돌리면서 헹군다. 이는 머리를 감길 때 적절한 방법입니다.", "5": "린스를 한 후 수건으로 닦아 말린다. 역시 중요한 단계이지만 올바른 첫 번째 방법이 아닙니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1322, '10', '침대에서 대상자의 머리를 감기는 방법으로 옳은 것은?', '["침대 모서리에 머리가 오도록 한다.", "방수포를 머리부터 엉덩이까지 깐다.", "목욕담요를 덮고, 이불은 다리까지 접어 내린다.", "머리 밑에 패드를 펴고 패드 끝은 매트리스 밑으로 접어 넣는다.", "패드가 없으면 이불을 말아서 사용한다."]'::jsonb, 1, NULL, NULL, '{"1": "대상자의 머리를 침대 모서리에 위치시키는 것이 좋다. 머리를 감기기 용이함이 확보된다.\n[정답]", "2": "방수포는 머리부터 엉덩이까지 깔 필요가 없다. 반드시 필요한 범위를 넘어가는 내용이다.", "3": "목욕담요를 덮는 것은 타당하지만, 이불을 다리까지 접어 내리는 것은 선택적이다.", "4": "머리 밑에 패드를 펴는 방식은 필요하지만, 패드 끝이 매트리스 밑으로 접혀야 한다는 지시는 없으므로 반드시 필요하진 않다.", "5": "패드가 없을 경우 이불을 말아 사용하는 것은 일반적이지 않다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1321, '10', '두발 청결을 위한 머리 감기기 방법으로 옳은 것은?', '["문과 창문을 열어놓는다.", "겨울에는 오전 시간을 이용한다.", "귐가이 솜으로 양쪽 귀를 막는다.", "목욕의자의 앉혀 머리를 뒤로 젖히고 감긴다.", "한기를 느끼지 않도록 물의 온도를 뜨겁게 한다."]'::jsonb, 3, NULL, NULL, '{"1": "문과 창문을 열어놓는 것은 환기를 위해 좋지만, 머리 감기기 방법으로는 직접적인 관련이 없다.\n[정답]", "2": "겨울에 오전 시간을 이용하는 것은 머리 감기기 방법으로 적절하지 않다. 겨울철은 외부 온도가 낮아 추가적인 주의가 필요하다.", "3": "귐가이 솜으로 양쪽 귀를 막는 것은 귀에 물이 들어가는 것을 방지할 수 있어 좋은 방법이다.", "4": "목욕의자에 앉혀 머리를 뒤로 젖히는 것은 안전하지만 올바른 방법이 아니다. 적절한 위치에서 감겨야 한다.", "5": "한기를 느끼지 않도록 물의 온도를 뜨겁게 하는 것은 피부에 손상을 줄 수 있다. 적정 온도를 유지해야 한다."}'::jsonb, '[{"term_ko": "두발", "term_vi": "Tóc", "def_ko": "머리카락과 몸의 털", "def_vi": "Tóc và lông trên cơ thể"}, {"term_ko": "청결", "term_vi": "Sạch sẽ", "def_ko": "깨끗함", "def_vi": "Sự sạch sẽ"}, {"term_ko": "겨울", "term_vi": "Mùa đông", "def_ko": "찬 계절", "def_vi": "Mùa lạnh"}, {"term_ko": "목욕의자", "term_vi": "Ghế tắm", "def_ko": "목욕 시 앉는 의자", "def_vi": "Ghế ngồi khi tắm"}, {"term_ko": "귐가이 솜", "term_vi": "Bông gòn bịt tai", "def_ko": "귀를 막는 솜", "def_vi": "Bông gòn để bịt tai"}, {"term_ko": "물의 온도", "term_vi": "Nhiệt độ nước", "def_ko": "물의 뜨거운 정도", "def_vi": "Mức độ nóng của nước"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1320, '10', '대상자의 머리를 감기는 방법으로 옳은 것은?', '["저녁 식사 후에 감긴다.", "10도 정도의 물로 감긴다.", "머리를 감기 전에 대소변을 보게 한다.", "두피에 염증이 있으면 두피보호제를 바른다.", "수건으로 감싼 머리카락을 비벼가며 물기를 제거한다."]'::jsonb, 3, NULL, NULL, '{"1": "저녁 식사 후에 감기는 방법은 특정하지 않으며, 개인의 상황에 따라 다를 수 있다.\n[정답]", "3": "머리를 감기 전에 대소변을 보게 하는 것은 대상자의 편안함과 청결을 위한 중요한 과정이다.", "2": "10도 정도의 물로 감기는 것은 너무 차가운 물로 대상자에게 불편함을 줄 수 있다.", "4": "두피에 염증이 있는 경우는 두피보호제를 사용하는 것이 좋지만, 반드시 그렇다고 할 수는 없다.", "5": "수건으로 비비며 물기를 제거하는 것은 두피에 손상을 줄 수 있으므로 바람직하지 않다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người theo dõi", "def_ko": "환자", "def_vi": "Bệnh nhân"}, {"term_ko": "두피", "term_vi": "Da đầu", "def_ko": "머리의 피부", "def_vi": "Da của đầu"}, {"term_ko": "대소변", "term_vi": "Đi vệ sinh", "def_ko": "배변", "def_vi": "Đi đại tiện"}, {"term_ko": "염증", "term_vi": "Viêm", "def_ko": "부종", "def_vi": "Sưng"}, {"term_ko": "보호제", "term_vi": "Sản phẩm bảo vệ", "def_ko": "지키는 것", "def_vi": "Sản phẩm bảo vệ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1319, '10', '대상자의 머리를 감기는 방법으로 옳은 것은?', '["두피를 손톱으로 마사지한다.", "공복과 식후를 피하여 감긴다.", "두피에 상처가 있으면 연고를 바른다.", "감긴 후에 남은 물기는 자연 건조한다.", "헤어드라이어를 두피에 바짝 대고 신속하게 말린다."]'::jsonb, 2, NULL, NULL, '{"1": "두피를 손톱으로 마사지한다는 것은 두피에 상처를 유발할 수 있어 적절하지 않다.\n[정답]", "2": "공복과 식후를 피하여 감긴다는 것은 대상자의 안전을 위해 매우 중요한 사항이다.", "3": "두피에 상처가 있으면 연고를 바르는 것은 해당 상황에 맞는 조치가 아니다. 상처를 치료하기 위해서는 의사의 상담이 필요하다.", "4": "감긴 후에 남은 물기를 자연 건조하는 것은 바람직한 방법이나, 적절한 방법은 대상자의 상태에 따라 다르다.", "5": "헤어드라이어를 두피에 바짝 대고 신속하게 말린다는 것은 화상을 입힐 위험이 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자", "def_vi": "Bệnh nhân"}, {"term_ko": "머리", "term_vi": "Đầu", "def_ko": "머리 부분", "def_vi": "Phần đầu"}, {"term_ko": "감기", "term_vi": "Gội", "def_ko": "씻다", "def_vi": "Rửa"}, {"term_ko": "공복", "term_vi": "Nhịn ăn", "def_ko": "음식을 먹지 않은 상태", "def_vi": "Trạng thái không ăn thức ăn"}, {"term_ko": "식후", "term_vi": "Sau khi ăn", "def_ko": "음식을 먹은 후", "def_vi": "Sau khi ăn"}, {"term_ko": "상처", "term_vi": "Vết thương", "def_ko": "다치다", "def_vi": "Bị thương"}, {"term_ko": "연고", "term_vi": "Thuốc mỡ", "def_ko": "치료용 연고", "def_vi": "Thuốc chữa bệnh"}, {"term_ko": "자연 건조하다", "term_vi": "Khô tự nhiên", "def_ko": "자연 상태로 말리다", "def_vi": "Làm khô tự nhiên"}, {"term_ko": "헤어드라이어", "term_vi": "Máy sấy tóc", "def_ko": "드라이기", "def_vi": "Máy sấy tóc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1318, '10', '의치를 세척할 때 의치세정제가 없을 경우 대신 사용할 수 있는 것은?', '["알코올", "표백제", "레몬즙", "주방세제", "과산화수소"]'::jsonb, 4, NULL, NULL, '{"1": "알코올은 소독에는 효과적이나 의치 세척에는 적합하지 않습니다.\n[정답]", "4": "주방세제는 의치세정제로 사용할 수 있는 적절한 대체품입니다.", "2": "표백제는 의치에 손상을 줄 수 있습니다.", "3": "레몬즙은 산성 성분이 있어 의치에 해를 끼칠 수 있습니다.", "5": "과산화수소는 의치 세척에 적합하지 않습니다."}'::jsonb, '[{"term_ko": "의치", "term_vi": "Hàm giả", "def_ko": "의수를 위한 인공 치아", "def_vi": "Răng giả"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1317, '10', '대상자의 의치를 관리하는 방법으로 옳은 것은?', '["의치를 소독할 때에는 표백제에 담근다.", "격일로 의치를 빼놓아 잇몸의 압박을 줄인다.", "윗니를 끼울 때에는 손바닥으로 밀어서 끼운다.", "의치를 끼우기 전에 전자레인지에 1분간 데워준다.", "찬물이 담긴 용기에 의치를 넣어 보관한다."]'::jsonb, 5, NULL, NULL, '{"1": "의지를 소독할 때에는 표백제 대신 전용 소독제를 사용해야 한다.\n[정답]", "5": "찬물에 담긴 용기에 보관하여 의치가 변형되는 것을 방지한다.", "2": "격일로 의치를 빼놓는 것은 잇몸의 건강에 좋지 않다.", "3": "윗니를 끼울 때에는 밀어서가 아니라 적절한 방법으로 착용해야 한다.", "4": "전자레인지에 데우는 것은 의치의 소재에 따라 손상을 줄 수 있다."}'::jsonb, '[{"term_ko": "의치", "term_vi": "Hàm giả", "def_ko": "틀니", "def_vi": "Hàm giả"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1316, '10', '대상자의 의치를 관리하는 방법으로 옳은 것은?', '["베타딘 용액에 담가 보관한다.", "세면기에 물을 받아서 의치를 헹군다.", "윗니와 아랫니 의치를 동시에 끼운다.", "의치 삽입 전에 구강세정제로 입안을 헹구게 한다.", "인지저하나 마비가 있는 경우 의치 사용을 못하게 한다."]'::jsonb, 4, NULL, NULL, '{"1": "베타딘 용액은 의치에 적합하지 않으며, 의치의 손상을 초래할 수 있다.\n[정답]", "4": "의치 삽입 전에 구강세정제로 입안을 헹구게 하는 것은 전반적인 구강 위생을 증진시킨다.", "2": "세면기에 물을 받아서 의치를 헹구는 것은 비위생적일 수 있다.", "3": "윗니와 아랫니 의치를 동시에 끼우는 것은 올바른 관리 방법이 아니다.", "5": "인지저하나 마비가 있는 경우에도 의치 사용은 가능하나, 적절한 관리가 필요하다."}'::jsonb, '[{"term_ko": "의치", "term_vi": "Răng giả", "def_ko": "틀니", "def_vi": "hàm giả"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1315, '10', '대상자의 의치를 관리하는 방법으로 옳은 것은?', '["뜨거운 물에 삶아서 소독한다.", "깨끗한 휴지에 싸서 보관한다.", "의치를 세척하여 끼운 채로 자게 한다.", "의치를 끼우기 전에 잇몸 마사지를 해준다.", "의치를 뺄 때에는 아래쪽을 먼저 빼 준다."]'::jsonb, 4, NULL, NULL, '{"1": "뜨거운 물은 의치의 변형을 초래할 수 있으므로 소독 방법으로 적절하지 않습니다.\n[정답]", "2": "깨끗한 휴지에 싸서 보관하는 것은 올바른 방법이 아니며, 적절한 보관 방법이 필요합니다.", "3": "의치를 끼운 채로 자게 하는 것은 치아에 부담을 줄 수 있으므로 올바른 방법이 아닙니다.", "4": "의치를 끼우기 전에 잇몸 마사지를 해주는 것은 잇몸의 혈액순환을 돕고 적응을 도울 수 있기 때문에 올바른 방법입니다.", "5": "의치를 뺄 때에는 위쪽을 먼저 빼는 것이 원칙입니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자", "def_vi": "Bệnh nhân"}, {"term_ko": "의치", "term_vi": "Răng giả", "def_ko": "인공 치아", "def_vi": "Răng nhân tạo"}, {"term_ko": "소독", "term_vi": "Khử trùng", "def_ko": "감염 예방을 위한 청결한 처리", "def_vi": "Xử lý sạch sẽ để ngăn ngừa nhiễm trùng"}, {"term_ko": "마사지", "term_vi": "Mát xa", "def_ko": "부드럽게 주물러 주는 행동", "def_vi": "Hành động xoa bóp nhẹ nhàng"}, {"term_ko": "잇몸", "term_vi": "Nướu", "def_ko": "치아가 심어진 부위", "def_vi": "Vùng mà răng được gắn vào"}]'::jsonb) on conflict (id) do nothing;
